INSERT INTO public.photos VALUES (21928, 'Vista aâ”œÂ®rea Coso Bajo aâ”œâ–’os 40', 'Archivo Municipal. 1927 (dataciâ”œâ”‚n improbable que aparece en la ficha tâ”œÂ®cnica del Archivo). Un vuelo a motor captura desde el Barrio de Jesâ”œâ•‘s el cuadrante al este del decumano maximo romano, desde el novâ”œÂ¡simo S. Vicente de Paâ”œâ•‘l (a la derecha) apenas comenzado a construir los nuevos edificios que lo delimitarâ”œÃ­n, hasta mâ”œÃ­s allâ”œÃ­ del Huerva (a la izquierda). Inmediatamente, el Ebro, el Puente de Hierro, el Paseo del Ebro (actual Echegaray y Caballero), la Plaza Tenerâ”œÂ¡as con el enorme Depâ”œâ”‚sito de Automâ”œâ”‚viles del Ejâ”œÂ®rcito, y el final del Coso Bajo, donde destaca la mole de la Universidad Literaria de la Magdalena, tal y como lucâ”œÂ¡a desde la profunda reforma de 1846. A su izquierda, parte del antiguo Barrio de la Seo (barrio del siglo XII y construcciones de los siglos XVI-XVIII), con un catâ”œÃ­logo de viales muy remozado por la impostaciâ”œâ”‚n de S. Vicente de Paâ”œâ•‘l, afectando total o parcialmente al Postigo al Ebro, calleja del Conde Alperche, callizo de La Rosa, calle del Garro, callizo del Retiro, calle del Silencio, calle Palafox, callizo de Don Morâ”œÂ¡n, placeta de Liâ”œâ–’â”œÃ­n, calle Juan de Aragâ”œâ”‚n, placeta de Segovia, plaza de Clariana, plaza del Reino.... Junto al Huerva, a la izquierda, el campo de fâ”œâ•‘tbol de la Torre de Bruil, o de la calle Asalto, activo desde 1924 y con capacidad para 6000 aficionados, donde jugaba el "Zaragoza F.C." Muy cerca, la fâ”œÃ­brica de regaliz ZARA, y el "Corral de Abastos de Intendencia" (actual parque "Corral de la leâ”œâ–’a"). El Puente de S. Josâ”œÂ® abre la Pza. de San Miguel (visible arriba del todo) hacia Miguel Servet y el Camino del Bajo Aragâ”œâ”‚n. Ya al otro lado del Huerva, la enorme superficie de los lavaderos (y tendederos) "de la Puerta del Duque". Inmediata, la harinera del Pilar. Finalmente, visual de la enorme estructura de la Tercera Comandancia de Intendencia del Ejâ”œÂ®rcito, sito sobre las ruinas del anterior Convento de San Josâ”œÂ®, que hasta comienzos del siglo XX fue Penal de convictos que redimâ”œÂ¡an sus penas cosiendo trajes. Incluido en la setentera "Op', 1940, 1940, 1949, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65528600, -0.87298300, '0101000020E6100000D3D85E0B7AEFEBBF69C36169E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14873165933.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14873165933.webp', 'https://www.flickr.com/photos/zaragozaantigua/14873165933/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
