INSERT INTO public.photos VALUES (22091, 'Santiago Apâ”œâ”‚stol c.1950', 'Estatua del Apâ”œâ”‚stol Santiago, obra del escultor Antonio Torres, en el taller de la calle de Florencio Jardiel, antes de ser colocada sobre la puerta Este de la basâ”œÂ¡lica del Pilar de Zaragoza. La obra de remodelaciâ”œâ”‚n de la fachada, dirigida por Teodoro Râ”œÂ¡os, fue inaugurada en 1952. Fuente visual: Imâ”œÃ­genes de nuestras vidas. El Periâ”œâ”‚dico de Aragâ”œâ”‚n, 2015.', 1950, 1950, 1950, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65709700, -0.87951800, '0101000020E610000058C9C7EE0225ECBF5DA626C11BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19154405196.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19154405196.webp', 'https://www.flickr.com/photos/zaragozaantigua/19154405196/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
