INSERT INTO public.photos VALUES (21352, 'Plaza del Pilar c.1900', 'Imagen capturada en la plaza del Pilar y centrada en el concurrido ingreso bajo o principal al templo metropolitano. En primer tâ”œÂ®rmino, el empedrado pavimento del plaza lindero con la calle de Damiâ”œÃ­n Forment.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65597400, -0.87821900, '0101000020E6100000F33977BB5E1AECBF5E83BEF4F6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54636251689.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54636251689.webp', 'https://www.flickr.com/photos/zaragozaantigua/54636251689/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23285, 'Calle de Alfonso I 1891', 'La calle Alfonso, una de esas tradicionales y castizas calles de las de "toda la vida", fue abierta en la dâ”œÂ®cada de 1860, como otra imitaciâ”œâ”‚n del Parâ”œÂ¡s del Segundo Imperio. Su propâ”œâ”‚sito era crear un marco escâ”œÂ®nico ideal para la burguesâ”œÂ¡a de la ciudad, uniendo el Coso con la plaza del Pilar. Su apertura se hizo modificando y realineando el trazado de todas las calles previas, comenzando por la calle del antiguo Trenque del Arzobispo, y terminando con la calle del antiguo Mesâ”œâ”‚n de los Navarros. Como suele ser habitual, comerciantes e inquilinos protestaron porque las obras significaban el fin del mundo y el colapso de la economâ”œÂ¡a internacional (por este orden). Todas las calles transversales debieron acomodar en chaflâ”œÃ­n su encuentro con la nueva vâ”œÂ¡a, y la homogeneidad compositiva se impuso en las fachadas de la calle, en cuyos bajos se instalâ”œâ”‚ la crema comercial de la ciudad: cafâ”œÂ®s, confiterâ”œÂ¡as, bazares, platerâ”œÂ¡as, sastres. Alfonso I se convirtiâ”œâ”‚ en sinâ”œâ”‚nimo de paseo, compras. escaparate, chafardeo, cotilleo. "Ganâ”œâ”‚ la ciudad" es lo que se suele decir cuando en efecto son los propietarios del suelo y los bancos los que se llevan la parte del leâ”œâ”‚n. En la imagen, visiâ”œâ”‚n en altura de la novâ”œÂ¡sima calle Alfonso I desde las alturas de la basâ”œÂ¡lica concatedral, que permite apreciar en perspectiva la pulcra rectitud del nuevo trazado de esta parte antigua de la ciudad. Al fondo, en el entronque con el Coso Alto, insâ”œâ”‚lita vista del palacio del marquâ”œÂ®s de Campo Franco, entre el palacio de Sâ”œÃ­stago (izquierda) y el palacio del conde Fuentes (derecha), antes de ser convertida en la sede del Banco de Aragâ”œâ”‚n (inaugurado en 1917). Mucho mâ”œÃ­s al fondo, el nuevo y descomunal edificio de la Facultad de Medicina y Ciencias, que se inaugurarâ”œÃ­ un par de aâ”œâ–’os despuâ”œÂ®s. Y mâ”œÃ­s allâ”œÃ­ no hay mâ”œÃ­s. Fuente visual: AHPZ, Estudio Coyne, c.1891', 1891, 1891, 1891, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65597700, -0.87920600, '0101000020E6100000A14D0E9F7422ECBFCFF6E80DF7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14984794535.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14984794535.webp', 'https://www.flickr.com/photos/zaragozaantigua/14984794535/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
