INSERT INTO public.photos VALUES (22704, 'Pl. del Pilar 1970', 'Zona oriental de la plaza del Pilar, en una vista capturada junto a la puerta Baja de la basâ”œÂ¡lica y con el telâ”œâ”‚n de fondo de la plaza de la Seo. Los elementos decorativos, ademâ”œÃ­s de un ajardinado espacio al pie del monumento a Goya, conforman uno de los cambiantes montajes que han caracterizado este singular escenario urbano. A la derecha y en primer tâ”œÂ®rmino, mozos de reemplazo del antiguo Servicio Militar Obligatorio se dirigen al Pilar.', 1970, 1970, 1970, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65584400, -0.87769600, '0101000020E61000007E8FFAEB1516ECBF90A339B2F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27709802468.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27709802468.webp', 'https://www.flickr.com/photos/zaragozaantigua/27709802468/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
