INSERT INTO public.photos VALUES (23802, 'Estudios folklâ”œâ”‚ricos 1965', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 11/05/1965. "Primera jornada de estudios folklâ”œâ”‚ricos aragoneses." En el programa, ponencias como "La vivienda popular aragonesa", o "La cerâ”œÃ­mica aragonesa", y actuaciones de grupos de Dance y Jota mostrando lo mejor de su repertorio en el Teatro Principal y la plaza del Pilar. Cerrâ”œâ”‚ Antonio Beltrâ”œÃ­n con las conclusiones de las sesiones de estudio. En la imagen, uno de los grupos de Dance en pleno "palotiau", bajo la presidencia de la Cruz de los Caâ”œÂ¡dos en la Cruzada de Liberaciâ”œâ”‚n contra el comunismo, sita en la plaza del Pilar. San Juan de los Panetes, en tierra de penumbra.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65708700, -0.88064600, '0101000020E61000008C4D2B85402EECBF39D0436D1BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15196109887.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15196109887.webp', 'https://www.flickr.com/photos/zaragozaantigua/15196109887/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
