INSERT INTO public.photos VALUES (21271, 'Campo Sepulcro 1900', 'El desde antiguo triangular Campo Sepulcro, era un espacio de fluido trâ”œÃ­nsito al suroeste de la ciudad, entre el muro de rejola, la puerta del Portillo, y los conventos extramuros de los Agustinos descalzos, y de los Trinitarios, ademâ”œÃ­s de enlazar con los caminos hacia Calatayud y Daroca. Tras la instalaciâ”œâ”‚n de la cercana estaciâ”œâ”‚n de ferrocarril de la compaâ”œâ–’â”œÂ¡a MZA, que pronto tomarâ”œÂ¡a su nombre, esta zona conociâ”œâ”‚ una notable variedad de usos, como espacio de desfiles y alardes militares, para probanza y exhibiciâ”œâ”‚n de ingenios volanderos (cometas), estadio de "football amateur"... y como estudio fotogrâ”œÃ­fico al aire libre. En la imagen, posado de "Plutâ”œâ”‚n", caballo ganador del concurso de ganado celebrado en las fiestas del Pilar. Junto a â”œÂ®l, su propietario (Mamâ”œÂ®s Lafita), de Fuentes de Ebro. Al fondo, tras el arbolado paseo de Marâ”œÂ¡a Agustâ”œÂ¡n, la câ”œâ•‘pula de la Casa de la Misericordia. Fuente: Foto Pasiego, Revista "Iris" (Barcelona).', 1900, 1900, 1900, 'Anos 1900', 'DELICIAS', 41.65283200, -0.89287600, '0101000020E6100000F6436CB07092ECBF21E4BCFF8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22369464911.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22369464911.webp', 'https://www.flickr.com/photos/zaragozaantigua/22369464911/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
