INSERT INTO public.photos VALUES (21040, 'Pl. de la Constituciâ”œâ”‚n 1860', '"Zaragoza. Fountain of Isabel II and the Salon of Saint Engracia". Imagen capturada a cierta altura desde la fachada edilicia del Coso recayente a la plaza de la Constituciâ”œâ”‚n y el Salâ”œâ”‚n de Santa Engracia, engalanados con ocasiâ”œâ”‚n de la visita de la reina Isabel II a la ciudad en octubre de ese aâ”œâ–’o. En primer tâ”œÂ®rmino, la fuente de la Princesa o de Neptuno fluye enâ”œÂ®rgicamente y abastece de agua a los carros de aguadores estacionados junto a ella. Pareciera que Neptuno, en este caso, hubiera sido despojado de su poderoso tridente, tal vez por reparaciâ”œâ”‚n, o hurto. Tanto la fuente como la plaza aparecen delimitadas por firmes y espaciados mojones de piedra. En el arranque del Salâ”œâ”‚n de Santa Engracia, a la derecha, unos de los prâ”œÂ¡stinos, esbeltos y funcionales mingitorios para aliviar insoslayables necesidades fisiolâ”œâ”‚gicas. La variedad de motivos y formas decorativas montados para la ocasiâ”œâ”‚n incluyen el monumental trampantojo o picaresca simulaciâ”œâ”‚n que al fondo aparentaba, mediante la colocaciâ”œâ”‚n de lienzos pintados encima, que la puerta de Santa Engracia era un arco triunfal. El efecto buscado se cumpliâ”œâ”‚ al menos durante los dâ”œÂ¡as de visita Real, cuando Isabel II pasâ”œâ”‚ bajo â”œÂ®l para dar una vuelta por la playa de Torrero y el Canal Imperial, y cuando se dirigiâ”œâ”‚ a la explanada de Campo Sepulcro a presidir un desfile militar. A la izquierda del Salâ”œâ”‚n destaca la novâ”œÂ¡sima fachada del convento de Jerusalâ”œÂ®n, reciâ”œÂ®n reconstruido segâ”œâ•‘n proyecto del arquitecto Pedro Martâ”œÂ¡nez Sangrâ”œâ”‚s. A la derecha, luminosa vista parcial de los porches del Salâ”œâ”‚n, cuando pretendâ”œÂ¡a, y conseguâ”œÂ¡a, ser un reflejo local de la parisina rue de Rivoli. Algunas figuras estacionadas en la plaza adquieren un inquietante perfil borroso, fantasmagâ”œâ”‚rico, como consecuencia del dilatado tiempo de exposiciâ”œâ”‚n empleado por el fotâ”œâ”‚grafo para capturar la escena en condiciones â”œâ”‚ptimas. Fuente visual: Charles Clifford, en J. Paul Getty Museum', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.65223700, -0.88088000, '0101000020E6100000556AF6402B30ECBFDE1E84807CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44636515855.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44636515855.webp', 'https://www.flickr.com/photos/zaragozaantigua/44636515855/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
