INSERT INTO public.photos VALUES (21362, 'Huerva al aire 1918', 'AHPZ-MF-COYNE. 1918. El râ”œÂ¡o Huerva habâ”œÂ¡a sido la gran trinchera sureâ”œâ–’a durante el bienio bâ”œÂ®lico 1808-1809. La fuerte orografâ”œÂ¡a de su cauce lo hacâ”œÂ¡an natural foso, infranqueable. Por eso la lucha por los puentes, como el de San Josâ”œÂ®, fue mâ”œÃ­s que encarnizada, homâ”œÂ®rica. Durante la segunda mitad del XIX la ciudad empezâ”œâ”‚ a salir de su medieval corsâ”œÂ® urbano, y se topâ”œâ”‚ con el râ”œÂ¡o. Hubo un proyecto de desviar su curso, pero el presupuesto superaba lo imaginable, y se descartâ”œâ”‚ por delirante. Los dueâ”œâ–’os de los terrenos sureâ”œâ–’os, ademâ”œÃ­s, congelaron cualquier intento de establecer una cabeza de puente hacia el sur, para dar tiempo a que el valor de sus propiedades se multiplicara. Sâ”œâ”‚lo hubo un controlado escape al bloqueo: el Paseo de Sagasta. Mientras, en las orillas del râ”œÂ¡o, especialmente a lo largo del Camino del Sâ”œÃ­bado, se ubicaron toda suerte de fâ”œÃ­bricas e instalaciones textiles, de curtidos, zapatos, tintes.. que desaguaban residuos y vertidos directamente. A pesar de eso, el râ”œÂ¡o tambiâ”œÂ®n era un hâ”œÃ­bitat natural para la expansiâ”œâ”‚n y recreo, incluyendo el baâ”œâ–’o en localizadas "pozas", y la pesca (barbos y cangrejos). La imagen captura el cauce nevado del Huerva antes de su cubrimiento en el arranque de la "Gran Vâ”œÂ¡a" (1925-1932). La he volteado horizontalmente porque en su estado original (Archivo Coyne), la Antigua Facultad de Medicina y Ciencias de la Universidad de Zaragoza quedaba en la orilla derecha, y el paisaje ha cambiado mucho desde entonces, pero no hasta ese extremo. Hace unos pocos aâ”œâ–’os (2009), con motivo de la renovaciâ”œâ”‚n de infraestructuras durante la recuperaciâ”œâ”‚n del tranvâ”œÂ¡a, el cauce del Huerva volviâ”œâ”‚ a ver la luz natural, 84 aâ”œâ–’os despuâ”œÂ®s de ser cubierto, y provocâ”œâ”‚ una conmociâ”œâ”‚n ciudadana. Ya pasâ”œâ”‚.', 1918, 1918, 1918, 'Anos 10', 'CENTRO', 41.64694100, -0.88583100, '0101000020E6100000240ED940BA58ECBF84B872F6CED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14665995347.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14665995347.webp', 'https://www.flickr.com/photos/zaragozaantigua/14665995347/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
