INSERT INTO public.photos VALUES (21282, 'Campo Sepulcro 1908', 'Imagen del bastante despejado mar de vâ”œÂ¡as de la estaciâ”œâ”‚n de ferrocarril de Campo Sepulcro, o de los Directos, inaugurada en 1896, para la lâ”œÂ¡nea MZA. A la derecha de las vâ”œÂ¡as y andenes, el muro que salvaba el notable desnivel en altura con el inmediato barrio de la Romareda y la estaciâ”œâ”‚n de Cariâ”œâ–’ena, por ello tambiâ”œÂ®n denominado "barrio de Cariâ”œâ–’ena". Al fondo, parte de los amplios terrenos que la empresa MZA tenâ”œÂ¡a en la zona del antiguo Campo del Sepulcro, desde el Cuartel de Trinitarios y hasta la carretera de Zaragoza a Teruel. A la izquierda, el edificio central de la estaciâ”œâ”‚n, tras el que quedaba la semirotonda del depâ”œâ”‚sito de locomotoras, y el acceso principal a la estaciâ”œâ”‚n. Bien pronto esta zona, con el impulso ferroviario, serâ”œÂ¡a uno de los polâ”œÂ¡gonos industriales destacados de la ciudad. Fuente visual: Museo del ferrocarril.', 1908, 1908, 1908, 'Anos 1900', 'DELICIAS', 41.65208100, -0.89493000, '0101000020E61000006CB2463D44A3ECBFE7ABE46377D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24772714805.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24772714805.webp', 'https://www.flickr.com/photos/zaragozaantigua/24772714805/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
