INSERT INTO public.photos VALUES (25169, 'Calle Galo Ponte 1980', 'Dibujo centrado en los restos del esquinero edificio entre la calle de Galo Ponte, antigua de la Audiencia, y mâ”œÃ­s antigua Subida de los Gigantes, y un despejado Coso alto, a la derecha. Justo a la izquierda, algunos balcones de la Audiencia, junto a la que el autor ha tomado los apuntes del natural. Desde ese momento, y hasta la fecha, el derribo se ha completado felizmente, y el solar sigue en productivo barbecho inmobiliario, a la espera de tiempos nuevos, tiempos salvajes.', 1980, 1980, 1980, 'Anos 80', 'CENTRO', 41.65381300, -0.88334600, '0101000020E610000064ADA1D45E44ECBF8E59F624B0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32501628372.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32501628372.webp', 'https://www.flickr.com/photos/zaragozaantigua/32501628372/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
