INSERT INTO public.photos VALUES (25713, 'General Sanjurjo 1976', 'Imagen de la antigua calle del General Sanjurjo, luego parte de la gran avenida de Câ”œÂ®sar Augusto como moderno sumatorio vial para trâ”œÃ­fico rodado, ademâ”œÃ­s, de las antiguas calles de Cerdâ”œÃ­n, Escuelas Pâ”œÂ¡as, Azoque, una parte de Capitâ”œÃ­n Portolâ”œÂ®s, la plaza de San Ildefonso, y algunas bocacalles, como Serâ”œâ”‚n. Destaca por su soledad momentâ”œÃ­nea, a la derecha, la mole de un gran hotel con su gran medianera como privilegiada plataforma publicitaria, y a la izquierda, la fachada del luego tristemente câ”œÂ®lebre Gran Teatro Fleta, y el acceso a la plaza de Salamero, antigua de Santa Fe. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.65220200, -0.88521300, '0101000020E61000003ECF9F36AA53ECBF6231EA5A7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30386624885.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30386624885.webp', 'https://www.flickr.com/photos/zaragozaantigua/30386624885/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
