INSERT INTO public.photos VALUES (23256, 'Fâ”œÃ­brica de regaliz Tur c.1900', 'Vista de la entrada de la fâ”œÃ­brica de regaliz Flor, Carenou y Tur en la calle Asalto de Zaragoza, entre el actual parque Corral de la Leâ”œâ–’a y el râ”œÂ¡o Huerva. En primer plano, la acequia que pasaba entre los terrenos que fueron viveros y almacâ”œÂ®n de abastos del ejâ”œÂ®rcito, y la factorâ”œÂ¡a. A la derecha, consulado francâ”œÂ®s de Zaragoza. Fuente: www.facebook.com/photo.php?fbid=635699779865162&set=g...', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64863900, -0.87183600, '0101000020E6100000F0366F9C14E6EBBF80F44D9A06D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21134866226.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21134866226.webp', 'https://www.flickr.com/photos/zaragozaantigua/21134866226/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
