INSERT INTO public.photos VALUES (21958, 'P.â”¬â•‘ Independencia aâ”œâ–’os 40', 'Paseo de la Independencia en los primeros aâ”œâ–’os 40. A la derecha, calle de San Miguel y Restaurante Peninsular. Al fondo, plaza de Espaâ”œâ–’a. Fuente: Instantâ”œÃ­neas zaragozanas, CAZAR, 1982.', 1940, 1940, 1949, 'Anos 40', 'CENTRO', 41.65124500, -0.88181400, '0101000020E61000004DF564FED137ECBF7E5704FF5BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20075070438.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20075070438.webp', 'https://www.flickr.com/photos/zaragozaantigua/20075070438/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22549, 'P.â”¬â•‘ de la Independencia c.1972', 'Postal nocturna del paseo de la Independencia, con la plaza de Espaâ”œâ–’a al fondo, cuando sus râ”œâ”‚tulos de neâ”œâ”‚n, y el reciâ”œÂ®n inaugurado edificio de Galerâ”œÂ¡as Preciados (1971) iluminando el entorno. Esta empresa fue adquirida en 1995 por otra empresa engaâ”œâ–’osamente de corte inglâ”œÂ®s. Fuente visual: www.delcampe.net/', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65106600, -0.88166500, '0101000020E610000011E4A0849936ECBFCEC4742156D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15023110161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15023110161.webp', 'https://www.flickr.com/photos/zaragozaantigua/15023110161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25125, 'Zaragoza 1809', 'Louis-Albert-Guislain (Barâ”œâ”‚n de Bacler D''Albe), y Godefroy Engelmann, Ca. 1830. "Fais-toi vieille, nous ne sommes pas des ogres: Des soldats franâ”œÂºais touillaient dans les ruines de Sarragosse, ils trouvent deux enfants cachâ”œÂ®s sous une voute et perissant de faim. Ils leur donnet leurs vivres." Durante las guerras peninsulares de 1808-1809, el militar francâ”œÂ®s Louis-Albert-Guislain visita Espaâ”œâ–’a en dos ocasiones. La primera (abril-mayo 1808), como responsable del "Cabinet Topographique de lÃ”Ã‡Ã–Empereur". La segunda, acompaâ”œâ–’ando a Napoleâ”œâ”‚n durante la campaâ”œâ–’a de noviembre 1808-enero 1809. En ellas, realiza croquis de los lugares recorridos, observa escenas y escucha el relato de algunos de los protagonistas. Con esta informaciâ”œâ”‚n, prepara una obra grâ”œÃ­fica que publicarâ”œÃ­ posteriormente, con grabados de escenas a la moda româ”œÃ­ntica (ruinas y elementos arquitectâ”œâ”‚nicos, vegetaciâ”œâ”‚n...) que, como en este caso, incluye una singular muestra de propaganda al estilo de la de los Sitios, pero desde la trinchera contraria (una especie de "agitprop contraSitial"). Asâ”œÂ¡, el descriptivo tâ”œÂ¡tulo "Mira, anciana, no somos ogros", introduce un intento de humanizar a las tropas francesas que sitiaban primero, y ocuparon despuâ”œÂ®s, la ciudad de Zaragoza. Al probable relato oral de los soldados implicados, se suma la explâ”œÂ¡cita voluntad polâ”œÂ¡tica en reflejarlo grâ”œÃ­ficamente para la posteridad, convenientemente escenificado. Asâ”œÂ¡, en un desolado paisaje urbano de ruinas y escombros no identificados (â”¬â”cerca del convento de San Francisco?), unos soldados imperiales se topan con dos famâ”œÂ®licos niâ”œâ–’os a los que dan sus propios vâ”œÂ¡veres, mientras la probable madre de las criaturas gesticula entre asustada y agradecida. Se trata de una imagen muy querida en la iconografâ”œÂ¡a pâ”œâ•‘blica de todos los ejâ”œÂ®rcitos ocupantes: la plâ”œÃ­stica, oficial y condescendiente benignidad castrense para con los indâ”œÂ¡genas civiles de los territorios ocupados, una vez derrotados. En este caso, ademâ”œÃ­s, tras una doble derrota: las dos ocupaciones ', 1809, 1809, 1809, 'Siglo XIX', 'CENTRO', 41.65202200, -0.88126700, '0101000020E6100000B66801DA5633ECBFE222F77475D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16093613925.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16093613925.webp', 'https://www.flickr.com/photos/zaragozaantigua/16093613925/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
