INSERT INTO public.photos VALUES (21436, 'Arco de San Roque 1911', 'Foto: Grasa. Unos cuantos guardias civiles custodian desde la plazuela de San Roque los inmuebles y el arco homâ”œâ”‚nimo, durante la huelga general revolucionaria del verano de 1911. Al fondo, el restaurante del Hotel Oriente, en el Coso Alto. Fuente: Revista Blanco y Negro, 24-9-1911.', 1911, 1911, 1911, 'Anos 10', 'CENTRO', 41.65319900, -0.88277900, '0101000020E6100000060FD3BEB93FECBFD4635B069CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40166715840.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40166715840.webp', 'https://www.flickr.com/photos/zaragozaantigua/40166715840/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21877, 'Calle Alfonso aâ”œâ–’os 30', 'Vista del chaflâ”œÃ­n del cafâ”œÂ® Moderno, entre el Coso Alto y la calle de Alfonso I, a la derecha. Fuente: HA.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65321800, -0.88223200, '0101000020E61000006F826F9A3E3BECBF4B94BDA59CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43890526765.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43890526765.webp', 'https://www.flickr.com/photos/zaragozaantigua/43890526765/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22596, 'Calle Azoque 1970', 'Imagen circunstancial de la calle Azoque, y de la plaza de Nâ”¬Â¬ Sâ”¬Â¬ del Carmen. La intenciâ”œâ”‚n del fotâ”œâ”‚grafo era capturar el vallado solar chaflanero entre el minimalista callejâ”œâ”‚n de San Jerâ”œâ”‚nimo y la plaza, antes de que fuera construido: un pedazo de la antigua Morerâ”œÂ¡a que cambiaba de aspecto. Desde luego que lo consiguiâ”œâ”‚, como tambiâ”œÂ®n plasmar uno de los escasos testimonios grâ”œÃ­ficos de algunos de los edificios de la antigua plaza del Carmen, de finales del siglo XVIII, aunque su planta bâ”œÃ­sica lo fuera del XV y XVI. Asâ”œÂ¡, aparece un pedazo del antiguo complejo del Convento-Colegio de las Recogidas, un aâ”œâ–’o antes de que las Carmelitas Terciarias, que lo gestionaban, se unieran a las Carmelitas Misioneras Teresianas. A su lado, el nâ”¬â•‘ 5 de la plaza ya era una reciente mutaciâ”œâ”‚n desarrollista, en la que lo que no tenâ”œÂ¡a de ancho, lo estirâ”œâ”‚ en vertical como si fuera material plâ”œÃ­stico. El nâ”¬â•‘ 8 mantenâ”œÂ¡a aâ”œâ•‘n una digna veteranâ”œÂ¡a. Y en el nâ”¬â•‘ 9, esquinera con la antigua calle Juego de la Pelota, la joya que fuera antigua casa del siglo XVII de don Eugenio Samper, profundamente remodelada en el XVIII, y que a finales de siglo era de Pedro Cortâ”œÂ®s y Larraz, Arzobispo de Guatemala que terminâ”œâ”‚ siendo Obispo de Tortosa, por lo que esta casa desde entonces era conocida como "del Obispo". Su planta, imponente fachada y amplio patio interior dejaban claro que se trataba de una "casona" de esas que dicen que Zaragoza tenâ”œÂ¡a tantas. Por sus paredes transcurrieron interesantes historias locales, hasta que sus ultimâ”œÂ¡simos propietarios decidieron aplicarle la piqueta para levantar sobre su solar la cosa que hoy hay. El exterminio de los edificios dieciochescos ("viejos", "antiguallas", "caducos") fue radical y concienzudo: sâ”œâ”‚lo quedan las fotos. Fuente visual: Archivo Municipal. Gerardo Sancho Ramo. Noviembre 1970.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65113400, -0.88457100, '0101000020E610000036AE7FD7674EECBF26A8E15B58D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17511061076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17511061076.webp', 'https://www.flickr.com/photos/zaragozaantigua/17511061076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
