INSERT INTO public.photos VALUES (24489, 'Paseo Independencia 1971', 'Postal publicitaria de los grandes almacenes Galerâ”œÂ¡as Preciados, inaugurados en 1971 en el paseo de la Independencia 11. En 1995, este comercio pasâ”œâ”‚ a ser propiedad de su competidor, El Corte Inglâ”œÂ®s. Fuente visual: www.zaragozaayeryhoy.com/', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.65115700, -0.88192200, '0101000020E6100000E5EE737CB438ECBFDEC7D11C59D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24796603875.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24796603875.webp', 'https://www.flickr.com/photos/zaragozaantigua/24796603875/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25368, 'Pâ”¬â•‘ de la Independencia c.1916', 'Imagen capturada en el bulevar del paseo de la Independencia posiblemente un festivo dâ”œÂ¡a. Al fondo, el Quiosco de la Mâ”œâ•‘sica emplazado originalmente en el recinto de la exposiciâ”œâ”‚n Hispano-Francesa de 1908, trasladado al paseo en 1912 a la altura de las calles de Câ”œÃ­diz (a la izquierda) y la de Jerâ”œâ”‚nimo Zurita (a la derecha). Desde entonces vertebrâ”œâ”‚ el paseo hasta su vuelta a la plaza de Castelar en 1927.', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.65110200, -0.88215700, '0101000020E6100000C5FF1D51A13AECBF1B2E724F57D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51019362787.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51019362787.webp', 'https://www.flickr.com/photos/zaragozaantigua/51019362787/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21495, 'Cabezo de Buenavista 1923', 'AHPZ. Gabriel Faci. 1923. "Paisaje nevado." La nieve caâ”œÂ¡da difumina los contornos, suaviza el paisaje. Con la nieve tambiâ”œÂ®n se precipita un silencio difâ”œÂ¡cil de definir. Todo es distinto. Mientras un tremendo temporal pasaba por encima del Reino de Espaâ”œâ–’a, en el primero de los inviernos de la Dictadura de Primo de Rivera, gente curiosa se iba al sur, donde estaba proyectado hacer un gran parque, al que tendrâ”œÂ¡a que conducir un nuevo y moderno vial denominado "Gran Vâ”œÂ¡a", sobre un cubierto râ”œÂ¡o Huerva. Pero la cosa estaba bastante parada. De momento, sâ”œâ”‚lo estaban garantizadas las buenas vistas desde el Cabezo. Abajo, entre la nieve, una leve vista del oscuro cauce de la acequia de las Adulas, contorneâ”œÃ­ndose desde su toma de agua del Canal, muy cerca de donde cinco aâ”œâ–’os despuâ”œÂ®s se levantarâ”œÃ­ el Rincâ”œâ”‚n de Goya. Otra lâ”œÂ¡nea de â”œÃ­rboles, un poco mâ”œÃ­s al fondo, seâ”œâ–’ala el cauce del Huerva.', 1923, 1923, 1923, 'Anos 20', 'UNIVERSIDAD', 41.63133000, -0.89516000, '0101000020E6100000DAFE959526A5ECBFE97DE36BCFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15270757968.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15270757968.webp', 'https://www.flickr.com/photos/zaragozaantigua/15270757968/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
