INSERT INTO public.photos VALUES (23431, 'C.â”¬Â¬ de Valencia 1911', 'Imagen capturada durante la intensa nevada que el dâ”œÂ¡a 14 de enero de 1911 cubriâ”œâ”‚ con un manto blanco la ciudad de Zaragoza. El fotâ”œâ”‚grafo Freudenthal centra su objetivo en la Fuente de los Incrâ”œÂ®dulos en su tradicional ubicaciâ”œâ”‚n junto a la carretera de Valencia e inmediata al apeadero de la lâ”œÂ¡nea del ferrocarril de Cariâ”œâ–’ena, que en la imagen queda a la izquierda y fuera de plano.', 1911, 1911, 1911, 'Anos 10', 'CASABLANCA', 41.62857100, -0.90794900, '0101000020E6100000EDF2AD0FEB0DEDBF651BB80375D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51774835206.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51774835206.webp', 'https://www.flickr.com/photos/zaragozaantigua/51774835206/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
