INSERT INTO public.photos VALUES (25181, 'Seminario Metropolitano 1943', 'Dibujo incluido en el anteproyecto del nuevo Seminario Metropolitano de Zaragoza firmado por Santiago Lagunas Mayandâ”œÂ¡a, Casimiro Lanaja Bel y Manuel Martâ”œÂ¡nez de Ubago, inspirado en formas historicistas neorromâ”œÃ­nicas y neogâ”œâ”‚ticas, y con capacidad para 400 aspirantes a sacerdotes. En 1945 su colocâ”œâ”‚ su primera piedra, y serâ”œÂ¡a inaugurado en 1952.', 1943, 1943, 1943, 'Anos 40', 'CASABLANCA', 41.63586000, -0.91004100, '0101000020E6100000C39CA04D0E1FEDBFD36A48DC63D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49414491933.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49414491933.webp', 'https://www.flickr.com/photos/zaragozaantigua/49414491933/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24843, 'Canal Imperial 1922', 'Imagen capturada en la orilla norte del tramo del Canal Imperial de Aragâ”œâ”‚n, desde el camino que en paralelo transcurre a la altura de Valdefierro, e inmediatamente anterior al denominado Puente-Acueducto de la Acequia del Medio que, de iguales dimensiones que el de Pedrola, conduce agua del râ”œÂ¡o Huerva y que originalmente abastecâ”œÂ¡a a las acequias del Medio, del Plano y del Brazal del Fierro.', 1922, 1922, 1922, 'Anos 20', 'CASABLANCA', 41.63503400, -0.92681000, '0101000020E61000006362F3716DA8EDBF8DEC4ACB48D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51940704552.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51940704552.webp', 'https://www.flickr.com/photos/zaragozaantigua/51940704552/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25938, 'Graveras de La Paz 1977', 'Esta es una de esas tremendas imâ”œÃ­genes que era posible captar en el guetto de las "Graveras", de las "Chabolas", porque sus denominaciones eran varias (y la mayor parte, denigrantes) en lo que hoy es el Parque de La Paz. La denominaciâ”œâ”‚n de "graveras" respondâ”œÂ¡a al hecho de ser, desde antiguo, lugares de extracciâ”œâ”‚n de â”œÃ­ridos ("grava") para obras. Desde los aâ”œâ–’os 50 del pasado esta zona se convirtiâ”œâ”‚ en un asentamiento de chabolas, hasta 1979, cuando, con la recuperaciâ”œâ”‚n de la democracia, desde el Ayuntamiento se exploraron fâ”œâ”‚rmulas, algunas de ellas muy problemâ”œÃ­ticas, errâ”œÃ­ticas, y mejorables, para darle una soluciâ”œâ”‚n a esta indignidad, felizmente superada, aunque chabolas sigue habiendo en la ciudad. Hubo que esperar a 1982 para ver transformarse esta zona en lo que hoy es. El objetivo fotogrâ”œÃ­fico nos sitâ”œâ•‘a en un elevado punto, en la actual parte alta de la Rotonda Villa de Pau, desde el que podemos vislumbrar el Puente de San Viator sobre el Canal, a la derecha. De la Pasarela peatonal metâ”œÃ­lica del mismo nombre sâ”œâ”‚lo se aprecia el arranque. La imponente mole de la fâ”œÃ­brica "ALUMALSA" queda al otro lado del Canal, ademâ”œÃ­s de edificios tan representativos como la Escuela Julio Cejador Frauca, y el Convento de las Monjas del Casal, con su caracterâ”œÂ¡stica espadaâ”œâ–’a. Al fondo, emergiendo tâ”œÂ¡midamente del tejado de "ALUMALSA", apenas vemos el remate de la neoclâ”œÃ­sica câ”œâ•‘pula de la iglesia de San Fernando. Justo a continuaciâ”œâ”‚n, los tremebundos macrobloques de la acera izquierda de Terrazas de Cuâ”œÂ®llar-Pintor Marâ”œÂ¡n Bagâ”œâ•â”œÂ®s, que dejan como enanitos a los mâ”œÃ­s veteranos conjuntos de la acera derecha. Fuente visual: "La evoluciâ”œâ”‚n urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1977, 1977, 1977, 'Anos 70', 'TORRERO', 41.62865100, -0.87869700, '0101000020E610000069FCC22B491EECBF81CCCEA277D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14855646151.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14855646151.webp', 'https://www.flickr.com/photos/zaragozaantigua/14855646151/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
