INSERT INTO public.photos VALUES (25957, 'Pinares de Venecia 1996', 'En el mes de marzo de 1996 se realizâ”œâ”‚ una acampada en los terrenos de los Pinares de Venecia por los que estaba proyectado que pasase el Tercer Cinturâ”œâ”‚n de ronda de la ciudad. Participâ”œâ”‚ mâ”œÃ­s de un millar de personas, convocadas por la Coordinadora Venecia-Torrero-La Paz contra el Tercer Cinturâ”œâ”‚n, con los lemas de Ã”Ã‡Â£No al Tercer Cinturâ”œâ”‚nÃ”Ã‡Ã˜ y Ã”Ã‡Â£Salvemos el pinar, salvemos el CanalÃ”Ã‡Ã˜, que ofrecâ”œÂ¡a un trazado alternativo menos agresivo con el entorno. En la imagen, parte de los acampados ensaya acciones de resistencia pasiva para el caso de que comiencen las obras. Al final, el trazado alternativo fue desestimado y la nueva vâ”œÂ¡a pasâ”œâ”‚ por donde estaba previsto, a partir de 2003.', 1996, 1996, 1996, 'Anos 90', 'TORRERO', 41.62461100, -0.89255300, '0101000020E6100000454B1E4FCB8FECBF66DCD440F3CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50367967793.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50367967793.webp', 'https://www.flickr.com/photos/zaragozaantigua/50367967793/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25944, 'Cabezo Cortado 1978', 'El Cabezo Cortado ha sido el mirador natural del barrio desde que gravas, arenas y arcillas, producto de la sedimentaciâ”œâ”‚n del Ebro, se dispusieron durante el Terciario en una terraza de varios metros de espesor sobre yesos y limos, y conformaron una elevaciâ”œâ”‚n desde la que la vista de la ciudad era estupenda. â”œÃ´leos, apuntes, fotografâ”œÂ¡as, incluso documentales, han surgido de la contemplaciâ”œâ”‚n desde su cumbre. Esto era lo normal. Esta imagen no hace eso, y enfoca justo al otro lado, hacia el Canal Imperial, su ribera, y el Barrio de la Paz. En primer tâ”œÂ®rmino, llaman la atenciâ”œâ”‚n los humanos grupos entre los pinos de la ladera, como si se tratase de un parque o zona verde al uso. Ya no se ven estas cosas desde hace tiempo, desde que se dejâ”œâ”‚ degradar el Cabezo hasta su actual situaciâ”œâ”‚n, en que da mucha penica. Con un poco de voluntad polâ”œÂ¡tica se podâ”œÂ¡a adecentar y dignificar, sin mucho costo. Serâ”œÂ¡a, ademâ”œÃ­s, una buena pedagogâ”œÂ¡a porque, aun en los tiempos del wifi, el tuiter, del face, del ipod, del..., es minorâ”œÂ¡a quien conoce esta zona. Al otro lado del Canal, imagen del Colegio de San Viator y la continuidad de las "Graveras" cuando eran consideradas por ciertos sectores como peor que adentrarse en territorio sioux (en el supuesto, ademâ”œÃ­s, de que ser sioux fuera malo). A este lado del Canal, muy al fondo, las moles de los bloques de otras Terrazas, la de Pina, hoy Cuâ”œÂ®llar, y los restos de la fâ”œÃ­brica Alumalsa. Casi ya fuera de plano, a la derecha, los bloques de la peculiar urbanizaciâ”œâ”‚n de la parcela de la calle Melilla nâ”¬â•‘ 28, reciâ”œÂ®n estrenaditos. Hacâ”œÂ¡a apenas un aâ”œâ–’o, no muy lejos de aquâ”œÂ¡, un policâ”œÂ¡a armada habâ”œÂ¡a disparado de muerte a un obrero en paro por hacer una pintada que decâ”œÂ¡a "Trabajo sâ”œÂ¡ Policâ”œÂ¡a no", y un esbozo de hoz y martillo. Una calle cercana lleva desde hace no mucho el nombre del asesinado: Miguel Vicente Basanta Lâ”œâ”‚pez. Fuente visual: "La evoluciâ”œâ”‚n urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1978, 1978, 1978, 'Anos 70', 'TORRERO', 41.63025500, -0.87297300, '0101000020E6100000F04FA91265EFEBBFFB912232ACD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20076476729.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20076476729.webp', 'https://www.flickr.com/photos/zaragozaantigua/20076476729/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22109, 'Tudor 1953', 'Aâ”œÂ®rea vista de la Factorâ”œÂ¡a de la Sociedad Espaâ”œâ–’ola del Acumulador Tudor, en las enormes y recientes instalaciones de la carretera de Navarra donde estaba ubicada desde 1946. Asâ”œÂ¡ serâ”œÃ­ hasta 1989. En la parte inferior, sobre la carretera de Logroâ”œâ–’o, el puente de paso del ferrocarril de Caminreal. Un segundo puente, mâ”œÃ­s inmediato, se quedâ”œâ”‚ en inacabado proyecto de "bypass" de conexiâ”œâ”‚n hacia Casetas. Fuente visual: Arxiu Nacional de Catalunya.', 1953, 1953, 1953, 'Anos 50', 'OLIVER-VALDEFIERRO', 41.65974100, -0.92102300, '0101000020E610000051A4FB390579EDBF486AA16472D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21979037130.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21979037130.webp', 'https://www.flickr.com/photos/zaragozaantigua/21979037130/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
