INSERT INTO public.photos VALUES (22771, 'Ctra. de Madrid 1979', 'Editorial Luis Vives en sus nuevas instalaciones diseâ”œâ–’adas por Joaquâ”œÂ¡n Maggioni Casadevall en la carretera de Madrid km 315,700. Al fondo, verde entorno del Barrio Oliver que mâ”œÃ­s adelante serâ”œÃ­ adecuado como homâ”œâ”‚nimo parque, tambiâ”œÂ®n llamado del Oeste. A la derecha, el Centro Santo â”œÃ¼ngel de Atades, inaugurado en 1969. Fuera de plano y hacia la derecha, el reformatorio El Buen Pastor, con el que confrontaba al otro lado de la carretera.', 1979, 1979, 1979, 'Anos 70', 'OLIVER-VALDEFIERRO', 41.64648600, -0.93328900, '0101000020E6100000EEED96E480DDEDBF33A9A10DC0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33537238213.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33537238213.webp', 'https://www.flickr.com/photos/zaragozaantigua/33537238213/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
