INSERT INTO public.photos VALUES (22755, 'C.â”¬â•‘ de la Almozara 1978', 'Interesante imagen del oficioso aparcadero intermodal habilitado a la entrada del literal camino de la Almozara, capturada a la altura de la calle de Monegros (a la izquierda), con el fondo del moderno bloque del paseo de Mâ”¬Â¬ Agustâ”œÂ¡n chaflanero con la calle de Santa Lucâ”œÂ¡a. Al fondo, a la derecha, edificios del complejo de la Compaâ”œâ–’â”œÂ¡a Industrial Agrâ”œÂ¡cola, recayentes al mar de vâ”œÂ¡as y a la Industrial Quâ”œÂ¡mica. Fuente visual: Banco de Imâ”œÃ­genes/Asociaciâ”œâ”‚n de Vecinos Barrio de San Josâ”œÂ®, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'LA ALMOZARA', 41.66026600, -0.89518000, '0101000020E6100000A110018750A5ECBF9354A69883D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32748624250.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32748624250.webp', 'https://www.flickr.com/photos/zaragozaantigua/32748624250/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
