INSERT INTO public.photos VALUES (26054, 'Avenida Tenor Fleta 1984', 'Foto: Tomâ”œÃ­s Mora Ruata. Vista de la avenida del Tenor Fleta, con el colegio de los Agustinos al fondo y la entrada de la calle de Uncastillo a la derecha. Fuente: www.facebook.com/photo.php?fbid=1536701036358009&set=...', 1984, 1984, 1984, 'Anos 80', 'SAN JOSâ”œÃ«', 41.63962200, -0.88073400, '0101000020E61000005D35CF11F92EECBFACE63922DFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32253731215.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32253731215.webp', 'https://www.flickr.com/photos/zaragozaantigua/32253731215/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
