INSERT INTO public.photos VALUES (25759, 'Jardâ”œÂ¡n de la Memoria 1992', 'Imagen en altura, capturada desde los altos bloques de la calle pintor Marâ”œÂ¡n Bagâ”œâ•â”œÂ®s, posiblemente su nâ”œâ•‘mero 8, con el aspecto del reciâ”œÂ®n inaugurado "Parque de la Memoria", en el barrio de San Josâ”œÂ®. Estos aterrazados terrenos formaron parte de las extensas instalaciones de la antigua fâ”œÃ­brica textil de Dâ”œÃ­maso Pina, y tras su derribo, fueron calificadas como espacio edificable para levantar necesarios rascacielos. La presiâ”œâ”‚n vecinal para conseguir que esto fuera una zona verde, con notables dificultades, largos aâ”œâ–’os de lucha, y demediado resultado, hallâ”œâ”‚ eco municipal, hasta llegar al resultado de la imagen. El terrible solanar, con el natural crecimiento de los nuevos â”œÃ­rboles, configura un espacio interior de apariencia hoy bien distinta, mâ”œÃ­s amable. Sobre el acusado desnivel del terreno, y con una insâ”œâ”‚lita atenciâ”œâ”‚n a los requerimientos vecinales del momento, se actuâ”œâ”‚ definiendo una serie de referencias emblemâ”œÃ­ticas y representativas de la historia del barrio: entre otros, y en primer tâ”œÂ®rmino, el monumento a la "Baâ”œâ–’ista", de Carlos Ochoa, el estanque de "Cantarranas", y un recuerdo del trazado de la antigua acequia de Ontanar, tres fogonazos del pasado ligado al agua, a las desaparecidas acequias al aire, sus "baâ”œâ–’os", y al derribado lavadero de la Balseta. A su lado, los primeros huertos urbanos de la ciudad, cuando eso aâ”œâ•‘n se consideraba nostâ”œÃ­lgico "ocio de viejos", un mini parque temâ”œÃ­tico de lo provinciano. Detrâ”œÃ­s hay un enorme espacio vacâ”œÂ¡o, convertido en plaza, donde deberâ”œÂ¡a estar la chimenea de la antigua fâ”œÃ­brica textil, pero que fue derribada con alevosâ”œÂ¡a y nocturnidad, cuando esas cosas viejas no se valoraban demasiado. A la derecha, la calle de Joaquâ”œÂ¡n Sorolla, y al fondo, las traseras de la calle Garcâ”œÂ¡a Lorca. Fuente visual: Revista "Nuestra Zaragoza", Ayuntamiento de Zaragoza.', 1992, 1992, 1992, 'Anos 90', 'SAN JOSâ”œÃ«', 41.63353700, -0.87923700, '0101000020E610000062DC0DA2B522ECBF29E78BBD17D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27460993726.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27460993726.webp', 'https://www.flickr.com/photos/zaragozaantigua/27460993726/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22714, 'Vista Miguel Servet 1970', 'Vista aâ”œÂ®rea de la calle de Miguel Servet y su entorno, desde las inmediaciones de la estaciâ”œâ”‚n de Utrillas (fuera de plano). En el centro de la imagen, el Matadero. Mâ”œÃ­s arriba, el cuartel de San Josâ”œÂ® y el resto de la ciudad consolidada, con el Pilar. Fuente: www.facebook.com/photo.php?fbid=10208503253957120&set...', 1970, 1970, 1970, 'Anos 70', 'SAN JOSâ”œÃ«', 41.64356200, -0.86952000, '0101000020E610000033F9669B1BD3EBBF6479573D60D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29670696426.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29670696426.webp', 'https://www.flickr.com/photos/zaragozaantigua/29670696426/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24396, 'Miguel Servet c.1960', 'Imagen de una maqueta que representa el antiguo colegio de La Salle Montemolâ”œÂ¡n en su esquinera ubicaciâ”œâ”‚n entre el camino de las Torres (izquierda), y la calle de Miguel Servet (derecha), en cuyo nâ”œâ•‘mero 36 tenâ”œÂ¡a radicada su direcciâ”œâ”‚n postal y entrada principal. Tras unos aâ”œâ–’os de provisional estancia en una casa de las inmediaciones ("casa de Policeto", desde 1909, como Colegio de Nuestra Seâ”œâ–’ora del Pilar), en 1916 fue inaugurado este centro, con nueva planta proyectada por Francisco Albiâ”œâ–’ana, autor del bloque central en forma hâ”œÂ¡brida de "T-L", con formas y aires neomudâ”œÂ®jares, casi racionalistas. Tenâ”œÂ¡a inmediata vecindad con la "Fundiciâ”œâ”‚n de Iranzo" (la construcciâ”œâ”‚n que chaflanea el principio del camino de las Torres), y al otro lado de Miguel Servet quedaba la Harinera del Pilar, y el cuartel de Intendencia de San Josâ”œÂ®. Poseâ”œÂ¡a el colegio dos pequeâ”œâ–’os patios donde la soberanâ”œÂ¡a del baloncesto era notable, a los que luego se aâ”œâ–’adiâ”œâ”‚ el gran patio del fondo, junto a la calle de la Concepciâ”œâ”‚n, resultado del encementamiento de una antigua zona de huertos. En 1929 mudâ”œâ”‚ su denominaciâ”œâ”‚n por la de Colegio La Salle Montemolâ”œÂ¡n. El curso 1971-1972 fue el â”œâ•‘ltimo en estas instalaciones, y el siguiente de 1972-1973 fue el pionero en las novâ”œÂ¡simas aulas de la calle Josâ”œÂ® Galiay, frente a la antigua Granja Agrâ”œÂ¡cola, donde mantuvo en su nombre de forma descontextualizada el "Montemolâ”œÂ¡n" de sus orâ”œÂ¡genes en lugar de actualizarlo por el de "Miraflores" de su nueva ubicaciâ”œâ”‚n, al estilo de los Lakers tras dejar Minnesota y r4esidenciarse en Los â”œÃ¼ngeles. El colegio de la imagen fue vendido, derribado, y sobre â”œÂ®l fue levantada una de esas renombradas modernidades habitacionales de las que esta ciudad tanto se enorgullece. Fuente visual: "Memoria Escolar 1971-1972", amable aportaciâ”œâ”‚n de Juan Carlos Crespo.', 1960, 1960, 1960, 'Anos 60', 'SAN JOSâ”œÃ«', 41.64714000, -0.87386400, '0101000020E610000016DBA4A2B1F6EBBF7BF7C77BD5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26134908475.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26134908475.webp', 'https://www.flickr.com/photos/zaragozaantigua/26134908475/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24534, 'Matadero c.1945', 'Imagen capturada en el patio principal del matadero municipal, a espaldas de la monumental puerta de entrada desde la calle de Miguel Servet, cuya sombra se proyecta sobre la fuente del Buen Pastor. Aparcados en los porches, camiones frigorâ”œÂ¡ficos para distribuciâ”œâ”‚n de la carne procesada en este veterano establecimiento en servicio desde 1887.', 1945, 1945, 1945, 'Anos 40', 'SAN JOSâ”œÃ«', 41.64476000, -0.87007600, '0101000020E6100000971AA19FA9D7EBBF6DE2E47E87D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50078126331.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50078126331.webp', 'https://www.flickr.com/photos/zaragozaantigua/50078126331/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
