INSERT INTO public.photos VALUES (24568, 'La Granja c.1928', 'Imagen capturada en la Granja Agrâ”œÂ¡cola durante la visita de la Comisiâ”œâ”‚n Permanente del ayuntamiento de la ciudad, encabezada por su alcalde, Miguel Alluâ”œÂ® Salvador. Junto a â”œÂ®l, el ingeniero-director de la Granja, Josâ”œÂ® Cruz Lapazarâ”œÃ­n Beristaâ”œÂ¡n, les muestra el funcionamiento de una trilla mecâ”œÃ­nica. Fuente visual: exposiciâ”œâ”‚n Ã”Ã‡Â£La investigaciâ”œâ”‚n agroalimentaria en Aragâ”œâ”‚n. Sus inicios con Rodrâ”œÂ¡guez AyusoÃ”Ã‡Ã˜. Centro de Investigaciâ”œâ”‚n y Tecnologâ”œÂ¡a Agroalimentaria de Aragâ”œâ”‚n (CITA).', 1928, 1928, 1928, 'Anos 20', 'SAN JOSâ”œÃ«', 41.63564100, -0.87072800, '0101000020E610000082C476F700DDEBBF957F2DAF5CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20110116930.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20110116930.webp', 'https://www.flickr.com/photos/zaragozaantigua/20110116930/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25138, 'Cementera Miraflores 1945', 'Postal publicitaria con el dibujo de las instalaciones de la fâ”œÃ­brica de Cementos Portland Zaragoza, en Miraflores. El Pilar de las dos torres, al fondo, referencia universalmente las enormes instalaciones de esta planta, que se extienden delimitadas por las lâ”œÂ¡neas de ferrocarril a Utrillas, y la que conecta Madrid con Barcelona. Fuente: Archivo Enrique Baile.', 1945, 1945, 1945, 'Anos 40', 'SAN JOSâ”œÃ«', 41.63145000, -0.86343500, '0101000020E6100000A818E76F42A1EBBF9487855AD3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20950434333.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20950434333.webp', 'https://www.flickr.com/photos/zaragozaantigua/20950434333/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21636, 'Calle de Miguel Servet 1925', 'Reciâ”œÂ®n llegado de los antiguos talleres de Carde y Escoriaza, redenominados Material Mâ”œâ”‚vil y Construcciones desde principios de los aâ”œâ–’os veinte, el novâ”œÂ¡simo coche que inauguraba en los Tranvâ”œÂ¡as de Zaragoza la serie de los "50", revestido de madera para hacer mâ”œÃ­s liviano su peso, y coloreado de amarillo. De fondo, la esquina del antiguo edificio de oficinas y direcciâ”œâ”‚n junto al ingreso al cocherâ”œâ”‚n de la calle de Miguel Servet, sito en su lado sur e inmediatos a la estaciâ”œâ”‚n de Utrillas.', 1925, 1925, 1925, 'Anos 20', 'SAN JOSâ”œÃ«', 41.63962900, -0.86622400, '0101000020E61000006954E0641BB8EBBF5E49F25CDFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50113666052.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50113666052.webp', 'https://www.flickr.com/photos/zaragozaantigua/50113666052/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22439, 'Miraflores 1962', 'Imagen de una locomotora a vapor de la MZA, serie 651/680, camino de la estaciâ”œâ”‚n de Campo Sepulcro, tras haber pasado por la de Miraflores (al fondo, a la derecha). La imagen se ha capturado desde la altura del puente para trâ”œÃ­fico rodado que daba continuidad al camino de Cabaldâ”œâ”‚s. Los campos de esta zona formaban parte de los terrenos de la antigua Granja Agrâ”œÂ¡cola. La estaciâ”œâ”‚n de Utrillas queda a la izquierda, fuera de plano. Al fondo, el gran complejo de la cementera de Miraflores, que incluye las chimeneas que emergen de la estaciâ”œâ”‚n ferroviaria. Fuente visual: image.slidesharecdn.com/', 1962, 1962, 1962, 'Anos 60', 'SAN JOSâ”œÃ«', 41.63351300, -0.86909800, '0101000020E6100000B79BE09BA6CFEBBFA14B38F416D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30819877595.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30819877595.webp', 'https://www.flickr.com/photos/zaragozaantigua/30819877595/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22882, 'Estaciâ”œâ”‚n de Utrillas 1985', 'Imagen panorâ”œÃ­mica de la antigua estaciâ”œâ”‚n de Utrillas, abandonada desde 1966. Hoy esta toma habrâ”œÂ¡a que hacerla desde la calle Valentâ”œÂ¡n Zabala, donde antes se localizaba la gran curva de acceso a la Estaciâ”œâ”‚n en que la vâ”œÂ¡a â”œâ•‘nica de entrada se multiplicaba hasta en ocho viales para conducir tanto al Depâ”œâ”‚sito de locomotoras (los "Arcos" de la izquierda), a los muelles de descarga de mercancâ”œÂ¡as, a los andenes para depositar/recoger pasaje en el Edificio Principal (a la derecha), al cocherâ”œâ”‚n de vagones, y al mar de vâ”œÂ¡as del fondo de la Estaciâ”œâ”‚n. Hacia la derecha, otras tres vâ”œÂ¡as conducâ”œÂ¡an al descargadero de las carboneras, donde la actual calle Bubierca. En la imagen, en primerâ”œÂ¡simo plano, soberanâ”œÂ¡a de aliagas, espartos, ontinas, sisallos, y alguna que otra aspirante a capitana que verdean, aun en blanco y negro, en el espacio de trâ”œÃ­nsito de las vâ”œÂ¡as del tren. Encima, magnâ”œÂ¡fico y dominante, el exoexqueleto del Depâ”œâ”‚sito de Locomotoras. De â”œÂ®l emerge, axial, la Chimenea MFU con matrâ”œÂ¡cula del aâ”œâ–’o 1925. A su lado, el cementoso depâ”œâ”‚sito de agua ya sâ”œâ”‚lo como ocasional criadero de renacuajos/ranas. Sin soluciâ”œâ”‚n de continuidad, los muros y enormes farolas de las cocheras de los autobuses urbanos que sustituyeron en ubicaciâ”œâ”‚n y trayectos a los tranvâ”œÂ¡as de la ciudad. Estos muros se retranquearon un bastante-mâ”œÃ­s-para-acâ”œÃ­, aprovechando que el Tâ”œÂ¡ber pasa por Roma, ocupando el lugar de las vâ”œÂ¡as del ferrocarril, de forma que cuando se construyâ”œâ”‚ el Colegio Pâ”œâ•‘blico Tomâ”œÃ­s Alvira hubo que retrasar la medianera unas decenas de metros. Gracias a eso hay una continuidad peatonal con la actual plaza de â”œÃ¼ngel Sanz Briz. Al fondo de la imagen, los bloques del Camino de Cabaldâ”œâ”‚s, antes de urbanizarse con bloques, y nuevos espacios abiertos, como la Plaza Fermâ”œÂ¡n Aguayo. Fuente visual: www.flickr.com/photos/ferrocarril-utrillas/10799465686/in...', 1985, 1985, 1985, 'Anos 80', 'SAN JOSâ”œÃ«', 41.63922800, -0.86757100, '0101000020E610000011A8FE4124C3EBBF00581D39D2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19645417384.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19645417384.webp', 'https://www.flickr.com/photos/zaragozaantigua/19645417384/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
