INSERT INTO public.photos VALUES (21820, 'Incendio Tudor 1935', 'Foto: Marâ”œÂ¡n Chivite. El martes 1 de octubre de 1935 se produjo un incendio en el edificio principal de la fâ”œÃ­brica de Acumuladores Tudor "La Pilar", aunque continuâ”œâ”‚ en funcionamiento en esa ubicaciâ”œâ”‚n hasta 1946. En la imagen, labores de extinciâ”œâ”‚n desde la avenida de la Repâ”œâ•‘blica (derecha). Tras el bloque incendiado, el paseo de Cuâ”œÂ®llar y el parque Pignatelli, con la câ”œâ•‘pula de la iglesia de San Fernando al fondo. Fuente: Heraldo de Aragâ”œâ”‚n.', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.63940900, -0.88593500, '0101000020E610000061376C5B9459ECBF50E27327D8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31644488321.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31644488321.webp', 'https://www.flickr.com/photos/zaragozaantigua/31644488321/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
