INSERT INTO public.photos VALUES (24541, 'C.â”¬â•‘ de las Torres 1924', 'Imagen capturada en el vecino solar del taller de canterâ”œÂ¡a de Bayod sito en el arbolado camino de las Torres (a la izquierda, tras la valla) y confrontando con la fâ”œÃ­brica del acumulador Tudor. En este solar estuvo ubicada una fâ”œÃ­brica de yeso, y en el momento de realizar la fotografâ”œÂ¡a se estaban obrando los cimientos de donde habnrâ”œÂ¡a de surgir el notable edificio de Casa Faci, chaflanero con el paseo de Sagasta.', 1924, 1924, 1924, 'Anos 20', 'UNIVERSIDAD', 41.64011800, -0.88620700, '0101000020E61000008A8F4FC8CE5BECBF5CCAF962EFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52170286347.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52170286347.webp', 'https://www.flickr.com/photos/zaragozaantigua/52170286347/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
