INSERT INTO public.photos VALUES (24175, 'Puente sobre el Huerva en Goya 1965', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 18/02/1965. "Nuevo puente sobre el Huerva". El soterramiento de las vâ”œÂ¡as del ferrocarril por la Avenida de Goya, supuso la construcciâ”œâ”‚n de un nuevo puente sobre el Huerva, sin nombre. En la imagen, obras de construcciâ”œâ”‚n del nuevo puente, con vista de los nuevos tâ”œâ•‘neles para el ferrocarril. Al fondo, la pasarela peatonal sobre el râ”œÂ¡o, que desaparecerâ”œÃ­ cuando el nuevo puente estâ”œÂ® terminado.', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.64347700, -0.89031100, '0101000020E61000001B9C887E6D7DECBF355D4F745DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14981631606.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14981631606.webp', 'https://www.flickr.com/photos/zaragozaantigua/14981631606/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
