INSERT INTO public.photos VALUES (26007, 'Calle de Juliâ”œÃ­n Sanz Ibâ”œÃ­â”œâ–’ez 1994', 'Foto: Archivo Taumar (Irene Taulâ”œÂ®s y Rafael Margalâ”œÂ®). Vista aâ”œÂ®rea del entorno de la calle de Juliâ”œÃ­n Sanz Ibâ”œÃ­â”œâ–’ez, que atraviesa la imagen de arriba abajo. A su derecha, la avenida de Madrid. Fuente: www.facebook.com/photo.php?fbid=1687671941456505&set=...', 1994, 1994, 1994, 'Anos 90', 'DELICIAS', 41.65177800, -0.91659000, '0101000020E610000086E63A8DB454EDBF4B2025766DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22221560139.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22221560139.webp', 'https://www.flickr.com/photos/zaragozaantigua/22221560139/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22617, 'Calle de Galâ”œÃ­n Bergua 1976', 'Urbanizaciâ”œâ”‚n de Las Delicias entre Los Enlaces y el Hospital Psiquiâ”œÃ­trico. Centra la imagen el polâ”œÂ®mico bloque de Construcciones Cinca S.A., levantado sin licencia de obra y contraviniendo ordenanzas municipales, luego legalizado a la carta. Al fondo, bloque sobre solar de la fâ”œÃ­brica de Criado y Lorenzo. Tras â”œÂ®l, la avenida de Madrid, y a su izquierda, esqueleto del bloque en construcciâ”œâ”‚n junto a Los Enlaces. En primer tâ”œÂ®rmino, temporal paisaje lunar.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64832000, -0.91562000, '0101000020E61000005B087250C24CEDBFDEAB5626FCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19310103081.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19310103081.webp', 'https://www.flickr.com/photos/zaragozaantigua/19310103081/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22747, 'Calle del Escultor Palao 1976', 'Imagen de la calle Escultor Palao en el "Polâ”œÂ¡gono 22", cuando era un sorprendente vial a tiempo parcial, pues parece ser que la empresa constructora "Criado y Lorenzo, SA" cerraba los portones al final de cada jornada, y los peatones y caminantes debâ”œÂ¡an buscar entonces otra ruta. Cosas de la Zaragoza de la â”œÂ®poca. Lo mismo sucedâ”œÂ¡a en las inmediatas Roger de Flor, y Galâ”œÃ­n Bergua. Tras la valla abierta con el sâ”œÂ¡mbolo "prohibido el paso", la calle Galâ”œÃ­n Bergua. Al fondo, antiguos bloques inmediatos a la desaparecida fâ”œÃ­brica de Criado y Lorenzo, luego derribados y sustituidos por otros mâ”œÃ­s nuevos. Detrâ”œÃ­s de ellos, a la derecha, emerge en obras el moderno bloque del nâ”¬â•‘ 96 de la Vâ”œÂ¡a Hispanidad. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64859500, -0.91534000, '0101000020E61000007C0F971C774AEDBFB0AC342905D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32402673544.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32402673544.webp', 'https://www.flickr.com/photos/zaragozaantigua/32402673544/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22769, 'Calle de Ramâ”œâ”‚n Salanova 1976', 'Imagen capturada desde la montaraz y agreste zona donde se trazarâ”œÂ¡a luego la prolongaciâ”œâ”‚n de Duquesa Villahermosa, con interesante visual del estado de las cosas en la zona suroeste del "Manicomio". A la izquierda, vista parcial de dos de los trillizos bloques de la novâ”œÂ¡sima calle de Ramâ”œâ”‚n Salanova. En el centro de la imagen, descampados varios para trâ”œÃ­nsito peatonal, y aparcamiento, que se extienden hasta el muro perimetral del enorme espacio verde del Hospital Psiquiâ”œÃ­trico de Nuestra Seâ”œâ–’ora del Pilar, del que emergen algunos de sus pabellones. Al fondo, estructuras de los nuevos bloques en construcciâ”œâ”‚n entre la calle de Barcelona, y la de Daroca. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64558000, -0.91245400, '0101000020E61000001D5723BBD232EDBFD1798D5DA2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33445685111.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33445685111.webp', 'https://www.flickr.com/photos/zaragozaantigua/33445685111/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22946, 'N.â”¬Â¬ S.â”¬Â¬ del Salz 1981', 'Campo del Club de Fâ”œâ•‘tbol Atlâ”œÂ®tico Delicias, denominado de Nuestra Seâ”œâ–’ora de Guadalupe, y localizado entre las calles del Escultor Palao, de Nuestra Seâ”œâ–’ora del Salz (telâ”œâ”‚n de fondo edilicio de la imagen), de Terrer y de Demetrio Galâ”œÃ­n Bergua. Este campo de tierra del barrio de Las Delicias estuvo activo hasta que en 1983 el planeamiento urbanâ”œÂ¡stico ubicâ”œâ”‚ en este emplazamiento el Colegio Pâ”œâ•‘blico Ciudad de Zaragoza y el homâ”œâ”‚nimo Pabellâ”œâ”‚n Deportivo Municipal. Fuente visual: Antonio Calvo Pedrâ”œâ”‚s, AMZ.', 1981, 1981, 1981, 'Anos 80', 'DELICIAS', 41.64850400, -0.91474000, '0101000020E61000002FFA0AD28C45EDBFA0A9D72D02D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38486173246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38486173246.webp', 'https://www.flickr.com/photos/zaragozaantigua/38486173246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23698, 'Calle de Terrer 1977', 'Escena nival capturada desde el bloque de la calle de Barcelona, tramo actualmente denominado calle de la Villa de Andorra, esquinero con la calle de Sigâ”œâ•â”œÂ®s, y centrada en los inmuebles de los nâ”œâ•‘meros 2-4 de la calle de Terrer, en cuyos bajos y desde 1972 destaca el Centro Comercial Delicias, mercado de proximidad que perdura. Ante â”œÂ®l pasa un autobâ”œâ•‘s urbano de la lâ”œÂ¡nea 31. Torrero-Delicias. En el solar de primer tâ”œÂ®rmino, ocupado por camiones, serâ”œÃ­ construido luego el Centro de Salud Universitas. A la izquierda, la calle de Nuestra Seâ”œâ–’ora del Salz, donde destaca el Campo de Nuestra Seâ”œâ–’ora de Guadalupe para la prâ”œÃ­ctica futbolâ”œÂ¡stica, hasta que en 1983 el planeamiento urbanâ”œÂ¡stico de la zona dedicâ”œâ”‚ estos terrenos para el Colegio Pâ”œâ•‘blico Ciudad de Zaragoza y el homâ”œâ”‚nimo Pabellâ”œâ”‚n Deportivo Municipal. Mâ”œÃ­s allâ”œÃ­, bloques de la calle de Demetrio Galâ”œÃ­n Bergua.', 1977, 1977, 1977, 'Anos 70', 'DELICIAS', 41.64736600, -0.91368600, '0101000020E61000008E041A6CEA3CEDBF6B459BE3DCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15808433362.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15808433362.webp', 'https://www.flickr.com/photos/zaragozaantigua/15808433362/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23727, 'Galâ”œÃ­n Bergua 1978', 'Irrepetible imagen centrada en el montaraz barbecho urbanâ”œÂ¡stico de la calle Demetrio Galâ”œÃ­n Bergua, en el tramo delimitado por las calles de Fray Juan Regla (tras los bloques del fondo), y la del Escultor Palao. Las parcelas de la derecha, recayentes a la calle de Nâ”¬Â¬ Sâ”¬Â¬ del Salz, incluyendo el enternecedor acceso a las parcelitas del nâ”¬â•‘ 10 A, B, C, D, y E de esa calle, perduran de forma prodigiosa. La terrosa pista de primer plano, por la que caminan algunos vecinos se convertirâ”œÃ­, al tiempo, en la acera de acceso a los modernos bloques de los nâ”œâ•‘meros 11-21 de Galâ”œÃ­n Bergua. Fuente visual: Banco de Imâ”œÃ­genes/Asociaciâ”œâ”‚n de Vecinos Barrio de San Josâ”œÂ®, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'DELICIAS', 41.64933200, -0.91571500, '0101000020E6100000CB9C2E8B894DEDBF861F9C4F1DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32348482514.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32348482514.webp', 'https://www.flickr.com/photos/zaragozaantigua/32348482514/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21226, 'Caballos en el Ebro 1905', '"Partida de la balsa", fotografâ”œÂ¡a del teniente Eladio Pascual, 1905. Imagen perteneciente al reportaje "Prâ”œÃ­cticas de paso de râ”œÂ¡os realizadas por el Regimiento Lanceros del Rey, 1â”¬â•‘ de Caballerâ”œÂ¡a". En este caso, se trata de pasar de una orilla a otra del Ebro, mediante una balsa construida con sacas rellenas de paja. Los caballos atravesaron el râ”œÂ¡o a nado. Al fondo parece vislumbrarse la silueta del Pilar. La zona donde se realizan las maniobras es, probablemente, aguas abajo, entre las desembocaduras de los râ”œÂ¡os Gâ”œÃ­llego y Huerva, que tambiâ”œÂ®n fueron objeto de prâ”œÃ­cticas militares en este mismo conjunto de ejercicios. Fuente: Revista La ilustraciâ”œâ”‚n Espaâ”œâ–’ola y Americana, 15-9-1905. hemerotecadigital.bne.es/', 1905, 1905, 1905, 'Anos 1900', 'LAS FUENTES', 41.65237400, -0.86017500, '0101000020E610000011C7BAB88D86EBBF5F61C1FD80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18465102323.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18465102323.webp', 'https://www.flickr.com/photos/zaragozaantigua/18465102323/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23741, 'Calle de N.â”¬Â¬ S.â”¬Â¬ del Salz 1976', 'Imagen capturada a la altura del nâ”œâ•‘mero 41 de la calle de N.â”¬Â¬ S.â”¬Â¬ del Salz y centrada en una singular pintada que proclama "â”¬Ã­Viva el alcalde!" y aparece firmada por la no menos singular facciâ”œâ”‚n ultraderechista "Alianza anticomunista/anticapitalista", como forma de respaldar al regidor Miguel Merino Pineda en el denominado "conflicto de las vallas", cuando durante la urbanizaciâ”œâ”‚n del Polâ”œÂ¡gono 22 (terrenos de la antigua fâ”œÃ­brica de Criado y Lorenzo) la empresa constructora "CYLSA" (Criado y Lorenzo, SA) cerraba los portones de obra al final de cada jornada que permitâ”œÂ¡an el paso por el recinto vallado de unos 50.000 metros cuadrados, cortando asâ”œÂ¡ los pasos usados por los peatones que debâ”œÂ¡an buscar otra ruta dando enorme rodeo. En primer tâ”œÂ®rmino, un SEAT 124, y al fondo la esquina con la calle del Escultor Palao.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64857600, -0.91450400, '0101000020E610000038F581E49D43EDBF397CD28904D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54252959002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54252959002.webp', 'https://www.flickr.com/photos/zaragozaantigua/54252959002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25980, 'Delicias 1968', 'Desde las once alturas del nâ”¬â•‘ 9 de la calle de Demetrio Galâ”œÃ­n Bergua, panorâ”œÃ­mica del barrio de Las Delicias. En primer tâ”œÂ®rmino, la calle de Nuestra Seâ”œâ–’ora del Salz, con detalle del nâ”¬â•‘ 16, en contrucciâ”œâ”‚n, y del singular acceso a las fincas A, B, C y D del nâ”¬â•‘ 8, y las A, B, C, D, y E del nâ”¬â•‘ 10. Detrâ”œÃ­s, la calle de Mosâ”œÂ®n Andrâ”œÂ®s Vicente, cruzada de izquierda a derecha por las calles de Fray Luis Regla, de Antonio Bravo, de Eloy Martâ”œÂ¡nez, y del Escultor Palao. Aâ”œâ–’os despuâ”œÂ®s, algunos inmuebles de esta calle serâ”œÂ¡an sustituidos por bloques mâ”œÃ­s altos, como en el caso de los nâ”œâ•‘meros 12-14, 18, y 20. A la derecha, traseras de los bloques de la plaza, actual calle, de la Ciudadela, que eclipsan a los norteâ”œâ–’os pabellones de Dronda, y de Santa Ana, del Hospital Psiquiâ”œÃ­trico Nuestra Seâ”œâ–’ora del Pilar. Al fondo, la perspectiva permite ver las cuatro torres del Pilar, con la câ”œâ•‘pula mayor en medio. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.64736100, -0.91414300, '0101000020E610000027C11BD2A840EDBF59DAA9B9DCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15236729062.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15236729062.webp', 'https://www.flickr.com/photos/zaragozaantigua/15236729062/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21534, 'Barrio de la Romareda 1927', 'Panorâ”œÃ­mica del barrio de la Romareda. Este conjunto conformâ”œâ”‚, con otros similares adyacentes, el actual barrio de Las Delicias. Se situâ”œâ”‚ en traseras de la Estaciâ”œâ”‚n de Campo Sepulcro, en la parte comprendida entre las actuales avenidas de Valencia y Madrid. Tomaba su nombre de la acequia alta de la Romareda. Fuente visual de la imagen: Mâ”¬Â¬ Pilar Biel Ibâ”œÃ­â”œâ–’ez, Zaragoza y la industrializaciâ”œâ”‚n: la arquitectura industrial 1875-1936, IFC, 2004.', 1927, 1927, 1927, 'Anos 20', 'DELICIAS', 41.64828000, -0.90216600, '0101000020E61000003605323B8BDEECBF5053CBD6FAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19472107288.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19472107288.webp', 'https://www.flickr.com/photos/zaragozaantigua/19472107288/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21714, 'Ciudad Jardâ”œÂ¡n 1936', 'Emplazamiento de Casas Baratas que se proyecta construir en la zona de ensanche de Miralbueno, secciâ”œâ”‚n 6â”¬Â¬. Zaragoza, mayo de 1936. Fuente: AMZ.', 1936, 1936, 1936, 'Anos 30', 'DELICIAS', 41.64617800, -0.90247800, '0101000020E6100000ED80EB8A19E1ECBF85B2F0F5B5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18934629413.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18934629413.webp', 'https://www.flickr.com/photos/zaragozaantigua/18934629413/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21716, 'Ciudad jardâ”œÂ¡n 1934', '"Plano Emplazamiento de 500 casas baratas que se proyectan en la Zona de Ensanche de Miralbueno [Ciudad Jardâ”œÂ¡n]", septiembre de 1934. Fuente: AMZ.', 1934, 1934, 1934, 'Anos 30', 'DELICIAS', 41.64617800, -0.90247800, '0101000020E6100000ED80EB8A19E1ECBF85B2F0F5B5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19554355432.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19554355432.webp', 'https://www.flickr.com/photos/zaragozaantigua/19554355432/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21912, 'Campo Sepulcro 1939', 'Imagen capturada en el gran complejo fabril de la empresa Material Mâ”œâ”‚vil y Construcciones sita al oeste de la estaciâ”œâ”‚n de ferrocarril de Campo Sepulcro y centrada en la ceremonia de la "Fiesta de la exaltaciâ”œâ”‚n del Trabajo" instituida por el Fuero del Trabajo y que se debâ”œÂ¡a celebrar obligatoriamente el 18 de julio coincidiendo con el aniversario del "Glorioso Alzamiento Nacional". Esta fiesta respondâ”œÂ¡a al "nuevo" concepto del trabajo como "fiesta de la hermandad y de la unidad de los productores incorporada en la alegrâ”œÂ¡a unâ”œÃ­nime de la Patria al festejar el 18 de julio". De esa forma, los "productores" tenâ”œÂ¡an que celebrar ese dâ”œÂ¡a "en agrupaciâ”œâ”‚n ordenada", reunidos en sus respectivas empresas y dispuestos "conforme a la jerarquâ”œÂ¡a natural de la producciâ”œâ”‚n" en lugar presidido por la Bandera Nacional, las del "Movimiento" y el retrato del "Caudillo" en sitio de honor, y si fuera posible, con mâ”œâ•‘sica de los respectivos himnos. Cerraban la fiesta los gritos reglamentarios de "ESPAâ”œÃ¦A, UNA; ESPAâ”œÃ¦A, GRANDE; ESPAâ”œÃ¦A, LIBRE; â”¬Ã­ARRIBA ESPAâ”œÃ¦A!" En la imagen, vista en altura del momento en que los "productores", dispuestos en el gran pasillo central flanqueado por las naves y talleres de esta empresa, saludan con el reglamentario brazo en alto a la enseâ”œâ–’a nacional que preside el acto. Al fondo, traseras de la larga calle de Roche y campos de cultivo que flanquean la carretera de Zaragoza a Valencia hasta los pabellones del cuartel de Palafox.', 1939, 1939, 1939, 'Anos 30', 'DELICIAS', 41.65061300, -0.89723100, '0101000020E6100000D3A23EC91DB6ECBF1DAD6A4947D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52156383140.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52156383140.webp', 'https://www.flickr.com/photos/zaragozaantigua/52156383140/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22181, 'Calle Escosura 1959', 'Imagen aâ”œÂ®rea sobrevolando el antiguo entorno, en primer tâ”œÂ®rmino, de las calles Escosura, Tarragona y â”œÃ¼vila, para obtener una buena perspectiva del complejo fabril de Material Mâ”œâ”‚vil y Construcciones, junto a la estaciâ”œâ”‚n de Campo Sepulcro y el barrio de Cariâ”œâ–’ena, a la derecha. A la izquierda, indefinido enlace con el barrio de Delicias. Al fondo, la Aljaferâ”œÂ¡a y la Almozara. Fuente visual: fondo fotogrâ”œÃ­fico TAF Helicâ”œâ”‚pteros SA , en Arxiu Nacional de Catalunya.', 1959, 1959, 1959, 'Anos 50', 'DELICIAS', 41.64892300, -0.89843100, '0101000020E61000006CCD565EF2BFECBFA54FABE80FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31895640275.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31895640275.webp', 'https://www.flickr.com/photos/zaragozaantigua/31895640275/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22249, 'Barrio de la Romareda 1956', 'Imagen capturada desde la altura de las nuevas naves seriadas de los talleres de Material Mâ”œâ”‚vil y Construcciones, S.A. en terrenos inmediatos al antiguo barrio de la Romareda, que a la izquierda se presenta arbolado y vertebrado por las calles del Moncayo y la antigua de Gascâ”œâ”‚n, actual de Escoriaza. Al fondo, inmuebles de la calles de Salamanca, Tarragona, â”œÃ¼vila y Escosura.', 1956, 1956, 1956, 'Anos 50', 'DELICIAS', 41.65070900, -0.89667300, '0101000020E6100000429946938BB1ECBF3F1BB96E4AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52321858824.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52321858824.webp', 'https://www.flickr.com/photos/zaragozaantigua/52321858824/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21544, 'Reformatorio Buen Pastor 1921', 'Dibujo de Regino Borobio del Reformatorio del Buen Pastor de Zaragoza, 1921. La Torre Ramona se acondicionâ”œâ”‚ para reformatorio en 1917 y dejâ”œâ”‚ de funcionar como tal en 1955. Tras funcionar como colegio de monjas, el edificio sigue en pie en la calle de Marâ”œÂ¡a de Aragâ”œâ”‚n del barrio de Las Fuentes en 2015. Fuente: Eloy Fernâ”œÃ­ndez Clemente, "Gente de orden", Ibercaja, 1995.', 1921, 1921, 1921, 'Anos 20', 'LAS FUENTES', 41.64094400, -0.86212600, '0101000020E61000006000E1438996EBBFA148F7730AD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20124614286.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20124614286.webp', 'https://www.flickr.com/photos/zaragozaantigua/20124614286/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22252, 'Campo Sepulcro 1953', 'Imagen capturada en el interior de una de las naves de la factorâ”œÂ¡a de Material Mâ”œâ”‚vil y Construcciones sita en el barrio de Cariâ”œâ–’ena o de la Romareda, junto a la estaciâ”œâ”‚n de Campo Sepulcro. La escena se centra en uno de los dos chasis del microcoche "Pulga" aquâ”œÂ¡ carrozado, una versiâ”œâ”‚n mâ”œÃ­s moderna del original proyecto mallorquâ”œÂ¡n patentado en 1950 y desarrollado en Ontinent (Valencia). Los microcoches o coches diminutos, algunos de ellos sustentados sobre tres ruedas como este "Pulga", conocieron un singular desarrollo en la Espaâ”œâ–’a de la larga posguerra (aâ”œâ–’os 50 y 60), siendo este modelo "Pulga" uno de los pioneros, si bien su producciâ”œâ”‚n fue muy modesta. Tras el vehâ”œÂ¡culo de primer tâ”œÂ®rmino, uno de los vagones ferroviarios fabricados en esta fâ”œÃ­brica.', 1953, 1953, 1953, 'Anos 50', 'DELICIAS', 41.65061300, -0.89723100, '0101000020E6100000D3A23EC91DB6ECBF1DAD6A4947D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54723497577.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54723497577.webp', 'https://www.flickr.com/photos/zaragozaantigua/54723497577/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22262, 'Trolebâ”œâ•‘s 1966', '1966. El Trolebâ”œâ•‘s 51 de la Lâ”œÂ¡nea "Ciudad Jardâ”œÂ¡n" haciendo la curva que desde Franco y Lâ”œâ”‚pez le permite seguir por Duquesa de Villahermosa para llegar a su destino en la Ciudad Jardâ”œÂ¡n, dar la vuelta en la calle Pedro de Luna, y coger San Juan Bosco para retornar a la Terminal de la Plaza de Santa Engracia. En primer tâ”œÂ®rmino, un taxi caracterâ”œÂ¡stico de la â”œÂ®poca en Zaragoza. A la izquierda, el Colegio de las "Josefinas" (Hijas de San Josâ”œÂ®). Al fondo, las naves del inmenso polâ”œÂ¡gono de Carde y Escoriaza, que llegaban hasta lo que luego, ya urbanizada, serâ”œÃ­ la Plaza de Roma', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.64828000, -0.90216600, '0101000020E61000003605323B8BDEECBF5053CBD6FAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14788184428.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14788184428.webp', 'https://www.flickr.com/photos/zaragozaantigua/14788184428/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22335, 'Calle Santander 1969', 'Pintura de Eduardo Laborda titulada "La calle Santander de Zaragoza". Posiblemente se trate del nuevo bloque de viviendas del nâ”¬â•‘ 32, esquina con la calle Josâ”œÂ® Pascasio Escoriaza, tan chocante con el hasta entonces mâ”œÃ­s humano en escala entorno de la antigua estaciâ”œâ”‚n de ferrocarril de Campo Sepulcro, con sus parcelas, huertos traseros... Al fondo, tal vez los bloques de las viviendas militares de Anselmo Clavâ”œÂ®, frente a la estaciâ”œâ”‚n. Fuente visual: "Eduardo Laborda. Simbolismo barroco", Cajalâ”œâ”‚n, 2006.', 1969, 1969, 1969, 'Anos 60', 'DELICIAS', 41.64916200, -0.89666200, '0101000020E6100000471CB28174B1ECBF29E78BBD17D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19537993041.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19537993041.webp', 'https://www.flickr.com/photos/zaragozaantigua/19537993041/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22564, 'Plaza de Roma 1974', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 08/09/1974. Los sucesivos proyectos de "Casas Baratas" y de ordenaciâ”œâ”‚n urbanâ”œÂ¡stica del crecimiento de la ciudad por el oeste dejaron pocas realidades en la zona del original barrio de la Romareda, o de Cariâ”œâ–’ena, salvo la aislada intervenciâ”œâ”‚n de la "Ciudad Jardâ”œÂ¡n". Habâ”œÂ¡a demasiados intereses especulativos en su contra y, ademâ”œÃ­s, la omnipotente presencia del enorme complejo fabril de Escoriaza, en las traseras de Campo Sepulcro, condicionaba cualquier actuaciâ”œâ”‚n. Cuando esta fâ”œÃ­brica se deslocalizâ”œâ”‚ a otra ubicaciâ”œâ”‚n, se abrieron nuevas calles, y la urbanizaciâ”œâ”‚n de la zona (grandes bloques de viviendas) avanzâ”œâ”‚ râ”œÃ­pidamente al albur del desarrollismo sesentero. Asâ”œÂ¡, la plaza de Roma y la estratâ”œÂ®gica Urbanizaciâ”œâ”‚n Parque Roma vieron la luz en fecha tan reciente como 1972, en un entorno irreconocible para quien recordara el paso del antiguo ferrocarril de Cariâ”œâ–’ena justo aquâ”œÂ¡. En la imagen, la plaza de Roma vista en altura, con la calle Vicente Berdusâ”œÃ­n a la derecha, luego la calle Italia, y el arranque, a la izquierda, de Duquesa Villahermosa.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.64948200, -0.89899000, '0101000020E610000014CB2DAD86C4ECBF9BABE63922D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15231545788.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15231545788.webp', 'https://www.flickr.com/photos/zaragozaantigua/15231545788/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22585, 'Calle Delicias c.1973', 'Vista de la calle Delicias de Zaragoza desde su embocadura en la calle Duquesa Villahermosa. A la izquierda, colegio pâ”œâ•‘blico Andrâ”œÂ®s Manjâ”œâ”‚n. Fuente: www.facebook.com/photo.php?fbid=1680995642145619&set=...', 1973, 1973, 1973, 'Anos 70', 'DELICIAS', 41.64792500, -0.90372300, '0101000020E61000008693347F4CEBECBF62A1D634EFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15647214881.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15647214881.webp', 'https://www.flickr.com/photos/zaragozaantigua/15647214881/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22599, 'D. Pedro de Luna 1975', 'El denominado "Dâ”œÂ¡a del Ahorro", celebrado a bombo y platillo como si de un ejercicio de participaciâ”œâ”‚n democrâ”œÃ­tica en la economâ”œÂ¡a se tratara, era sin embargo algo mâ”œÃ­s pedestre, y menos revolucionario: un puro ejercicio de captaciâ”œâ”‚n del ahorro de los pobres por parte de las entidades gestoras del dinero ajeno que, a cambio, "regalaban" libros sobre recuerdos regionalistas entraâ”œâ–’ables y amables, algunos sesudos libros de historia para decorar estanterâ”œÂ¡as, frescas colonias de garrafâ”œâ”‚n, et cetera. De esta forma, y otras mâ”œÃ­s, la entidad de ahorro que aparece en la imagen consiguiâ”œâ”‚ cuatriplicar sus recursos ajenos en pocos aâ”œâ–’os, convirtiâ”œÂ®ndose en la tercera de las Cajas Confederadas espaâ”œâ–’olas. Otro asunto muy distinto era en quâ”œÂ® invertâ”œÂ¡a luego esos dineros, siquiera si lo hacâ”œÂ¡a en la "regiâ”œâ”‚n aragonesa" (y Rioja, por supuesto), y con quâ”œÂ® resultados. En la imagen, una de las filas, o "colas" que se organizaban a la entrada de estas entidades de ahorro en esos dâ”œÂ¡as tan seâ”œâ–’alados, de "fiesta del ahorro". La clase social de quienes forman la cola es esa que estâ”œÃ­ acostumbrada a hacer cola siempre, incluso para dar su dinero a un interâ”œÂ®s ridâ”œÂ¡culo, o a cambio de un libro de cocina. Estamos en la que fuera calle de Josâ”œÂ® Arias, luego denominada D. Pedro de Luna, casi en la esquina con el antiguo Camino de la Mosquetera y la acequia de la Romareda, luego Duquesa Villahermosa. La agencia de la entonces caja, hoy banco, sigue en el mismo sitio. Lo que ha desaparecido es el edificio de ladrillo de su izquierda. Fuente: foto Gerardo Sancho Ramo, en AMZ.', 1975, 1975, 1975, 'Anos 70', 'DELICIAS', 41.64822400, -0.90329200, '0101000020E61000003CA1D79FC4E7ECBFBC3D0801F9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18582357213.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18582357213.webp', 'https://www.flickr.com/photos/zaragozaantigua/18582357213/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22742, 'Calle de Vicente Berdusâ”œÃ­n 1973', 'A lomos de un mulo, un avezado jinete (el detalle del modelo de calzado que gasta lo delata) cruza con resoluciâ”œâ”‚n por el final de la calle de Vicente Berdusâ”œÃ­n y se encamina hacia la calle de la Duquesa de Villahermosa. De fondo, portal de ingreso al moderno bloque esquinero del nâ”¬â•‘ 24 de Vicente Berdusâ”œÃ­n, actual nâ”¬â•‘ 46. A la izquierda, local reservado para instalar una sucursal de la Caja de Ahorros de la Inmaculada. A la derecha, local comercial donde aâ”œâ–’os despuâ”œÂ®s se constituirâ”œÃ­ la Ferreterâ”œÂ¡a Arias. A espaldas del fotâ”œâ”‚grafo, el antiguo y gran complejo industrial de Material Mâ”œâ”‚vil y Construcciones, ya redenominada Construcciones y Auxiliar de Ferrocarriles, y en proceso de reubicaciâ”œâ”‚n en unas nuevas instalaciones en la avenida de Cataluâ”œâ–’a.', 1973, 1973, 1973, 'Anos 70', 'DELICIAS', 41.64983700, -0.89894600, '0101000020E61000002CD7DB662AC4ECBF895DDBDB2DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31800517187.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31800517187.webp', 'https://www.flickr.com/photos/zaragozaantigua/31800517187/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22751, 'Calle de Escosura 1976', 'Imagen del calificado como "â”œâ•‘ltimo â”œÃ­rbol de Escosura", que tambiâ”œÂ®n fue finalmente arrancado durante las obras de vialidad y aguas que tras varios meses renovaron el abastecimiento y saneamiento de esta antigua calle, antes denominada de Roche. El â”œÃ­rbol estaba ubicado a la altura del nâ”¬â•‘ 38-B, en la imagen flanqueado por dos parcelas luego sustituidas por modernos edificios. Hacia la derecha, direcciâ”œâ”‚n avenida de Valencia. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64798500, -0.89842000, '0101000020E61000007250C24CDBBFECBF37A6272CF1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32611850383.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32611850383.webp', 'https://www.flickr.com/photos/zaragozaantigua/32611850383/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23041, 'Calle de Vicente Berdusâ”œÃ­n 1994', 'Imagen capturada durante la urbanizaciâ”œâ”‚n de la calle de Vicente Berdusâ”œÃ­n y el tramo de la calle de Escoriaza y Fabro comprendido entre esta calle y la avenida de Madrid. En primer tâ”œÂ®rmino, vehâ”œÂ¡culos aparcados sobre los solares de antiguas parcelas derribadas entre las calles de Româ”œÃ­n Izuzquiza y de Fuendetodos, donde a finales de esta dâ”œÂ®cada se construirâ”œÂ¡a el actual inmueble del nâ”¬â•‘ 30 de la calle de Vivente Berdusâ”œÃ­n. Hacia el fondo y a la izquierda, bloques de viviendas del camino de la Mosquetera y de las calles de Hilariâ”œâ”‚n Eslava. Navas de Tolosa y Doâ”œâ–’a Blanca de Navarra. Al fondo, bloques de la calle de Fuenterrabâ”œÂ¡a. A la derecha, bloques de la urbanizaciâ”œâ”‚n Parque Roma. La urbanizaciâ”œâ”‚n de esta zona incluâ”œÂ¡a la renovaciâ”œâ”‚n del servicio de alcantarillado para resolver las crâ”œâ”‚nicas deficiencias de evacuaciâ”œâ”‚n de aguas pluviales que se acumulaban en el paso a desnivel de la avenida de Madrid.', 1994, 1994, 1994, 'Anos 90', 'DELICIAS', 41.65087700, -0.89879700, '0101000020E6100000EFC517EDF1C2ECBFFB5B02F04FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50380195132.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50380195132.webp', 'https://www.flickr.com/photos/zaragozaantigua/50380195132/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23122, 'Vâ”œÂ¡a Univâ”œÂ®rsitas 2006', 'Foto: Marâ”œÂ¡a Torres-Solanot. Construcciâ”œâ”‚n del Centro Câ”œÂ¡vico Esquinas del Psiquiâ”œÃ­trico, en la Vâ”œÂ¡a Univâ”œÂ®rsitas 30-32. En 2003 fueron adjudicadas las obras de este entorno por parte del Gobierno de Aragâ”œâ”‚n al grupo Bruesa. Los equipamientos municipales incluidos fueron un pabellâ”œâ”‚n polideportivo, un teatro y este centro, inaugurado en 2010. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'DELICIAS', 41.64679300, -0.90780100, '0101000020E6100000C7D5C8AEB40CEDBF1024EF1CCAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31130296583.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31130296583.webp', 'https://www.flickr.com/photos/zaragozaantigua/31130296583/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23317, 'Plaza de Roma 1968', '1968. Familia Roldâ”œÃ­n. "Gravera (Plaza Roma) vista desde la C/ Italia". La urbanizaciâ”œâ”‚n del polâ”œÂ¡gono industrial de Carde y Escoriaza en las traseras de la Estaciâ”œâ”‚n Campo Sepulcro iba a suponer que la ciudad tuviera una "Plaza de Roma" modelada como eje entre Duquesa Villahermosa, y las nuevas calles de Santander y Vicente Berdusâ”œÃ­n, ademâ”œÃ­s de propiciar el crecimiento de altos y modernos bloques residenciales. En la imagen, familiar posado a la entrada de la calle Desiderio Escosura, desde lo que mâ”œÃ­s tarde serâ”œÃ­ la Plaza de Roma, con el enorme bloque de entrada a la calle en plena construcciâ”œâ”‚n. Al fondo, el no menos impresionante Edificio Torresol. A la izquierda, insâ”œâ”‚lita vista de las calles Tarragona y â”œÃ¼vila. Antes, restos piqueteados de las naves de Carde y Escoriaza, utilizados como parque infantil de juego, como pasaba en todos los barrios de la periferia de la ciudad, sin que aparentemente ninguna madre entrara en coma.', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.64898500, -0.89908700, '0101000020E6100000B247A81952C5ECBF1B4CC3F011D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14783752810.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14783752810.webp', 'https://www.flickr.com/photos/zaragozaantigua/14783752810/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23693, 'Hospital Psiquiâ”œÃ­trico 1964', 'Ayuntamiento de Zaragoza/Gerardo Sancho, 4/7/1964. Instalaciones del Hospital Psiquiâ”œÃ­trico Nuestra Seâ”œâ–’ora del Pilar de Zaragoza (manicomio). Al fondo, la capilla que aâ”œâ•‘n se levanta en el parque. En primer plano, busto con arbusto de D. Manuel Dronda, prâ”œâ”‚cer local fallecido el 1 de diciembre de 1899, que habâ”œÂ¡a dedicado tiempo y fortuna a la mejora del manicomio, comprando terrenos y mandando construir pabellones. La DPZ acordâ”œâ”‚ que a su cadâ”œÃ­ver se le hiciera una mascarilla funeraria (por el escultor Palao) para un busto fundido en metal que honrara su memoria en lugar principal del establecimiento.', 1964, 1964, 1964, 'Anos 60', 'DELICIAS', 41.64685600, -0.91068400, '0101000020E6100000E2B19FC55224EDBF569C6A2DCCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15024451200.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15024451200.webp', 'https://www.flickr.com/photos/zaragozaantigua/15024451200/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23702, 'San Simeâ”œâ”‚n, o los Gigantes en el manicomio 1925', 'Se estiman en unos 400 los tipos de trastornos mentales que acompaâ”œâ–’an al ser humano en su trâ”œÃ­nsito por este valle de lâ”œÃ­grimas. Entre los mâ”œÃ­s comunes se encuentran los trastornos afectivos (depresiones y distimias), de ansiedad (fobias, angustias, obsesivos compulsivos, somatizaciâ”œâ”‚n ...), adicciones (innâ”œâ•‘meras), trastornos psicâ”œâ”‚ticos (esquizofrenia, bipolaridad ...), y aquellos asociados a la tercera edad (demencias, trastornos del sueâ”œâ–’o ...) A pesar de sus enormes complejidades, la "locura", como simplificaciâ”œâ”‚n extrema del asunto, es interpretada culturalmente como un defecto, un estigma: loco es quien ha perdido la razâ”œâ”‚n. Desde que en la edad media se pretendâ”œÂ¡a sanar al loco mediante la "extracciâ”œâ”‚n de la piedra de la locura", o cirugâ”œÂ¡a mayor, han sido varias las estrategias de las polâ”œÂ¡ticas pâ”œâ•‘blicas a la hora de afrontar este tema, aunque la mâ”œÃ­s generalizada ha sido la asociada con el estigma que le acompaâ”œâ–’a: poner al loco fuera de circulaciâ”œâ”‚n como medida de saneamiento social, y recluirlo en un hospital, junto a los pobres. Hasta que en 1914 se desarrolla la enfermerâ”œÂ¡a mental de carâ”œÃ­cter laico, y en los aâ”œâ–’os 20 se crea la Escuela Nacional de Sanidad y la Escuela de Psiquiatrâ”œÂ¡a, los tratamientos consistâ”œÂ¡an en un internado donde se velaba por la salud corporal, la alimentaciâ”œâ”‚n y la educaciâ”œâ”‚n en la doctrina cristiana. En Zaragoza, la DPZ acordâ”œâ”‚ construir segâ”œâ•‘n estos preceptos, en 1873, un Manicomio Modelo en la Granja de Nâ”¬Â¬. Sâ”¬Â¬. del Pilar, en el Terminillo. Hasta entonces, los asilados estaban ingresados en el Hospital de Gracia. Una vez terminados, los nuevos pabellones tenâ”œÂ¡an capacidad para 600 enfermos, con casi 4 hectâ”œÃ­reas de buena huerta alrededor. En 1912 este Manicomio pasâ”œâ”‚ a depender del Estado. En la imagen, el Rey y la Reina encabezan la tradicional comparsa de Gigantes en los jardines y pabellones del Manicomio, para fiestear a los internos. â”œÃ«stos observan atentamente a los inanimados artefactos despojados de sus titiriteros, mientras que uno de ellos pref', 1925, 1925, 1925, 'Anos 20', 'DELICIAS', 41.64690100, -0.91150000, '0101000020E61000005EBA490C022BEDBFF65FE7A6CDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18484244615.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18484244615.webp', 'https://www.flickr.com/photos/zaragozaantigua/18484244615/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23704, 'Calle Delicias 1925', 'Fuente: Mâ”¬Â¬ Pilar Biel Ibâ”œÃ­â”œâ–’ez, Zaragoza y la industrializaciâ”œâ”‚n: la arquitectura industrial 1875-1936, IFC, 2004.', 1925, 1925, 1925, 'Anos 20', 'DELICIAS', 41.65027300, -0.90474300, '0101000020E6100000211E8997A7F3ECBF643C4A253CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19039560603.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19039560603.webp', 'https://www.flickr.com/photos/zaragozaantigua/19039560603/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23705, 'Calle Sangenâ”œÂ¡s 1924', 'Acceso de los Talleres Chalmeta en 1924. Fundados en 1919, producâ”œÂ¡an envases metâ”œÃ­licos, artâ”œÂ¡culos de hojalaterâ”œÂ¡a y estampaciones sobre metales. Estaban situados en la calle de Antonio Sangenâ”œÂ¡s 40 del barrio de las Delicias. Fuente: La Esfera, 3 de enero de 1925.', 1924, 1924, 1924, 'Anos 20', 'DELICIAS', 41.65013000, -0.90335800, '0101000020E6100000198F52094FE8ECBF0113B87537D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19845170688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19845170688.webp', 'https://www.flickr.com/photos/zaragozaantigua/19845170688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23707, 'Isabel de Borbâ”œâ”‚n 1913', 'Visita de la infanta Isabel de Borbâ”œâ”‚n, "la Chata", hija de la reina Isabel II, al Manicomio de Zaragoza en julio de 1913. Le acompaâ”œâ–’an el prior del Manicomio de Nuestra Seâ”œâ–’ora del Pilar, la superiora y el mâ”œÂ®dico director, dr. Gimeno Riera. Fuente: Fotografâ”œÂ¡a de Aurelio Grasa publicada en el libro "Aurelio Grasa 1893-1972", Galerâ”œÂ¡a Costa, 3, 1976. Pâ”œÃ­gina 37. Formâ”œâ”‚ parte de la exposiciâ”œâ”‚n conmemorativa celebrada en dicha galerâ”œÂ¡a en 1978. Tambiâ”œÂ®n fue publicada en la pâ”œÃ­gina 53 del catâ”œÃ­logo "Aurelio Grasa reportero grâ”œÃ­fico 1910-1917", RSFZ, Galerâ”œÂ¡a Costa,3. Zaragoza 2003. Fotografia publicada en Heraldo de Aragâ”œâ”‚n el 23 de julio de 1913, en ABC el 25 de julio de 1913. El periâ”œâ”‚dico ABC conserva una copia de esa fotografâ”œÂ¡a de Aurelio Grasa que el mismo enviâ”œâ”‚ para su publicaciâ”œâ”‚n. www.aureliograsa.es', 1913, 1913, 1913, 'Anos 10', 'DELICIAS', 41.64716400, -0.91050300, '0101000020E6100000CD1DFD2FD722EDBF03931B45D6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21280020406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21280020406.webp', 'https://www.flickr.com/photos/zaragozaantigua/21280020406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23710, 'Calle Delicias aâ”œâ–’os 80', 'Foto: Vâ”œÂ¡ctor M. Soriano. Vista de la calle Delicias de Zaragoza, a la altura del nâ”œâ•‘mero 34. A la izquierda, calle Bâ”œÂ®lgica. Al fondo, avenida de Madrid. En 1990, se remodelâ”œâ”‚ y convirtiâ”œâ”‚ en peatonal. Fuente visual: www.facebook.com/photo.php?fbid=1082365388459063&set=...', 1980, 1980, 1989, 'Anos 80', 'DELICIAS', 41.65100400, -0.90513900, '0101000020E61000004FB16A10E6F6ECBF58C85C1954D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22357529120.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22357529120.webp', 'https://www.flickr.com/photos/zaragozaantigua/22357529120/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23711, 'Calle de Garcâ”œÂ¡a Sâ”œÃ­nchez 1976', 'Parada terminal que enlazaba las lâ”œÂ¡neas 22 y 24 del autobâ”œâ•‘s urbano entre Las Fuentes y Las Delicias, en la calle de Josâ”œÂ® Garcâ”œÂ¡a Sâ”œÃ­nchez. Al fondo, el colegio de las Hijas de San Josâ”œÂ®, Al fondo, el colegio de las Hijas de San Josâ”œÂ®, chaflanero entre Duquesa Villahermosa y Marcelino de Unceta. La huelga que anuncia el cartel durâ”œâ”‚ del 8 al 11 de octubre, cuando se llegâ”œâ”‚ a un principio de acuerdo. Por si acaso, el domingo 10 salieron autobuses conducidos por personal del Parque Mâ”œâ”‚vil de los ministerios civiles, y microbuses por châ”œâ”‚feres del Ejâ”œÂ®rcito de Tierra.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64841800, -0.90014800, '0101000020E6100000F2E9B12D03CEECBFA1116C5CFFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24006878943.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24006878943.webp', 'https://www.flickr.com/photos/zaragozaantigua/24006878943/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23737, 'Manicomio 1913', 'Visita de la infanta Isabel de Borbâ”œâ”‚n, "la Chata", hija de la reina Isabel II, al Manicomio de Nuestra Seâ”œâ–’ora del Pilar en el Terminillo, en julio de 1913. Le acompaâ”œâ–’an el prior de los Hermanos de San Juan de Dios y la superiora de las Hermanas de la Caridad de Santa Ana, sor Amalia Porcano, ademâ”œÃ­s del espigado subdirector mâ”œÂ®dico, doctor Joaquâ”œÂ¡n Gimeno Riera. A la derecha y en segundo plano, el arzobispo Juan Soldevila, siempre interesado en todo lo relacionado con el Terminillo. A la izquierda, uno de los lacayos del coche de caballos en que se desplazaba la infanta por la ciudad en su estancia.', 1913, 1913, 1913, 'Anos 10', 'DELICIAS', 41.64731800, -0.90945100, '0101000020E61000005A10CAFB381AEDBF5A0EF450DBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50783415323.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50783415323.webp', 'https://www.flickr.com/photos/zaragozaantigua/50783415323/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23740, 'Barrio de Roche 1927', 'Imagen capturada en el barrio de Roche, resultante de la parcelaciâ”œâ”‚n a principios de los aâ”œâ–’os 20 del campo de Juan Roche sito en una perifâ”œÂ®rica ubicaciâ”œâ”‚n entre la carretera de Valencia, la estaciâ”œâ”‚n de Cariâ”œâ–’ena y los talleres de Material Mâ”œâ”‚vil y Construcciones (hacia el fondo). La de la imagen se trataba probablemente de la parcela ya construida y con el numeral 13 de este barrio particular de una sola calle. Tras el 18 de julio de 1936 la calle serâ”œÂ¡a redenominada de Desiderio Escosura. Actualmente esta localizaciâ”œâ”‚n se corresponderâ”œÂ¡a con el punto donde la calle del Obispo Tajâ”œâ”‚n cruza la de Escosura.', 1927, 1927, 1927, 'Anos 20', 'DELICIAS', 41.64769500, -0.89843200, '0101000020E610000083C13577F4BFECBF306475ABE7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52324354983.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52324354983.webp', 'https://www.flickr.com/photos/zaragozaantigua/52324354983/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24030, 'Calle Duquesa Villahermosa 2003', 'Foto: Beatriz Benedicto. Entorno conocido como "Esquinas del Psiquiâ”œÃ­trico", con la calle de la Duquesa de Villahermosa en el centro, atravesâ”œÃ­ndolo de izquierda a derecha. Allâ”œÂ¡ estâ”œÃ­n situadas las ferias del barrio de las Delicias. Entre 2007 y 2011, el entorno se urbanizarâ”œÃ­ con equipamientos pâ”œâ•‘blicos y viviendas. Al fondo a la derecha, Vâ”œÂ¡a Universitas. Fuente: www.facebook.com/photo.php?fbid=532016703802554&set=g...', 2003, 2003, 2003, 'Siglo XXI', 'DELICIAS', 41.64665700, -0.90708000, '0101000020E6100000BB61DBA2CC06EDBF5F5D15A8C5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26208873619.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26208873619.webp', 'https://www.flickr.com/photos/zaragozaantigua/26208873619/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24217, 'Campo Sepulcro 1949', 'Imagen capturada en la factorâ”œÂ¡a de Material Mâ”œâ”‚vil y Construcciones sita junto a la estaciâ”œâ”‚n de Campo Sepulcro y centrada en la armadura interior de uno de los diez automotores basados en el modelo Renault ABJ-4 encargados por RENFE, que una vez finalizados recibirâ”œÂ¡an la denominaciâ”œâ”‚n de ABJ-7 dentro de la serie RENFE 9313-9332. Al fondo, vista parcial del barrio de Cariâ”œâ–’ena o de la Romareda con algunos de los singulares "hotelitos" vertebrados en torno a la calle del Moncayo. A la izquierda despunta una de las torrecillas de la antigua fâ”œÃ­brica de chocolates Orâ”œâ•‘s entonces ocupada por la sociedad Industrias del Cartonaje S.A.', 1949, 1949, 1949, 'Anos 40', 'DELICIAS', 41.64993900, -0.89733800, '0101000020E610000054A86E2EFEB6ECBF8EB27E3331D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54726346345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54726346345.webp', 'https://www.flickr.com/photos/zaragozaantigua/54726346345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25916, 'Duquesa Villahermosa 1969', 'Imagen de la unidad nâ”¬â•‘ 74 (un BUT de dos pisos) de la lâ”œÂ¡nea de trolebuses "Ciudad Jardâ”œÂ¡n", avanzando por la calle Duquesa Villahermosa hacia el emboque con la calle Pedro Lâ”œâ”‚pez de Luna, donde iniciar el retorno hacia la plaza de Santa Engracia. La imagen ha sido capturada, casualmente, en la esquina de la calle Don Pedro de Luna. Al fondo, a la izquierda, el gran bloque esquinero con la calle Luis Franco y Lâ”œâ”‚pez. A la derecha, arbolado de la "Ciudad Jardâ”œÂ¡n" y, emergente, grâ”œâ•‘a de obra, posiblemente del nuevo bloque del nâ”¬â•‘ 30 de la calle de Luis Franco y Lâ”œâ”‚pez. Fuente visual: desequilibros.blogspot.com.es/', 1969, 1969, 1969, 'Anos 60', 'DELICIAS', 41.64802500, -0.90309800, '0101000020E610000000A8E2C62DE6ECBFC5FEB27BF2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30512970254.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30512970254.webp', 'https://www.flickr.com/photos/zaragozaantigua/30512970254/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25967, 'Huerta del Manicomio 1971', 'En 1873 la DPZ acordâ”œâ”‚ construir un Manicomio Modelo en la Granja de Ntra. Sra. del Pilar, en el Terminillo. Las obras comenzaron en 1878, pero muchos asilados continuaban ingresados en el antiguo Hospital de Gracia. En 1912 el Manicomio pasâ”œâ”‚ a depender del Estado. Una vez terminados, los pabellones tenâ”œÂ¡an capacidad para 600 enfermos, y hasta 4 hectâ”œÃ­reas de buena huerta. El Plan Larrodera (1968) recalificâ”œâ”‚ parte de las zonas verdes para ladrillo, pero la presiâ”œâ”‚n ejercida durante aâ”œâ–’os de movilizaciones, encabezada por las Asociaciones de cabezas de Familia del barrio, consiguieron modificar el Plan, y terreno para el desdoblamiento de Vâ”œÂ¡a Universitas y Duquesa Villahermosa, y para crear un nuevo Parque. En la imagen, parte de las huertas del Manicomio, la mâ”œÃ­s cercana a Duquesa Villahermosa y al Grupo de Viviendas "Severino Aznar" (derecha). En el centro, el Colegio Pâ”œâ•‘blico "Josâ”œÂ® Marâ”œÂ¡a Mir". A su izquierda, el bloque de viviendas de la calle Santa Rita de Casia, en la actualidad vecino al CDM "Duquesa Villahermosa". Con la prolongaciâ”œâ”‚n de Duquesa de Villahermosa y el paso de la Vâ”œÂ¡a Universitas, esta zona ha vivido una autâ”œÂ®ntica mutaciâ”œâ”‚n. Fuente visual: "Zaragoza 1908-2008. Arquitectura y Urbanismo".', 1971, 1971, 1971, 'Anos 70', 'DELICIAS', 41.64673200, -0.90666100, '0101000020E610000083E0F1ED5D03EDBF6AA33A1DC8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14794570428.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14794570428.webp', 'https://www.flickr.com/photos/zaragozaantigua/14794570428/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25973, 'Ciudad Jardâ”œÂ¡n c.1945', 'AHPZ. Estudio Coyne. Aâ”œâ–’os 40. "Ciudad jardâ”œÂ¡n." Imagen tomada desde cierta altura en la calle Duquesa de Villahermosa, esquina calle Delicias. La que se abre a la izquierda (Lorenzo Calvo de Rozas) es una de las calles interiores de la barriada. Al fondo, la ciudad. Construida entre 1936-39, segâ”œâ•‘n proyecto de Miguel â”œÃ¼ngel Navarro. Ideadas dentro de la filosofâ”œÂ¡a de construcciâ”œâ”‚n de "Casas Baratas", el franquismo reorientâ”œâ”‚ su adjudicaciâ”œâ”‚n, en positivo, hacia gentes leales al nuevo râ”œÂ®gimen, y en negativo hacia quienes no.', 1945, 1945, 1945, 'Anos 40', 'DELICIAS', 41.64781500, -0.90343200, '0101000020E6100000AC1DC539EAE8ECBFDB6D179AEBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15114921416.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15114921416.webp', 'https://www.flickr.com/photos/zaragozaantigua/15114921416/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25999, 'La Bozada 1991', 'Foto: Archivo Taumar (Irene Taulâ”œÂ®s y Rafael Margalâ”œÂ®). Vista aâ”œÂ®rea del barrio de la Bozada, con el IES Jerâ”œâ”‚nimo Zurita a la derecha, el parque Avempace en el centro y la Vâ”œÂ»a Univâ”œÂ®rsitas arriba. En la esquina superior derecha, el Hospital Clâ”œÂ¡nico. Fuente: www.facebook.com/photo.php?fbid=1687674314789601&set=...', 1991, 1991, 1991, 'Anos 90', 'DELICIAS', 41.64414800, -0.90849800, '0101000020E6100000B267CF656A12EDBF54E4107173D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21785689684.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21785689684.webp', 'https://www.flickr.com/photos/zaragozaantigua/21785689684/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21567, 'Calle de Alfonso I c.1920', 'En 1918, Celestino Salinero Ena ampliâ”œâ”‚ y reformâ”œâ”‚ los originales "Grandes talleres de confecciâ”œâ”‚n La Casa Blanca" (Alfonso I, 22). La ampliaciâ”œâ”‚n incorporâ”œâ”‚ la planta calle del nâ”¬â•‘ 24 de la finca, chaflanero con la calle Miguel Molino. La reforma le confiriâ”œâ”‚ una nueva fachada de conjunto, con el caracterâ”œÂ¡stico color blanco como seâ”œâ–’a de identidad, y unos interiores tambiâ”œÂ®n redecorados. En la imagen, la nueva fachada comercial. A la izquierda, la calle Miguel Molino. Fuente visual: aportaciâ”œâ”‚n de Mariano Lacruz Pâ”œÂ®rez de una reproducciâ”œâ”‚n fotogrâ”œÃ­fica realizada por Mariano Lacruz Berdejo sobre una imagen original cedida por Marâ”œÂ¡a Josâ”œÂ® Salinero (nieta de Celestino Salinero).', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65471900, -0.88031000, '0101000020E6100000B3EF8AE07F2BECBFF0880AD5CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23243939405.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23243939405.webp', 'https://www.flickr.com/photos/zaragozaantigua/23243939405/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21568, '&quot;La Casa Blanca&quot; c.1920', 'Imagen de los "Grandes talleres de confecciâ”œâ”‚n La Casa Blanca" (Alfonso I, 22-24), de Celestino Salinero Ena, tras la reforma y ampliaciâ”œâ”‚n de 1918, con un curioso y considerable trampantojo en forma de dibujo que integra toda la primera planta de la finca en el comercio (la parte real era la del fondo, recayente a la calle de Goya, ademâ”œÃ­s de toda la planta calle). El chaflâ”œÃ­n de primer plano de la imagen, el real (planta calle) y el dibujado (primera planta), en el arranque de la calle Miguel Molino. En la parte superior, cartel indicativo del Hotel de Elâ”œÂ¡as Cequiel establecido en este inmueble del nâ”¬â•‘ 24 de la calle de Alfonso I y del nâ”¬â•‘ 2 de la calle de Miguel Molino. Fuente visual: aportaciâ”œâ”‚n de Mariano Lacruz Pâ”œÂ®rez de una reproducciâ”œâ”‚n fotogrâ”œÃ­fica realizada por Mariano Lacruz Berdejo sobre una imagen original cedida por Marâ”œÂ¡a Josâ”œÂ® Salinero (nieta de Celestino Salinero).', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65471900, -0.88031000, '0101000020E6100000B3EF8AE07F2BECBFF0880AD5CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23246383025.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23246383025.webp', 'https://www.flickr.com/photos/zaragozaantigua/23246383025/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21671, 'Calle de Alfonso I aâ”œâ–’os 30', 'Aâ”œâ–’os 30 del siglo XX. Colecciâ”œâ”‚n Vâ”œÂ¡ctor Barâ”œâ”‚n. Fila de mujeres para comprar en "Las nuevas sederâ”œÂ¡as". El portal de vecinos entre esa tienda y el Bazar es el nâ”œâ•‘mero 26 de la calle, donde vive Dolores Serrat, consejera de Educaciâ”œâ”‚n del Gobierno de Aragâ”œâ”‚n entre 2011 y 2015 y miembro del Partido Popular. El dato es vox pâ”œâ”‚puli porque las manifestaciones ciudadanas recorrâ”œÂ¡an obligadas otros itinerarios para no molestarla; ademâ”œÃ­s de que allâ”œÂ¡ mismo el profesor Antonio Aramayona se colocaba a protestar diariamente desde junio de 2013 por la polâ”œÂ¡tica de Educaciâ”œâ”‚n de la DGA.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65505700, -0.88009600, '0101000020E6100000B0E42A16BF29ECBF080264E8D8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14760231379.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14760231379.webp', 'https://www.flickr.com/photos/zaragozaantigua/14760231379/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21881, 'Calle de Alfonso I 1931', 'Imagen capturada en la calle de Alfonso I en el punto donde desde la izquierda desemboca la calle de la Manifestaciâ”œâ”‚n, y donde hacia la derecha comienza la calle de Espoz y Mina. Hacia el fondo, manzanas finales del tramo hasta la plaza del Pilar, que al fondo presenta su antigua y despejada fachada, mâ”œÃ­s visible por la realizaciâ”œâ”‚n de la foto en â”œÂ®poca invernal, como ilustran los â”œÃ­rboles de la plaza. Entre los bajos comerciales entoldados a la izquierda, la tienda de tejidos de Pascual Blasco D''Harcourt. En la umbrâ”œÂ¡a derecha, guanterâ”œÂ¡a La Catalana.', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65545500, -0.87982800, '0101000020E6100000E25CC30C8D27ECBFF67F0EF3E5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47569597722.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47569597722.webp', 'https://www.flickr.com/photos/zaragozaantigua/47569597722/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
