INSERT INTO public.photos VALUES (22392, 'Calle Olmo 1965', 'Calle del Olmo. Al fondo, la calle del Temple. Fuente visual: Foto Leonardo Pâ”œÂ®rez Obis, donada por â”œÃ¼ngel Hernâ”œÃ­ndez Mostajo para www.rafaelcastillejo.com', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65553400, -0.88188900, '0101000020E6100000F777B6476F38ECBF42B5C189E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22750235347.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22750235347.webp', 'https://www.flickr.com/photos/zaragozaantigua/22750235347/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23287, 'Calle de Alfonso I 1909', 'Imagen de la calle Alfonso I enfocando en direcciâ”œâ”‚n hacia el Coso Alto. La calle de la izquierda es la de Espoz y Mina. La de la derecha, Manifestaciâ”œâ”‚n. Al fondo, fachada del palacio del marquâ”œÂ®s de Campo Franco, que pocos aâ”œâ–’os despuâ”œÂ®s serâ”œÃ­ piqueteado para dar paso al edificio del Banco de Aragâ”œâ”‚n, obra de Manuel del Busto (1913). Fuente: Instituto Amatller de Arte Hispâ”œÃ­nico (Arxiu Mas).', 1909, 1909, 1909, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65555100, -0.87971000, '0101000020E610000066DAFE959526ECBF18EE5C18E9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15700543099.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15700543099.webp', 'https://www.flickr.com/photos/zaragozaantigua/15700543099/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23291, 'Calle de Alfonso I 1908', 'Vista de la calle de Alfonso I, desde el cruce con las calles Contamina (izquierda), y Goya (derecha). Antes de la instalaciâ”œâ”‚n del local comercial "La Casa Blanca".', 1908, 1908, 1908, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65545300, -0.87984000, '0101000020E6100000F2CD3637A627ECBF558847E2E5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20364430090.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20364430090.webp', 'https://www.flickr.com/photos/zaragozaantigua/20364430090/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23295, 'Calle Manifestaciâ”œâ”‚n c.1895', 'Luminosa imagen finisecular capturada desde el primer piso del 82 de la calle Manifestaciâ”œâ”‚n (actual 40), hacia el punto de cruce entre esta calle, y la de Alfonso I, por donde transita hacia la plaza del Pilar una humana procesionaria. En los bajos del 89-91 (actual 35), el "Comercio de Valero Palomar". Al otro lado de la calle Alfonso I, arranca hacia la izquierda el callejâ”œâ”‚n de la Leche, y hacia la derecha los primeros edificios impares de la calle Espoz y Mina, que no es que parezca estrecharse: es que lo hace. En los aâ”œâ–’os 20 del siglo XX, la Leche serâ”œÃ­ redenominada "Fray Juan Cebriâ”œÃ­n". Fuente: donaciâ”œâ”‚n de Luis Gâ”œâ”‚mez Laguna, Archivo Pâ”œâ•‘blico Municipal.', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65545300, -0.87984000, '0101000020E6100000F2CD3637A627ECBF558847E2E5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22622105418.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22622105418.webp', 'https://www.flickr.com/photos/zaragozaantigua/22622105418/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23299, 'Calle de Alfonso I c.1910', 'En 1908, el ayerbense Celestino Salinero Ena visitâ”œâ”‚ la ciudad de Parâ”œÂ¡s, y quedâ”œâ”‚ impresionado por el comercio denominado "La Maison Blanche", especializado en la venta de ropa "blanca". A la vuelta, mientras Zaragoza celebraba el Centenario I de los "Sitios", Celestino se embarcâ”œâ”‚ en la aventura de reproducir en la ciudad lo visto en Parâ”œÂ¡s. Asâ”œÂ¡, en la calle Alfonso I nâ”¬â•‘ 22 (local y primera planta), junto a la entrada de la calle Goya, fundâ”œâ”‚ "La Casa Blanca", unos innovadores y exitosos "grandes" talleres de confecciâ”œâ”‚n y venta directa de gâ”œÂ®neros de punto, juegos de cama, cubierta, toallas, mantelerâ”œÂ¡as... De la ciudad de la luz se trajo, tambiâ”œÂ®n, la francesa idea de iluminar el comercio con lâ”œÃ­mparas de gas, siendo pionero en Zaragoza. En la imagen, Celestino Salinero Ena posando ante su empresa vital. Fuente visual: aportaciâ”œâ”‚n de Mariano Lacruz Pâ”œÂ®rez de una reproducciâ”œâ”‚n fotogrâ”œÃ­fica realizada por Mariano Lacruz Berdejo sobre una imagen original cedida por Marâ”œÂ¡a Josâ”œÂ® Salinero (nieta de Celestino Salinero).', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65471900, -0.88031000, '0101000020E6100000B3EF8AE07F2BECBFF0880AD5CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23242807685.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23242807685.webp', 'https://www.flickr.com/photos/zaragozaantigua/23242807685/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23315, 'Calle de Alfonso I 1908', 'Imagen capturada en la calle de Alfonso I durante la visita del rey Alfonso XIII el dâ”œÂ¡a 15 de junio de ese aâ”œâ–’o a diversos eventos relacionados con el primer centenario del asedio francâ”œÂ®s de 1808. En este caso se trata de la "procesiâ”œâ”‚n câ”œÂ¡vico-religiosa" que acompaâ”œâ–’aba los fâ”œÂ®retros de las heroâ”œÂ¡nas Casta â”œÃ¼lvarez, Manuela Sancho y Agustina Zaragoza desde el templo del Pilar y hasta la iglesia del Portillo, donde fueron inhumadas. La instantâ”œÃ­nea, realizada a la altura del nâ”¬â•‘ 28 de la calle, junto al emboque a la calle de Espoz y Mina donde destaca al fondo el depâ”œâ”‚sito de transparentes de "La Veneciana", recoge el paso del cortejo en torno al rey Alfonso XIII flanqueado por los infantes Luis Alfonso y Luis Fernando, precedido por el marquâ”œÂ®s de Viana y seguido por los ministros del gobierno (Gracia y Justicia y Guerra), ademâ”œÃ­s de varios otros marqueses, generales y condes. Las crâ”œâ”‚nicas informan que antes de la procesiâ”œâ”‚n las nubes descargaron una fuerte tormenta que con naturalidad convirtiâ”œâ”‚ las terrosas calles del recorrido, como es el caso de la de Alfonso I, en simpâ”œÃ­ticos barrizales.', 1908, 1908, 1908, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65540700, -0.87993600, '0101000020E61000007A56D28A6F28ECBFE4486760E4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52079851856.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52079851856.webp', 'https://www.flickr.com/photos/zaragozaantigua/52079851856/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24245, 'Calle de Alfonso I 1947', 'Imagen capturada en la calle Alfonso I, a la altura del nâ”¬â•‘ 28, frente al callejâ”œâ”‚n de las Once Esquinas, donde tenâ”œÂ¡a su estudio el "pintor-fotâ”œâ”‚grafo" navarro â”œÃ¼ngel Hilario Garcâ”œÂ¡a de Jalâ”œâ”‚n, cuya denominaciâ”œâ”‚n artâ”œÂ¡stica era la que figura en el cartel anunciador: Jalâ”œâ”‚n â”œÃ¼ngel. Aparcado tranquilamente en la calle, un Peugeot 202, y delante, posado de tres elegantes seâ”œâ–’oras. Fuente visual: www.todocoleccion.net/', 1947, 1947, 1947, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65523200, -0.87996700, '0101000020E61000003BE5D18DB028ECBF76A565A4DED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30638539700.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30638539700.webp', 'https://www.flickr.com/photos/zaragozaantigua/30638539700/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24400, 'San Cayetano 1899', 'Desde las alturas del antiguo palacio de Guara, en la calle de la Montera, un vistazo en direcciâ”œâ”‚n noroeste muestra los tejados del barrio de San Felipe, y la câ”œâ•‘pula y torrecillas de la iglesia de Santa Isabel de Portugal, o de San Cayetano, denominaciâ”œâ”‚n que en la â”œÂ®poca de la imagen (y parece ser que todavâ”œÂ¡a) era considerada "vulgar" o asâ”œÂ¡ llamada por el "vulgo", si bien era esa la histâ”œâ”‚rica denominaciâ”œâ”‚n de la casa, convento e iglesia de los padres clâ”œÂ®rigos regulares de la providencia, o religiosos teatinos, sus regentes. Fuente visual: Francisco Gâ”œâ”‚rriz, Archivo Municipal de Zaragoza', 1899, 1899, 1899, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65553400, -0.88188900, '0101000020E6100000F777B6476F38ECBF42B5C189E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28406008944.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28406008944.webp', 'https://www.flickr.com/photos/zaragozaantigua/28406008944/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24479, 'Imprenta Berdejo Casaâ”œâ–’al 1925', 'Taller de la "Imprenta de Arte Berdejo Casaâ”œâ–’al", en su ubicaciâ”œâ”‚n de la calle Loscos 7 (antigua Jazmâ”œÂ¡n). La captura se ha realizado con motivo de la tirada en prensa del nâ”œâ•‘mero 1 de la revista "Aragâ”œâ”‚n", â”œâ”‚rgano de expresiâ”œâ”‚n del "Sindicato de Iniciativa y Propaganda de Aragâ”œâ”‚n" (SIPA). En el colectivo posado, junto al personal del taller, el secretario del SIPA, Eduardo Cativiela y Pâ”œÂ®rez, que sostiene un ejemplar de la revista. y junto a â”œÂ®l, Eduardo Berdejo Casaâ”œâ–’al, editor de la revista, y propietario de la imprenta. Fuente: Foto Larraz, amablemente proporcionada por Mariano Lacruz Pâ”œÂ®rez.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65556900, -0.88063200, '0101000020E61000004DF4F928232EECBFBEA25BAFE9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22528904220.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22528904220.webp', 'https://www.flickr.com/photos/zaragozaantigua/22528904220/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25070, 'Camarada Fleta 1936', 'â”œÃ¼ngel Jalâ”œâ”‚n (â”œÃ¼ngel Hilario Garcâ”œÂ¡a de Jalâ”œâ”‚n Hueto), Diputaciâ”œâ”‚n de Zaragoza, agosto 1936. Retrato de Miguel Burro Fleta. Imagen del tenor Fleta habilitado con el uniforme de la Falange Espaâ”œâ–’ola de las JONS (Juntas de Ofensiva Nacional-Sindicalista), capturado de tal traza en el Estudio fotogrâ”œÃ­fico de â”œÃ¼ngel Jalâ”œâ”‚n (Alfonso I, 28) cuando ya no habâ”œÂ¡a rojos en la costa. Falleciâ”œâ”‚ apenas dos aâ”œâ–’os despuâ”œÂ®s, y en su homenaje, la nueva, leal y digital corporaciâ”œâ”‚n municipal cambiâ”œâ”‚ de nombre a la calle Fletas, por "Avenida del Tenor Fleta". Fuente: web.dpz.es/arscatalogi.es/foto.asp?index=2851', 1936, 1936, 1936, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65497800, -0.88015400, '0101000020E6100000D731AEB8382AECBFBCCCB051D6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15696653438.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15696653438.webp', 'https://www.flickr.com/photos/zaragozaantigua/15696653438/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25895, 'Calle del Olmo, c. 1968', 'Pintura centrada en el cruce de las calles del Olmo, desde donde el autor ha capturado la escena, y del Temple, donde al fondo destaca la portalada de acceso al nâ”œâ•‘mero 14 de esa calle, una vivienda posiblemente del siglo XVII construida sobre el solar de una parte del gran complejo monâ”œÃ­stico de la Orden del Temple que ocupâ”œâ”‚ toda esa manzana.y que da nombre a esa calle. A la derecha, vista parcial del antiguo inmueble del nâ”¬â•‘ 11 de la calle del Temple, posteriormente derribado junto con sus vecinas de los nâ”œâ•‘meros 13 y 15 y que a finales de los aâ”œâ–’os 80 del pasado siglo XX su solar conformâ”œâ”‚ un singular espacio poblado de bancos de sentarse y arbolitos, un antecedente al desarrollo, veinte aâ”œâ–’os despuâ”œÂ®s, del proyecto "Estonoesunsolar" y que desde principios de este siglo XXI fue objeto de un desarrollo edilicio que conformâ”œâ”‚ el moderno inmueble del actual nâ”¬â•‘ 18 de la calle del Olmo.', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65553500, -0.88191000, '0101000020E6100000D47D00529B38ECBF12312592E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53205391874.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53205391874.webp', 'https://www.flickr.com/photos/zaragozaantigua/53205391874/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20887, 'Fundaciâ”œâ”‚n de Caesaraugusta', 'Emilio Gil Murillo, "Origen y fundaciâ”œâ”‚n de Zaragoza ", 1896. Ayuntamiento de Zaragoza. La imagen representa idealizado el rito romano de fundaciâ”œâ”‚n de la ciudad, en el 14 antes de la Era. Antes de iniciarlo, el augur consultâ”œâ”‚ los auspicios para asegurarse, mediante signos visibles, de que los dioses no se oponâ”œÂ¡an al establecimiento de la ciudad en el lugar escogido. Los dioses no dijeron ni pâ”œÂ¡o. Entonces, revestido con una toga dispuesta a la antigua usanza, cogiâ”œâ”‚ las estevas de un arado de bronce, tirado por una ternera y un toro, y trazâ”œâ”‚ un surco alrededor de la futura urbe, siguiendo la misma lâ”œÂ¡nea a lo largo de la cual habrâ”œÂ¡a de levantarse el muro delimitador. En el transcurso de la ceremonia, se procuraba que toda la tierra levantada por la reja cayese al interior del recinto. Tras â”œÂ®l, los asistentes recogâ”œÂ¡an los terrones que a veces saltaban fuera del perâ”œÂ¡metro y los volvâ”œÂ¡an a echar donde el rito establecâ”œÂ¡a. Al llegar al sitio previsto para las 4 puertas principales, se levantaba el arado con el fin de dejar un espacio libre de toda consagraciâ”œâ”‚n. Cuando el oficiante alcanzâ”œâ”‚ el punto de partida, la ciudad quedâ”œâ”‚ virtualmente fundada.', NULL, NULL, NULL, NULL, 'CASCO HISTâ”œÃ´RICO', 41.65210400, -0.87346600, '0101000020E6100000BB5F05F86EF3EBBF9FCBD42478D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14753929599.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14753929599.webp', 'https://www.flickr.com/photos/zaragozaantigua/14753929599/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20892, 'Domus Calle Heroâ”œÂ¡smo siglo I', 'En 1991 se documentâ”œâ”‚, en el solar de la calle Heroâ”œÂ¡smo 5 y 7 con Aâ”œâ–’â”œâ”‚n (en la imagen, a la derecha) de Zaragoza, una domus romana del siglo I, extramuros de la colonia. Fuente: Zaragoza. Prehistoria y arqueologâ”œÂ¡a, Ayuntamiento de Zaragoza, 1991.', 50, NULL, 99, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65117300, -0.87349900, '0101000020E6100000AAD6C22CB4F3EBBFE48409A359D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18564315843.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18564315843.webp', 'https://www.flickr.com/photos/zaragozaantigua/18564315843/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20893, 'â”œÃ¼nforas ca. 20', 'Campo de â”œÃ­nforas romano, enterradas hacia el aâ”œâ–’o 20 despuâ”œÂ®s de la Era, como drenaje o câ”œÃ­mara de aire para evitar humedades en las casas procedentes de las crecidas del râ”œÂ¡o Ebro. En mayo de 2003 se descubriâ”œâ”‚ este conjunto de casi un millar de â”œÃ­nforas puestas hacia abajo, en el solar de la plaza de las Tenerâ”œÂ¡as 9 de Zaragoza. Fuente visual: www.facebook.com/photo.php?fbid=1234779646549079&set=...', NULL, NULL, NULL, NULL, 'CASCO HISTâ”œÃ´RICO', 41.65292800, -0.87130000, '0101000020E61000005227A089B0E1EBBF44520B2593D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19386927608.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19386927608.webp', 'https://www.flickr.com/photos/zaragozaantigua/19386927608/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20896, 'Plaza Asso 1991', 'Tareas de recuperaciâ”œâ”‚n de un tramo de cloaca romana, descubierta en 1990 en la plaza Asso de Zaragoza. Al fondo, la calle Martâ”œÂ¡n Carrillo y la torre de la iglesia de la Magdalena. Fuente: Zaragoza. Prehistoria y arqueologâ”œÂ¡a, Ayuntamiento de Zaragoza, 1991.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65308900, -0.87399300, '0101000020E61000008CDAFD2AC0F7EBBF4D309C6B98D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23648332264.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23648332264.webp', 'https://www.flickr.com/photos/zaragozaantigua/23648332264/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20898, 'Plaza Magdalena 1990', 'En 1990 se hallâ”œâ”‚ un tramo de losas de la calzada romana del Decumano Mâ”œÃ­ximo, que sirviâ”œâ”‚ para confirmar que la calle Mayor se hallaba sobre â”œÂ®ste. En la foto, el comienzo de la calle Mayor, a la altura de la plaza de la Magdalena, con la iglesia homâ”œâ”‚nima arriba a la izquierda. Fuente: Las cloacas de Cesaraugusta, IFC, 2013.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65223900, -0.87360700, '0101000020E610000042D0D1AA96F4EBBF7F164B917CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24194356511.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24194356511.webp', 'https://www.flickr.com/photos/zaragozaantigua/24194356511/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20922, 'Colegio del Padre Eterno 1778', 'Plano del terreno de las Escuelas Pâ”œâ•‘blicas y del Colegio del Padre Eterno, Joseph Arberuela, Zaragoza, 19 de diciembre de 1778. El colegio del Padre Eterno, de los jesuitas, albergâ”œâ”‚ desde 1788 las primeras instalaciones del Seminario Conciliar de San Valero y San Braulio. Se encontraba en el actual Coso 127, esquina con la calle de San Lorenzo. Fuente: Archivo General de Simancas, Ministerio de Cultura de Espaâ”œâ–’a.', 1778, 1778, 1778, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65158800, -0.87402800, '0101000020E6100000A839799109F8EBBFA73B4F3C67D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20225243629.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20225243629.webp', 'https://www.flickr.com/photos/zaragozaantigua/20225243629/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20941, 'Convento de San Agustâ”œÂ¡n 1563', 'El convento de San Agustâ”œÂ¡n tal y como aparece en la vista de Zaragoza realizada en 1663 por el dibujante Anton van der Wyngaerde/Antonio de las Viâ”œâ–’as.', 1563, 1563, 1563, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65140000, -0.87079400, '0101000020E61000005FB2F1608BDDEBBFA54E401361D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54387299485.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54387299485.webp', 'https://www.flickr.com/photos/zaragozaantigua/54387299485/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20956, 'Coso Bajo 1808', '"Ruinas del Seminario vistas por la noche: cuando los patriotas, que no podâ”œÂ¡an asistir a la defensa de las puertas, a la luz de sus linternas y de los incendios, causados por las bombas, buscaban entre los escombros a los muertos para darles sepultura". Serie Ruinas de Zaragoza, de Juan Gâ”œÃ­lvez (dibujo) y Fernando Brambila (grabado), Câ”œÃ­diz, 1812. El conjunto de edificios del Seminario Mayor de Zaragoza se extendâ”œÂ¡a por el Coso Bajo en direcciâ”œâ”‚n al Ebro, mâ”œÃ­s allâ”œÃ­ de la calle de San Jorge. En la acera de la gran mole semiderruida, mâ”œÃ­s al fondo, se ve la entrada a la plaza de la Magdalena. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65158800, -0.87402800, '0101000020E6100000A839799109F8EBBFA73B4F3C67D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15267099411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15267099411.webp', 'https://www.flickr.com/photos/zaragozaantigua/15267099411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20967, 'Universidad 1814', '"La Academia de Zaragoza al regreso de Fernando VII". Medalla realizada por Antonio Martâ”œÂ¡nez y acuâ”œâ–’ada por la Universidad de Zaragoza cuando se reanudaron las clases tras la retirada de los franceses en 1814. En 1913 se terminâ”œâ”‚ una reforma que modificâ”œâ”‚ su aspecto, a cargo de Ricardo Magdalena. Al fondo a la derecha, personificaciâ”œâ”‚n del râ”œÂ¡o Ebro. Fuente: Museo del Prado.', 1814, 1814, 1814, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65222400, -0.87323600, '0101000020E61000004D13B69F8CF1EBBF49D576137CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18985824170.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18985824170.webp', 'https://www.flickr.com/photos/zaragozaantigua/18985824170/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22670, 'Feria de Muestras 1976', 'Imagen en altura de la Feria de Muestras, y su caracterâ”œÂ¡stico mirador acristalado, desde un punto de vista contrario a la inmensa mayorâ”œÂ¡a de las capturas realizadas de la zona: hacia el noreste, mirando hacia la ciudad. Este pequeâ”œâ–’o detalle permite observar el agujero, a la derecha, donde antes estuvieron los talleres de la Editorial Luis Vives, y ahora se estaba gestando la macizada y compacta manzana de bloques habitacionales que la iba a sustituir. Eso permite, excepcionalmente, visual directa de la calle Luis Vives y el desemboque a ella de Andrâ”œÂ®s Piquer, Teresa de Jesâ”œâ•‘s, y Mariano Supervâ”œÂ¡a, con el Grupo "Francisco Caballero" y restos supervivientes de antiguos hotelitos de la zona del Ensanche de Miralbueno, al poco derribados y sustituidos por cosas mâ”œÃ­s modernas y apropiadas. Fuente visual: Gerardo Sancho Ramo (Archivo Pâ”œâ•‘blico Municipal).', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63744800, -0.89883900, '0101000020E6100000ABD1AB014AC3ECBF477364E597D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23539505284.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23539505284.webp', 'https://www.flickr.com/photos/zaragozaantigua/23539505284/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21009, 'Arco de Valencia 1867', 'Imagen del antiguo arco de Valencia poco antes de su derribo realizado entre el 20 de enero y el 15 de febrero de ese aâ”œâ–’o, al objeto de despejar las casas de los nâ”œâ•‘meros 71, 73, 75 y 77 del Coso (a la derecha) que afeaban el ingreso a la Universidad Literaria, y parte de la casa del nâ”¬â•‘ 96 de la calle Mayor (a la izquierda). El derribo del arco se hizo hilada a hilada de piedra, y el de las casas piso a piso, sin permitirse "derribos en grandes masas". Tal vez por ello llamaron la atenciâ”œâ”‚n buen nâ”œâ•‘mero de piedras que lucâ”œÂ¡an caracteres latinos, algunas de las cuales sobrevivieron al reaprovechamiento de los materiales del derribo, que aunque se realizâ”œâ”‚ dentro de los lâ”œÂ¡mites de tiempo establecidos, dejâ”œâ”‚ durante varios meses un "rastro" de grandes piedras "y no menores excabaciones" o cisternas ante la despejada fachada de la Universidad Literaria. La captura de esta fotografâ”œÂ¡a se ha realizado desde el arranque de la vecina calle de Palomar. En primer tâ”œÂ®rmino, tramo del Coso que hasta ese momento era denominado "plaza de la Magdalena", caracterizado por las botigas comerciales y puestos ambulantes allâ”œÂ¡ establecidos. Al fondo, tras el arco, vista de la barroca portada de la iglesia parroquial de Santa Marâ”œÂ¡a Magdalena, cuya torre despunta a la izquierda. Tras el derribo del arco y las casas, una nueva plaza de la Magdalena surgiâ”œâ”‚ entonces en su actual ubicaciâ”œâ”‚n.', 1867, 1867, 1867, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65210700, -0.87336500, '0101000020E6100000C2120F289BF2EBBF103FFF3D78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15092142102.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15092142102.webp', 'https://www.flickr.com/photos/zaragozaantigua/15092142102/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21010, 'Puerta de Valencia 1867', 'Puerta de Valencia vista desde la puerta de la iglesia de la Magdalena, justo antes de ser demolida ese aâ”œâ–’o, para dar a la plaza de la Magdalena algo mâ”œÃ­s de desahogo y dejar al descubierto el frontispicio de la Universidad. Al fondo, el Coso bajo y la calle de Palomar. Fuente visual: Santos â”œÃ¼lvarez y Serra, en AMZ.', 1867, 1867, 1867, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65201200, -0.87320400, '0101000020E61000007590D78349F1EBBFBE4C142175D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15093846679.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15093846679.webp', 'https://www.flickr.com/photos/zaragozaantigua/15093846679/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21097, 'Paraninfo de la Universidad 1880', 'Sesiâ”œâ”‚n inaugural del Congreso Filoxâ”œÂ®rico celebrado en 1880 en el paraninfo de la Universidad de Zaragoza en la plaza de la Magdalena. No confundir con el actual edificio sito en la plaza de Paraâ”œÂ¡so, construido posteriormente. La plaga vitivinâ”œÂ¡cola de la filoxera fue detectada en Francia en 1865. Las 952.000 Ha de viâ”œâ–’edo que tenâ”œÂ¡a en cultivo la provincia de Zaragoza quedaron reducidas, tras la plaga, a 12.275. El congreso cuya inauguraciâ”œâ”‚n reproduce el croquis se celebrâ”œâ”‚ para intentar frenar la catâ”œÃ­strofe agrâ”œÂ¡cola que se preveâ”œÂ¡a. El dibujo, de Bernardo Rico y Ortega, basado en un croquis apuntado por "D. Lascun", posiblemente Dionisio Lasuâ”œÂ®n. Fuente visual: "La Ilustraciâ”œâ”‚n Espaâ”œâ–’ola y Americana".', 1880, 1880, 1880, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65221400, -0.87327900, '0101000020E61000001F1329CDE6F1EBBF26FF93BF7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14856449014.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14856449014.webp', 'https://www.flickr.com/photos/zaragozaantigua/14856449014/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21111, 'Pl. de la Magdalena 1889', '"Saragosse. â”œÃ«glise de la Magdeleine". Fuente: J. Lâ”œÂ®vy et Cie, en "Zaragoza en la mirada ajena", Cortes de Aragâ”œâ”‚n, 2012.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65236800, -0.87371300, '0101000020E6100000ACE122F774F5EBBF7D7A6CCB80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22736718751.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22736718751.webp', 'https://www.flickr.com/photos/zaragozaantigua/22736718751/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21135, 'Plaza de la Magdalena c.1880', 'Luminosa imagen capturada desde la altura del inmueble del nâ”¬â•‘ 188 del Coso Bajo y centrada en la plaza de la Magdalena, donde destaca la torre y la puerta de ingreso a la iglesia parroquial de Santa Marâ”œÂ¡a Magdalena. A la izquierda, desemboque de la calle Mayor en la plaza con vista de las â”œâ•‘ltimas casas del lado de los pares tras la calle de Pelegrin. A la derecha, esquina del final de la calle de Martâ”œÂ¡n Carrillo con el arranque de la calle de la Universidad, donde destaca la antigua Casa Tejada, en cuyos bajos se abre la puerta de un comercio de ultramarinos donde tambiâ”œÂ®n se despachaba carbâ”œâ”‚n de haya. A continuaciâ”œâ”‚n, leve vista de la fachada de la Universidad Literaria. Como el cielo de la fotografâ”œÂ¡a ha sido "editado" en origen, ha desaparecido la vista de la inacabada torre de Santiago y de la câ”œâ•‘pula central del templo del Pilar, que deberâ”œÂ¡an despuntar sobre Casa Tejada, asâ”œÂ¡ como la torre de la Seo. Hemos volteado horizontalmente la fotografâ”œÂ¡a tal y como aparece en el AHPZ, para darle sentido y sensibilidad.', 1880, 1880, 1880, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65224000, -0.87350900, '0101000020E61000008D5F7825C9F3EBBF4F92AE997CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52230624372.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52230624372.webp', 'https://www.flickr.com/photos/zaragozaantigua/52230624372/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21145, 'Cuartel de Caballos Sementales 1899', 'â”œÃ¼lbum del Ministerio de la Guerra. Ministerio de Defensa de Espaâ”œâ–’a. 1899. Por Real orden de 17 de agosto de 1885 se creâ”œâ”‚ en Zaragoza una secciâ”œâ”‚n de sementales al objeto de la mejora de la cabaâ”œâ–’a de Aragâ”œâ”‚n, con 85 sementales percherones y boloâ”œâ–’eses. El 22 de marzo de 1905 se crea el Quinto Depâ”œâ”‚sito de Caballos Sementales. Su ubicaciâ”œâ”‚n, terrenos municipales de la Calle del Asalto. Allâ”œÂ¡ estuvieron hasta el 18 de julio de 1989. En la imagen, carruaje con tres sementales ante la puerta del Depâ”œâ”‚sito. Detrâ”œÃ­s del muro, al fondo, la calle Asalto y su confluencia con Alonso V.', 1899, 1899, 1899, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65126900, -0.86970100, '0101000020E6100000478D093197D4EBBF06F357C85CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14991847139.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14991847139.webp', 'https://www.flickr.com/photos/zaragozaantigua/14991847139/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21157, 'Calle de la Universidad 1898', 'Instituto Universitario Provincial de Zaragoza, 1898. En 1847 se separaron las docencias de los institutos y las universidades, creâ”œÃ­ndose este centro en el edificio de la Universidad Literaria de La Magdalena. Su entrada estaba en la calle Universidad. En 1933 fue trasladado al edificio del suprimido Colegio del Salvador, y se le dio el nombre de "Instituto Nacional de Segunda Enseâ”œâ–’anza Goya". Despuâ”œÂ®s del 18 de julio de 1936, fue trasladado a la Escuela de Artes, primero, y luego regresâ”œâ”‚ a la Magdalena. Cuando se inaugurâ”œâ”‚ el edificio del nuevo Instituto "Goya" junto al Huerva y la avenida Goya, se trasladâ”œâ”‚ allâ”œÂ¡ definitivamente en 1959. Fuente visual: www.facebook.com/photo.php?fbid=10204723386338133&set...', 1898, 1898, 1898, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65304800, -0.87297400, '0101000020E61000000744882B67EFEBBFEE5BAD1397D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19510424782.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19510424782.webp', 'https://www.flickr.com/photos/zaragozaantigua/19510424782/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21162, 'Calle Mayor 1893', '"Fragmento de la torre e iglesia de Santa Magdalena". Este dibujo, basado en una fotografâ”œÂ¡a, captura en altura la torre y parcialmente la iglesia con la calle Mayor a sus pies, estrecha como originalmente era. Por una de esas casualidades ocasionales, el dibujante se ha centrado en la fâ”œÃ­brica de la torre tal y como fue trabajada por los alarifes medievales que la levantaron, y ha prescindido del remate barroco aâ”œâ–’adido posteriormente. Fuente: "La Ilustraciâ”œâ”‚n Ibâ”œÂ®rica", Barcelona.', 1893, 1893, 1893, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65236800, -0.87371300, '0101000020E6100000ACE122F774F5EBBF7D7A6CCB80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20497312783.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20497312783.webp', 'https://www.flickr.com/photos/zaragozaantigua/20497312783/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21205, 'Cuartel de San Agustâ”œÂ¡n 1907', 'Postal. "Colecciâ”œâ”‚n Patria y Fe nâ”œâ•‘m. 8, Zaragoza 1908 - Centenario de los Sitios", 1907. "El convento de San Agustâ”œÂ¡n, donde hoy se encuentran las Factorâ”œÂ¡as militares, hâ”œÃ­llase situado en las afueras, en un punto muy apetecido por los franceses cuando intentaron entrar en Zaragoza por la plaza de la Magdalena; durante el segundo sitio, el uno de febrero, se apoderaron de â”œÂ®l las tropas de Napoleâ”œâ”‚n." Puerta de entrada al cuartel de San Agustâ”œÂ¡n, antes convento. Lo que parece un guardia espera sentado tranquilo. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65071100, -0.87039700, '0101000020E61000001B2B31CF4ADAEBBFE012807F4AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14750296987.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14750296987.webp', 'https://www.flickr.com/photos/zaragozaantigua/14750296987/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21246, 'Pl. de la Magdalena 1907', 'Postal. "Colecciâ”œâ”‚n Patria y Fe nâ”œâ•‘m. 27, Zaragoza 1908 - Centenario de los Sitios", 1907. "Uno de los edificios mâ”œÃ­s antiguos de Zaragoza; muy castigado por hallarse detrâ”œÃ­s de la puerta de Valencia, frente a la cual los franceses colocaron el 7 de febrero de 1809, un caâ”œâ–’â”œâ”‚n de a 24, con el que abrieron una gran brecha. En sus cisternas fueron sepultadas numerosas vâ”œÂ¡ctimas." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65236800, -0.87371300, '0101000020E6100000ACE122F774F5EBBF7D7A6CCB80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20150686613.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20150686613.webp', 'https://www.flickr.com/photos/zaragozaantigua/20150686613/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21247, 'Ruinas del Hospitalito 1907', 'Postal. "Colecciâ”œâ”‚n Patria y Fe nâ”œâ•‘m. 29, Zaragoza 1908 - Centenario de los Sitios", 1907. "Efecto de las bombas enemigas en la capilla de este benâ”œÂ®fico establecimiento conocido con el nombre de Hospitalito de la Magdalena. Despuâ”œÂ®s de la explosiâ”œâ”‚n del almacâ”œÂ®n de la pâ”œâ”‚lvora (27junio), en el Hospitalito fueron custodiados los enseres de las casas arruinadas, y en su cementerio enterrâ”œÃ­ronse las vâ”œÂ¡ctimas." El Hospitalito u "Hospitalico de Nuestra Seâ”œâ–’ora de la Misericordia u Hospital de Niâ”œâ–’os y Niâ”œâ–’as Huâ”œÂ®rfanos de la ciudad de Zaragoza" fue fundado en 1543 y arruinado en 1808. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65172600, -0.87326300, '0101000020E6100000B3D1393FC5F1EBBFF8F9EFC16BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20150826383.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20150826383.webp', 'https://www.flickr.com/photos/zaragozaantigua/20150826383/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21256, 'Calle Heroâ”œÂ¡smo 1907', 'Postal. "Colecciâ”œâ”‚n Patria y Fe nâ”œâ•‘m. 22, Zaragoza 1908 - Centenario de los Sitios", 1907. "En esta calle, que viene a salir al Coso en las inmediaciones de la plaza de la Magdalena, riâ”œâ–’â”œÂ®ronse luchas formidables, cuerpo a cuerpo, entre sitiadores y sitiados. Minâ”œÃ­ronse las casas, que fueron asaltadas una a una, y reconquistadas igualmente a cuenta de sangre y vidas." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65085200, -0.87403600, '0101000020E61000005EDA70581AF8EBBFA2444B1E4FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20582520218.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20582520218.webp', 'https://www.flickr.com/photos/zaragozaantigua/20582520218/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21261, 'Calle de las Tenerâ”œÂ¡as 1907', 'Postal. "Colecciâ”œâ”‚n Patria y Fe nâ”œâ•‘m. 39, Zaragoza 1908 - Centenario de los Sitios", 1907. "Llamado asâ”œÂ¡ por haberse destinado alguna de sus casas a la fabricaciâ”œâ”‚n de curtidos. En su lugar hallâ”œÃ­base antes emplazada la puerta del Sol. A este arrabal pertenecâ”œÂ¡a el llamado corral de Marigaita desde donde se dominaba gran parte de la ribera del Ebro, por lo cual se construyeron allâ”œÂ¡ muy importantes baterâ”œÂ¡as que riâ”œâ–’eron fieras luchas." Vista de la actual calle de Alonso V en su confluencia con la plaza de las Tenerâ”œÂ¡as. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65316900, -0.87164300, '0101000020E6100000CA3159DC7FE4EBBF69E1B20A9BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20763354052.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20763354052.webp', 'https://www.flickr.com/photos/zaragozaantigua/20763354052/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21262, 'Calle del Pozo 1907', 'Postal. "Colecciâ”œâ”‚n Patria y Fe nâ”œâ•‘m. 2, Zaragoza 1908 - Centenario de los Sitios", 1907. "Por el buen punto de vista que ofrecâ”œÂ¡a esta casa, cuya entrada estâ”œÃ­ por la calle de Palomar, las balas enemigas hicieron blanco en ella frecuentemente. Durante el segundo sitio los franceses intentaron penetrar en Zaragoza por este punto pero, sin pasar de la plaza de la Magdalena, siempre fueron enâ”œÂ®rgicamente rechazados." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65125200, -0.87232000, '0101000020E6100000EEB1F4A10BEAEBBF30BABC395CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20767321535.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20767321535.webp', 'https://www.flickr.com/photos/zaragozaantigua/20767321535/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21380, 'Coso Bajo c.1910', 'Anselmo Marâ”œÂ¡a Coyne, Diputaciâ”œâ”‚n de Zaragoza, ca. 1910 Imagen de tremenda carretada de aguateros en el Coso Bajo, a la altura de la plaza de la Magdalena. A la izquierda, la Universidad Literaria de la Magdalena, antes de su reforma por Ricardo Magdalena. Fuente: web.dpz.es/arscatalogi.es/foto.asp?index=2818', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65201200, -0.87320400, '0101000020E61000007590D78349F1EBBFBE4C142175D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15854328636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15854328636.webp', 'https://www.flickr.com/photos/zaragozaantigua/15854328636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21421, 'Plaza de las Tenerâ”œÂ¡as 1911', 'Danzantes en la plaza de las Tenerâ”œÂ¡as, durante las fiestas de la Virgen del Carmen. Al fondo, acceso a la plazuela de la Rebolerâ”œÂ¡a.', 1911, 1911, 1911, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65312700, -0.87155900, '0101000020E6100000541A31B3CFE3EBBF3A9160AA99D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31581924166.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31581924166.webp', 'https://www.flickr.com/photos/zaragozaantigua/31581924166/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21427, 'Instituto aâ”œâ–’os 10', 'Grupo de profesores (con birrete) y demâ”œÃ­s personal del Instituto General y Tâ”œÂ®cnico de Zaragoza (antes Instituto Universitario Provincial), en el patio de su sede en el edificio de la Universidad Literaria, con entrada por la calle Universidad. En esa â”œÂ®poca fueron alumnos Ramâ”œâ”‚n J. Sender y Marâ”œÂ¡a Moliner. El archivo del que procede la imagen se halla hoy en la sede del Instituto Goya, heredero de aquâ”œÂ®l desde 1959. Fuente: Archivo IES Goya de Zaragoza.', 1910, 1910, 1919, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65265400, -0.87290000, '0101000020E610000074B515FBCBEEEBBF42CD902A8AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32973656955.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32973656955.webp', 'https://www.flickr.com/photos/zaragozaantigua/32973656955/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21642, 'Coso Bajo, c.1926', 'Imagen capturada desde la altura del nâ”¬â•‘ 182 del tramo bajo del Coso y centrada un carro a la puerta de la tienda de comestibles de Esteban Martâ”œÂ¡nez. A la derecha y al fondo, entrada a la plaza de la Magdalena y vista al ingreso principal a la Universidad Literaria de Zaragoza. En primer tâ”œÂ®rmino, tendido tranviario de la lâ”œÂ¡nea Magdalena-Mercado, antes Circunvalaciâ”œâ”‚n.', 1926, 1926, 1926, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65197600, -0.87340200, '0101000020E61000000C5A48C0E8F2EBBF71E316F373D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51126969715.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51126969715.webp', 'https://www.flickr.com/photos/zaragozaantigua/51126969715/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21707, 'Casa Gavâ”œÂ¡n 1930', 'Foto Palacio. 1930. Imagen de la antigua "Casa Gavâ”œÂ¡n", esquinada entre la calle Palafox (derecha), y la calle Pedro Liâ”œâ–’â”œÃ­n (a la izquierda). Salvada de las obras de apertura de San Vicente de Paâ”œâ•‘l, por estar un poco alejada del epicentro del nuevo vial, varias dâ”œÂ®cadas despuâ”œÂ®s serâ”œÂ¡a piqueteada para construir encima una indescriptible edificaciâ”œâ”‚n de Telefâ”œâ”‚nica. Fuente visual: "Aragâ”œâ”‚n : revista grâ”œÃ­fica de cultura aragonesa" (Aâ”œâ–’o VI, Nâ”¬â•‘ 63, dic. 1930).', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65360900, -0.87406300, '0101000020E6100000C498F4F752F8EBBF86AFAF75A9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16012092932.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16012092932.webp', 'https://www.flickr.com/photos/zaragozaantigua/16012092932/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21790, 'Coso Bajo c.1934', 'Vista aâ”œÂ®rea del Coso bajo y sus alrededores. Arriba a la izquierda, el gran edificio de la Universidad de la Magdalena. A la derecha, el intrincado laberinto de la calle del Sepulcro, Pallaruelo, del Lobo, Monserrate, Conde de Alperche, Chantre... Fuente visual: www.facebook.com/photo.php?fbid=575487972606230&set=g...', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65335400, -0.87184100, '0101000020E610000061FBC9181FE6EBBFFB5A971AA1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24147192773.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24147192773.webp', 'https://www.flickr.com/photos/zaragozaantigua/24147192773/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21952, 'Calle Universidad 1949', 'Imagen de la calle Universidad capturada desde el tramo entre las calles Torrellas y Palafox, que es la primera calle que se abre a la izquierda. Al fondo, la calle Don Teobaldo, con leve vista del Convento de las Canonesas del Sto. Sepulcro. Inmediata, a la derecha, la calle Trinidad. La imagen se ha tomado justo al lado de los muros de la antigua Universidad Literaria de la Magdalena. Fuente visual: Juan Mora Insa, AMZ.', 1949, 1949, 1949, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65322600, -0.87285500, '0101000020E610000075CDE49B6DEEEBBFCD72D9E89CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19171108130.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19171108130.webp', 'https://www.flickr.com/photos/zaragozaantigua/19171108130/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21990, '&quot;CEFA&quot; Plaza de Asso, 1946', 'Imagen del interior de los originales talleres de Celulosa Fabril "CEFA", empresa fundada por Eduardo Blanchard Castillo en 1946, en el nâ”¬â•‘ 1 de la plaza de Asso, entre las calles del â”œÃ´rgano, y Torrellas. Allâ”œÂ¡ se acometâ”œÂ¡a la fabricaciâ”œâ”‚n de câ”œÃ­psulas de celulosa para tapones de botellas, y pronto comenzarâ”œÂ¡a la producciâ”œâ”‚n de gelatinas, sacarinas y jabones, y en 1952, el desarrollo de la inyecciâ”œâ”‚n de termoplâ”œÃ­sticos, que hizo de los juguetes una de las grandes seâ”œâ–’as de identidad de la empresa. A mediados de esa dâ”œÂ®cada, este espacio se habâ”œÂ¡a quedado muy pequeâ”œâ–’o, lo que derivâ”œâ”‚ en su traslado a una nueva y mucho mayor planta, en la calle de Miguel Servet. Fuente visual: "CEFA: una mirada al futuro 1946-2016", en Archivo Josâ”œÂ® Marâ”œÂ¡a Ballestâ”œÂ¡n Miguel.', 1946, 1946, 1946, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65294000, -0.87378700, '0101000020E61000003F70952710F6EBBF0820B58993D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30749184261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30749184261.webp', 'https://www.flickr.com/photos/zaragozaantigua/30749184261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22021, 'Calle de Josâ”œÂ® Palafox c.1940', 'Imagen del â”œâ•‘ltimo tramo de la calle de Josâ”œÂ® Palafox, donde destaca a la derecha, en el nâ”¬â•‘ 29, el Laboratorio Quâ”œÂ¡mico Municipal construido en 1914 con proyecto de Josâ”œÂ® de Yarza Echenique. Frente a â”œÂ®l, los antiguos inmuebles de los nâ”œâ•‘meros 28 y 30. Hacia el fondo, la calle se estrecha de forma notable hasta el cruce con la de Gavâ”œÂ¡n. La imagen estâ”œÃ­ realizada desde la esquina con la calle de la Universidad, a espaldas de la homâ”œâ”‚nima e histâ”œâ”‚rica instituciâ”œâ”‚n educativa, con un tancredo en primer tâ”œÂ®rmino ejerciendo de tal.', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65324200, -0.87286500, '0101000020E610000058569A9482EEEBBFD32F116F9DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49898657137.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49898657137.webp', 'https://www.flickr.com/photos/zaragozaantigua/49898657137/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22036, 'Calle del â”œÃ´rgano c.1940', 'Grabado de Salvador Martâ”œÂ¡nez Blasco con una vista de la calle del â”œÃ´rgano y la iglesia de la Magdalena. A la derecha, casona de los Lanes de Villanueva, esquinera con la calle de Martâ”œÂ¡n Carrillo y derribada a principios de los aâ”œâ–’os 40. Su piedra armera con el escudo perdura en el Museo de Zaragoza.', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65269700, -0.87387400, '0101000020E6100000FA635A9BC6F6EBBF429946938BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54413600082.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54413600082.webp', 'https://www.flickr.com/photos/zaragozaantigua/54413600082/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22110, 'Calle Mayor 1951', 'Imagen del â”œâ•‘ltimo tramo de la calle Mayor, paralelo a la iglesia parroquial de la Magdalena, casi ya en la plaza del mismo nombre. En el lateral del templo luce soleado, aâ”œâ•‘n, el antiguo bajorrelieve en forma de capilla, o figurado altar, dedicada a San Cristâ”œâ”‚bal de Licia, que ademâ”œÃ­s le daba nombre al arquitrabado "arco" bajo el que embocaba, justo enfrente, la calle de San Cristâ”œâ”‚bal, entre la "Farmacia" de la imagen (edificio luego derribado), y el abalconado nâ”¬â•‘ 60 de la calle Mayor (sobrevive). Esta tipologâ”œÂ¡a de "arcos" era prâ”œÃ­ctica comâ”œâ•‘n como forma de ganar espacio extra habitacional en zonas densamente edificadas de la ciudad antigua, dejando la altura suficiente para que pudiera transitar por debajo, sin problemas, una persona a lomos de caballerâ”œÂ¡a. Fuente visual: Juan Mora Insa, en AMZ.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65236800, -0.87371300, '0101000020E6100000ACE122F774F5EBBF7D7A6CCB80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22004534908.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22004534908.webp', 'https://www.flickr.com/photos/zaragozaantigua/22004534908/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22141, 'Calle de Gavâ”œÂ¡n 1951', 'Imagen de la calle de Gavâ”œÂ¡n, que fuera antiguo callizo de Domingo Vero, capturada en el tramo entre la plaza de Asso, y la calle de Palafox, al fondo destaca el esquinero y superviviente palacio del siglo XVI de los Gurrea de Castro. Fuente visual: Juan Mora Insa, Archivo Municipal de Zaragoza.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65362100, -0.87391600, '0101000020E6100000B56FEEAF1EF7EBBF4A7D59DAA9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25052731130.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25052731130.webp', 'https://www.flickr.com/photos/zaragozaantigua/25052731130/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21644, 'Fray Luis Amigâ”œâ”‚ 1921', 'Imagen capturada en la casa-reformatorio del Buen Pastor establecida desde 1917 en Torre-Ramona, con un posado de la comunidad de religiosos Terciaros capuchinos de Nâ”¬Â¬ Sâ”¬Â¬ de la Soledad encargada de administrar esta instituciâ”œâ”‚n. Entre los posantes destaca la figura de Fray Luis Amigâ”œâ”‚ (nacido como Josâ”œÂ® Marâ”œÂ¡a Amigâ”œâ”‚ Ferrer), el segundo sentado desde la izquierda, fundador de la congregaciâ”œâ”‚n en 1889 y obispo desde 1907, durante una visita a sus hermanos. Una derivada de su apellido hizo que popularmente se conociera a esta congregaciâ”œâ”‚n como "amigonianos".', 1921, 1921, 1921, 'Anos 20', 'LAS FUENTES', 41.64205800, -0.86345600, '0101000020E6100000861E317A6EA1EBBF4D11E0F42ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51246815274.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51246815274.webp', 'https://www.flickr.com/photos/zaragozaantigua/51246815274/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22900, 'Felipe Gonzâ”œÃ­lez 1983', 'Foto: EFE. Felipe Gonzâ”œÃ­lez, presidente del gobierno espaâ”œâ–’ol entre 1982 y 1996, inaugura la 17â”¬Â¬ ediciâ”œâ”‚n de la FIMA (Feria Internacional de Maquinaria Agrâ”œÂ¡cola) en la Feria de Muestras de Zaragoza. A la izquierda, Josâ”œÂ® Luis Martâ”œÂ¡nez Candial, entonces presidente de la Câ”œÃ­mara de Comercio e Industria de Zaragoza y despuâ”œÂ®s de Ibercaja. Fuente: Ayuntamiento de Valladolid.', 1983, 1983, 1983, 'Anos 80', 'UNIVERSIDAD', 41.63759000, -0.89959300, '0101000020E6100000A5BC564277C9ECBFDA20938C9CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21246408275.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21246408275.webp', 'https://www.flickr.com/photos/zaragozaantigua/21246408275/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22177, 'Calle del Asalto 1951', 'Despejada imagen de la parte final de la calle de Asalto capturada desde el principio de la calle de Monreal, con el irregular tramo donde desembocan en ella, por la derecha, las calle de la Rebolerâ”œÂ¡a, y la de Alonso V. A la izquierda, olmos (posiblemente) junto a la acequia que proveâ”œÂ¡a de agua a los talleres y fâ”œÃ­bricas textiles ubicadas en esta zona, recuerdo de cuando siglos atrâ”œÃ­s esta era la "rebolerâ”œÂ¡a" de la ciudad, donde se trataban y curtâ”œÂ¡an pieles; de esta acequia se derivaba, poco despuâ”œÂ®s. un riego que todavâ”œÂ¡a era denominado "de los Curtidores". A continuaciâ”œâ”‚n de los â”œÃ­rboles, el ingreso al cuartel de Remonta y de Sementales del Ejâ”œÂ®rcito y, al fondo, la antigua y gran torre de Juan Faustino Bruil y Olliarburu, luego de Monserrat, y que en 1965 serâ”œÂ¡a parque Bruil. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65197000, -0.86989200, '0101000020E61000003FAA61BF27D6EBBF8FFCC1C073D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31583846812.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31583846812.webp', 'https://www.flickr.com/photos/zaragozaantigua/31583846812/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22251, 'Calle de San Cristâ”œâ”‚bal 1953', 'Pintura de la calle y el arco de San Cristâ”œâ”‚bal, por Antonio Marâ”œÂ¡a Almazâ”œÃ­n, 1953. Al fondo, el inicio de la calle Mayor.', 1953, 1953, 1953, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65225800, -0.87401200, '0101000020E61000003CF88903E8F7EBBFF646AD307DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54414106768.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54414106768.webp', 'https://www.flickr.com/photos/zaragozaantigua/54414106768/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22279, 'Universidad de la Magdalena 1968', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 05/09/1968. Derribo de la antigua Universidad de la Magdalena. Imagen tomada desde la Plaza de la Magdalena. A la derecha, el Coso Bajo. "Hay que rendirse a la evidencia, no se podâ”œÂ¡a evitar la demoliciâ”œâ”‚n de un edificio como â”œÂ®ste: un caserâ”œâ”‚n inmenso que no admitâ”œÂ¡a reformas satisfactorias y que, al desaparecer, darâ”œÃ­ paso a modernos y eficaces edificios que albergarâ”œÃ­n centros y dependencias de Enseâ”œâ–’anza Media y Primaria, construidos de acuerdo con las mâ”œÃ­s modernas directrices pedagâ”œâ”‚gicas. Y el futuro gran edificio tendrâ”œÃ­ desde luego una fachada de estilo mudâ”œÂ®jar, que harâ”œÃ­ juego con la inmediata iglesia de la Magdalena, cuya graciosa torre ha sido devuelta al mâ”œÃ­s brillante momento de su prâ”œÂ¡stino gâ”œâ”‚tico-mudâ”œÂ®jar; con lo que la plaza que se abre ante ella puede convertirse en uno de los rincones mâ”œÃ­s evocadores y bellos de Zaragoza". Ã”Ã‡Ã¶ Ramâ”œâ”‚n Salanova (ABC, 21.09.1968)', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65241600, -0.87349300, '0101000020E6100000211E8997A7F3EBBF8EB1135E82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14990204666.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14990204666.webp', 'https://www.flickr.com/photos/zaragozaantigua/14990204666/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
