INSERT INTO public.photos VALUES (23538, 'Pl. de la Magdalena 1677', 'Entrada de Carlos II en Zaragoza. Dibujo, 1910. El 1 de mayo de 1677 el rey Carlos II jurâ”œâ”‚ los Fueros de Aragâ”œâ”‚n en la Seo de Zaragoza, y el 14 daban comienzo, en presencia del monarca, las Cortes del Reino. Las Cortes se celebraron finalmente en Zaragoza, y no en Calatayud, como estaba previsto inicialmente. El rey permaneciâ”œâ”‚ en la capital aragonesa hasta el 2 de junio. Fuente: reinadodecarlosii.blogspot.com.es/2012/03/las-relaciones-...', 1677, 1677, 1677, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65201200, -0.87320400, '0101000020E61000007590D78349F1EBBFBE4C142175D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15033442500.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15033442500.webp', 'https://www.flickr.com/photos/zaragozaantigua/15033442500/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23541, 'Puerta del Sol 1749', '"Puerta del Sol", Antonio Callaved, 2011. Esta puerta cerraba la ciudad al final del actual Coso Bajo, junto a las Tenerâ”œÂ¡as. Fue construida en 1749 y derribada en el siglo XIX. La piedra con un sol tallado que la coronaba se conserva en el Museo de Zaragoza. Fuente: pinturascallaved.wordpress.com/5-mi-pintura-en-la-filatelia/', 1749, 1749, 1749, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65335400, -0.87184100, '0101000020E610000061FBC9181FE6EBBFFB5A971AA1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15092631837.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15092631837.webp', 'https://www.flickr.com/photos/zaragozaantigua/15092631837/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23542, 'Incendio discoteca Flying 1990', 'Foto Eduardo Bayona/El Periâ”œâ”‚dico de Aragâ”œâ”‚n. La madrugada del domingo 14 de enero de 1990 se produjo un incendio en la discoteca Flying, sita en la esquina de la calle Trinidad con Don Teobaldo. Murieron 43 personas. En la imagen podemos ver varios de los cadâ”œÃ­veres depositados en el exterior de la sala, en la calle Trinidad.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65333800, -0.87267200, '0101000020E6100000335184D4EDECEBBFF59D5F94A0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15161776125.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15161776125.webp', 'https://www.flickr.com/photos/zaragozaantigua/15161776125/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23544, 'Pl. de San Agustâ”œÂ¡n 1964', 'Celebracioes festivas en la plaza de San Agustâ”œÂ¡n en 1964. Fuente: www.facebook.com/photo.php?fbid=385217108301791&set=o...', 1964, 1964, 1964, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65090800, -0.87080100, '0101000020E6100000FF5E0A0F9ADDEBBF365A0EF450D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15738315929.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15738315929.webp', 'https://www.flickr.com/photos/zaragozaantigua/15738315929/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23545, 'Calle de la Universidad 1954', 'Chiquillerâ”œÂ¡a jugando entre claroscuros en la calle de la Universidad. Una canciâ”œâ”‚n infantil parece escucharse entre risas: Al corro de la patata, comeremos ensalada, como comen los seâ”œâ–’ores, naranjitas y limones... Al fondo, la plaza de la Magdalena, y a la izquierda e inmediata, la calle de la Trinidad. Este entorno, luego desaparecido, sâ”œâ”‚lo perdura ya en la memoria, como sucede con el que fuera trenque de la muralla de piedra, la plaza del Estudio, y los colegios de San Vicente Ferrer, de la Trinidad y de San Juan Bautista de los Navarros. Y por supuesto el edificio de la vieja Universidad, entre las puertas de Valencia y del Sol. En la solana de la imagen, entrada del viejo Instituto Goya, denominaciâ”œâ”‚n desde 1933 del anterior Instituto de Segunda Enseâ”œâ–’anza de la Magdalena. Fuente visual: Foto Pomarâ”œâ”‚n.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65329800, -0.87267200, '0101000020E6100000335184D4EDECEBBF6745D4449FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16166489434.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16166489434.webp', 'https://www.flickr.com/photos/zaragozaantigua/16166489434/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23546, 'Las Tenerâ”œÂ¡as 1591', 'F. Mota es el nombre con el que firmaba sus trabajos el pintor Fernando Fernâ”œÃ­ndez Mota, ilustrador de publicaciones entre finales del XIX y principios del XX. En este caso, se trata de otro interesante ejercicio de reinvenciâ”œâ”‚n histâ”œâ”‚rica propio del nacionalismo româ”œÃ­ntico decimonâ”œâ”‚nico, aquâ”œÂ¡ centrado en los extraâ”œâ–’os sucesos y alteraciones del verano de 1591. Esta imagen es muestra de los desvarâ”œÂ¡os que dichas alteraciones produjeron en el imaginario româ”œÃ­ntico-conservador. Tomando una reciente fotografâ”œÂ¡a del francâ”œÂ®s Jean Laurent de un pedazo del lienzo de las murallas medievales de las Tenerâ”œÂ¡as, este pintor ceutâ”œÂ¡ F. Mota agrega unos desorientados soldados que parecen sacados de una expediciâ”œâ”‚n del extremeâ”œâ–’o Pizarro al otro lado del charco, y construye una representaciâ”œâ”‚n considerada "pintura histâ”œâ”‚rica". Que los soldados estâ”œÃ­n desorientados, es literal: viniendo desde Utebo (como dicen las crâ”œâ”‚nicas histâ”œâ”‚ricas), en lugar de entrar por la puerta de Sancho, la del Portillo, o incluso la de Baltax, esta tropa habrâ”œÂ¡a dado la vuelta a la ciudad, hasta buscar el ingreso por la Portaza. Mientras tanto, la ciudad, al fondo, esperando pacientemente a ser "conquistada". Fuente visual: Ã”Ã‡Â£Entrada de las tropas castellanas en ZaragozaÃ”Ã‡Ã˜, Fernando Fernâ”œÃ­ndez Mota, 1919.', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65335400, -0.87184100, '0101000020E610000061FBC9181FE6EBBFFB5A971AA1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17666352789.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17666352789.webp', 'https://www.flickr.com/photos/zaragozaantigua/17666352789/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23547, 'Coso Bajo 1959', 'Imagen del punto donde la antigua calle de San Lorenzo desemboca en el Coso. El edificio central, esquinero entre ambas calles, con el aâ”œâ–’adido del pequeâ”œâ–’o de su derecha, varias dâ”œÂ®cadas despuâ”œÂ®s serâ”œÃ­ reinventado en nueva planta. Los demâ”œÃ­s edificios, perduran. Fuente visual: "Aragâ”œâ”‚n. Cuatro ensayos", 1960, Banco de Aragâ”œâ”‚n.', 1959, 1959, 1959, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65171100, -0.87362700, '0101000020E610000009E23C9CC0F4EBBFC3B81B446BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18797925412.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18797925412.webp', 'https://www.flickr.com/photos/zaragozaantigua/18797925412/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22167, 'Vista aâ”œÂ®rea Las Fuentes 1955', 'Vista aâ”œÂ®rea del nâ”œâ•‘cleo inaugural del barrio de Las Fuentes: las viviendas para tranviarios llamadas Grupo Vizconde de Escoriaza, levantadas en 1953, y la primera fase del grupo de viviendas "Josâ”œÂ® Antonio Girâ”œâ”‚n", de 1955. En 1957, el tranvâ”œÂ¡a ampliarâ”œÃ­ sus servicios hasta aquâ”œÂ¡, con la inauguraciâ”œâ”‚n de su lâ”œÂ¡nea 17 "Las Fuentes". Al fondo, el râ”œÂ¡o Ebro y la ciudad consolidada. Fuente: TAF Helicâ”œâ–“pters. Arxiu Nacional de Catalunya.', 1955, 1955, 1955, 'Anos 50', 'LAS FUENTES', 41.64833000, -0.85835400, '0101000020E61000004D81CCCEA277EBBF0282397AFCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30989909240.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30989909240.webp', 'https://www.flickr.com/photos/zaragozaantigua/30989909240/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23548, 'Pl. de la Magdalena 1591', '"Motâ”œÂ¡n en Zaragoza en defensa de los Fueros". Ilustraciâ”œâ”‚n de Fernando Fernâ”œÃ­ndez Mota, 1910 La fantasâ”œÂ¡a recreacionista asociada a la instrumentalizaciâ”œâ”‚n polâ”œÂ¡tica del pasado histâ”œâ”‚rico, en ocasiones genera escenarios delirantes como el presente, en el que el autor de la ilustraciâ”œâ”‚n sitâ”œâ•‘a una acciâ”œâ”‚n de 1591 en un entorno imposible en el barrio de la Magdalena de esa â”œÂ®poca: la Puerta de Valencia se ha evaporado, siendo que fue derribada casi tres siglos despuâ”œÂ®s (1867), y la puerta de acceso a la iglesia parroquial de la Magdalena es recolocada tal y como quedarâ”œÃ­ tras su orientaciâ”œâ”‚n de 1730 (hasta entonces, por la calle Mayor), e incluso aparece la portada neoclâ”œÃ­sica que le serâ”œÃ­ aâ”œâ–’adida mâ”œÃ­s tarde, en 1758. Si este es el escenario de la Magdalena de 1591, câ”œâ”‚mo serâ”œÃ­n los sucesos que en ella acontecen. Fuente: Historia de Espaâ”œâ–’a, Miguel Seguâ”œÂ¡, 1910.', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65201200, -0.87320400, '0101000020E61000007590D78349F1EBBFBE4C142175D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18965139881.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18965139881.webp', 'https://www.flickr.com/photos/zaragozaantigua/18965139881/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23549, 'Pedro Santisteve 1990', 'Pedro Santisteve (Zaragoza, 1958), abogado penalista y alcalde de Zaragoza desde 2015, sustituyendo a Juan Alberto Belloch (2003-2015). En la imagen, en el bar La Vâ”œÂ¡a Lâ”œÃ­ctea (Doctor Palomar 25) en 1990. Fuente: Asociaciâ”œâ”‚n Cultural y Recreativa Barrio Verde de Zaragoza.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65113200, -0.87187600, '0101000020E61000007D5A457F68E6EBBF85B01A4B58D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19065572706.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19065572706.webp', 'https://www.flickr.com/photos/zaragozaantigua/19065572706/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23550, 'Calle Mayor 1847', 'Dibujo de Josâ”œÂ® Gâ”œâ”‚mez Piquer de 1997, recreando el rincâ”œâ”‚n de la calle Mayor nâ”¬â•‘ 59 (a la izquierda, fuera de la imagen) donde fue instalada la Escuela Profesional de Veterinaria de Zaragoza en 1847, y hasta 1853. En las inmediaciones, en la esquina de la calle de Torrejâ”œâ”‚n con Mayor, hoy sede del PCE en Aragâ”œâ”‚n, tuvo su sede el Colegio de Nuestra Seâ”œâ–’ora del Torrejâ”œâ”‚n, colegio mayor universitario seglar fundado en 1602 y clausurado a mediados del siglo XIX. El dibujo supone la torre de la iglesia de La Magdalena sin su recrecimiento barroco, que sâ”œÂ¡ estaba en la fecha que se intenta reflejar. Fuente: Crâ”œâ”‚nica de 150 aâ”œâ–’os de estudios veterinarios en Aragâ”œâ”‚n. IFC, 2000.', 1847, 1847, 1847, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65244800, -0.87403700, '0101000020E610000074CE4F711CF8EBBF992B836A83D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19115291828.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19115291828.webp', 'https://www.flickr.com/photos/zaragozaantigua/19115291828/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23551, 'Coso Bajo 1984', 'Foto Arturo Burgos, 1984. Calle del Coso Bajo de Zaragoza en 1984, con visual de sus nâ”œâ•‘meros pares en el tramo comprendido entre las plazas de La Magdalena y las Tenerâ”œÂ¡as. Fuente: Zaragoza, sus calles y su historia, 1984.', 1984, 1984, 1984, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65240800, -0.87278000, '0101000020E6100000CB4A9352D0EDEBBF0BD3F71A82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19428864662.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19428864662.webp', 'https://www.flickr.com/photos/zaragozaantigua/19428864662/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23553, 'Plaza de la Magdalena 1960', 'Imagen del funeral, el 19 de octubre de 1960, de Carmelo Zaldâ”œÂ¡var, jefe de administraciâ”œâ”‚n del Ayuntamiento de Zaragoza. La comitiva se dirige, desde la calle Mayor, a la puerta de la iglesia de la Magdalena. En el lateral del templo se observa la capilla exterior adosada dedicada a San Cristâ”œâ”‚bal, como el arco que tenâ”œÂ¡a enfrente en la calle del mismo nombre. AL fondo de la calle, el mercado de San Vicente de Paâ”œâ•‘l, recayente a la vâ”œÂ¡a del mismo nombre. Fuente: AMZ.', 1960, 1960, 1960, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65236800, -0.87371300, '0101000020E6100000ACE122F774F5EBBF7D7A6CCB80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20466773353.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20466773353.webp', 'https://www.flickr.com/photos/zaragozaantigua/20466773353/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23554, 'Calle del â”œÃ´rgano 1989', 'La calle del â”œÃ´rgano el 17 de febrero de 1989, en las traseras de la iglesia de La Magdalena, que debe su nombre al receptâ”œÃ­culo de ese instrumento, que forma un pasadizo o arco sobre la vâ”œÂ¡a. En primer plano, el pilâ”œâ”‚n de piedra ya desaparecido, como casi todos los de su entorno. La imagen estâ”œÃ­ tomada desde la calle Mayor, con la de Martâ”œÂ¡n Carrillo al fondo. Fuente: "Memoria de las calles de Zaragoza", Juliâ”œÃ­n Ruiz Marâ”œÂ¡n, Librerâ”œÂ¡a General, 2002.', 1989, 1989, 1989, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65244800, -0.87403700, '0101000020E610000074CE4F711CF8EBBF992B836A83D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21053815984.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21053815984.webp', 'https://www.flickr.com/photos/zaragozaantigua/21053815984/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23557, 'Calle de Olleta 1967', 'Calle de Jusepillo de Olleta en 1967. Comienza en la de San Agustâ”œÂ¡n y termina en la de las Arcadas. La imagen estâ”œÃ­ capturada justo antes de que la calle Barrioverde cruce la calle Olleta, ascendente y adoquinada de izquierda a derecha. Al fondo, a la izquierda, se deriva la calle de Luzâ”œÃ­n. Fuente visual: Foto Leonardo Pâ”œÂ®rez Obis, donada por â”œÃ¼ngel Hernâ”œÃ­ndez Mostajo para www.rafaelcastillejo.com', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65219900, -0.87368200, '0101000020E6100000EB5223F433F5EBBFF1BDBF417BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22728082717.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22728082717.webp', 'https://www.flickr.com/photos/zaragozaantigua/22728082717/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23560, 'Calle San Cristâ”œâ”‚bal 1965', 'Insâ”œâ”‚lita imagen, posiblemente de la antigua plazuela de Juan del Corral, como ensanche de la calleja de San Cristâ”œâ”‚bal de la Magdalena, que conectaba la calle de San Lorenzo, al fondo, con la calle Mayor, en este caso bajo un arquitrabado arco nominado tambiâ”œÂ®n "de San Cristâ”œâ”‚bal". De ser asâ”œÂ¡, esta plazuela tendrâ”œÂ¡a relaciâ”œâ”‚n con el lugar donde estuvo la casa solariega de esta familia infanzona de caballeros hidalgos, apellidados del Corral, o Ximâ”œÂ®nez del Corral, que se establecieron en la ciudad en el siglo XVII. Unos aâ”œâ–’os despuâ”œÂ®s de esta captura fotogrâ”œÃ­fica, el entorno edificatorio fue bastante transformado, aunque la plazuela mantiene su planta de "quesito" (mâ”œÃ­s o menos). Fuente visual: Foto Leonardo Pâ”œÂ®rez Obis, donada por â”œÃ¼ngel Hernâ”œÃ­ndez Mostajo para www.rafaelcastillejo.com', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65212200, -0.87414100, '0101000020E6100000B1F7E28BF6F8EBBF4580D3BB78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22758258227.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22758258227.webp', 'https://www.flickr.com/photos/zaragozaantigua/22758258227/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23561, 'Calle Olleta 1967', 'Calle de Jusepillo de Olleta en 1967. Comienza en la de San Agustâ”œÂ¡n y termina en la de las Arcadas. Hoy radicalmente transformada. La imagen estâ”œÃ­ capturada, precisamente, donde la calle Olleta desembocaba en la calle de las Arcadas, cuyo antiguo (y desaparecido) azulejo nâ”œâ•‘mero 21, bajo el de la aseguradora de incendios, referencia el lugar. Los tendedores con cuerda, y una prenda a secar, seâ”œâ–’ales de moradores. Fuente visual: Foto Leonardo Pâ”œÂ®rez Obis, donada por â”œÃ¼ngel Hernâ”œÃ­ndez Mostajo para www.rafaelcastillejo.com', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65219900, -0.87187900, '0101000020E6100000C136E2C96EE6EBBFF1BDBF417BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22826932950.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22826932950.webp', 'https://www.flickr.com/photos/zaragozaantigua/22826932950/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23565, 'Coso Bajo 1986', 'Imagen capturada en el Coso Bajo y centrada en el tramo de los antiguos y dispares nâ”œâ•‘meros impares entre la calle de San Lorenzo (izquierda) y la plaza de la Magdalena (a la derecha, fuera de plano). Este tramo serâ”œÂ¡a profundamente remodelado aâ”œâ–’os despuâ”œÂ®s. Fuente visual: AMZ.', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65182500, -0.87363700, '0101000020E6100000EC6AF294D5F4EBBF8CDB68006FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24834862868.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24834862868.webp', 'https://www.flickr.com/photos/zaragozaantigua/24834862868/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23566, 'Plaza de la Magdalena 1960', 'Imagen, desde cierta altura, de la sesentera plaza de la Magdalena durante el funeral de Carmelo Zaldâ”œÂ¡var, jefe de administraciâ”œâ”‚n del Ayuntamiento. A la izquierda, la calle Mayor. En el centro, la iglesia parroquial de Santa Marâ”œÂ¡a Magdalena, funcional, y con el remate barroco de la torre. A la derecha, el edificio de la antigua Universidad Literaria (hasta 1958 sede del Instituto Goya), y el que fuera colegio de San Juan Bautista. Por encima, despuntan dos torres pilaristas. Fuente visual: Archivo Municipal de Zaragoza.', 1960, 1960, 1960, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65223900, -0.87360700, '0101000020E610000042D0D1AA96F4EBBF7F164B917CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25499727161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25499727161.webp', 'https://www.flickr.com/photos/zaragozaantigua/25499727161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23568, 'Pl. de San Agustâ”œÂ¡n 1991', 'Imagen parcial de la plaza de San Agustâ”œÂ¡n capturada desde el final de la calle Viola, con vista del espacio donde desembocan las calles de San Agustâ”œÂ¡n y de las Arcadas. A la derecha, parte del antiguo convento y cuartel de San Agustâ”œÂ¡n que luego serâ”œÂ¡a reformada para acoger la biblioteca municipal Marâ”œÂ¡a Moliner. Fuente visual: AMZ.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65116000, -0.87126600, '0101000020E61000004DBC033C69E1EBBF4F3BFC3559D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28318398369.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28318398369.webp', 'https://www.flickr.com/photos/zaragozaantigua/28318398369/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23569, 'Calle Martâ”œÂ¡n Carrillo aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste representando la calle de Martâ”œÂ¡n Carrillo, con la iglesia de la Magdalena a la derecha y la plaza homâ”œâ”‚nima al fondo. Fuente: Lâ”œÃ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65255000, -0.87373700, '0101000020E6100000CEC3094CA7F5EBBF9D8026C286D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31595527374.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31595527374.webp', 'https://www.flickr.com/photos/zaragozaantigua/31595527374/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23573, 'Pl. Magdalena 1931', 'Foto: Miguel Marâ”œÂ¡n Chivite. "Animado aspecto de las puertas del colegio electoral instalado en la Universidad, durante la maâ”œâ–’ana del domingo" 12 de abril de 1931, dâ”œÂ¡a de las elecciones municipales, cuyo resultado determinâ”œâ”‚ la llegada de la Segunda Repâ”œâ•‘blica dos dâ”œÂ¡as despuâ”œÂ®s. Fuente: Heraldo de Aragâ”œâ”‚n.', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65218900, -0.87338300, '0101000020E61000005C3CBCE7C0F2EBBFCDE7DCED7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31898187726.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31898187726.webp', 'https://www.flickr.com/photos/zaragozaantigua/31898187726/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23574, 'Plaza de la Universidad c.1929', 'Imagen de la monumental escalera de la antigua Universidad Literaria de la Magdalena. Esta fue una de las destacadas piezas que Ricardo Magdalena dio nuevo empaque en la gran reforma acometida entre 1907-1912. De 1925 es el elemento que centraliza la imagen, una lâ”œÃ­pida que fue inaugurada durante la Dictadura de Primo de Rivera, con presencia del rey Alfonso XIII, en homenaje a los estudiantes valencianos muertos en los asedios de Zaragoza en 1808-1809. Cuando en 1967 este lugar fue derribado, la lâ”œÃ­pida fue demediada y reinstalada sin atributos identificativos en un insâ”œâ”‚lito establecimiento de la ciudad. Oficialmente se la dio por desaparecida, de forma que la lâ”œÃ­pida que hoy se encuentra en el actual Paraninfo de la plaza de Paraâ”œÂ¡so es una reproducciâ”œâ”‚n de la lâ”œÃ­pida que, sobre el mismo asunto, fue inaugurada en 1924 en la Universidad de Valencia. Parece enrevesado, aunque tal vez sâ”œâ”‚lo sea que Zaragoza tiene complejas sinuosidades que fluyen en el mar de fondo de su acontecer histâ”œâ”‚rico, bajo una engaâ”œâ–’osa apariencia de simplicidad. Fuente visual: foto Juan Mora Insa, en elblogdezaragoza.blogspot.com.es/', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65283500, -0.87293900, '0101000020E6100000EBE40CC51DEFEBBF9357E71890D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32214302646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32214302646.webp', 'https://www.flickr.com/photos/zaragozaantigua/32214302646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23576, 'Coso Bajo 1814', '"Entrada triunfal de Fernando VII en Zaragoza". â”œÃ´leo sobre lienzo, Miguel Parra Abril, 1818. La escena representa la visita de Fernando VII a Zaragoza, el 6 de abril de 1814. La comitiva estaba formada tambiâ”œÂ®n por su hermano Carlos Marâ”œÂ¡a Isidro, el duque de San Carlos y Josâ”œÂ® Palafox. Entraron por el puente de Piedra, siguieron por las Tenerâ”œÂ¡as, pasaron por la plaza de la Magdalena y subieron por el Coso hasta llegar al palacio de Sâ”œÃ­stago. El rey estuvo en Zaragoza hasta el 11 de abril. El escenario escogido para el cuadro es el tramo del Coso Bajo con las simbâ”œâ”‚licas ruinas del seminario, tomando como modelo el grabado de Gâ”œÃ­lvez y Brambila de 1814 "Ruinas del Seminario". Se trata del edifico que se ve al fondo, entre las calles de San Jorge y San Lorenzo. Fuente visual: Palacio Real de Madrid.', 1814, 1814, 1814, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65158800, -0.87421900, '0101000020E61000009F56D11F9AF9EBBFA73B4F3C67D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32856669552.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32856669552.webp', 'https://www.flickr.com/photos/zaragozaantigua/32856669552/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23578, 'Universidad Literaria c.1929', 'Imagen capturada en el descansillo de la monumental escalera de la Universidad Literaria de la Magdalena, una de las destacadas piezas que Ricardo Magdalena habâ”œÂ¡a reformado en 1907-1912 dâ”œÃ­ndole este imponente aspecto. En la planta baja, acceso desde el vestâ”œÂ¡bulo recayente a la plaza de la Magdalena y ventanas a la galerâ”œÂ¡a del patio de luces. Toda esta zona quedâ”œâ”‚ convertida en un campo de cascotes cuando el edificio fue derribado a finales de la prodigiosa dâ”œÂ®cada de los aâ”œâ–’os sesenta, que terminaron depositados en uno de los abundantes vertederos de escombros que jalonaban la periferia de una ciudad ensimismada en la modernidad y progreso. Fuente visual: foto Juan Mora Insa, en elblogdezaragoza.blogspot.com.es/', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65218900, -0.87338300, '0101000020E61000005C3CBCE7C0F2EBBFCDE7DCED7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34922119006.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34922119006.webp', 'https://www.flickr.com/photos/zaragozaantigua/34922119006/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23580, 'Calle del Râ”œÂ¡o 1986', 'Imagen capturada desde el solar de los antiguos talleres y almacenes municipales de la Rebolerâ”œÂ¡a y centrada en los edificios de vivienda de los antiguos nâ”œâ•‘meros 16, 18, 29 y 22 de la calle del Râ”œÂ¡o. A la derecha, ingreso al callejâ”œâ”‚n del Râ”œÂ¡o. A la izquierda, esquinero y moderno bloque del nâ”¬â•‘ 18 de la calle Monreal. Aâ”œâ–’os despuâ”œÂ®s, estos inmuebles serâ”œÂ¡an derribados y sustituidos por el moderno bloque del nâ”¬â•‘ 18 de la calle del Râ”œÂ¡o. Justo enfrente serâ”œÂ¡a construido otro nuevo bloque correspondiente a los actuales nâ”¬â•‘ 7, 9 y 11 de la misma calle, junto al CEIP (Colegio Pâ”œâ•‘blico de Educaciâ”œâ”‚n Infantil y Primaria) y al Pabellâ”œâ”‚n Deportivo Municipal Tenerâ”œÂ¡as. Fuente visual: AMZ.', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65343700, -0.87010700, '0101000020E610000058A9A0A2EAD7EBBF887FD8D2A3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37743144235.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37743144235.webp', 'https://www.flickr.com/photos/zaragozaantigua/37743144235/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23581, 'Iglesia Magdalena c.1966', 'Vista de la iglesia de Santa Marâ”œÂ¡a Magdalena cuando comienzan a desmocharle la torre para devolverle el probable aspecto original, eliminando su remate barroco.', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65253300, -0.87391700, '0101000020E6100000CC63CDC820F7EBBFC7478B3386D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38037597074.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38037597074.webp', 'https://www.flickr.com/photos/zaragozaantigua/38037597074/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23582, 'Coso Bajo 1986', 'Imagen capturada en el Coso Bajo y centrada en los solares y antiguos edificios correspondientes a los nâ”œâ•‘meros 170, 172 y 174 del Coso, y el nâ”œâ•‘mero 5 del arranque de la calle de San Agustâ”œÂ¡n (a la derecha). Desde finales de la dâ”œÂ®cada siguiente estos inmuebles serâ”œÂ¡an derribados y sobre sus solares se levantarâ”œÂ¡an las actuales viviendas que allâ”œÂ¡ se ubican. Al fondo, a la derecha, el nâ”¬â•‘ 2 de la calle de Jusepillo Olleta. Fuente visual: AMZ.', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65204200, -0.87292900, '0101000020E6100000075C57CC08EFEBBF29CFBC1C76D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38580739381.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38580739381.webp', 'https://www.flickr.com/photos/zaragozaantigua/38580739381/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23583, 'Coso Bajo 1986', 'Imagen capturada en el Coso Bajo y centrada en los antiguos edificios (de finales del siglo XIX) correspondientes a los nâ”œâ•‘meros 174 (parcial), 176, 178 y 180, esquinero con el arranque de la calle de Alcober, de la que se muestran las fachadas de los nâ”œâ•‘meros 1, 3 y 5. De todos ellos perdura el nâ”œâ•‘mero 180. El resto fueron luego derribados, bien para dar paso a modernas construcciones habitacionales (actual nâ”œâ•‘mero 174), bien para "esponjar" esta zona ubicada entra las plazas de la Magdalena, Tenerâ”œÂ¡as, y San Agustâ”œÂ¡n mediante un solar habilitado para uso pâ”œâ•‘blico (esquina Alcober-Coso). Fuente visual: AMZ.', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65241900, -0.87253200, '0101000020E6100000C3D4963AC8EBEBBFFF243E7782D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38639236771.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38639236771.webp', 'https://www.flickr.com/photos/zaragozaantigua/38639236771/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23584, 'Convento de San Agustâ”œÂ¡n 1809', 'Imagen del costumbrista â”œâ”‚leo sobre lienzo &quot;Heroica defensa de la torre de San Agustâ”œÂ¡n en Zaragoza en la Guerra de la Independencia&quot; pintado por Câ”œÂ®sar â”œÃ¼lvarez Dumont en 1884, posiblemente basado en el Episodio Nacional de Benito Pâ”œÂ®rez Galdâ”œâ”‚s, &quot;Zaragoza&quot;. Los verâ”œÂ¡dicos hechos referidos sucedieron durante el segundo asedio de la ciudad por las tropas francesas, en febrero de 1809. El â”œâ”‚leo centra la atenciâ”œâ”‚n en el interior de la torre del convento de San Agustâ”œÂ¡n y unos peleones paisanos dispuestos en colorista y triangular composiciâ”œâ”‚n que culmina en la campana de la torre. A la izquierda, una gran bota de vino y varios grafitis patriâ”œâ”‚ticos en la pared, entre los que destacan &quot;gabacho&quot;, despectiva denominaciâ”œâ”‚n del francâ”œÂ®s desde el siglo XVII y &quot;Pepe Botella&quot;, capciosa referencia al rey Josâ”œÂ® I Bonaparte. Fuente visual: www.museodelprado.es', 1809, 1809, 1809, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65090300, -0.87077200, '0101000020E61000006BB8C83D5DDDEBBF24EF1CCA50D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39937575692.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39937575692.webp', 'https://www.flickr.com/photos/zaragozaantigua/39937575692/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23585, 'Calle de San Cristâ”œâ”‚bal c.1965', 'Imagen capturada en la antigua calle de San Cristâ”œâ”‚bal con una interesante vista parcial de la torre de la iglesia parroquial de la Magdalena emergiendo entre antiguas viviendas de la calle Mayor, construidas en el siglo XVI y muy reformadas en el XIX. El remate de la torre seguâ”œÂ¡a siendo el tradicional desde â”œÂ®poca barroca. Fuente visual: foto Palacio, AMZ.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65225800, -0.87401200, '0101000020E61000003CF88903E8F7EBBFF646AD307DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40580927171.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40580927171.webp', 'https://www.flickr.com/photos/zaragozaantigua/40580927171/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23586, 'Calle de Josâ”œÂ® Palafox 1991', 'Imagen centrada en el solar conformado tras el derribo del nâ”¬â•‘ 31 de la calle de Josâ”œÂ® Palafox (tramo antiguamente denominado de San Vicente) y el nâ”¬â•‘ 15 de la calle Universidad (antigua de la Trinidad), tras una transitoria y colorista remodelaciâ”œâ”‚n hasta que se llevara a cabo el correspondiente desarrollo urbanâ”œÂ¡stico. Este solar lindaba, a la izquierda, con el antiguo Laboratorio Quâ”œÂ¡mico Municipal construido en 1914 segâ”œâ•‘n proyecto del arquitecto municipal Josâ”œÂ® de Yarza Echenique. A la derecha, los nâ”œâ•‘meros 16 y 14 de la calle de Don Teobaldo, construidos en la dâ”œÂ®cada de los aâ”œâ–’os treinta, y fachada del convento de las Canonesas Regulares del Santo Sepulcro. Pocos aâ”œâ–’os despuâ”œÂ®s, sobre este solar serâ”œÂ¡a construido el actual nâ”¬â•‘ 18 de la calle de Don Teobaldo. Fuente visual: AMZ.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65328400, -0.87295000, '0101000020E6100000E561A1D634EFEBBF028063CF9ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42332210674.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42332210674.webp', 'https://www.flickr.com/photos/zaragozaantigua/42332210674/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23587, 'Calle de Alonso V 1986', 'Imagen capturada en la calle de Alonso V y centrada en el tramo de los inmuebles de los nâ”œâ•‘meros 6-12 (de derecha a izquierda), adosados desde finales del siglo XIX sobre la muralla medieval de ladrillo que delimitaba la ciudad en esta zona, dejando extramuros a la rebolerâ”œÂ¡a, al otro lado de la entonces calle de las Tenerâ”œÂ¡as. El estrechisimo inmueble del nâ”¬â•‘ 8, a la derecha del â”œÃ­rbol de la escena, se correspondâ”œÂ¡a con uno de los antiguos torreones que desde finales del siglo XVII habâ”œÂ¡a sido reconvertido en vivienda. Tras estos edificios circulaba la calle de las Arcadas, en el tramo donde a la izquierda desembocaba la calle de Jusepillo de Olleta. En el momento de tomar esta fotografâ”œÂ¡a se estaba procediendo a urbanizar la calle de Alonso V. Una intervenciâ”œâ”‚n municipal posterior supuso la restauraciâ”œâ”‚n y rehabilitaciâ”œâ”‚n, previo derribo de las viviendas adosadas, de este y otros dos torreones, ademâ”œÃ­s de algunos inmediatos lienzos del tramo de muralla medieval. En este caso la rehabilitaciâ”œâ”‚n del oculto torreâ”œâ”‚n tuvo que ser forzosamente muy creativa.', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65252900, -0.87143800, '0101000020E610000095BBCFF1D1E2EBBF8658FD1186D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48108411727.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48108411727.webp', 'https://www.flickr.com/photos/zaragozaantigua/48108411727/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23588, 'Calle de Alonso V 1986', 'Imagen capturada en la calle de Alonso V y centrada en el tramo de los inmuebles de los nâ”œâ•‘meros 10-16 (de derecha a izquierda), adosados desde finales del siglo XIX sobre la muralla medieval de ladrillo que delimitaba la ciudad en esta zona, dejando extramuros a la rebolerâ”œÂ¡a, al otro lado de la entonces calle de las Tenerâ”œÂ¡as. El inmueble del nâ”¬â•‘ 16, a la izquierda, se habâ”œÂ¡a construido previo derribo del tercero de los antiguos cubos de la muralla, desde la antigua puerta de la Portaza, luego del Sol. Tras estos edificios circulaba la calle de las Arcadas y el desemboque en la misma de la calle de Jusepillo de Olleta. En el momento de tomar esta fotografâ”œÂ¡a se estaba procediendo a urbanizar la calle de Alonso V. Una intervenciâ”œâ”‚n municipal posterior supuso la restauraciâ”œâ”‚n creativa, previo derribo de las viviendas adosadas, de este tramo de la muralla medieval, y se apuntâ”œâ”‚ la preexistencia del referido y desaparecido cubo de la muralla con una reconstrucciâ”œâ”‚n parcial.', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65244800, -0.87127800, '0101000020E61000005E2D776682E1EBBF992B836A83D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48114400817.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48114400817.webp', 'https://www.flickr.com/photos/zaragozaantigua/48114400817/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23590, 'Calle de Martâ”œÂ¡n Carrillo 1991', 'Imagen capturada desde cierta altura en el inmueble del nâ”¬â•‘ 5 de la calle del â”œÃ´rgano, y centrada los modernos edificios residenciales que a la izquierda se extienden en esta manzana desde la calle de Torrellas, la plaza de Asso (nâ”¬â•‘ 6) la calle de Martâ”œÂ¡n Carrillo (nâ”¬â•‘ 3, 5 y 7) y hasta la calle de la Universidad. Fueron proyectados por los arquitectos Teâ”œâ”‚filo Martâ”œÂ¡n Sâ”œÃ­enz y Luis Fernâ”œÃ­ndez Ramâ”œÂ¡rez sobre los solares de antiguas casonas en esta parte del barrio de la Magdalena, incluyendo la fotogâ”œÂ®nica Casa Tejada. En primer tâ”œÂ®rmino, aspecto de la calle de Martâ”œÂ¡n Carrillo tras la urbanizaciâ”œâ”‚n integral de esta zona, dotâ”œÃ­ndola de nuevo mobiliario urbano, arbolado, iluminaciâ”œâ”‚n e incluyendo itinerarios peatonales. A la izquierda, las referidas viviendas residenciales aâ”œâ•‘n sin ocupar, y con los bajos comerciales tapiados de obra y aâ”œâ•‘n vacantes. A la derecha, lienzo norteâ”œâ–’o de la iglesia parroquial de Santa Marâ”œÂ¡a Magdalena. Al fondo y a la izquierda, el IES Pedro de Luna, recayente a la plaza de la Magdalena y construido donde estuviera la homâ”œâ”‚nima universidad. Tras el Coso Bajo, vista parcial del solar tras derribo del nâ”¬â•‘ 164, esquinero con la calle de Alejandro Palomar y construido algunos aâ”œâ–’os despuâ”œÂ®s.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65269700, -0.87387400, '0101000020E6100000FA635A9BC6F6EBBF429946938BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50262950396.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50262950396.webp', 'https://www.flickr.com/photos/zaragozaantigua/50262950396/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23591, 'Discoteca Flying 1990', 'Terrible matinal del domingo 14 de enero de 1990 tras el incendio en la discoteca Flying sita en la esquina de la calle de Don Teobaldo, desde donde se ha capturado esta imagen, con la de la Trinidad, que por la derecha y hacia el fondo desciende hasta el Coso Bajo. En primer tâ”œÂ®rmino, ingreso al local siniestrado en el que murieron 43 personas, con rastros en la fachada de las tâ”œâ”‚xicas emanaciones causantes de la catâ”œÃ­strofe.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65330600, -0.87259700, '0101000020E610000089CE328B50ECEBBFEA23F0879FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50307864071.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50307864071.webp', 'https://www.flickr.com/photos/zaragozaantigua/50307864071/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23593, 'Calle de San Lorenzo 1991', 'Imagen del tramo final de la calle de San Lorenzo, con su tradicional pequeâ”œâ–’o comercio (como "Casa Paco. Novelas-Revistas", a la izquierda) y "aceras" liliputienses, capturada desde el desemboque en el Coso Bajo. Inmediato y a la derecha, vista parcial del gran solar resultante del derribo de los antiguos inmuebles de los nâ”œâ•‘meros 53 y 55 de esta calle y de los nâ”œâ•‘meros 135 y 137 del Coso, refundidos poco tiempo despuâ”œÂ®s en el moderno inmueble del nâ”¬â•‘ 137 del Coso. Hacia el fondo y a la izquierda, Arranque de la calle de los Pelegrâ”œÂ¡n y vista del esquinero inmueble del nâ”¬â•‘ 51 de la calle de San Lorenzo, que a finales de la dâ”œÂ®cada serâ”œÃ­ derribado y sustituido por el actual nâ”¬â•‘ 1 de los Pelegrâ”œÂ¡n.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65178300, -0.87377700, '0101000020E61000005CE7DF2EFBF5EBBF5D8B16A06DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50439910588.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50439910588.webp', 'https://www.flickr.com/photos/zaragozaantigua/50439910588/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23594, 'Calle de Aâ”œâ–’â”œâ”‚n 1991', 'Imagen capturada en la calle de Pedro Garcâ”œÂ®s Aâ”œâ–’â”œâ”‚n durante la construcciâ”œâ”‚n, a la derecha, de las 45 viviendas municipales de alquiler levantadas sobre el gran solar dejado tras el derribo de los antiguos inmuebles de los nâ”œâ•‘meros 5-7, 9 y 11-13 de esta calle, ademâ”œÃ­s del nâ”¬â•‘ 5-7 de la calle del Heroâ”œÂ¡smo. El ingreso a las viviendas desde donde se ha realizado la imagen estaba proyectado mediante un gran espacio interior porticado que recibirâ”œÂ¡a el nombre de plaza de Aâ”œâ–’â”œâ”‚n. Esta gran manzana delimitada entre las calles del Heroâ”œÂ¡smo, Cantâ”œÂ¡n y Gamboa, la Torre y Aâ”œâ–’â”œâ”‚n resultâ”œâ”‚ ser rica en restos arqueolâ”œâ”‚gicos que aâ”œâ–’os mâ”œÃ­s tarde, con motivo de nuevas excavaciones en esta â”œâ•‘ltima calle, donde estuvieran los derribados inmuebles nâ”¬â•‘ 21 y 23, revelarâ”œÂ¡an las estructuras arquitectâ”œâ”‚nicas de varias destacadas "domus" romanas de la dinastâ”œÂ¡a Julio-Claudia, abandonadas a finales del siglo I de nuestra era, donde se encontraron los restos del mejor conjunto de bienes muebles y decoraciones domâ”œÂ®sticas de la colonia Caesaraugusta. Al fondo de la imagen, arranque de la calle de Aâ”œâ–’â”œâ”‚n desde la del Heroâ”œÂ¡smo.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65070100, -0.87352000, '0101000020E610000087DC0C37E0F3EBBFBC3C9D2B4AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50494632363.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50494632363.webp', 'https://www.flickr.com/photos/zaragozaantigua/50494632363/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23595, 'La Magdalena, 1865', 'Iglesia de Santa Marâ”œÂ¡a Magdalena recreada con el supuesto aspecto que tenâ”œÂ¡a antes de la gran reforma barroca que en 1727-30 reorientâ”œâ”‚ su entrada principal, pasando de la calle Mayor a la antigua cabecera del templo, en la plaza de la Magdalena, y recreciâ”œâ”‚ la original torre con un remate que aquâ”œÂ¡ aparece en color mâ”œÃ­s atenuado y que perdurâ”œâ”‚ hasta que fue eliminado en la rehabilitaciâ”œâ”‚n de 1970. El punto de vista estâ”œÃ­ tomado desde la plaza de la Magdalena, quedando a la izquierda la calle Mayor, y a la derecha la calle de Martâ”œÂ¡n Carrillo. A espaldas quedaba la Puerta de Valencia.', 1865, 1865, 1865, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65235200, -0.87378800, '0101000020E61000005664744012F6EBBF77BD344580D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50880882348.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50880882348.webp', 'https://www.flickr.com/photos/zaragozaantigua/50880882348/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24020, 'Calle Monreal 2002', 'En marzo de 2002 se celebrâ”œâ”‚ en Zaragoza una "reuniâ”œâ”‚n informal" de Ministros de Defensa de la Uniâ”œâ”‚n Europea. El Foro Zaragoza 2002, formado por cerca de 40 asociaciones, convocâ”œâ”‚ un acto antimilitarista ante la puerta de la fâ”œÃ­brica de armas Instalaza, en la calle Monreal 27. Esta empresa, fundada en 1943, "es una compaâ”œâ–’ia de vanguardia que aplica las â”œâ•‘ltimas tecnologâ”œÂ¡as en el diseâ”œâ–’o, desarrollo y fabricaciâ”œâ”‚n de equipos y material para ofrecer soluciones eficaces". Sus productos "equipan a las fuerzas armadas de paâ”œÂ¡ses de todo el mundo, con resultados muy satisfactorios y con un mâ”œÃ­ximo nivel de operatividad y eficacia". Fuente: Agencia EFE.', 2002, 2002, 2002, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65244700, -0.86942200, '0101000020E61000007F880D164ED2EBBFC9AF1F6283D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24629717866.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24629717866.webp', 'https://www.flickr.com/photos/zaragozaantigua/24629717866/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24220, 'Pl. de la Magdalena 1872', 'Dibujo: Pradilla; grabado: Severini. 1872. "Zaragoza. Fiestas del Pilar. Cabalgata histâ”œâ”‚rica de don Jaime el Conquistador." Grabado con la recreaciâ”œâ”‚n histâ”œâ”‚rica de la entrada del rey Jaime I el Conquistador en la ciudad de Valencia el 28 de septiembre de 1238. Esta cabalgata fue incluida en el programa de las Fiestas del Pilar, y en la imagen se adentra en el Coso Bajo proveniente de la calle Mayor. Al fondo, la plaza de la Magdalena. Unos aâ”œâ–’os antes se habâ”œÂ¡a dado el nombre de Don Jaime I a uno de los principales viales de la ciudad. Fuente: "La Ilustraciâ”œâ”‚n Espaâ”œâ–’ola y Americana", Madrid, Aâ”œâ–’o XVI, nâ”¬â•‘ XLII, 08-11-1872.', 1872, 1872, 1872, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65201200, -0.87320400, '0101000020E61000007590D78349F1EBBFBE4C142175D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15283479654.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15283479654.webp', 'https://www.flickr.com/photos/zaragozaantigua/15283479654/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24414, 'Tenerâ”œÂ¡as 1942', 'Imagen de la capilla habilitada en el cuartel del Grupo de Automâ”œâ”‚viles del 5â”¬â•‘ Cuerpo de Ejâ”œÂ®rcito, ubicado desde 1937 en la confluencia de la calle del Asalto, la plaza de las Tenerâ”œÂ¡as, y la ribera del Ebro. Una buena muestra de la abrumadora memoria histâ”œâ”‚rica de la guerra de 1936-39, el perenne homenaje a los muertos durante la Cruzada, y la â”œÂ¡ntima relaciâ”œâ”‚n entre fuerzas armadas, e iglesia catâ”œâ”‚lica. Fuente: Archivo Coyne. AHPZ', 1942, 1942, 1942, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65370900, -0.87120100, '0101000020E610000087C267EBE0E0EBBFE90C8CBCACD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32796858004.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32796858004.webp', 'https://www.flickr.com/photos/zaragozaantigua/32796858004/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24879, 'Muralla medieval c.1877', 'Archivo RUIZ VERNACCI, Jean Laurent y Câ”œÂ¡a. 1872-1879. Titulado "Torreâ”œâ”‚n del Trovador", se trata de una de las torres de la muralla medieval de râ”œÂ®jola, en la actual calle de Alonso V.', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65237600, -0.87120600, '0101000020E6100000F986C267EBE0EBBFFF58880E81D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14843226426.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14843226426.webp', 'https://www.flickr.com/photos/zaragozaantigua/14843226426/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24911, 'Muralla medieval 2013', 'Foto: Rusolera, abril de 2013. El 6 de abril de 2013 se derrumbâ”œâ”‚ parte del lienzo de la muralla medieval de Zaragoza, entre la calle de Alonso V y la de las Arcadas. Unos 25 metros, que fueron repuestos meses despuâ”œÂ®s. Fuente: zaragozaciudad.net/zaragozafluye/2014/091801-muralla-medi...', 2013, 2013, 2013, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65259200, -0.87125700, '0101000020E610000080272D5C56E1EBBFCCD0782288D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21494516160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21494516160.webp', 'https://www.flickr.com/photos/zaragozaantigua/21494516160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25964, 'Colegio San Agustâ”œÂ¡n 1994', 'Tras el desalojo del 23 de diciembre de 1993 de la Casa de la Paz, en el paseo de Sagasta 52, el colectivo de okupas de Zaragoza buscâ”œâ”‚ un nuevo alojamiento en el abandonado colegio de San Agustâ”œÂ¡n, en el nâ”œâ•‘mero 5 de la calle homâ”œâ”‚nima, a principios de 1994, como ilustra la foto. Fueron desalojados en una semana. En mayo de 1996 volvieron a intentarlo.', 1994, 1994, 1994, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65153900, -0.87181600, '0101000020E6100000292504ABEAE5EBBFC68844A165D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52492136001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52492136001.webp', 'https://www.flickr.com/photos/zaragozaantigua/52492136001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20960, 'La Lonja 1858', '"Town Hall Zaragoza". J.B. Waring (dib.) y T.H. Macquoid (lit.), 1858. Colecciâ”œâ”‚n Pascual de Quinto. Vista de la Lonja de Mercaderes de Zaragoza (Juan de Sariâ”œâ–’ena, 1551), desde la plaza de La Seo. A la izquierda del edificio queda la calle del Pilar; a la derecha, la Casa de la Ciudad (antiguo Ayuntamiento), en la ribera del râ”œÂ¡o Ebro; y donde pasa el jinete es la actual calle de Don Jaime I. Fuente: commons.wikimedia.org/wiki/File:Zaragoza_-_La_Lonja.webp', 1858, 1858, 1858, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65566000, -0.87642500, '0101000020E610000096B20C71AC0BECBFCEA5B8AAECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15498200202.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15498200202.webp', 'https://www.flickr.com/photos/zaragozaantigua/15498200202/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21030, 'Puerta del â”œÃ¼ngel 1860', '"Entrada de SS. MM. en Zaragoza por la puerta del â”œÃ¼ngel el dâ”œÂ¡a 7 de octubre de 1860". Dibujo con la vista desde el interior de la ciudad de la nueva Puerta del â”œÃ¼ngel, construida en el lugar de la anterior con motivo de la visita de la reina Isabel II, el rey consorte Francisco de Asâ”œÂ¡s de Borbâ”œâ”‚n, y los infantes y el heredero al trono, futuro Alfonso XII. A la izquierda, las "casas consistoriales" del viejo ayuntamiento. A la derecha, el edificio del arzobispado en la plaza de la Seo. La puerta estarâ”œÃ­ en pie sâ”œâ”‚lo ocho aâ”œâ–’os. Su exagerada ornamentaciâ”œâ”‚n superior, de materiales efâ”œÂ¡meros, todavâ”œÂ¡a mucho menos. Fuente visual: AMZ', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65590200, -0.87614900, '0101000020E6100000118AADA06909ECBFC4B0C398F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24331023153.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24331023153.webp', 'https://www.flickr.com/photos/zaragozaantigua/24331023153/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21091, 'La Lonja c.1877', 'Imagen capturada en el interior de la nave-salâ”œâ”‚n de la renacentista Lonja de Mercaderes con una vista transversal orientada hacia el muro oriental y la puerta de ingreso desde la calle de la Lonja. A la izquierda y fuera de plano quedaban las dos puertas que la comunicaban con la anexa Casa Ayuntamiento. Destaca la bâ”œâ”‚veda de crucerâ”œÂ¡a estrellada, las columnas denominadas "aragonesas" por la inserciâ”œâ”‚n de un anillo en su fuste a un tercio de la altura, y la portada ornamentada en relieve y en yeso con el escudo imperial flanqueado por leones. Esta fotografâ”œÂ¡a resulta excepcional ya que posiblemente incluye en ella el posado del fotâ”œâ”‚grafo francâ”œÂ®s Jean Laurent, de blanco y sentado a la izquierda, y su equipo de colaboradores.', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65581500, -0.87657800, '0101000020E61000002D944C4EED0CECBFF59CF4BEF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52453284748.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52453284748.webp', 'https://www.flickr.com/photos/zaragozaantigua/52453284748/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21113, 'Lonja-Ayuntamiento c.1880', 'Al principio de la antigua calle de la Cuchillerâ”œÂ¡a, otra imagen de la Lonja en tiempos en que era utilizada como espacio para actos pâ”œâ•‘blicos varios, incluyendo el sorteo de "los Quintos" (Servicio Militar Obligatorio para quienes no podâ”œÂ¡an evadirse pagando), y algunas representaciones teatrales. A su derecha, inmediato, la Casa Consistorial en su ubicaciâ”œâ”‚n de siglos y siglos, con el edificio levantado unas dâ”œÂ®cadas antes, con resabios dieciochescos, y puerta principal de acceso arquitrabado y en orden dâ”œâ”‚rico. Fuente visual: Anselmo Marâ”œÂ¡a Coyne, Estudio Coyne (DARA_AHPZ)', 1880, 1880, 1880, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65591300, -0.87633500, '0101000020E610000097E2AAB2EF0AECBFB8020AF5F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23310046131.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23310046131.webp', 'https://www.flickr.com/photos/zaragozaantigua/23310046131/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21115, 'Calle de la Lonja 1889', 'Fachada principal del renacentista edificio de la Lonja, en una imagen capturada desde la plaza de la Seo. A su izquierda, la calle del Pilar, apenas un callejâ”œâ”‚n antes del derribo de las parcelas de los nâ”œâ•‘meros 36 a 44 accesorio, y la nâ”¬â•‘ 7 de la calle de Don Jaime I. A su derecha, las Casas de la ciudad, o ayuntamiento, y el ingreso desde el puente de Piedra. A pesar de que desde mediados del siglo XIX se acometiâ”œâ”‚ la realineaciâ”œâ”‚n y la unificaciâ”œâ”‚n de los varios nombres que, de toda la vida, tenâ”œÂ¡an los diferentes tramos de la calle Don Jaime I (Nueva de San Gil, Baja de San Pedro, Virgen del Rosario, Cuchillerâ”œÂ¡a), este todavâ”œÂ¡a era denominada "calle de la Lonja", y mâ”œÃ­s tarde "Fernando el Catâ”œâ”‚lico". Mientras el seâ”œâ–’or Max Junghâ”œÃ±ndel preparaba la câ”œÃ­mara para realizar esta imagen, un heterogâ”œÂ®neo grupo de paisanos se ha estacionado en medio, hasta que salga el pajarito. La baja intensidad del trâ”œÃ­fico rodado facilitâ”œâ”‚ un limpio y despejado resultado.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65550100, -0.87642800, '0101000020E6100000DA8EA9BBB20BECBF66BFEE74E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25573691181.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25573691181.webp', 'https://www.flickr.com/photos/zaragozaantigua/25573691181/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21219, 'Puente de Piedra c.1900', 'Imagen capturada desde cierta altura del puente de Piedra y el Arrabal. Fuente visual: fototipia Lucas Escolâ”œÃ­, en www.memoriademadrid.es/', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65646200, -0.87669800, '0101000020E6100000D6FECEF6E80DECBF8B8862F206D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15672942110.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15672942110.webp', 'https://www.flickr.com/photos/zaragozaantigua/15672942110/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21232, 'Ribera del Ebro c.1900', 'Imagen capturada desde la ribera del Ebro, junto la "Posada del Rey", espacio de confluencia y descanso de carros, carretas, diligencias, ademâ”œÃ­s de las gentes asociadas a estos medios de negocio y transporte. A la izquierda, la verja que delimitaba el palacio de los marqueses de Ayerbe. A la derecha, el puente de Piedra que cruza el Ebro. Al fondo, la iglesia parroquial de Altabâ”œÃ­s, el convento de Santa Isabel, y un macizo torreâ”œâ”‚n del cuartel de San Lâ”œÃ­zaro. Fuente visual: Colecciâ”œâ”‚n Antonio Arguas Perdiguer, en "El libro de oro de Aragâ”œâ”‚n", EPA, 1997.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65625600, -0.87693200, '0101000020E6100000A01B9AB2D30FECBFE2E6543200D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19376659492.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19376659492.webp', 'https://www.flickr.com/photos/zaragozaantigua/19376659492/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21287, 'Seâ”œâ–’oritas 1903', 'Foto: Algora. "Grupo de las seâ”œâ–’oritas que tomaron parte en el concurso de corte organizado por doâ”œâ–’a Pilar del Valle y celebrado como final de las fiestas de la patrona de Zaragoza en la Lonja local de dicha poblaciâ”œâ”‚n". Fuente: Diario ABC, 30-10-1903.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65582800, -0.87663100, '0101000020E6100000E31C75745C0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26075864338.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26075864338.webp', 'https://www.flickr.com/photos/zaragozaantigua/26075864338/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21360, 'Plaza de La Seo 1900', 'Fotografâ”œÂ¡a capturada en la plaza de La Seo que continâ”œâ•‘a lo representado en la imagen anterior, donde transita el cortejo municipal salido del homâ”œâ”‚nimo templo durante la celebraciâ”œâ”‚n, posiblemente, de la festividad del patrâ”œâ”‚n de la ciudad. Aquâ”œÂ¡ el cortejo estâ”œÃ­ dejando la plaza y cruza la calle de la Lonja, luego de Fernando el Catâ”œâ”‚lico. Al fondo, fachada de la Casa-Lonja a esta calle. A la derecha e inmediata, esquina del Seminario Conciliar, y hacia el fondo, vista parcial de la Casa Consistorial.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65547900, -0.87635200, '0101000020E61000001A187959130BECBF7E1B62BCE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54788549083.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54788549083.webp', 'https://www.flickr.com/photos/zaragozaantigua/54788549083/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21372, 'La Lonja y el Pilar 1918', 'Una mirada hacia el Oeste desde la torre de La Seo, capturando la calle Don Jaime I y la del Pilar (con las manzanas de viviendas en su entorno), La Lonja, El Pilar y la arbolada plaza de su nombre. Al fondo, tras la clâ”œÂ¡nica del Doctor Palomar y el antiguo palacio de Aytona, la torre y câ”œâ•‘pula de San Juan de los Panetes, y el Torreâ”œâ”‚n de la Zuda. Sobre el Ebro, el puente del Ferrocarril. En la margen izquierda, grandes arboledas, un verdadero bosque de ribera. Fuente: Zaragoza 1908-2008. FCC.', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65572700, -0.87652800, '0101000020E6100000BCE7C072840CECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15524839000.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15524839000.webp', 'https://www.flickr.com/photos/zaragozaantigua/15524839000/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21373, 'La Seo c.1910', 'Fototeca del Patrimonio Artâ”œÂ¡stico. Archivo Conde de Polentinos. Aurelio de Colmenares y Orgaz. 1892-1930. "Zaragoza II. [Plaza del Pilar y Catedral de San Salvador o la Seo]". Tras voltear horizontalmente la imagen de la Fototeca, muestra correctamente una vista de la plaza de La Seo y la Lonja, desde la calle del Pilar.', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65556000, -0.87685800, '0101000020E61000000D8D2782380FECBF6B48DC63E9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15608802721.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15608802721.webp', 'https://www.flickr.com/photos/zaragozaantigua/15608802721/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21451, 'Calle de Don Jaime I c.1918', 'La esquina suroriental de la Lonja marca, a la izquierda, el final de la calle del Pilar en su desemboque en la de don Jaime I, en una imagen realizada desde la inmediata plaza de La Seo, y antes de ser adoquinada esta calle, cuando todavâ”œÂ¡a mantenâ”œÂ¡a el tradicional firme de tierra. Desde el puente de Piedra irrumpe por la derecha un tranvâ”œÂ¡a de la lâ”œÂ¡nea del Gâ”œÃ­llego, posiblemente el nâ”¬â•‘ 32, encaminado hacia la terminal en la plaza de la Constituciâ”œâ”‚n.', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65564700, -0.87652400, '0101000020E61000006117450F7C0CECBF3A5CAB3DECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50784003357.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50784003357.webp', 'https://www.flickr.com/photos/zaragozaantigua/50784003357/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21478, 'La Lonja desde la Seo 1922', 'AHPZ. Archivo Fotogrâ”œÃ­fico Julio Requejo. Junio 1922. "La lonja desde la torre de L''Aseo [La Seo]."', 1922, 1922, 1922, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65559100, -0.87643300, '0101000020E61000004C530438BD0BECBFA646E867EAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14914596106.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14914596106.webp', 'https://www.flickr.com/photos/zaragozaantigua/14914596106/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21587, 'Calle Fernando el Catâ”œâ”‚lico c.1923', 'Puesto de venta ambulante en la calle de Fernando el Catâ”œâ”‚lico, con el fondo del seminario metropolitano. Al fondo, el paseo del Ebro.', 1923, 1923, 1923, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65581400, -0.87622500, '0101000020E6100000D200DE02090AECBF252191B6F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24787073652.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24787073652.webp', 'https://www.flickr.com/photos/zaragozaantigua/24787073652/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21595, 'Calle Don Jaime c.1920', 'Calle de Don Jaime I, en su confluencia con la del Pilar (al fondo a la izquierda). Tras el caballero de primer plano, la Lonja. A la izquierda, comercio de recuerdos neoclasicista. Fuente: Foto Jesâ”œâ•‘s Cormâ”œÃ­n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65559800, -0.87660000, '0101000020E6100000228E75711B0DECBF58A9A0A2EAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24878756026.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24878756026.webp', 'https://www.flickr.com/photos/zaragozaantigua/24878756026/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21649, 'Calle del Pilar 1923', 'Inâ”œÂ®dita imagen capturada en la calle del Pilar, esquina con la plaza de la Seo y la calle de Fernando el Catâ”œâ”‚lico, que hacia el fondo y a la derecha conduce al paseo del Ebro y el puente de Piedra. En primer tâ”œÂ®rmino, una vendedora ambulante de frutas y verduras, entre las que destacan granadas de temporada. Frente a ella, el "brasero" o solanera de la Lonja, donde se arrima hasta una pareja de urbanos junto a otro puesto ambulante.', 1923, 1923, 1923, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65555100, -0.87670600, '0101000020E61000008C9FC6BDF90DECBF18EE5C18E9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51371172171.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51371172171.webp', 'https://www.flickr.com/photos/zaragozaantigua/51371172171/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21659, 'Plaza de La Seo, c.1920', 'Imagen tomada en la plaza de La Seo, donde destaca su isleta de verdor centrada en la Fuente de la Samaritana y la ingrata presencia de su denostado mingitorio. Hacia el fondo y tras la calle de Fernando el Catâ”œâ”‚lico, ensanche de la calle del Pilar.', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65547900, -0.87635200, '0101000020E61000001A187959130BECBF7E1B62BCE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53605982143.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53605982143.webp', 'https://www.flickr.com/photos/zaragozaantigua/53605982143/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21740, 'Lonja 1933', 'Imagen de conjunto de la antigua Lonja y Casa de la Moneda de la ciudad, capturada en cierta altura desde el Seminario Diocesano. En primer plano, las traseras del edificio convertidas en despejada zona de jardines y disfrute ciudadano, tras derribo de las antiguas Casas de la Ciudad. A la izquierda, la calle Fernando el Catâ”œâ”‚lico que conduce a la plaza de la Seo. A la derecha, la que fuera Posada del Rey, junto al palacio de los marqueses de Ayerbe, y el Pilar. Fuente visual: "Revista Espaâ”œâ–’ola de Turismo".', 1933, 1933, 1933, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65588600, -0.87624900, '0101000020E6100000F3E2C4573B0AECBFBFF38B12F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21776602559.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21776602559.webp', 'https://www.flickr.com/photos/zaragozaantigua/21776602559/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21765, 'Plaza La Seo 1932', 'Plaza de la Seo desde la calle del Pilar. A la izquierda, la Lonja. Al fondo, el Arco del Arzobispo.', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65559800, -0.87660000, '0101000020E6100000228E75711B0DECBF58A9A0A2EAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22621963413.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22621963413.webp', 'https://www.flickr.com/photos/zaragozaantigua/22621963413/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21767, 'Jardines de La Lonja 1932', 'Jardines de la Lonja junto al paseo de la Ribera. Al fondo, el palacio de los marqueses de Ayerbe y el Pilar. Fuente visual: Foto Conrado Barlâ”œÂ®s, donada por Daniel Barlâ”œÂ®s y digitalizada por Josâ”œÂ® Luis Cintora para www.rafaelcastillejo.com', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65610300, -0.87648200, '0101000020E6100000A60BB1FA230CECBF5CE7DF2EFBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22622365053.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22622365053.webp', 'https://www.flickr.com/photos/zaragozaantigua/22622365053/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21884, 'La Lonja 1938', 'Imagen capturada en los jardines traseros de la Lonja, donde los posados con palomas se habâ”œÂ¡an convertido en una antropolâ”œâ”‚gica tradiciâ”œâ”‚n. En este caso, el objetivo se centra, entre bancas palomas, en uno de los aviadores alemanes de la Legiâ”œâ”‚n Câ”œâ”‚ndor radicados en la ciudad y con servicio en el grupo de bombardeo K/88 establecido en el aerâ”œâ”‚dromo Sanjurjo. Por el paseo del Ebro, al fondo, coincide concurrido trâ”œÃ­fico de caballerâ”œÂ¡a, carro, y vehâ”œÂ¡culo a motor. A la derecha, quiosco de los jardines.', 1938, 1938, 1938, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65640500, -0.87693400, '0101000020E6100000CD0358E4D70FECBF27F73B1405D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49596274877.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49596274877.webp', 'https://www.flickr.com/photos/zaragozaantigua/49596274877/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21897, 'Calle del Pilar c.1934', 'Imagen capturada en la calle del Pilar con el objetivo dirigido hacia la plaza de La Seo, donde destaca a la izquierda el arco del Arzobispo. Unos guardias de asalto caminan junto a la Lonja en direcciâ”œâ”‚n a la plaza del Pilar. A la derecha, el singular establecimiento "El Pilar", multitienda de objetos artâ”œÂ¡sticos de recuerdo, objetos de escritorio y ornamentos religiosos.', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65572700, -0.87686700, '0101000020E6100000D921FE614B0FECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50945685863.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50945685863.webp', 'https://www.flickr.com/photos/zaragozaantigua/50945685863/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21925, 'Ribera del Pilar c.1940', 'AHPZ-Archivo Fotogrâ”œÃ­fico Josâ”œÂ® Galiay, (SF). El Pilar desde la ribera del Ebro.', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65629600, -0.87643300, '0101000020E61000004C530438BD0BECBF703FE08101D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14700887978.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14700887978.webp', 'https://www.flickr.com/photos/zaragozaantigua/14700887978/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22202, 'Ximâ”œÂ®nez de Embâ”œâ•‘n 1958', 'Imagen de la calle de Tomâ”œÃ­s Ximâ”œÂ®nez de Embâ”œâ•‘n capturada desde la ampliada plaza del Pilar. A la izquierda, el edificio en construcciâ”œâ”‚n de la nueva Casa Consistorial. A la derecha, la Lonja. Al fondo, el paseo del Ebro, y el fondo escâ”œÂ®nico de la margen izquierda. Fuente visual: archivo Heraldo de Aragâ”œâ”‚n, en "Padre Ebro. El râ”œÂ¡o Ebro y el siglo XX".', 1958, 1958, 1958, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65590600, -0.87700600, '0101000020E610000032AA0CE36E10ECBF06A051BAF4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33823491101.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33823491101.webp', 'https://www.flickr.com/photos/zaragozaantigua/33823491101/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22219, 'Plaza del Pilar 1954', 'Imagen capturada desde la torre de la Seo, posiblemente a la altura de su segundo cuerpo en ladrillo, con una buena perspectiva de la nueva plaza de las Catedrales como sumatorio de las antiguas plazas del Pilar y de Huesca, para convertirse en escenario de multitudinarias ceremonias de reafirmaciâ”œâ”‚n del râ”œÂ®gimen franquista y su â”œÂ¡ntima vinculaciâ”œâ”‚n con la iglesia catâ”œâ”‚lica. En primer tâ”œÂ®rmino, breve visual de la arbolada plaza de La Seo y de la calle de Don Jaime I. A la derecha, Lonja y andamios de obra de la nueva Casa Consistorial, cuyo avanzado desarrollo en la fachada recayente a la plaza se debâ”œÂ¡a al Congreso Mariano de este aâ”œâ–’o, para dar una imagen escâ”œÂ®nica de falso acabado ante los miles de congresistas venidos de fuera de la ciudad. Del templo del Pilar, detrâ”œÃ­s, despuntan las obras de las dos nuevas torres ribereâ”œâ–’as, patrocinadas econâ”œâ”‚micamente por Francisco Urzaiz y Leonor Sala, cuando ambas todavâ”œÂ¡a ascendâ”œÂ¡an en sintonâ”œÂ¡a, luego rota por el mayor desarrollo de la torre noroeste en su finalizaciâ”œâ”‚n.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65552700, -0.87688900, '0101000020E6100000CE1B2785790FECBF8F52094FE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48300029697.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48300029697.webp', 'https://www.flickr.com/photos/zaragozaantigua/48300029697/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22236, 'Plaza del Pilar 1954', 'Imagen capturada desde la altura del inmueble chaflanero entre la plaza de La Seo y la calle de Don Jaime I, con una vista centrada en la plaza del Pilar. Por la derecha y sobre el firme se destaca la alargada sombra de la torre de la Seo. Tras ella, la Lonja y la nueva Casa Consistorial haciendo las funciones de una "aldea Potemkim": la fachada recayente a la plaza ha sido terminada a marchas forzadas para el Congreso Mariano celebrado en este entorno, mientras el resto seguâ”œÂ¡a en obras. A su lado, el templo del Pilar con las torres de la ribera en construcciâ”œâ”‚n. Al fondo, resplandece al sol el reciâ”œÂ®n terminado "Altar de la Patria" o "Monumento a los hâ”œÂ®roes y mâ”œÃ­rtires de Zaragoza. Caâ”œÂ¡dos en la Cruzada de Liberaciâ”œâ”‚n 1936-1939".', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65567900, -0.87673900, '0101000020E61000007B1684F23E0EECBF45D61A4AEDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50682145953.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50682145953.webp', 'https://www.flickr.com/photos/zaragozaantigua/50682145953/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22267, 'Cine Pax 1968', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/diciembre 1968. Los 60 arrancaban en la ciudad con la apertura de varios Cines (no "salas" de cine, Cines), porque en Espaâ”œâ–’a la televisiâ”œâ”‚n aâ”œâ•‘n no amenazaba con matar a la estrella de la radio, y del cine. Asâ”œÂ¡, en 1961 abrieron sus puertas el "Dux" y el "Roxy", dos cines "de barrio", en San Josâ”œÂ® y Montemolâ”œÂ¡n, respectivamente. En 1963 vio la luz el "Pax", en la Plaza de la Seo nâ”¬â•‘ 6, con capacidad de 600 personas, y orientado hacia un tipo de cine entre lo familiar, y lo tolerado-para-todos-los-pâ”œâ•‘blicos. Serâ”œÃ­ clausurado en 1984, junto con otros 15 cines de la ciudad (entre ellos, todos los cines de barrio). En la imagen, animada fila para el "Pax" cuando proyectaba el norteamericano filme "Rosie!", al que la peculiar espaâ”œâ–’olizaciâ”œâ”‚n del tâ”œÂ¡tulo le habâ”œÂ¡a aâ”œâ–’adido la coletilla "Una seâ”œâ–’ora riquâ”œÂ¡sima", una comedia donde aparecâ”œÂ¡a la angelical Sandra Dee, la misma que una dâ”œÂ®cada despuâ”œÂ®s serâ”œÂ¡a parodiada con caâ”œâ•‘stica gracia en "Grease".', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65551900, -0.87617000, '0101000020E6100000EF8FF7AA9509ECBF0C74ED0BE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14850753965.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14850753965.webp', 'https://www.flickr.com/photos/zaragozaantigua/14850753965/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22285, 'Riada de 1961', 'Foto Heraldo de Aragâ”œâ”‚n, 1961. La riada del Ebro a su paso por el puente de Piedra de Zaragoza en enero de 1961, la mayor del siglo XX. Fuente: www.heraldo.es/noticias/especiales/2014/07/11/grandes_ria...', 1961, 1961, 1961, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65625900, -0.87638600, '0101000020E61000001F8315A75A0BECBF535A7F4B00D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15161139382.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15161139382.webp', 'https://www.flickr.com/photos/zaragozaantigua/15161139382/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22647, 'La Lonja 1970', 'Celebraciâ”œâ”‚n del concurso Maja Internacional en el palacio de la Lonja de Zaragoza, el 11 de mayo de 1970. Este certamen tuvo su sede en la ciudad en diez ocasiones, entre 1966 y 1975. En 1970 resultâ”œâ”‚ ganadora la representante de Chile, Marâ”œÂ¡a Isabel Pâ”œÂ®rez (quinta por la izquierda). Fuente: www.chileancharm.com/', 1970, 1970, 1970, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65572700, -0.87652800, '0101000020E6100000BCE7C072840CECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20928761109.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20928761109.webp', 'https://www.flickr.com/photos/zaragozaantigua/20928761109/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23173, 'Antonio Lâ”œâ”‚pez 2009', 'Imagen del pintor manchego Antonio Lâ”œâ”‚pez Garcâ”œÂ¡a en la plaza del Pilar, durante una apariciâ”œâ”‚n pâ”œâ•‘blica en la que se ofreciâ”œâ”‚ al Cabildo del Pilar para pintar una bâ”œâ”‚veda del templo, y esculpir un bulto redondo relacionado. A la izquierda del pintor, el cenotafio de Goya que antes estuviera en el Rincâ”œâ”‚n de Goya del Parque de Buenavista. Tras retrasos y contingencias varias, el 11 de enero de 2016, pocos dâ”œÂ¡as despuâ”œÂ®s del cumpleaâ”œâ–’os 80 de este pintor, fue presentado, mediante una proyecciâ”œâ”‚n sobre la câ”œâ•‘pula objeto de la intervenciâ”œâ”‚n, el boceto con la imagen del rostro de una mujer que simbolizaba a la Virgen Marâ”œÂ¡a. El carâ”œÃ­cter hiperrealista de la pintura propuesta, en lâ”œÂ¡nea con el reconocido estilo del autor, y la ausencia de los tradicionales sâ”œÂ¡mbolos y atributos marianos, llevaron al Cabildo a descartar el proyecto por no adecuado, o lejano de la oficial iconodulâ”œÂ¡a mariana. Fuente visual: foto Josâ”œÂ® Miguel Marco, en www.tribunadelamoraleja.com/', 2009, 2009, 2009, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65562800, -0.87691200, '0101000020E6100000D9092FC1A90FECBFC32B499EEBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33274996414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33274996414.webp', 'https://www.flickr.com/photos/zaragozaantigua/33274996414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23797, 'Vista aâ”œÂ®rea 1990', 'Se aprecian las obras en la plaza del Pilar, el templete levantado frente a la Delegaciâ”œâ”‚n del Gobierno, los andamios de la restauraciâ”œâ”‚n de la Lonja, las ruinas del Foro romano en la plaza de La Seo, el Monumento a los Caâ”œÂ¡dos sin terminar de desmantelar...', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65571800, -0.87649800, '0101000020E6100000124DA088450CECBF03B34291EED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14885512645.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14885512645.webp', 'https://www.flickr.com/photos/zaragozaantigua/14885512645/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23805, 'Traseras Lonja 1927', 'Imagen desde cierta altura de las traseras de La Lonja, cuando presentaban una feraz zona verde, con visual de las traseras de los edificios de la calle del Pilar, y el Pilar, al fondo. En el jardâ”œÂ¡n del palacio del Marquâ”œÂ®s de Ayerbe, imagen del quiosco realizado con materiales reciclados del derribado palacio o casa de Torrellas (s. XV). Fuente: Instituto Amatller de Arte Hispâ”œÃ­nico (Arxiu Mas).', 1927, 1927, 1927, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65603200, -0.87641600, '0101000020E6100000C91D3691990BECBF939048DBF8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15284977933.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15284977933.webp', 'https://www.flickr.com/photos/zaragozaantigua/15284977933/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23856, 'El Pilar desde la Seo 1930', 'Vista de la calle y el templo del Pilar desde la Seo, con su torre a la izquierda. Fuente: Foto para postal de Comercial Josan. Cesiâ”œâ”‚n de la familia de Josâ”œÂ® Marâ”œÂ¡a Sanz Gonzâ”œÃ­lez a Rafael Castillejo. Dataciâ”œâ”‚n y procesado:', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65554500, -0.87701600, '0101000020E61000001633C2DB8310ECBF350708E6E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27369756636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27369756636.webp', 'https://www.flickr.com/photos/zaragozaantigua/27369756636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23862, 'Plaza del Pilar 1966', 'Totâ”œÂ®mica puesta en escena del acto de fe de "ver la tele", en aparatos de 20/24 pulgadas, en la plaza del Pilar, de noche, y en invierno. En el interior de la inmediata Lonja, a la derecha, estaba teniendo lugar una representaciâ”œâ”‚n de jotas, y los aparatos televisores retransmitâ”œÂ¡an a quienes no habâ”œÂ¡an podido entrar a verlo en directo, cortesâ”œÂ¡a de una local empresa especializada en la venta de electrodomâ”œÂ®sticos. En la imagen, las traseras del monumento a Francisco de Goya, como telâ”œâ”‚n de fondo al espectâ”œÃ­culo, de cuando "ver la tele" era un privilegiado entretenimiento. Fuente: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65554200, -0.87691100, '0101000020E6100000C21550A8A70FECBFC493DDCCE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30074102022.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30074102022.webp', 'https://www.flickr.com/photos/zaragozaantigua/30074102022/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23867, 'El Pilar 1906', 'Vista del Pilar desde el paseo del Ebro, con el palacio de Ayerbe a la izquierda, y la torre sureste andamiada por estar a punto de ser terminada.', 1906, 1906, 1906, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65647100, -0.87648200, '0101000020E6100000A60BB1FA230CECBFDFE2E13D07D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30640584910.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30640584910.webp', 'https://www.flickr.com/photos/zaragozaantigua/30640584910/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23873, 'Procesiâ”œâ”‚n Lonja 1940', 'La Virgen del Pilar es llevada en procesiâ”œâ”‚n ante la Lonja, durante los actos del XIX centenario de su viaje a Zaragoza, exactamente el aâ”œâ–’o 40. Destaca la presencia de representantes civiles. Al fondo, la manzana de casas que en pocos aâ”œâ–’os serâ”œÃ­ derribada para construir el nuevo ayuntamiento. Fuente: www.facebook.com/groups/fotosantiguasdezaragoza/permalink...', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65562800, -0.87691200, '0101000020E6100000D9092FC1A90FECBFC32B499EEBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30880033041.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30880033041.webp', 'https://www.flickr.com/photos/zaragozaantigua/30880033041/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23876, 'Paseo del Ebro 1940', 'Imagen capturada en los jardines y zona de esparcimiento entre la antigua Lonja y el paseo del Ebro. A la izquierda, las traseras de los edificios recayentes a la calle del Pilar, como la antigua posada de los Reyes, y el palacio de Ayerbe, con su reciclado cenador que al fondo despunta del jardâ”œÂ¡n vallado. Fuente visual: Ferrâ”œÃ­n Forns Navarro, Ajuntament de Girona.', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65610300, -0.87648200, '0101000020E6100000A60BB1FA230CECBF5CE7DF2EFBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30979688124.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30979688124.webp', 'https://www.flickr.com/photos/zaragozaantigua/30979688124/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23883, 'Palacio de Ayerbe aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste que muestra la Posada de los Reyes y el Palacio de Ayerbe, en el paseo de la Ribera. Estos edificios se encontraban entre la Lonja y el Pilar. Fuente: Lâ”œÃ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65640500, -0.87693400, '0101000020E6100000CD0358E4D70FECBF27F73B1405D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31629399793.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31629399793.webp', 'https://www.flickr.com/photos/zaragozaantigua/31629399793/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23902, 'Plaza del Pilar 1967', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 1 de la plaza de La Seo, esquinero con la calle de Don Jaime I. con una vista de la plaza del Pilar que alcanza hasta San Juan de los Panetes, al fondo. En primer tâ”œÂ®rmino, el moderno Monumento a Goya. La ocupaciâ”œâ”‚n de la plaza como espacio de aparcamiento de vehâ”œÂ¡culos progresa adecuadamente.', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65548700, -0.87681400, '0101000020E61000002499D53BDC0EECBF01FA7DFFE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49328681616.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49328681616.webp', 'https://www.flickr.com/photos/zaragozaantigua/49328681616/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23904, 'Paseo del Ebro c.1930', 'Imagen capturada desde la altura del Seminario Conciliar en el arranque de la calle de Don Jaime I y orientada hacia el noroeste, siguiendo la perspectiva del paseo del Ebro. En primer tâ”œÂ®rmino, caseta del peso pâ”œâ•‘blico de la Puerta del â”œÃ¼ngel y los Jardines de la Lonja, las traseras de los inmuebles del tramo de los impares de la calle del Pilar, con el homâ”œâ”‚nimo templo de telâ”œâ”‚n de fondo edilicio. A la derecha, cauce del râ”œÂ¡o Ebro y arboleda de Macanaz,', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65612000, -0.87648100, '0101000020E61000008F17D2E1210CECBF32207BBDFBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50150605706.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50150605706.webp', 'https://www.flickr.com/photos/zaragozaantigua/50150605706/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23908, 'Paseo del Ebro c.1908', 'Despejada y luminosa imagen capturada en el paseo del Ebro a la altura del fielato de consumos de la Puerta del â”œÃ¼ngel, con una interesante panorâ”œÃ­mica de la antigua fachada urbana del inmediato tramo ribereâ”œâ–’o, desde la posada de los Reyes, junto a cuya solanera se concentran varios carros y caballerâ”œÂ¡as, las traseras y jardines de la gran casa de los Ayerbe, las casas de los Infantes y el templo del Pilar. A la derecha, poste del tendido elâ”œÂ®ctrico de la lâ”œÂ¡nea de Circunvalaciâ”œâ”‚n.', 1908, 1908, 1908, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65641700, -0.87668500, '0101000020E6100000AF997CB3CD0DECBFEBC4E57805D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51719140471.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51719140471.webp', 'https://www.flickr.com/photos/zaragozaantigua/51719140471/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23909, 'Plaza del Pilar 1966', 'Nocturna e invernal imagen capturada en la plaza del Pilar y en el entorno al monumento a Francisco de Goya, centrada en el montaje realizado por el establecimiento "Radio La Corona" consistente en la instalaciâ”œâ”‚n de algo mâ”œÃ­s de treinta televisores "Vanguard" para ofrecer la retransmisiâ”œâ”‚n de la ceremonia de homenaje al equipo cultural-deportivo que presidido por el fotâ”œâ”‚grafo Guillermo Fatâ”œÃ­s Ojuel representaba a Zaragoza en el concurso de TVE "La uniâ”œâ”‚n hace la fuerza" y en el que resultâ”œâ”‚ ganador. Tambiâ”œÂ®n fueron homenajeados los componentes del equipo finalista, de La Coruâ”œâ–’a. Ademâ”œÃ­s los ganadores se llevaron 999.999 pesetas, y 333.333 los finalistas. Mientras en la Lonja tenâ”œÂ¡a lugar la gran ceremonia de homenaje con presencia de las autoridades locales y del jefe de programas de TVE, seâ”œâ–’or Adolfo Suâ”œÃ­rez Gonzâ”œÃ­lez, siendo presentada y animada por los conductores del programa televisivo seâ”œâ–’ores Mario Beut y Antolâ”œÂ¡n Garcâ”œÂ¡a, estos televisores sirvieron al doble propâ”œâ”‚sito de ofrecer las imâ”œÃ­genes retransmitidas en directo a quienes no pudieron ingresar al interior de la Lonja, y de servir de publicidad para la firma comercial que los instalâ”œâ”‚. Al fondo y a la izquierda del abarrotado entorno al monumento a Goya, cartel luminoso del Cine Pax en la plaza de La Seo.', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65548700, -0.87681400, '0101000020E61000002499D53BDC0EECBF01FA7DFFE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52464858820.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52464858820.webp', 'https://www.flickr.com/photos/zaragozaantigua/52464858820/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23965, 'Requetâ”œÂ® navarro 1936', 'AHPZ. Archivo Coyne. Manuel Coyne. 1936. Tras el 18 de julio, voluntarios carlistas navarros, o requetâ”œÂ®s (denominaciâ”œâ”‚n de los soldados carlistas durante la Primera Guerra Carlista, 1833-1840), secundaron las fuerzas nacionalistas que se levantaron en armas contra la Repâ”œâ•‘blica democrâ”œÃ­tica. "Pacificada" Navarra, se plantaron como fuerza de choque armada en los frentes abiertos, como Zaragoza. En la imagen, el Ã”Ã‡Â£Tercio de Doâ”œâ–’a Marâ”œÂ¡a de las NievesÃ”Ã‡Ã˜ de requetâ”œÂ®s navarros, tras cruzar el puente de Piedra, llega al entorno de la Seo. A la izquierda, la Lonja y la calle del Pilar. Al fondo, el cuartel de San Lâ”œÃ­zaro.', 1936, 1936, 1936, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65571100, -0.87630900, '0101000020E61000004818062CB90AECBF50508A56EED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15020622255.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15020622255.webp', 'https://www.flickr.com/photos/zaragozaantigua/15020622255/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23971, 'Majas Internacionales 1975', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 27/05/1975. "Majas Internacionales." En coherencia con la declaraciâ”œâ”‚n por parte de la ONU de 1975 como "Aâ”œâ–’o Internacional de la Mujer", en Zaragoza se celebra la orgâ”œÃ­nica elecciâ”œâ”‚n de la "Maja Internacional". En la imagen, las aspirantes al tâ”œÂ¡tulo, tras una recepciâ”œâ”‚n oficial en el Ayuntamiento a cargo del Alcalde, Mariano Horno Liria, hacen un simpâ”œÃ­tico posado-homenaje ante el monumento a Francisco Goya en la Plaza del Pilar, pero Goya no cabe en la foto. Al fondo, a la izquierda, cartel del Cine Pax. A la derecha, encima de la Estatua de la Libertad humanizada, visual de la plaza de La Seo.', 1975, 1975, 1975, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65548700, -0.87679200, '0101000020E6100000309FAC18AE0EECBF01FA7DFFE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15111823609.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15111823609.webp', 'https://www.flickr.com/photos/zaragozaantigua/15111823609/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23979, 'Muâ”œâ–’ecos timbaleros 1905', 'Fotograbado "La Luz". 1905. "Los timbaleros del Ayuntamiento". Esta tarjeta postal reproduce el fotomontaje de unos muâ”œâ–’ecos vestidos con el uniforme de Timbaleros del Ayuntamiento, delante de una imagen de la fachada del entonces edificio del Ayuntamiento de la ciudad, situado en las traseras de La Lonja. Aâ”œâ–’os despuâ”œÂ®s el Ayuntamiento serâ”œÂ¡a trasladado a la calle de la Democracia. Fuente: "La tarjeta postal ilustrada", Francisco Palâ”œÃ­ Laguna.', 1905, 1905, 1905, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65603200, -0.87641600, '0101000020E6100000C91D3691990BECBF939048DBF8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15299563115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15299563115.webp', 'https://www.flickr.com/photos/zaragozaantigua/15299563115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23980, 'Pablo Serrano 1975', 'Pablo Serrano Aguilar durante el montaje de la Exposiciâ”œâ”‚n antolâ”œâ”‚gica organizada por la Comisiâ”œâ”‚n de Cultura del Ayuntamiento en el Palacio de la Lonja (marzo-abril de 1975), con el posado del autor junto a Interpretaciâ”œâ”‚n de La Piedad, una de las obras expuestas. En septiembre de ese aâ”œâ–’o, y en protesta por los fusilamientos ejecutados por el râ”œÂ®gimen franquista a finales de ese mes, retirâ”œâ”‚ su obra de la exposiciâ”œâ”‚n Telecom 75 (Ginebra, Suiza).', 1975, 1975, 1975, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65584700, -0.87662100, '0101000020E6100000FF93BF7B470DECBF011764CBF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15302777212.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15302777212.webp', 'https://www.flickr.com/photos/zaragozaantigua/15302777212/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24071, 'La Lonja 1966', 'Imagen de la danesa Jeannette Christjansen (centro) tras su proclamaciâ”œâ”‚n como Maja Internacional 1966 en la Lonja, acompaâ”œâ–’ada de sus cuatro Damas de Honor: de izquierda a derecha, la irlandesa Muriel O''Hanlon, la belga Rossette Menegain, la francesa Liliane Burnier, y la espaâ”œâ–’ola Silvia Veiga. En el posado van vestidas a la manera tradicionalista de maja espaâ”œâ–’ola, y Jeannette luce capote de brega firmado para la ocasiâ”œâ”‚n por el popular matador de toros Manuel Benâ”œÂ¡tez "El Cordobâ”œÂ®s". El jurado del certamen estuvo compuesto por ilustres damas locales, esposas de las autoridades provinciales, y varios "crâ”œÂ¡ticos de bellezas femeninas" como el modisto Pedro Rodrâ”œÂ¡guez, el director del No-Do, Manuel Augusto Garcâ”œÂ¡a Viâ”œâ–’olas (se rodâ”œâ”‚ un reportaje para este noticiario), Pedro Chicote, y Antonio Mingote. Fuente visual: revista Blanco y Negro (Madrid), en hemeroteca.abc.es/', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65582800, -0.87662300, '0101000020E61000002D7C7DAD4B0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34333147690.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34333147690.webp', 'https://www.flickr.com/photos/zaragozaantigua/34333147690/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24081, 'Calle Don Jaime 1904', 'Foto: Lete. En el marco de las fiestas de octubre, se celebrâ”œâ”‚ una recepciâ”œâ”‚n municipal a "los representantes de la Coronilla de Aragâ”œâ”‚n". La imagen capta el momento en que estos llegan "con su famosa senyera" hasta las casas del Ayuntamiento, al fondo. A la izquierda, fachada este de la Lonja. Fuente: Diario ABC, 27-10-1904.', 1904, 1904, 1904, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65574000, -0.87634200, '0101000020E6100000368FC360FE0AECBFEB56CF49EFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39256330224.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39256330224.webp', 'https://www.flickr.com/photos/zaragozaantigua/39256330224/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21354, 'Plaza de la Constituciâ”œâ”‚n 1900', 'Invernal escena capturada en la plaza de la Constituciâ”œâ”‚n centrada en el emboque a la calle de los Mâ”œÃ­rtires, flanqueada por los inmuebles de los nâ”œâ•‘meros 35-39 del Coso a la izquierda y los nâ”œâ•‘meros 41-45 a la derecha. En la solana de los bajos de estos edificios destaca la nutrida presencia de varias decenas de paisanos en lo que era denominado castiza y clasistamente "brasero de los pobres", uno de los varios existentes en la ciudad. A la derecha y en la calzada inmediata puede verse un coche cerrado tipo C, posiblemente de los construidos en Liverpool por Julius G. Neville, en servicio en la lâ”œÂ¡nea de Torrero. Si bien el Ayuntamiento habâ”œÂ¡a autorizado en 1898 el cambio de sistema de tracciâ”œâ”‚n para seguir asâ”œÂ¡ el modelo de la pionera Bilbao, en la imagen este coche sigue estando traccionado por una pareja de machos que le daban una velocidad media de 10-15 km/hora. En primer tâ”œÂ®rmino, la Fuente de la Princesa, sobre la que ya desde 1886 pendâ”œÂ¡a la amenaza de desmonte y sustituciâ”œâ”‚n primero por otra fuente "mâ”œÃ­s câ”œâ”‚moda y mâ”œÃ­s artâ”œÂ¡stica", una estatua del Justicia Juan Lanuza luego, y finalmente el monumento que hoy ocupa su lugar. Por ello, no eran extraâ”œâ–’os los abundantes y denigrantes epâ”œÂ¡tetos difundidos en la prensa de la â”œÂ®poca y dedicados a ella como cada vez que en esta ciudad se quiere derribar o desmontar algâ”œâ•‘n edificio o monumento: "antigua", "antiestâ”œÂ®tica", "horrible", "vetusta"... En la imagen puede apreciarse que le falta el brazo derecho, efecto derivado de la agresiâ”œâ”‚n de un paisano pasado de algo. Parece ser magnâ”œÂ®tica la presencia de este bulto redondo, se encuentre ubicado donde sea, a las agresiones en su contra, bien centradas en su extendido brazo derecho o bien en el tridente que porta. Ya en 1860 se le tuvo que reponer este mismo brazo con motivo de la visita de la reina Isabel II que tuvo lugar ese aâ”œâ–’o.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65220100, -0.88104400, '0101000020E6100000E7C8CA2F8331ECBF91B586527BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54776029575.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54776029575.webp', 'https://www.flickr.com/photos/zaragozaantigua/54776029575/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24124, 'La Lonja 1966', 'Imagen capturada en la Lonja durante la "presentaciâ”œâ”‚n en sociedad" de treinta y cinco "damitas zaragozanas" pertenecientes a la alta sociedad local en la "Gran Gala de Debutantes" organizada por la Comisiâ”œâ”‚n de Fiestas el 8 de octubre de ese aâ”œâ–’o. La fiesta escenificâ”œâ”‚ que estas jâ”œâ”‚venes de la Zaragoza de bien vestâ”œÂ¡an "sus primeras galas de mujer" por primera vez en un festejo colectivo que tradicionalmente se realizaba de forma individual, bien en el Casino Mercantil, bien en la propia Lonja municipal. El inusual nâ”œâ•‘mero de "jovencitas" participantes en 1966 fue sustancialmente reducido en aâ”œâ–’os siguientes, probablemente para conferir al acto un carâ”œÃ­cter mâ”œÃ­s exclusivo y menos colectivo, o tal vez por el creciente desapego social a este tipo de ceremoniales tan carpetovetâ”œâ”‚nicos. En la imagen posan escalonadas las treinta y cinco "bellâ”œÂ¡simas seâ”œâ–’oritas debutantes en primorosos modelos de noche" portando una rosa roja. Las flanquean elementos de la Policâ”œÂ¡a Municipal en traje de gala. A la izquierda y ante el micrâ”œâ”‚fono, Demetrio Galâ”œÃ­n Bergua pronuncia un discurso "dedicado a exaltar las virtudes y belleza de nuestras mujeres" y donde les advertâ”œÂ¡a que "de ahora en adelante debâ”œÂ¡an ser modelos y prototipos de damas aragonesas", sea lo que sea que significara esta aserciâ”œâ”‚n.', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65581500, -0.87657800, '0101000020E61000002D944C4EED0CECBFF59CF4BEF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54664598920.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54664598920.webp', 'https://www.flickr.com/photos/zaragozaantigua/54664598920/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24125, 'La Lonja 1967', 'Imagen capturada en la Lonja durante la exclusiva e iniciâ”œÃ­tica "gran gala de debutantes" que tuvo lugar el 7 de octubre de ese aâ”œâ–’o organizada por el Ayuntamiento en beneficio de la Asociaciâ”œâ”‚n Nacional de la Lucha Contra el Câ”œÃ­ncer. La habitual presencia de las primeras autoridades locales fue eclipsada por acudir a ella para presidir el acto en carne mortal la unigâ”œÂ®nita Marâ”œÂ¡a del Carmen Franco Martâ”œÂ¡nez-Bordiâ”œâ•‘, consorte X marquesa de Villaverde, en su calidad de presidenta de la referida asociaciâ”œâ”‚n anticancerâ”œÂ¡gena, acompaâ”œâ–’ada por su esposo el docto marquâ”œÂ®s, al que las malas lenguas calificaban por razones que no vienen al cuento como "El Yernâ”œÂ¡simo", "marquâ”œÂ®s de Vespaverde" o "marquâ”œÂ®s de Vayavida". En esta ocasiâ”œâ”‚n fueron quince las "seâ”œâ–’oritas debutantes vestidas de blanco y magnâ”œÂ¡ficas en su juventud y belleza" que "vistieron sus primeras galas de mujer". En la imagen algunas de ellas posan ordenadas en filas tras saludar personalmente y recibir de manos de la marquesa de Villaverde sus "carnets de baile" y antes de su desfile tras el que se sentarâ”œÂ¡an para dar inicio a la cena y el posterior baile que durâ”œâ”‚ hasta las primeras horas de la madrugada, amenizado por las orquestas "Los Magos y Farrâ”œÂ®s" y el conjunto "Los Sarakostas" y que contâ”œâ”‚ ademâ”œÃ­s con las actuaciones de Marâ”œÂ¡a Dolores Pradera, acompaâ”œâ–’ada de los Gemelos; el dâ”œâ•‘o Juan y Junior, y el Quinteto del Club de Jazz de Radio Zaragoza.', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65581500, -0.87657800, '0101000020E61000002D944C4EED0CECBFF59CF4BEF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54668742814.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54668742814.webp', 'https://www.flickr.com/photos/zaragozaantigua/54668742814/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24138, 'Feria de Muestras 1934', 'Foto A. de la Barrera, 1934. Interior de la Lonja de Zaragoza durante la celebraciâ”œâ”‚n de la I Feria de Muestras Regional Aragonesa. Vemos la esquina suroeste del edificio, con el stand de la Sociedad General de Esterilizaciâ”œâ”‚n, cuyo domicilio social estaba en la calle de Joaquâ”œÂ¡n Costa 16. El procedimiento domâ”œÂ®stico Foncal, patentado por esa empresa, conseguâ”œÂ¡a matar las bacterias del agua mediante un proceso catalâ”œÂ¡tico, al instalar en las tuberâ”œÂ¡as un ingenio metâ”œÃ­lico. Fuente: Revista Aragâ”œâ”‚n, diciembre de 1934.', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65585400, -0.87681500, '0101000020E61000003B8DB454DE0EECBFB3791C06F3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20031364553.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20031364553.webp', 'https://www.flickr.com/photos/zaragozaantigua/20031364553/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24143, 'Feria de Muestras 1934', 'Plano del recinto de la I Feria de Muestras Regional Aragonesa, 1934. La Sociedad Econâ”œâ”‚mica Aragonesa de Amigos del Paâ”œÂ¡s organizâ”œâ”‚ en 1934 la primera Feria de Muestras Aragonesa en el palacio de la Lonja y sus jardines adyacentes. Se trataba de un muestrario de empresas de industria y comercio, que aparecen en el listado bajo el grâ”œÃ­fico. La entrada tenâ”œÂ¡a lugar en el edificio, por la calle Don Jaime I, y la salida por los jardines. Al aâ”œâ–’o siguiente se celebrâ”œâ”‚ la segunda, en la â”œâ•‘ltima zona de cubrimiento del râ”œÂ¡o Huerva, cercana a la plaza de Paraâ”œÂ¡so. No hubo mâ”œÃ­s, hasta 1941. Fuente: Revista Aragâ”œâ”‚n, diciembre de 1934.', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65592600, -0.87654600, '0101000020E610000056116E32AA0CECBF4D4C1762F5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20465197289.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20465197289.webp', 'https://www.flickr.com/photos/zaragozaantigua/20465197289/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24154, 'Expo 1919', 'Medalla en bronce realizada por el escultor Josâ”œÂ® Clara para conmemorar la Exposiciâ”œâ”‚n Hispano-Francesa de Bellas Artes celebrada en la Lonja durante los meses de mayo y junio de ese aâ”œâ–’o, en cuya secciâ”œâ”‚n espaâ”œâ–’ola se pudo ver obras de, entre otros, Nonell, Picasso, Regoyos, Zuloaga, Benlliure, Gargallo, Julio Antonio, y Macho. De la parte francesa, la representaciâ”œâ”‚n incluyâ”œâ”‚, entre otros, a los pintores Vlaminck, Friesz, Camoin, siendo la primera vez que en Zaragoza se veâ”œÂ¡an sus obras "fauves". Esta exposiciâ”œâ”‚n, a diferencia de la de 1908, apenas fue cubierta por los medios de comunicaciâ”œâ”‚n, de forma que casi nadie se enterâ”œâ”‚, ni antes, durante, ni despuâ”œÂ®s. La medalla de la imagen representa idealmente a Francia, con Marianne, y a Espaâ”œâ–’a, con una baturra, tal vez de nombre Pilar. Fuente visual: www.museunacional.cat/', 1919, 1919, 1919, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65580900, -0.87663000, '0101000020E6100000CC28965B5A0DECBF13B69F8CF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30144516644.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30144516644.webp', 'https://www.flickr.com/photos/zaragozaantigua/30144516644/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22315, 'Calle de Pedro Cubero c.1965', 'Procesiâ”œâ”‚n de Santa Rosa de Lima, patrona del barrio de Las Fuentes, a cargo de los tranviarios residentes en el Grupo Vizconde de Escoriaza, pasando por la calle de Pedro Cubero en direcciâ”œâ”‚n a la de Salvador Minguijâ”œâ”‚n, procedente la parroquia del mencionado Grupo de viviendas, levantado en 1953 para los trabajadores de la sociedad Tranvâ”œÂ¡as de Zaragoza. Su presidente, â”œÃ¼ngel Escoriaza Castillâ”œâ”‚n, introdujo el culto a la santa peruana en el barrio.', 1965, 1965, 1965, 'Anos 60', 'LAS FUENTES', 41.64783000, -0.86011000, '0101000020E61000004BCD1E680586EBBF10AFEB17ECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15759816212.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15759816212.webp', 'https://www.flickr.com/photos/zaragozaantigua/15759816212/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24155, 'La Lonja 1919', 'Imagen del interior de la antigua Lonja, como escenario de la Exposiciâ”œâ”‚n Hispano-Francesa de Bellas Artes celebrada durante los meses de mayo y junio de ese aâ”œâ–’o. La toma longitudinal (posiblemente con el lienzo este al fondo), ilustra la disposiciâ”œâ”‚n espacial de algunos de los bultos redondos y cuadros de la exposiciâ”œâ”‚n, la decoraciâ”œâ”‚n con motivos florales, y la iluminaciâ”œâ”‚n por medio de grandes lâ”œÃ­mparas que penden de las renacentistas bâ”œâ”‚vedas. De entre los bultos redondos que aparecen en la imagen, destacamos las dos obras de Josâ”œÂ® Clarâ”œÃ­: "El crepâ”œâ•‘sculo", y "La diosa". Del local escultor Josâ”œÂ® Bueno, que entonces estaba terminando su recreaciâ”œâ”‚n del rey Alfonso I "El Batallador" para el monumento del cabezo de Buenavista, esta muestra contâ”œâ”‚ con sus obras "La tarde", y "Humanidad". La primera decorarâ”œÂ¡a un jardâ”œÂ¡n urbano cerca de la plaza de Aragâ”œâ”‚n, y la segunda serâ”œÂ¡a colocada en la "fosa comâ”œâ•‘n" del cementerio. Fuente visual: Foto Cepero, revista "La Esfera", en hemerotecadigital.bne.es/', 1919, 1919, 1919, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65580900, -0.87663000, '0101000020E6100000CC28965B5A0DECBF13B69F8CF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30752746936.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30752746936.webp', 'https://www.flickr.com/photos/zaragozaantigua/30752746936/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24163, 'Feria de Muestras 1934', 'Imagen con uno de los carteles anunciadores de la primera Feria de Muestras organizada en octubre de 1934 en el recinto de la Lonja y sus adyacentes jardines, en una instalaciâ”œâ”‚n coordinada por el arquitecto Borobio. El cartel, diseâ”œâ–’ado por Guillermo Pâ”œÂ®rez, recoge precisamente la antigua Lonja como escenario central de la muestra, y se centra en su fachada recayente a la calle de Don Jaime I. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65582800, -0.87662300, '0101000020E61000002D7C7DAD4B0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36522148345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36522148345.webp', 'https://www.flickr.com/photos/zaragozaantigua/36522148345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24165, 'Paseo del Ebro 1934', 'Excepcional imagen capturada en el paseo del Ebro y centrada en el cruce con la calle de Don Jaime I, donde destaca el montaje realizado con motivo de la I Feria de Muestras Regional Aragonesa, celebrada entre el 5 y el 20 de octubre de 1934 en el espacio de la antigua Lonja, con 51 "stands", y los jardines inmediatos, donde se dio cabida a otros 27 "stands" ademâ”œÃ­s de un bar y un tablado para mâ”œâ•‘sica. Junto a la zona de los pabellones montados donde estuviera la antigua Casa Consistorial, delimitados por numerosas banderas y banderolas festivas, la caseta de consumos de la Puerta del â”œÃ¼ngel y el quiosco de la Sociedad Protectora de Animales. De fondo, la monumental fachada al paseo formada por las traseras de la calle del Pilar, con la Posada del Rey y el palacio de los marqueses de Ayerbe, y el templo del Pilar. Por el paseo circula un tranvâ”œÂ¡a de la lâ”œÂ¡nea "6. Magdalena-Mercado". En primer tâ”œÂ®rmino y a la izquierda, esquina del Seminario conciliar. Hacia la derecha, acceso al Puente de Piedra.', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65605600, -0.87621300, '0101000020E6100000C18F6AD8EF09ECBF1B2C9CA4F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52278034883.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52278034883.webp', 'https://www.flickr.com/photos/zaragozaantigua/52278034883/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24219, 'Comparsa 1901', 'Gigantes y Cabezudos junto a la Lonja en 1901. La comparsa estâ”œÃ­ viniendo por la calle del Pilar (a la izquierda) hacia la de Don Jaime I. La imagen estâ”œÃ­ tomada desde la plaza de La Seo. En primer tâ”œÂ®rmino, el cabezudo Robaculeros.', 1901, 1901, 1901, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65546700, -0.87647600, '0101000020E61000001E537765170CECBFBA4DB857E6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15246931012.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15246931012.webp', 'https://www.flickr.com/photos/zaragozaantigua/15246931012/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24226, 'Timbaleros 1891', '"Los timbaleros de la ciudad de Zaragoza", â”œâ”‚leo sobre lienzo, Anselmo Gascâ”œâ”‚n de Gotor, 1891. Los timbaleros, al frente de una comitiva de ministriles seguida de los maceros. Tras ellos, los oficios concejiles con sombreros de copa. Salen del Ayuntamiento, a la derecha de la Lonja y fuera de la imagen. Al fondo, la calle del Pilar. Fuente: "El municipio en Aragâ”œâ”‚n", DPZ, 2004.', 1891, 1891, 1891, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65553200, -0.87653900, '0101000020E6100000B66455849B0CECBFA1BDFA78E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20532962772.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20532962772.webp', 'https://www.flickr.com/photos/zaragozaantigua/20532962772/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24233, 'Gigantes y cabezudos 1859', 'Dibujo alusivo a las fiestas del Pilar de 1859, con la comparsa de gigantes y cabezudos, proveniente de la calle del Pilar y situada en la plaza de La Seo, con vistas a la Lonja (al fondo a la derecha). Estas figuras serâ”œÃ­n remplazadas al aâ”œâ–’o siguiente por las diseâ”œâ–’adas por Fâ”œÂ®lix Oroz. Tambiâ”œÂ®n el edificio de la izquierda desaparecerâ”œÃ­ en poco tiempo.', 1859, 1859, 1859, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65549100, -0.87638700, '0101000020E61000003677F4BF5C0BECBF42E90B21E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29398419343.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29398419343.webp', 'https://www.flickr.com/photos/zaragozaantigua/29398419343/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24385, 'Calle del Pilar 1931', 'En el contexto de la celebraciâ”œâ”‚n del Centenario IV del nacimiento de Teresa de Cepeda y Ahumada, la Compaâ”œâ–’â”œÂ¡a de Santa Teresa de Jesâ”œâ•‘s proyecta en 1915 una expansiâ”œâ”‚n que incluye la estratâ”œÂ®gica plaza de Zaragoza, con la idea de fundar una escuela de formaciâ”œâ”‚n de maestras catâ”œâ”‚licas. En setiembre de ese aâ”œâ–’o llegan a la ciudad las primeras HH. Teresianas a buscar ubicaciâ”œâ”‚n, mientras se alojan donde las Oblatas (Pâ”¬â•‘ de las Damas). El Arzobispo Soldevila les ofrece las ruinas del antiguo convento de las Adoratrices, en San Juan de los Panetes, mas se inclinan por un piso de alquiler en la calle del Pilar, con el azulejo nâ”œâ•‘mero 19, en el edificio esquinero justo antes de la Seo, donde confluye la calle de Bayeu. Establecidas ya al comienzo de ese curso, el piso quedâ”œâ”‚ pronto pequeâ”œâ–’o, debiendo expandirse al entresuelo y a dos pisos extra del mismo edificio para dar cabida tanto a las alumnas internas de magisterio, como al alumnado externo de primeras enseâ”œâ–’anzas. La demanda de plazas continuaba, y resultaba imposible continuar allâ”œÂ¡, de forma que a comienzos de los aâ”œâ–’os 20 se buscâ”œâ”‚ una nueva ubicaciâ”œâ”‚n, mâ”œÃ­s espaciosa, que se encontrâ”œâ”‚ en los promisorios terrenos en urbanizaciâ”œâ”‚n de la antigua huerta de Santa Engracia, en el entorno de la nueva plaza de Castelar. La imagen de Roisin estâ”œÃ­ realizada desde la plaza de la Seo, cuando el Colegio Teresiano estaba ya en su nueva ubicaciâ”œâ”‚n de la calle Sanclemente, aunque la fenomenal fotografâ”œÂ¡a recoge tal vez la mejor instantâ”œÃ­nea con detalle del edificio de la calle del Pilar (donde la panaderâ”œÂ¡a) que acogiâ”œâ”‚ la primera sede zaragozana del Colegio Teresiano del Pilar. Como todos sus vecinos de zona, a excepciâ”œâ”‚n de la Lonja, este edificio serâ”œÂ¡a demolido a finales de dâ”œÂ®cada. Fuente visual: Lucien Roisin, "Lonja y torres del Pilar", en "Zaragoza, aâ”œâ–’os veinte. 81 fotografâ”œÂ¡as de Roisin (1925-1931)", Instituciâ”œâ”‚n Fernando el Catâ”œâ”‚lico, 2014. Fuente textual: Exposiciâ”œâ”‚n "Centenario Compaâ”œâ–’â”œÂ¡a Santa Teresa de Jesâ”œâ•‘s - Zaragoza", y la muy amable colaboraci', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65574200, -0.87692200, '0101000020E6100000BC92E4B9BE0FECBF8B4E965AEFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23134325411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23134325411.webp', 'https://www.flickr.com/photos/zaragozaantigua/23134325411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24586, 'Lonja con andamio 1889', 'J. Lâ”œÂ®vy et Cie. "Palais de la bourse" (Palacio de la Bolsa), 1889 Podemos ver la Lonja con andamiaje, un tranvâ”œÂ¡a "de sangre" y un heterogâ”œÂ®neo conjunto de viandantes por el final de la calle de Don Jaime.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65550300, -0.87646400, '0101000020E61000000DE2033BFE0BECBF07B7B585E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14794547078.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14794547078.webp', 'https://www.flickr.com/photos/zaragozaantigua/14794547078/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24587, 'Lonja de Mercaderes. Interior. 1885', 'A.M.Z. Sign. 0913. La Lonja, Zaragoza. [1885] Magnâ”œÂ¡fico edificio civil renacentista que albergaba las reuniones de los prâ”œâ”‚ceres mercantiles de la ciudad (1551). Hoy sigue en pie en la plaza del Pilar, mostrando exposiciones municipales.', 1885, 1885, 1885, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65577200, -0.87651500, '0101000020E610000095826E2F690CECBFF6D03E56F0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14858893205.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14858893205.webp', 'https://www.flickr.com/photos/zaragozaantigua/14858893205/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24590, 'Lonja c.1877', 'Jean Laurent, "Zaragoza-La Lonja". Al principio de la antigua calle de la Cuchillerâ”œÂ¡a, otra de las imâ”œÃ­genes de la Lonja capturadas por Jean Laurent, en tiempos en que era utilizada como espacio para actos pâ”œâ•‘blicos varios, incluyendo el sorteo de "los Quintos" (Servicio Militar Obligatorio para quienes no podâ”œÂ¡an pagarse el no hacerlo), y algunas representaciones teatrales. A su derecha, y pegado, el edificio de la Casa Consistorial levantado unas dâ”œÂ®cadas antes, con resabios dieciochescos, y puerta principal de acceso arquitrabado y en orden dâ”œâ”‚rico. Fuente: "Mirar el mundo otra vez. 25 aâ”œâ–’os de fotografâ”œÂ¡a en la galerâ”œÂ¡a Spectrum".', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65572700, -0.87652800, '0101000020E6100000BCE7C072840CECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16610030380.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16610030380.webp', 'https://www.flickr.com/photos/zaragozaantigua/16610030380/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24593, 'Puerta del â”œÃ¼ngel c.1865', 'Vista de la â”œâ•‘ltima versiâ”œâ”‚n de la Puerta del â”œÃ¼ngel, con la Lonja en primer plano a la izquierda, seguida de las casas consistoriales. Fuente: Instantâ”œÃ­neas zaragozanas, CAMPZAR, 1982.', 1865, 1865, 1865, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65590200, -0.87614900, '0101000020E6100000118AADA06909ECBFC4B0C398F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24865007091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24865007091.webp', 'https://www.flickr.com/photos/zaragozaantigua/24865007091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24595, 'La Lonja 1991', 'Imagen de la escultura en bronce titulada "Caballito", con posado de su autor, el modelista Francisco Rallo Lahoz, en las traseras de la Lonja. El broncâ”œÂ¡neo equino fue concebido como homenaje de la ciudad al fotâ”œâ”‚grafo Angel Cordero Gracia, que ejerciâ”œâ”‚ de "minutero" en los jardines de la plaza de la Lonja recayentes al paseo del Ebro, entre 1925 y 1978, en el entorno donde fue ubicado este bulto redondo. El original caballito era de cartâ”œâ”‚n piedra, y en â”œÂ®l se sentaban las niâ”œâ–’as y niâ”œâ–’os que iban a ser retratados. Posiblemente esta imagen fuera capturada en la inauguraciâ”œâ”‚n oficial de esta obra. Fuente visual: Antonio Calvo Pedrâ”œâ”‚s, AMZ.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65610300, -0.87648200, '0101000020E6100000A60BB1FA230CECBF5CE7DF2EFBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30491155170.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30491155170.webp', 'https://www.flickr.com/photos/zaragozaantigua/30491155170/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24596, 'La Lonja c.1902', 'Imagen editada por la Fototipia Hauser y Menet (Madrid) con el nâ”¬â•‘ 134 de las imâ”œÃ­genes de "Zaragoza" incluidas en la serie postal de Espaâ”œâ–’a para la Uniâ”œâ”‚n Postal Universal, que captura una vista canicular de la Lonja desde cierta altura, en la arbolada plaza de la Seo. A la izquierda, la ensanchada esquina del final de la calle del Pilar. A la derecha, en la calle de Don Fernando el Catâ”œâ”‚lico, la Casa del Ayuntamiento. Al fondo, el puente de Piedra y casas del Arrabal. Fuente visual: www.todocoleccion.net/', 1902, 1902, 1902, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65582800, -0.87662300, '0101000020E61000002D7C7DAD4B0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33908400994.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33908400994.webp', 'https://www.flickr.com/photos/zaragozaantigua/33908400994/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24598, 'La Lonja c.1892', 'Imagen editada por la Fototipia Hauser y Menet (Madrid) con el nâ”¬â•‘ 287 entre las imâ”œÃ­genes de "Zaragoza" incluidas en la serie postal de Espaâ”œâ–’a, que captura una vista de la Lonja desde la zona de sombra maâ”œâ–’anera de la plaza de la Seo. A la izquierda, la esquina del final de la calle del Pilar. A la derecha, las Casas de la Ciudad, o ayuntamiento. En la plaza, a la derecha, e inmediatas, un grupo de mujeres se abastecen de agua en la fuente de la Samaritana (fuera de plano). Fuente visual: www.todocoleccion.net/', 1892, 1892, 1892, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65582800, -0.87662300, '0101000020E61000002D7C7DAD4B0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34673697456.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34673697456.webp', 'https://www.flickr.com/photos/zaragozaantigua/34673697456/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24599, 'La Lonja 1844', '"Salâ”œâ”‚n de la Lonja", como parte integrante de las Casas de la Ciudad, o Ayuntamiento. Fuente visual: "Recuerdos y Bellezas de Espaâ”œâ–’a. Obra destinada a dar a conocer sus monumentos, antigâ”œâ•edades y vistas pintorescas en lâ”œÃ­minas dibujadas del natural y litografiadas por F. J. Parcerisa, acompaâ”œâ–’adas de texto por P. Piferrer y J. M. Quadrado. Aragâ”œâ”‚n: Josâ”œÂ® Marâ”œÂ¡a Quadrado. 1844."', 1844, 1844, 1844, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65582800, -0.87662300, '0101000020E61000002D7C7DAD4B0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34737152251.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34737152251.webp', 'https://www.flickr.com/photos/zaragozaantigua/34737152251/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24600, 'Marquâ”œÂ®s de Almenara 1591', '"El pueblo zaragozano hiere al marquâ”œÂ®s de Almenara". Ilustraciâ”œâ”‚n de F. Blanch que recrea el ataque de algunos ciudadanos en 1591 contra â”œÃ¬â”œâ–’igo Hurtado de Mendoza y de la Cerda, marquâ”œÂ®s de Almenara, enviado por Felipe II a Zaragoza en 1588. Muriâ”œâ”‚ en la câ”œÃ­rcel dos semanas despuâ”œÂ®s. Al fondo, la calle del Pilar, la Lonja y las casas consistoriales. A la derecha, fragmento de la Diputaciâ”œâ”‚n del Reino en la plaza de la Seo. Fuente visual: Historia de Espaâ”œâ–’a, Miguel Seguâ”œÂ¡, 1910, en todocoleccion.net.', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65548300, -0.87641700, '0101000020E6100000E01115AA9B0BECBFBF0AF0DDE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40204809215.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40204809215.webp', 'https://www.flickr.com/photos/zaragozaantigua/40204809215/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24601, 'Plaza del Pilar 1981', 'Imagen capturada en la plaza del Pilar junto al ingreso principal a la Lonja, escenario de la Exposiciâ”œâ”‚n "50 aniversario del Cuerpo de Bomberos de Zaragoza", donde se conmemoraba a constituciâ”œâ”‚n de este Cuerpo como servicio profesional de extinciâ”œâ”‚n de incendios a cargo del Ayuntamiento en el aâ”œâ–’o 1931. El vehâ”œÂ¡culo de primer tâ”œÂ®rmino formaba parte de la exposiciâ”œâ”‚n de material histâ”œâ”‚rico de bomberos, y se trata de un camiâ”œâ”‚n que transportaba una escalera mâ”œâ”‚vil Magirus E-1 que estuvo en servicio desde 1937 y hasta 1966. Se considera que el â”œÂ®xito de esta exposiciâ”œâ”‚n fue el germen del Museo del Fuego inaugurado en 2012.', 1981, 1981, 1981, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65567900, -0.87673900, '0101000020E61000007B1684F23E0EECBF45D61A4AEDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50143937168.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50143937168.webp', 'https://www.flickr.com/photos/zaragozaantigua/50143937168/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24605, 'Plaza de la Seo 1974', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/Marzo 1974. Imagen de la Plaza de la Seo desde la calle Don Jaime. La fuente que aparece fue la que sustituyâ”œâ”‚ a la de La Samaritana, cuando fue desmontada y trasladada, primero al Parque Bruil, luego a la Plaza del Justicia. Mâ”œÃ­s tardes, a finales de los aâ”œâ–’os 80, la Plaza de la Seo habâ”œÂ¡a alcanzado un lamentable estado que llevâ”œâ”‚ a redactar un proyecto de remodelaciâ”œâ”‚n que incluâ”œÂ¡a el regreso de La Samaritana, pero el hallazgo de los restos del Foro Romano obligaron a transformar el proyecto en lo que hoy vemos.', 1974, 1974, 1974, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65551100, -0.87642200, '0101000020E610000052D66F26A60BECBF8995D1C8E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14718879029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14718879029.webp', 'https://www.flickr.com/photos/zaragozaantigua/14718879029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24608, 'La Seo aâ”œâ–’os 20', 'Otto Wunderlich. 1920-1936. "Zaragoza. [Plaza del Pilar] La Torre de la Seo [o La Catedral del Salvador en su Epifanâ”œÂ¡a y Puerta de San Bartolomâ”œÂ® en la fachada principal o neocâ”œÃ­sica]". Imagen tomada desde la calle el Pilar. Fuente visual: Archivo Wâ”œâ•nderlich (WUN-05810) www.mcu.es/fototeca_patrimonio/Visor?usarVisorMCU=true&am...', 1920, 1920, 1929, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65570300, -0.87679200, '0101000020E6100000309FAC18AE0EECBFCE716E13EED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877342207.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877342207.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877342207/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24612, 'â”œÃ¼ngel Cordero Gracia 1974', 'â”œÃ¼ngel Cordero Gracia ejerciâ”œâ”‚ de fotâ”œâ”‚grafo minutero desde 1925, retratando niâ”œâ–’os y niâ”œâ–’as sobre un caballito de madera en los jardines traseros de la Lonja. Era Minutero porque entre el posado, la instantâ”œÃ­nea, y el revelado, se sucedâ”œÂ¡an escasos minutos, una prâ”œÃ­ctica que estuvo realizando hasta 1978, y por la que pasaron varias generaciones de jâ”œâ”‚venes, y no tan jâ”œâ”‚venes, bien locales, o de paso por la ciudad. En 1991 el Ayuntamiento homenajeâ”œâ”‚ su memoria instalando, en el mismo espacio donde estuvo trabajando tanto tiempo, una escultura en bronce sobre pedestal circular de granito rosa, obra de Francisco Rallo Lahoz, que representa al caballito protagonista de tantas instantâ”œÃ­neas. En la imagen, â”œÃ¼ngel Cordero se encamina, cargado con sus herramientas de trabajo recogidas en la plaza de San Bruno nâ”¬â•‘ 3, hacia la Lonja cruzando por la plaza de La Seo. El objetivo de la câ”œÃ­mara, aun cubierto, nos observaÃ”Ã‡Âª', 1974, 1974, 1974, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65551100, -0.87617000, '0101000020E6100000EF8FF7AA9509ECBF8995D1C8E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15047796462.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15047796462.webp', 'https://www.flickr.com/photos/zaragozaantigua/15047796462/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24627, 'Calle del Pilar 1920', 'Foto: Julio Requejo. Aspecto de la calle del Pilar con la Seo al fondo, en junio de 1920. La imagen ha sido volteada horizontalmente para su correcta visualizaciâ”œâ”‚n. Fuente: DARA/AHPZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65572700, -0.87652800, '0101000020E6100000BCE7C072840CECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21193339789.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21193339789.webp', 'https://www.flickr.com/photos/zaragozaantigua/21193339789/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24658, 'Plaza de La Seo c.1942', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 19 de la antigua calle del Pilar antes de su derribo para despejar de viejas casonas el tramo mâ”œÃ­s oriental de la ampliada plaza del Pilar, y dejar espacio a la nueva Casa Consistorial. Inmediata y a la izquierda, la Lonja, y al fondo, la plaza de La Seo. A la derecha y fuera de plano, el despejado solar sobre el que estaba proyectado construir, entre otros edificios, la nueva sede del Gobierno Civil.', 1942, 1942, 1942, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65578300, -0.87694200, '0101000020E610000083A44FABE80FECBFEA2285B2F0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49305726783.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49305726783.webp', 'https://www.flickr.com/photos/zaragozaantigua/49305726783/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25198, 'Puerta del â”œÃ¼ngel 1851', '"Dibujos que representan dos proyectos para la Puerta del â”œÃ¼ngel de esta Ciudad, arreglados â”œÃ­ lo mandado por M. II. SS. Gobernador de la Provincia, y Alcalde Corregidor de esta Capital". Zaragoza, 12 de septiembre de 1851. Ninguno de los dos proyectos de esta puerta, entre las Casas Consistoriales y el Seminario Conciliar, fue levantado. En 1860 se erigiâ”œâ”‚ otro modelo, obra de Miguel Jeliner y Germâ”œÃ­. Fuente: AMZ.', 1851, 1851, 1851, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65596400, -0.87608600, '0101000020E61000007978CF81E508ECBF3AADDBA0F6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32126168596.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32126168596.webp', 'https://www.flickr.com/photos/zaragozaantigua/32126168596/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25650, 'Don Jaime I c.1925', 'Archivo Municipal de Zaragoza. "Procesiâ”œâ”‚n religiosa" en la que, aunque asâ”œÂ¡ lo parezca, quien va solemne bajo palio no es el tranvâ”œÂ¡a de la Lâ”œÂ¡nea "Arrabal". Imagen tomada en la calle Don Jaime, con la Lonja a la izquierda, y la plaza de la Seo a la derecha.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65562200, -0.87640700, '0101000020E6100000FD885FB1860BECBFE144F46BEBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14964558620.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14964558620.webp', 'https://www.flickr.com/photos/zaragozaantigua/14964558620/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25671, 'Don Jaime I, c.1925', '"Zaragoza II. [La Lonja]". Captura visual del entronque de la calle de don Jaime I, la calle del Pilar, a la izquierda, y la arbolada plaza de la Seo, a la derecha. Al fondo, el puente de Piedra. Vertebra la imagen el sencillo e imponente edificio de la antigua Lonja de mercaderes, ya despejada de las derribadas Casas de la Ciudad. A la izquierda, el antiguo nâ”¬â•‘ 6 de la calle Don Jaime I, derribado durante la radical creaciâ”œâ”‚n de la gran plaza del Pilar. Incrustados en el firme, los raâ”œÂ¡les tranviarios de las ya electrificadas lâ”œÂ¡neas "Arrabal" y "Gâ”œÃ­llego". La circulaciâ”œâ”‚n rodada, fluida. Fuente visual: Archivo del Conde de Polentinos (Aurelio de Colmenares y Orgaz), Fototeca del Patrimonio Artâ”œÂ¡stico', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65550100, -0.87642800, '0101000020E6100000DA8EA9BBB20BECBF66BFEE74E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27785373001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27785373001.webp', 'https://www.flickr.com/photos/zaragozaantigua/27785373001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25673, 'Don Jaime I, 1968', 'Imagen de la unidad nâ”¬â•‘ 164 (serie 150, o topolinos), de la lâ”œÂ¡nea tranviaria 4 ("Arrabal") encaminada hacia la plaza de la Seo. Esta unidad se activaba cuando las dos tranvâ”œÂ¡as "oficiales" de la lâ”œÂ¡nea (el 223, y el 228) estaban averiados, como parece ser el caso. A la izquierda, el acceso desde el puente de Piedra. Detrâ”œÃ­s, el multifuncional edificio del arzobispado, antiguo Seminario Conciliar, ahora ocupado, entre otros, por Radio Popular, y por el cine Pax. A la derecha, quiosco y densa arboleda de la plaza de la Seo. Fuente visual: trotskeetravel.com/, a travâ”œÂ®s de www.forotrenes.com/', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65549100, -0.87638700, '0101000020E61000003677F4BF5C0BECBF42E90B21E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31170380711.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31170380711.webp', 'https://www.flickr.com/photos/zaragozaantigua/31170380711/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25676, 'Lonja c.1925', 'Imagen de la Lonja, despejada de las antiguas Casas de la Ciudad (ayuntamiento), estratâ”œÂ®gica entre las calles de don Jaime I y del Pilar, y el paseo del Ebro. Fuente visual: "Casa Lonja. Exterior", en Ã”Ã‡Â£El arte en Espaâ”œâ–’a. Zaragoza, con texto de Anselmo Gascâ”œâ”‚n de Gotor. Ediciâ”œâ”‚n Thomas. Patronato Nacional de Turismo.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65596400, -0.87608600, '0101000020E61000007978CF81E508ECBF3AADDBA0F6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33515081093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33515081093.webp', 'https://www.flickr.com/photos/zaragozaantigua/33515081093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25683, 'Calle de Don Jaime I 1968', 'Veraniega imagen capturada en la calle de Don Jaime I ( (original cardo de la Cesaraugusta romana) y centrada en el trolebâ”œâ•‘s nâ”¬â•‘ 14 modelo BUT London (ubicaciâ”œâ”‚n del volante a la diestra) de un piso realizando el trayecto de regreso en la lâ”œÂ¡nea Gâ”œÃ­llego y en direcciâ”œâ”‚n al tramo medio del Coso. De fondo edilicio, el antiguo seminario metropolitano, que entonces albergaba diversas dependencias del arzobispado, como Radio Popular y el cine Pax (que reestrenaba la comedia "Tres en un sofâ”œÃ­"), amâ”œÂ®n de la sucursal de una importante local caja de ahorros. Hacia la derecha se abre la plaza de La Seo.', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65552700, -0.87653500, '0101000020E61000005B94D920930CECBF8F52094FE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51570599902.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51570599902.webp', 'https://www.flickr.com/photos/zaragozaantigua/51570599902/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20883, 'La Seo s. XIV', 'Dibujo de Francisco â”œÃ¬â”œâ–’iguez, 1937. La recreaciâ”œâ”‚n representa el templo en su â”œÂ®poca mudâ”œÂ®jar. La tesis oficial no contempla que la actual torre barroca utilizara el emplazamiento del alminar octogonal de la mezquita mayor de Saraqusta, pero algunos investigadores sostienen esa opciâ”œâ”‚n. Fuente: sites.google.com/site/zagralandalus/los-alminares-de-la-seo, a travâ”œÂ®s de www.facebook.com/photo.php?fbid=1864645023755215&set=...', 1350, 1300, 1399, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65524300, -0.87609700, '0101000020E610000073F56393FC08ECBF6AF7AB00DFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30682686311.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30682686311.webp', 'https://www.flickr.com/photos/zaragozaantigua/30682686311/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20891, 'Gran Cloaca ca. 20', 'La â”¬Â½Gran Cloacaâ”¬â•— del foro romano de Caesaraugusta resurgiâ”œâ”‚ al levantar en 1982 la plaza de La Seo. Un siglo antes (1870) ya se dio con ella. Hoy se encuentra conservada como una estructura mâ”œÃ­s del Museo del Foro de Caesaraugusta. Fue realizada a finales del reinado de Augusto, o comienzos del de Tiberio, entre el aâ”œâ–’o 10 y el 20 de la Era, como parte del sistema de saneamiento y evacuaciâ”œâ”‚n de aguas del nuevo foro. Construida en opus caementicium, se cubriâ”œâ”‚ con bâ”œâ”‚veda de medio caâ”œâ–’â”œâ”‚n. La altura interior es de 2.64 m. y la luz de 1.78 m. El espesor de las paredes es de 60 cm. En la imagen, vista parcial de los restos de la "Gran Cloaca" al aire en la plaza de la Seo. Archivo Luis Serrano. Fuente: "El Ebro", Ediciones Oroel, 1986.', NULL, NULL, NULL, NULL, 'CASCO HISTâ”œÃ´RICO', 41.65529600, -0.87621900, '0101000020E61000004948A46DFC09ECBF8D9944BDE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16814002841.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16814002841.webp', 'https://www.flickr.com/photos/zaragozaantigua/16814002841/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21138, 'Plaza de La Seo c.1895', '"Vista de la Catedral de San Salvador (La Seo)", y de la Plaza de la Seo, desde altura. Fuente visual: Esudio Coyne (DARA-AHPZ).', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65516600, -0.87616500, '0101000020E61000007DCB9C2E8B09ECBFBFB9BF7ADCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14745087029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14745087029.webp', 'https://www.flickr.com/photos/zaragozaantigua/14745087029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21139, 'Plaza de La Seo c.1895', 'Vista de la Lonja de mercaderes desde la plaza de La Seo. Fuente visual: Estudio Coyne (DARA-AHPZ).', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65519000, -0.87621800, '0101000020E61000003354C554FA09ECBF47551344DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14750916237.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14750916237.webp', 'https://www.flickr.com/photos/zaragozaantigua/14750916237/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21150, 'Plaza de La Seo c.1895', '"La Lonja". Foto Colecciâ”œâ”‚n Universidad Michel de Montaigne, Burdeos. Toma de la plaza de la Seo de Zaragoza, mirando hacia la Lonja, cuando el antiguo edificio de viviendas (esquina entre la calle del Pilar y Don Jaime, a la izquierda) aâ”œâ•‘n estaba intacto. A la derecha, edificio del arzobispado. La fuente de la Samaritana, con utilidad no sâ”œâ”‚lo estâ”œÂ®tica. Mediados de la dâ”œÂ®cada de 1890. Fuente visual: gallica.bnf.fr/', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65529600, -0.87621900, '0101000020E61000004948A46DFC09ECBF8D9944BDE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15704539937.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15704539937.webp', 'https://www.flickr.com/photos/zaragozaantigua/15704539937/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21166, 'Plaza de La Seo c.1895', 'Imagen de la plaza de la Seo centrada en la fuente de la Samaritana cuando era el acuâ”œÃ­tico epicentro de una notable foresta, y a su funciâ”œâ”‚n estâ”œÂ®tica se unâ”œÂ¡a la funcional de proveedora de agua. Habâ”œÂ¡a sido instalada en 1866. A la izquierda, la Lonja y la Casa Consistorial. Enfrente, tras la de Samaria, el Seminario Conciliar. Fuente visual: Estudio Coyne (DARA-AHPZ).', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65538100, -0.87630000, '0101000020E61000007B832F4CA60AECBFBBB54C86E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23025287529.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23025287529.webp', 'https://www.flickr.com/photos/zaragozaantigua/23025287529/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21198, 'Plaza de La Seo 1890', 'Coloreada imagen capturada desde la altura del inmueble del nâ”¬â•‘ 3 de la plaza de La Seo con una interesante vista de la antigua plaza y su entorno, dominado por la esbelta torre barroca de la catedral del Salvador en su Epifanâ”œÂ¡a y su clasicista fachada que decora el ingreso por la puerta occidental del templo. A la izquierda, el Arco del Arzobispo que comunica con el homâ”œâ”‚nimo palacio. La plaza aparece vertebrada alrededor, en primer tâ”œÂ®rmino, de la fuente de la Samaritana, realizada en la fundiciâ”œâ”‚n Averly.', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65534200, -0.87643800, '0101000020E6100000BE175FB4C70BECBFFDD8243FE2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51425457922.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51425457922.webp', 'https://www.flickr.com/photos/zaragozaantigua/51425457922/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21241, 'Calle Don Jaime c.1900', 'Grupo de tres hombres caminando tranquilamente por la calle de Don Jaime I de Zaragoza. Al fondo, el cruce con la calle del Pilar y la Lonja. Fuente: www.facebook.com/photo.php?fbid=1668897606655861&set=...', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65528000, -0.87662200, '0101000020E610000016889E94490DECBF87DC0C37E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19894433228.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19894433228.webp', 'https://www.flickr.com/photos/zaragozaantigua/19894433228/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21242, 'Plaza de La Seo c.1900', 'Plaza de La Seo de Zaragoza, vista desde la calle de Don Jaime I. A la izquierda, el Palacio Arzobispal y el Arco del Arzobispo. En el centro, la estatua de la Samaritana ante la catedral. Fuente: www.facebook.com/photo.php?fbid=1668896829989272&set=...', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65528000, -0.87662200, '0101000020E610000016889E94490DECBF87DC0C37E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20057509096.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20057509096.webp', 'https://www.flickr.com/photos/zaragozaantigua/20057509096/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22482, 'Av. Compromiso de Caspe 1962', 'Tranquila imagen capturada en el antiguo camino de las Fuentes, ya redenominado como avenida del Compromiso de Caspe y centrada en el tramo de los impares (a la derecha) entre las recientes calles Doctor Iranzo y Obispo Laplana, poco antes de Salvador Minguijâ”œâ”‚n, que entonces seâ”œâ–’alaba el "nec plus ultra" de la ciudad en esta perifâ”œÂ®rica barriada. Hacia el fondo de la imagen, el lejano principio de la avenida desde la calle de Miguel Servet. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1962, 1962, 1962, 'Anos 60', 'LAS FUENTES', 41.64538000, -0.86299400, '0101000020E61000007C9DD497A59DEBBF0ABFD4CF9BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39282866304.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39282866304.webp', 'https://www.flickr.com/photos/zaragozaantigua/39282866304/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23647, 'Aerâ”œâ”‚dromo Sanjurjo 1939', 'El Aerâ”œâ”‚dromo Sanjurjo, en Garrapinillos, fue habilitado como base aâ”œÂ®rea a comienzos de 1937 por los nacionalistas, en un estratâ”œÂ®gico emplazamiento desde el que poder intervenir râ”œÃ­pidamente en los principales frentes de guerra. En â”œÂ®l se aposentâ”œâ”‚ importante nâ”œâ•‘mero y calidad de aviones de la Legiâ”œâ”‚n Câ”œâ”‚ndor alemana, y de la Legionaria italiana. Fue tal su importancia, que en octubre de 1937 un escuadrâ”œâ”‚n de "Chatos" y "Moscas" republicanos lo atacaron, destruyendo y daâ”œâ–’ando entre 17 y 30 aviones de los facciosos. En la imagen, una lâ”œÂ¡nea de cazas Fiat CR-32 de la Aviaciâ”œâ”‚n Legionaria Italiana, en los â”œâ•‘ltimos dâ”œÂ¡as de la guerra. Al fondo, un polivalente Ju-52 y un bombardero He-111 de la Legiâ”œâ”‚n Câ”œâ”‚ndor. Aâ”œâ–’os despuâ”œÂ®s, a los aviones alemanes e italianos se les aâ”œâ–’adirâ”œÂ¡an los de la fuerza aâ”œÂ®rea de los Estados Unidos de Norteamâ”œÂ®rica. Fuente visual: www.aviationcorner.net/', 1939, 1939, 1939, 'Anos 30', NULL, 41.66303700, -1.02413100, '0101000020E6100000CD1DFD2FD762F0BFDC847B65DED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18009158285.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18009158285.webp', 'https://www.flickr.com/photos/zaragozaantigua/18009158285/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21335, 'Plaza de La Seo 1903', 'Grabado que recoge el paso del Rosario que, proveniente de la calle de Don Jaime I, da una vueltecilla a la plaza de la Seo para encaminarse luego a la calle del Pilar la noche del 18 de octubre de 1903, en el marco de la visita a Zaragoza del rey Alfonso XIII, que presidiâ”œâ”‚ su paso desde el balcâ”œâ”‚n central del Palacio Arzobispal (a la izquierda) habilitado como morada real durante su estancia de tres dâ”œÂ¡as. La plaza de La Seo y la fachada del palacio fueron iluminadas para tal ocasiâ”œâ”‚n por la compaâ”œâ–’â”œÂ¡a Electro Peral Zaragozana. En el centro de la escena aparece la carroza titulada "la Venida de la Virgen", tallada en madera por el escultor Francisco de Borja ese mismo aâ”œâ–’o y que hacâ”œÂ¡a aquâ”œÂ¡ su estreno, siendo la â”œâ•‘nica figura de este Rosario que no es de cristal. Aparece portada por 32 jâ”œâ”‚venes con tâ”œâ•‘nicas blancas y escoltados por todos los acâ”œâ”‚litos de los templos de Zaragoza que portaban pebeteros en los que se quemaba incienso y mirra. Tras ella, la carroza que representa a la basâ”œÂ¡lica del Pilar, creada por Policarpo Valero y Bernabâ”œÂ® y ampliado a las cuatro torres en 1895 por Leâ”œâ”‚n Quintana y Bianchi. A la derecha, vista de uno de los dos faroles con forma de leâ”œâ”‚n, obra del taller de hojalateros y vidrieros de los Tiesto y construido en 1865-1866.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65527000, -0.87635200, '0101000020E61000001A187959130BECBF64062AE3DFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52539891386.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52539891386.webp', 'https://www.flickr.com/photos/zaragozaantigua/52539891386/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21358, 'Plaza de La Seo 1900', 'Imagen centrada en la fachada occidental de la Seo, flanqueada por el Arco del Arzobispo a la izquierda y la torre del templo. La escena incluye una vista parcial de la plaza de La Seo y, en primer tâ”œÂ®rmino, el empedrado paso peatonal por el arranque de la calle de Don Jaime I, donde destaca el tendido tranviario que por 10 câ”œÂ®ntimos y desde la plaza de la Constituciâ”œâ”‚n conduce hacia la izquierda al Arrabal por el Puente de Piedra.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65519800, -0.87625600, '0101000020E6100000938FDD054A0AECBFCA332F87DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54785682811.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54785682811.webp', 'https://www.flickr.com/photos/zaragozaantigua/54785682811/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21363, 'Plaza de La Seo c.1910', 'AHPZ-Archivo Coyne, 1907-1930. Plaza de la Seo.', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65509400, -0.87628300, '0101000020E6100000F94D61A5820AECBF25E7C41EDAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877890581.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877890581.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877890581/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21744, 'La Seo 1938', 'Tras dos aâ”œâ–’os de ocultamiento por parte del bando franquista, en 1938 se revelâ”œâ”‚ la muerte de Josâ”œÂ® Antonio Primo de Rivera, lâ”œÂ¡der de la Falange fusilado en Alicante el 20 de noviembre de 1936. En la imagen, profusiâ”œâ”‚n de coronas de flores al pie de la torre de la Seo, con motivo del funeral celebrado en noviembre de 1938 en memoria del polâ”œÂ¡tico fascista. Fuente: Archivo Heraldo de Aragâ”œâ”‚n.', 1938, 1938, 1938, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65518200, -0.87613800, '0101000020E6100000170D198F5209ECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21841817375.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21841817375.webp', 'https://www.flickr.com/photos/zaragozaantigua/21841817375/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21772, 'Plaza La Seo 1932', 'Plaza de la Seo y Fuente de la Samaritana. Al fondo, el Pilar. Fuente visual: Foto Conrado Barlâ”œÂ®s, donada por Daniel Barlâ”œÂ®s y digitalizada por Josâ”œÂ® Luis Cintora para www.rafaelcastillejo.com', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65538100, -0.87630000, '0101000020E61000007B832F4CA60AECBFBBB54C86E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22854992097.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22854992097.webp', 'https://www.flickr.com/photos/zaragozaantigua/22854992097/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21814, 'Calle Pabostrâ”œÂ¡a 1934', 'Imagen de la procesiâ”œâ”‚n del Domingo de Ramos 25 de marzo de 1934, reproducida en la revista Blanco y Negro en abril de 1935. Los palmeros desfilan por la calle de la Pabostrâ”œÂ¡a, con la de Diego Dormer al fondo. Fuente: www.todocoleccion.net', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65444100, -0.87617200, '0101000020E61000001C78B5DC9909ECBFAD1402B9C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30702428252.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30702428252.webp', 'https://www.flickr.com/photos/zaragozaantigua/30702428252/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21965, 'Plaza del Pilar 1949', 'Imagen de la despejada plaza del Pilar en su reciente ampliaciâ”œâ”‚n por derribo entre Don Jaime I (izquierda), y el edificio del Gobierno Civil en construcciâ”œâ”‚n (a la derecha, fuera de plano). La imagen se ha capturado desde la puerta de la Lonja. Enfrente, el nuevo edificio del nâ”¬â•‘ 16 de la plaza, esquinero con Don Jaime I, el primero de los tres de ese tramo. A su derecha, las traseras de los nuevos 25 y 27 de la calle Santiago, y por el solar del 23, visual de las antiguas viviendas aâ”œâ•‘n sin derribar del 30-32, a la derecha del Palacio de Montemuzo. En la plaza, autobuses de lâ”œÂ¡nea regular entre Zaragoza y el entorno municipal y provincial. Fuente Visual: Fotos Ysa, Archivo Pâ”œâ•‘blico Municipal.', 1949, 1949, 1949, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65541700, -0.87696300, '0101000020E610000061AA99B51410ECBF081F4AB4E4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22177307702.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22177307702.webp', 'https://www.flickr.com/photos/zaragozaantigua/22177307702/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22081, 'Calle Pabostrâ”œÂ¡a 1951', 'Archivo Municipal. Archivo Juan Mora. 1951 Imagen de la calle Pabostria, capturada desde su arranque en la calle Dormer nâ”¬â•‘ 8. A la izquierda, la Puerta Sur, o de la Pabostrâ”œÂ¡a de la Catedral de El Salvador, medieval acceso en desuso. La denominaciâ”œâ”‚n de "pabostrâ”œÂ¡a" hacâ”œÂ¡a referencia a la cercana residencia del encargado de la hacienda y los bienes temporales de la catedral. Desde antiguo, este cargo fue teniendo varias denominaciones: "Procuraciâ”œâ”‚n", "Mensa Comâ”œâ•‘n", "Mensa Capitular", "Prepositura", y "Pabostrâ”œÂ¡a". El que tiene la llave de la caja, en plata.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65446100, -0.87629900, '0101000020E6100000658F5033A40AECBFF4C0C760C5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15760216592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15760216592.webp', 'https://www.flickr.com/photos/zaragozaantigua/15760216592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22128, 'Pl. de la Seo c.1959', 'Plaza de La Seo. Al fondo, el edificio sin terminar del nuevo Ayuntamiento, y el Pilar. En primer tâ”œÂ®rmino, las vâ”œÂ¡as de la tranviaria lâ”œÂ¡nea del Arrabal. Fuente visual: Foto Leonardo Pâ”œÂ®rez Obis, donada por â”œÃ¼ngel Hernâ”œÃ­ndez Mostajo para www.rafaelcastillejo.com', 1959, 1959, 1959, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65534100, -0.87635300, '0101000020E6100000310C5872150BECBF2D5DC136E2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23159778261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23159778261.webp', 'https://www.flickr.com/photos/zaragozaantigua/23159778261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22200, 'Pl. de La Seo 1954', 'Imagen de la plaza de la Seo capturada desde los jardines que hubiera en la ampliada plaza del Pilar, en el tramo desde la nueva Casa Consistorial, y hasta la calle de Don Jaime I, al fondo. Por esta calle, precisamente, transita un trolebâ”œâ•‘s (posiblemente el nâ”¬â•‘ 15, un Vectra-Escoriaza) de la lâ”œÂ¡nea del Gâ”œÃ­llego, en su retorno a la terminal del Coso. Fuente visual: archivo Heraldo de Aragâ”œâ”‚n, en "Padre Ebro. El râ”œÂ¡o Ebro y el siglo XX".', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65536300, -0.87629000, '0101000020E610000098FA7953910AECBF15014EEFE2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33572915190.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33572915190.webp', 'https://www.flickr.com/photos/zaragozaantigua/33572915190/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22359, 'Plaza de La Seo 1961', '"Plaza de la Catedral", â”œâ”‚leo sobre lienzo, Alberto Pâ”œÂ®rez Piqueras, 1961. Premio Goya en el concurso Arte zaragozano actual de 1962. Representaciâ”œâ”‚n neocubista de la plaza de La Seo de Zaragoza, con el Palacio Arzobispal al fondo, la fuente de la Samaritana y la entrada a la catedral. Fuente: Colecciâ”œâ”‚n del Ayuntamiento de Zaragoza.', 1961, 1961, 1961, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65530900, -0.87635300, '0101000020E6100000310C5872150BECBF22E3512AE1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20886096742.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20886096742.webp', 'https://www.flickr.com/photos/zaragozaantigua/20886096742/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22833, 'Foro Romano c.1989', 'En 1980, durante los trabajos de restauraciâ”œâ”‚n en La Seo, se hallâ”œâ”‚ una cloaca cuya funciâ”œâ”‚n era la de recoger las aguas caâ”œÂ¡das de la plaza del templo del Foro romano. Ese mismo aâ”œâ–’o se hallaba tambiâ”œÂ®n otra cloaca en la calle de Don Jaime. En 1982, los arqueâ”œâ”‚logos localizaron el sistema de desagâ”œâ•e de las termas que se hallan (musealizadas) en la calle de San Juan y San Pedro. Entre 1988 y 1994, con las excavaciones arqueolâ”œâ”‚gicas en la plaza de La Seo (1988-1991) y solares contiguos (1991-1994), se completâ”œâ”‚ el conocimiento de los canales y cloacas al servicio del Foro de Caesaraugusta. Hay 30 cloacas registradas arqueolâ”œâ”‚gicamente en la ciudad, cuyo conjunto es superior a los 600 metros de longitud. En la imagen, el subsuelo de la Plaza de la Seo levantado, excavado, y estudiado. A la izquierda, fuera del perâ”œÂ¡metro arqueolâ”œâ”‚gico, la base de la Torre de la Seo.', 1989, 1989, 1989, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65524600, -0.87616500, '0101000020E61000007DCB9C2E8B09ECBFDB6AD619DFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14754262510.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14754262510.webp', 'https://www.flickr.com/photos/zaragozaantigua/14754262510/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22911, 'Plaza La Seo c.1988', 'Excavaciâ”œâ”‚n arqueolâ”œâ”‚gica del foro romano en la plaza de La Seo. Al fondo, en el centro, calle de Don Jaime I. Fuente visual: Foto Leonardo Pâ”œÂ®rez Obis, donada por â”œÃ¼ngel Hernâ”œÃ­ndez Mostajo para www.rafaelcastillejo.com', 1988, 1988, 1988, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65534100, -0.87635300, '0101000020E6100000310C5872150BECBF2D5DC136E2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23150712055.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23150712055.webp', 'https://www.flickr.com/photos/zaragozaantigua/23150712055/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22912, 'Plaza La Seo c.1988', 'Excavaciâ”œâ”‚n arqueolâ”œâ”‚gica del foro romano. Al fondo, la plaza del Pilar. Fuente visual: Foto Leonardo Pâ”œÂ®rez Obis, donada por â”œÃ¼ngel Hernâ”œÃ­ndez Mostajo para www.rafaelcastillejo.com', 1988, 1988, 1988, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65534100, -0.87635300, '0101000020E6100000310C5872150BECBF2D5DC136E2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23186574831.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23186574831.webp', 'https://www.flickr.com/photos/zaragozaantigua/23186574831/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22935, 'La Seo 1989', 'Vista nocturna de las excavaciones arqueolâ”œâ”‚gicas en la plaza de La Seo, con la catedral al fondo, en 1989. Esta prospecciâ”œâ”‚n tuvo lugar entre 1988 y 1991, dando como resultado el museo del Foro Romano. Fuente: "La plaza de La Seo. Zaragoza. Investigaciones Histâ”œâ”‚rico-Arqueolâ”œâ”‚gicas". Ayuntamiento de Zaragoza, 1989.', 1989, 1989, 1989, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65536300, -0.87629000, '0101000020E610000098FA7953910AECBF15014EEFE2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32171401686.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32171401686.webp', 'https://www.flickr.com/photos/zaragozaantigua/32171401686/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23850, 'Pl. de la Seo c.1955', 'Imagen de la nocturna procesionaria confesional del Rosario de Cristal, con detalle del "paso" del legendario (fantâ”œÃ­stico) niâ”œâ–’o-mâ”œÃ­rtir Dominguito de Val, santificado por la rama mâ”œÃ­s antisemita y medieval del catolicismo, que lo mantiene en su devocionario aun despuâ”œÂ®s del Concilio Vaticano II. A su vera, sus patrocinados y canoros "infanticos". La captura se ha realizado en la plaza de la Seo, junto a las desaparecidas Casas de los Infantes de la Seo, que quedan a la izquierda, fuera de plano. Al fondo, a la derecha, las aâ”œÂ®reas y visuales jaculatorias de neâ”œâ”‚n instaladas en el templo metropolitano del Pilar al comienzo de la dâ”œÂ®cada, para facilitar el acompaâ”œâ–’amiento a la jaculatoria oral que suena, tres veces al dâ”œÂ¡a, desde el aâ”œâ–’o del seâ”œâ–’or de 1940, Aâ”œâ–’o II de la Victoria. Fuente visual: Archivo Coyne (DARA-AHPZ).', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65529300, -0.87625700, '0101000020E6100000A983BC1E4C0AECBF1C261AA4E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26620438382.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26620438382.webp', 'https://www.flickr.com/photos/zaragozaantigua/26620438382/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23994, 'Milagro del Niâ”œâ–’o-Hostia 1427', 'Pintura del siglo XVII situada en el paâ”œâ–’o lateral izquierdo de la capilla de Santo Dominguito de Val de la Seo de Zaragoza, atribuida por Josâ”œÂ® Camâ”œâ”‚n Aznar a Bartolomâ”œÂ® Vicente. Procesiâ”œâ”‚n en la plaza del la Seo de Zaragoza, en la que el arzobispo Alonso de Argâ”œâ•ello, que lo fue entre 1419 y 1429, porta en brazos bajo palio al Niâ”œâ–’o Jesâ”œâ•‘s, para llevarlo a la catedral. La leyenda narra que una mujer casada consultâ”œâ”‚ a un alfaquâ”œÂ¡ (doctor en leyes musulmâ”œÃ­n, considerado mago) para eliminar los malos tratos que le propinaba su marido. El remedio aconsejado fue procurarse una hostia consagrada. La mujer comulgâ”œâ”‚ en San Miguel sin tragarse la hostia, y la metiâ”œâ”‚ en un cofre. Al abrirlo habâ”œÂ¡a un niâ”œâ–’o, que el alfaquâ”œÂ¡ ordenâ”œâ”‚ quemar. El niâ”œâ–’o saliâ”œâ”‚ ileso y se lo contaron al obispo, que organizâ”œâ”‚ la procesiâ”œâ”‚n. Dejaron al niâ”œâ–’o en el altar de la capilla de San Valero y al dâ”œÂ¡a siguiente en una misa, el niâ”œâ–’o se volviâ”œâ”‚ a convertir en hostia y el obispo se la tragâ”œâ”‚. En la imagen, la comitiva municipal sigue al palio detrâ”œÃ­s de un grupo de capitulares. A la derecha, los maceros. Al fondo, la supuesta puerta de la Seo, aunque la câ”œâ•‘pula que se ve detrâ”œÃ­s recuerda a la que tenâ”œÂ¡a la Diputaciâ”œâ”‚n del Reino. Fuente visual: "El municipio en Aragâ”œâ”‚n", DPZ, 2004.', 1427, 1427, 1427, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65518200, -0.87613800, '0101000020E6100000170D198F5209ECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20549754211.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20549754211.webp', 'https://www.flickr.com/photos/zaragozaantigua/20549754211/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24227, 'Pl. de la Seo c.1955', '"Rosario de Cristal. Paso de Santo Dominguito de Val. Infanticos. Gente". De las antiguas (y desaparecidas) Casas de los Infantes de la Seo, en la plaza de la Seo, sale el procesional y confesional paso del legendario niâ”œâ–’o-mâ”œÃ­rtir. El artificio luminario para capturar la nocturna escena atrae miradas y gestos. La del guardia, no. Fuente visual: Archivo Coyne (DARA-AHPZ).', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65504000, -0.87637300, '0101000020E6100000F71DC3633F0BECBF32C9C859D8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22463231459.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22463231459.webp', 'https://www.flickr.com/photos/zaragozaantigua/22463231459/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23685, 'Aerâ”œâ”‚dromo Sanjurjo 1939', 'Imagen capturada en el Aerâ”œâ”‚dromo Sanjurjo y centrada en un aeroplano alemâ”œÃ­n modelo Messerschmitt Bf 108 B, utilizado en funciones de comunicaciâ”œâ”‚n, enlace y correo por el Grupo de Bombardeo K-88 de la Legiâ”œâ”‚n Condor. Desde finales de 1937, durante la Batalla de Teruel, y hasta la campaâ”œâ–’a de Cataluâ”œâ–’a, a principios de 1939, este fue uno de los aerâ”œâ”‚dromos utilizados por el contingente alemâ”œÃ­n enviado por la Alemania nazi para respaldar a los sublevados nacionalistas en la guerra civil, sobre todo como base de bombarderos.', 1939, 1939, 1939, 'Anos 30', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49561229801.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49561229801.webp', 'https://www.flickr.com/photos/zaragozaantigua/49561229801/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24591, 'Plaza de la Seo 1976', 'Al fondo, la Lonja como espectacular marco escâ”œÂ®nico de la exposiciâ”œâ”‚n Arte faraâ”œâ”‚nico, organizada por la Direcciâ”œâ”‚n General de Bellas Artes del Patrimonio Artâ”œÂ¡stico Cultural, e integrada por 219 piezas legâ”œÂ¡timamente egipcias procedentes del antiguo territorio del Nilo, primero expuestas en Madrid, luego en Zaragoza, y finalmente en Barcelona. Por encima y a la izquierda, emerge la torre de Santa Leonor del Pilar, con su fluorescente jaculatoria. En primer tâ”œÂ®rmino, la plaza de La Seo con la humidificante fuente que en 1962 sustituyâ”œâ”‚ a la entraâ”œâ–’able y tradicional de La Samaritana, que primero viajâ”œâ”‚ al parque de Bruil para terminar en la plaza del Justicia. Tras ella, el tradicional quiosco de prensa anunciando entre otras las revistas masculina y femenina del boyante Opus Dei, y dos personas mayores tomando el sol en un banco, en una maâ”œâ–’ana bien fresca.', 1976, 1976, 1976, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65529600, -0.87621900, '0101000020E61000004948A46DFC09ECBF8D9944BDE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16659900758.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16659900758.webp', 'https://www.flickr.com/photos/zaragozaantigua/16659900758/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24592, 'Lonja-Ayuntamiento c.1888', 'La calle de la Lonja con su activo ritmo vital cotidiano como continuaciâ”œâ”‚n del puente de Piedra que comunica con el Arrabal, al fondo. Un tranvâ”œÂ¡a "de sangre", carros tirados por caballerâ”œÂ¡as, y un heterogâ”œÂ®neo grupo de viandantes, bullen en el entorno de la Lonja y la Casa Consistorial. La plaza de la Seo, inmediata, se abre a la derecha. La calle del Pilar, a la izquierda. Fuente visual: Estudio Coyne (DARA-AHPZ).', 1888, 1888, 1888, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65538100, -0.87630000, '0101000020E61000007B832F4CA60AECBFBBB54C86E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23366682236.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23366682236.webp', 'https://www.flickr.com/photos/zaragozaantigua/23366682236/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24594, 'La Lonja 1901', 'Grupo de personas ante la Lonja, en la confluencia de la calle de Don Jaime I con la del Pilar. Fuente: www.delcampe.net', 1901, 1901, 1901, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65540500, -0.87656800, '0101000020E61000004A0B9755D80CECBF4451A04FE4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28512100995.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28512100995.webp', 'https://www.flickr.com/photos/zaragozaantigua/28512100995/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24597, 'Plaza de la Seo 1902', 'Imagen capturada junto a la fuente denominada Samaritana en la antigua plaza de la Seo, erigida no como mero ornato visual, sino como destacado punto de provisiâ”œâ”‚n del lâ”œÂ¡quido elemento para consumo de boca, como manifiesta la nutrida parroquia congregada en torno a ella, si bien parece que son las mujeres las que, provistas de câ”œÃ­ntaros de diversas capacidades, efectivamente realizan esa funciâ”œâ”‚n, mientras los indâ”œÂ¡genas parecen estar vareando el agua de forma estâ”œâ”‚lida. Al fondo de la imagen, la calle de la Lonja y el desemboque en ella de la estilizada calle del Pilar, donde destaca el edificio de la casa de la Lonja como antigua dependencia anexa a la casa del Ayuntamiento. Esta imagen fue comercializada como vista estereoscâ”œâ”‚pica de la ciudad bajo el tâ”œÂ¡tulo "The old Exchange (1551) and Plaza de La Seo, Saragossa, Spain", cuando la Lonja era curiosamente catalogada como "mercado bursâ”œÃ­til". Fuente visual: Underwood & Underwood Publishers (Estados Unidos de Norteamâ”œÂ®rica), en Zaragoza estereoscâ”œâ”‚pica, fotografâ”œÂ¡a profesional y comercial 1850-1970, PUZ.', 1902, 1902, 1902, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65536300, -0.87629000, '0101000020E610000098FA7953910AECBF15014EEFE2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34255489843.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34255489843.webp', 'https://www.flickr.com/photos/zaragozaantigua/34255489843/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24603, 'Plaza de La Seo 1902', 'Imagen estereoscâ”œâ”‚pica capturada en la plaza de La Seo con el fondo de la "old Exchange" (Lonja) entre la calle del Pilar (cuya esquina aparece ensanchada tras el derribo de las inmediatas casas) y el paseo del Ebro. En primer tâ”œÂ®rmino, la fuente de la Samaritana en su original ubicaciâ”œâ”‚n de la plaza como importante punto de suministro de agua. A la derecha, el seminario ,metropolitano conciliar.', 1902, 1902, 1902, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65539800, -0.87639500, '0101000020E6100000EC17EC866D0BECBF91EEE714E4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51422225697.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51422225697.webp', 'https://www.flickr.com/photos/zaragozaantigua/51422225697/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24604, 'Plaza de La Seo 1878', 'Imagen capturada por el fotâ”œâ”‚grafo villanovense Gregorio Sabatâ”œÂ® Fâ”œÂ®rriz e integrada en el â”œÃ­lbum "Vistas de Zaragoza", centrada en una vista del entorno de la plaza de La Seo tomada desde la altura de la vivienda del Cabildo adosada a la cara suroeste de la torre de la catedral y a la capilla de las santas Justa y Rufina. En primer tâ”œÂ®rmino, la plaza de La Seo con sus jardines y â”œÃ­rboles vertebrados en torno a la Fuente de la Samaritana instalada en 1866. A la derecha, fachada del Seminario Conciliar construido sin demasiados remilgos sobre los restos del Palacio de la Diputaciâ”œâ”‚n del Reino de Aragâ”œâ”‚n, que fueron arrasados para la ocasiâ”œâ”‚n. Al fondo y a la izquierda, viviendas de la manzana de la calle de Don Jaime I comprendida entre las calles del Pilar y de Juan Martâ”œÂ¡n Goicoechea. Aquâ”œÂ¡ figuran la nâ”œâ•‘mero 7, esquinera con la calle del Pilar, y su vecina la nâ”œâ•‘mero 9. Al otro lado de esa calle, la Casa-Lonja anexa a la Casa Consistorial como escenario de diversas actividades municipales y tambiâ”œÂ®n anual espacio donde se procedâ”œÂ¡a a la "declaraciâ”œâ”‚n de soldados" de los individuos que de forma obligatorio formaban parte del reemplazo de quintas (incluyendo entre ellos a quienes no podâ”œÂ¡an permitirse la redenciâ”œâ”‚n en metâ”œÃ­lico del servicio o aquellos que acudâ”œÂ¡an como "sustitutos" de los seâ”œâ–’oritos y privilegiados) y que debâ”œÂ¡an "ingresar en caja" en torno al 1 de mayo para cumplir con los preceptivos cuatro aâ”œâ–’os de "servicio activo".', 1878, 1878, 1878, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65519800, -0.87625600, '0101000020E6100000938FDD054A0AECBFCA332F87DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54760597074.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54760597074.webp', 'https://www.flickr.com/photos/zaragozaantigua/54760597074/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24607, 'Calle Dormer aâ”œâ–’os 20', 'Otto Wunderlich. 1920-1936. "Zaragoza. Calle Diego Dormer y La Torre de la Seo [o Catedral del Salvador en su Epifanâ”œÂ¡a, al fondo]". A la izquierda, el Palacio renacentista conocido como casa de Miguel Donlope o de la Real Maestranza de Caballerâ”œÂ¡a, por servir de sede a esta Corporaciâ”œâ”‚n zaragozana. Construido durante la tercera y cuarta dâ”œÂ®cada del siglo XVI es un ejemplo del modelo de casa-palacio aragonâ”œÂ®s. Fuente visual: Archivo Wâ”œâ•nderlich (WUN-05815) www.mcu.es/fototeca_patrimonio/Visor?usarVisorMCU=true&am...', 1920, 1920, 1929, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65435600, -0.87653500, '0101000020E61000005B94D920930CECBF7FF8F9EFC1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14876971170.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14876971170.webp', 'https://www.flickr.com/photos/zaragozaantigua/14876971170/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24609, 'Torre de la Seo sin chapitel 1860', 'Un rayo incendiâ”œâ”‚ el chapitel de la torre de la Seo en 1850, matando al campanero. Hasta 1861 no se empezâ”œâ”‚ a colocar el nuevo chapitel, fundido en los talleres Julio Goybet y Câ”œÂ¡a. de Zaragoza. La pequeâ”œâ–’a torrecilla a la izquierda de la demediada torre de La Seo serâ”œÂ¡a la insâ”œâ”‚lita torre de la desaparecida iglesia de Santiago, sita en la calle Don Jaime I. Mâ”œÃ­s informaciâ”œâ”‚n sobre el suceso: tausiet.blogspot.com/2016/01/rayo-sobre-la-seo-muerte-de-... Fuente visual: Mariano Jâ”œâ•‘dez y Ortiz. 1859-1860. â”œÃ¼lbum: Andrâ”œÂ®s Martâ”œÂ¡n e Ipâ”œÃ­s. Col. Mariano Martâ”œÂ¡n Casalderrey, Zaragoza.', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65470400, -0.87610700, '0101000020E6100000567E198C1109ECBFBB473657CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14896850475.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14896850475.webp', 'https://www.flickr.com/photos/zaragozaantigua/14896850475/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24613, 'Palmeros en La Seo 1974', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 07/04/1974. Palmeros en procesiâ”œâ”‚n de palmas en la plaza de la Seo. A la izquierda, la catedral, con espacios seâ”œâ–’alados en suelo para aparcar en baterâ”œÂ¡a. Al fondo, la callejuela Ramâ”œâ”‚n Cuâ”œÂ®llar. A la derecha, antiguo edificio residencial de la plaza con el bar "La Cadiera" en la esquina.', 1974, 1974, 1974, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65522200, -0.87608900, '0101000020E6100000BD546CCCEB08ECBF53CF8250DED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15048052115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15048052115.webp', 'https://www.flickr.com/photos/zaragozaantigua/15048052115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24618, 'Calle del Pilar aâ”œâ–’os 20', 'Calle del Pilar (derecha), esquina con la de Don Jaime I, desde la plaza de la Seo. El edificio comercial que centra la imagen tuvo distintos usos: aquâ”œÂ¡ parece ofrecer obras artâ”œÂ¡sticas de recuerdo, o souvenirs, de escultura, pintura, artesanâ”œÂ¡a. Luego fue cafeterâ”œÂ¡a y tienda de ultramarinos (Pedro Santamera), hasta desaparecer con la manzana de la que formaba parte, cuando los numerosos derribos para dar paso a la nueva gran plaza del Pilar. Fuente visual: Crâ”œâ”‚nica de Zaragoza 1900-1920.', 1920, 1920, 1929, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65542400, -0.87667200, '0101000020E610000087342A70B20DECBFBA8102EFE4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15472718210.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15472718210.webp', 'https://www.flickr.com/photos/zaragozaantigua/15472718210/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24619, 'Dormer 1973', 'Archivo Municipal. Gerardo Sancho Ramo. Julio 1973. Los "Gigantes", como los "Cabezudos", no pisan mucho las calles en julio, pero ese aâ”œâ–’o estaba justificada la sofoquina: se estaban rodando imâ”œÃ­genes para la pelâ”œÂ¡cula "Gigantes y Cabezudos", basada en la zarzuela del mismo tâ”œÂ¡tulo, y uno de los fragmentos recogâ”œÂ¡a, precisamente, la Salida de los Gigantes y Cabezudos en el entorno de La Seo y la actual plaza de San Bruno, mientras sonaban acordes musicales asociados, y la interpretaciâ”œâ”‚n de Ã”Ã‡Â£Cuando era niâ”œâ–’a y jugabaÃ”Ã‡Ã˜. Esta pelâ”œÂ¡cula estaba producida por TVE, dirigida por Josâ”œÂ® Antonio Pâ”œÃ­ramo, y actuada (las piezas musicales estaban dobladas) por destacadas personalidades de la interpretaciâ”œâ”‚n. Se estrenâ”œâ”‚ de octubre de ese aâ”œâ–’o, con gran â”œÂ®xito. En la imagen, durante una pausa del rodaje la chiquillerâ”œÂ¡a juega entre los Gigantes, que descansan junto a la calle Dormer, en el antiguo barrio de la Seo.', 1973, 1973, 1973, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65458900, -0.87626600, '0101000020E6100000761893FE5E0AECBF22A98592C9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15476308213.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15476308213.webp', 'https://www.flickr.com/photos/zaragozaantigua/15476308213/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24625, 'Roscones 1916', 'Foto Sâ”œÃ­nchez Româ”œÃ­n. La Hormiga de Oro, febrero de 1916. Venta de roscones el dâ”œÂ¡a de San Valero en la puerta de la Seo de Zaragoza, el 29 de enero de 1916.', 1916, 1916, 1916, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65518200, -0.87613800, '0101000020E6100000170D198F5209ECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18530408643.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18530408643.webp', 'https://www.flickr.com/photos/zaragozaantigua/18530408643/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24626, 'Gran cloaca de Caesar Augusta siglo I', 'â”œÃ«poca de Tiberio. 14-37 d.C. Detalle del interior de la gran cloaca de Caesar Augusta bajo la actual plaza de La Seo. Se halla musealizada junto a los restos del foro. Desde el Renacimiento se utilizâ”œâ”‚ como pasadizo subterrâ”œÃ­neo, bodegas y despensas. Fuente: Catâ”œÃ­logo Aquaria. DPZ, 2006', 50, NULL, 99, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65518200, -0.87613800, '0101000020E6100000170D198F5209ECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18676012115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18676012115.webp', 'https://www.flickr.com/photos/zaragozaantigua/18676012115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
