INSERT INTO public.photos VALUES (24634, 'Plaza La Seo ca. 1972', 'Plaza de la Seo, con imagen de la Lonja, el Ayuntamiento, y el Pilar. Fuente visual: Foto Leonardo Pâ”œÂ®rez Obis, donada por â”œÃ¼ngel Hernâ”œÃ­ndez Mostajo para www.rafaelcastillejo.com', 1972, 1972, 1972, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65534100, -0.87635300, '0101000020E6100000310C5872150BECBF2D5DC136E2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22754253057.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22754253057.webp', 'https://www.flickr.com/photos/zaragozaantigua/22754253057/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24636, 'Calle Cisne 1972', 'Dos niâ”œâ–’as cargadas de libros caminan por la calle del Cisne, antigua de Zaporta hasta 1863, hacia el final de la calle de Diego Dormer, al fondo. A la izquierda, anexas dependencias de la Seo, y a la derecha, inmuebles de los nâ”œâ•‘meros 2 y 4 de la calle, y tapia del patio del palacio de la Real Maestranza de Caballerâ”œÂ¡a. El recoleto barrio de La Seo, pequeâ”œâ–’o laberinto urbano milenario y descuidado, mantenâ”œÂ¡a pese a ello la calma y el sabor.', 1972, 1972, 1972, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65478000, -0.87649300, '0101000020E6100000A088450C3B0CECBF9609BFD4CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23135317372.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23135317372.webp', 'https://www.flickr.com/photos/zaragozaantigua/23135317372/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
