INSERT INTO public.photos VALUES (24638, 'Calle San Valero c.1972', 'La calle de San Valero, antigua de la Frenerâ”œÂ¡a hasta 1863, se abre desde la de Don Jaime I, y conecta con la Seo. En la imagen, solares dejados tras derribo de los inmuebles de los nâ”œâ•‘meros 5-7, 9 y 11, este â”œâ•‘ltimo esquinero con la calle de Ramâ”œâ”‚n Cuâ”œÂ®llar. A la derecha, râ”œâ”‚tulo de una popular taberna sita en el local del nâ”¬â•‘ 8, que perdura. Al fondo, rotunda, la catedral del Salvador, con aâ”œâ–’ejos anexos en la calle del Cisne, luego derribados.', 1972, 1972, 1972, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65501200, -0.87683600, '0101000020E61000001893FE5E0A0FECBF683EE76ED7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23158919212.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23158919212.webp', 'https://www.flickr.com/photos/zaragozaantigua/23158919212/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22737, 'C.â”¬â•‘ de la Mosquetera 1973', 'Bicolor rebaâ”œâ–’o de ovejas ramonea en un campo inmediato al camino de la Mosquetera y compone una tâ”œÂ¡pica visiâ”œâ”‚n de la periferia de la ciudad del momento, tomada a espaldas de la avenida de Gâ”œâ”‚mez Laguna. De fondo escâ”œÂ®nico, y de izquierda a derecha, viviendas del principio de la calle de Marâ”œÂ¡a Guerrero, en el barrio de La Bozada; pabellâ”œâ”‚n de la Infanta Isabel y el de Pensionistas del arbolado Hospital Psiquiâ”œÃ­trico Nuestra Seâ”œâ–’ora del Pilar; grandes bloques en construcciâ”œâ”‚n que aâ”œâ–’os mâ”œÃ­s tarde quedarâ”œÃ­n en una esquinera ubicaciâ”œâ”‚n entre la prolongaciâ”œâ”‚n de la calle de la Duquesa de Villahermosa y la nueva Vâ”œÂ¡a Universitas; y finalmente, a la derecha, el bloque del nâ”¬â•‘ 9 de la calle de Santa Rita de Casia. En el transcurso de unos cuantos aâ”œâ–’os, este escenario conocerâ”œÂ¡a una radical transformaciâ”œâ”‚n. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.64267000, -0.90821600, '0101000020E6100000A58636001B10EDBF670FB40243D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31481183387.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31481183387.webp', 'https://www.flickr.com/photos/zaragozaantigua/31481183387/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24640, 'Plaza de Santa Marta 1976', 'Imagen, desde la plaza de Santa Marta, del antiguo palacio del marquesado de Huarte. Este edificio seâ”œâ–’orial fue construido a principios del siglo XVI segâ”œâ•‘n la planta estâ”œÃ­ndar de las casonas nobles en la ciudad (gran patio central en torno al que se ordenan las estancias, con entrada por la antigua calle de Zaporta, luego Dormer, y esquina a Pabostria). A mediados del pasado siglo XX pasâ”œâ”‚ a propiedad de una entidad local de ahorro, hasta que a finales de los aâ”œâ–’os 70 â”œÂ®sta negociâ”œâ”‚ su conversiâ”œâ”‚n en sede estable del Archivo Histâ”œâ”‚rico Provincial, hasta ese momento en el antiguo palacio de Sobradiel, sede del Colegio de Notarios. La imagen captura las obras de restauraciâ”œâ”‚n y acondicionamiento del antiguo palacio, que comenzarâ”œÃ­ a funcionar como AHPZ en 1980, con documentaciâ”œâ”‚n desde el siglo X de la Era, hasta el XX. A la izquierda, la calle Dormer, el antiguo palacio de la Maestranza y, al fondo, la torre y catedral de la Seo. Fuente visual: Gerardo Sancho Ramo (Archivo Pâ”œâ•‘blico Municipal).', 1976, 1976, 1976, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65420600, -0.87650100, '0101000020E610000056293DD34B0CECBF6A6CAF05BDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23454505874.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23454505874.webp', 'https://www.flickr.com/photos/zaragozaantigua/23454505874/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
