INSERT INTO public.photos VALUES (24654, 'Plaza de La Seo 1945', 'Imagen capturada desde la altura de la torre "Nueva", o de Nuestra Seâ”œâ–’ora del Pilar del homâ”œâ”‚nimo templo, con el objetivo puesto en la Lonja, la plaza de la Seo, y la fachada de la catedral de San Salvador. En primerâ”œÂ¡simo plano, a la izquierda, vista parcial del cerrado perâ”œÂ¡metral en el que estaba prevista la construcciâ”œâ”‚n del nuevo ayuntamiento de la ciudad. Fuente visual: postal de la editorial "Soberanas", en www.ebay.es/', 1945, 1945, 1945, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65540500, -0.87656800, '0101000020E61000004A0B9755D80CECBF4451A04FE4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34435973965.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34435973965.webp', 'https://www.flickr.com/photos/zaragozaantigua/34435973965/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24656, 'Vista desde la Seo c.1916', 'Imagen capturada desde la altura de la torre barroca de la Seo, centrada en una vista hacia el sur urbano. En primer tâ”œÂ®rmino, tejados en el entorno de la recoleta plaza de Santa Marta, y a la derecha, traza de la calle de Don Jaime I, donde destaca el solar dejado tras el derribo de la antigua casa del conde de Atarâ”œÂ®s, en la esquina con la calle de Espoz y Mina, donde poco despuâ”œÂ®s se construirâ”œÂ¡a el referencial inmueble diseâ”œâ–’ado por Francisco Albiâ”œâ–’ana, que perdura. Hacia el fondo y siguiendo al calle, atalaya de la iglesia parroquial de San Gil Abad. Hacia la izquierda, la calle de San Jorge, donde destaca la nueva sede central de la Caja de Ahorros de Zaragoza, en la esquina con la calle de San Andrâ”œÂ®s, donde despunta levemente la torrecilla de esta pequeâ”œâ–’a y homâ”œâ”‚nima iglesia. Siguiendo la calle de San Jorge hacia la izquierda, emerge rotunda la antigua iglesia de San Pedro Nolasco, de planta de cruz griega. Mâ”œÃ­s hacia el fondo y a la derecha, el paseo de la Independencia. En el centro de la imagen, las torres de las dos centrales elâ”œÂ®ctricas sitas en el entorno de la calle de San Miguel, sobre el fondo despejado de la antigua huerta de Santa Engracia que alcanza hasta la homâ”œâ”‚nima iglesia parroquial.', 1916, 1916, 1916, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65455700, -0.87673900, '0101000020E61000007B1684F23E0EECBF162F1686C8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49105600518.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49105600518.webp', 'https://www.flickr.com/photos/zaragozaantigua/49105600518/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24895, 'La Samaritana c.1958', 'Plaza de La Seo con la fuente de la Samaritana fundida en Averly, trasladada en 1962 a la plaza del Justicia. Fuente. www.facebook.com/photo.php?fbid=808979045791389&set=o...', 1958, 1958, 1958, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65527500, -0.87619100, '0101000020E6100000CD9541B5C109ECBF76711B0DE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15204337611.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15204337611.webp', 'https://www.flickr.com/photos/zaragozaantigua/15204337611/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
