INSERT INTO public.photos VALUES (25161, 'Calle Pabostrâ”œÂ¡a aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste, con una vista del palacio de la Real Maestranza de Caballerâ”œÂ¡a en la calle de Diego Dormer, al fondo, desde la de la Pabostrâ”œÂ¡a. A la derecha, puerta sur de la Seo. Fuente: Lâ”œÃ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65446500, -0.87630100, '0101000020E610000092770E65A80AECBF36B05582C5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32062694170.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32062694170.webp', 'https://www.flickr.com/photos/zaragozaantigua/32062694170/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25165, 'Calle San Valero aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste. Al fondo de la calle San Valero, se distingue el lateral sur de la Seo. Fuente: Lâ”œÃ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65490600, -0.87673000, '0101000020E6100000AE81AD122C0EECBF22FAB5F5D3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32318536381.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32318536381.webp', 'https://www.flickr.com/photos/zaragozaantigua/32318536381/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25185, 'Plaza de La Seo 1909', '"Plaza de la Seo (Zaragoza)", â”œâ”‚leo sobre lienzo, Rafael Aguado Arnal, 1909. Colecciâ”œâ”‚n particular, Bilbao. Vista de la arbolada plaza de La Seo, con la catedral al fondo.', 1909, 1909, 1909, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65528900, -0.87634200, '0101000020E6100000368FC360FE0AECBFDB368C82E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52490931279.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52490931279.webp', 'https://www.flickr.com/photos/zaragozaantigua/52490931279/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25516, 'Paza de La Seo c.1897', 'Imagen capturada en la arbolada plaza de la Seo con motivo de la Solemnidad del Cuerpo y la Sangre de Cristo durante el protocolario desfile del Ayuntamiento en Corporaciâ”œâ”‚n, que abre una secciâ”œâ”‚n de la Guardia Municipal montada en traje de gala. Al fondo, fachada e ingreso principal de la Seo, desde donde sale la procesionaria. A la izquierda, el seminario conciliar, el palacio arzobispal y el arco del Arzobispo. Fuente visual: cesbor.blogspot.com.es/', 1897, 1897, 1897, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65536900, -0.87608300, '0101000020E6100000349C3237DF08ECBFF7E7A221E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25562239067.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25562239067.webp', 'https://www.flickr.com/photos/zaragozaantigua/25562239067/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25907, 'Plaza de la Seo 1970', 'Apacible imagen de la plaza de la Seo, cuando el articulado tranvâ”œÂ¡a 253, de la Lâ”œÂ¡nea 10 "Academia" estâ”œÃ­ presto a girar por la derecha para encaminarse al Puente de Piedra, tal y como venâ”œÂ¡a haciendo desde los aâ”œâ–’os sesenta. Un aâ”œâ–’o despuâ”œÂ®s de esta captura fotogrâ”œÃ­fica, la lâ”œÂ¡nea serâ”œÂ¡a clausurada, tras algo mâ”œÃ­s de cuarenta aâ”œâ–’os de servicio. Justo detrâ”œÃ­s del tranvâ”œÂ¡a, el cine "Pax" proyecta el musical "Funny Girl", con Barbra Streisand, y Omar Sharif. En la arbolada plaza, los sombreados bancos presentan notable parroquia. Fuente visual: Familia Cuyâ”œÃ¡s (cartotecadigital.icc.cat/)', 1970, 1970, 1970, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65538100, -0.87630000, '0101000020E61000007B832F4CA60AECBFBBB54C86E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24329925710.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24329925710.webp', 'https://www.flickr.com/photos/zaragozaantigua/24329925710/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22004, 'Colegio Santa Inâ”œÂ®s 1941', 'Dibujo del proyecto de nuevo edificio para el colegio de Santa Inâ”œÂ®s, por Lorenzo Monclâ”œâ•‘s, agosto de 1941. Serâ”œÃ­ levantado en 1942, en el chaflâ”œÃ­n entre las calles de Santa Inâ”œÂ®s y Boggiero, sobre terrenos del convento de Santa Inâ”œÂ®s. En 1949 fue ampliado y traspasado a las dominicas de la Anunciata. Fuente: www.ebay.es', 1941, 1941, 1941, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65646100, -0.89113700, '0101000020E61000007B2DE8BD3184ECBFBB0CFFE906D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36109225604.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36109225604.webp', 'https://www.flickr.com/photos/zaragozaantigua/36109225604/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23029, 'Calle del Conde de Aranda 1992', 'La calle del Conde de Aranda, tradicional salida hacia el oeste desde el centro de la ciudad, con sus 740 metros de longitud, vista desde las inmediaciones de la calle de Santa Inâ”œÂ®s, a la izquierda, con el Coso Alto al fondo. Su configuraciâ”œâ”‚n cambiâ”œâ”‚ aâ”œâ–’os despuâ”œÂ®s, en virtud de una remodelaciâ”œâ”‚n que, finalizada en 2004, incluyâ”œâ”‚ aceras mâ”œÃ­s anchas y una medianera ajardinada con palmeras.', 1992, 1992, 1992, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65582500, -0.89117800, '0101000020E610000020459DB98784ECBF1973D712F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50207027816.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50207027816.webp', 'https://www.flickr.com/photos/zaragozaantigua/50207027816/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23919, 'Tranvâ”œÂ¡a lâ”œÂ¡nea 5 1967', 'Aâ”œâ–’o 1967. Tranvâ”œÂ¡a de la lâ”œÂ¡nea 5 (Venecia-Delicias), a su paso por la calle "General Franco". Detrâ”œÃ­s del tranvâ”œÂ¡a, los restos de la manzana donde estuvo ubicada la antigua Casa de la Galera, como câ”œÃ­rcel correcional de mujeres durante los siglos XVII-XIX, que luego fue câ”œÃ­rcel masculina, y tambiâ”œÂ®n escuela de niâ”œâ–’os. Fuente visual: J. Ibâ”œÃ­â”œâ–’ez - Colecciâ”œâ”‚n Asociaciâ”œâ”‚n Filatâ”œÂ®lica Zaragozana "Gregorio Sierra".', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65593500, -0.89130800, '0101000020E6100000AC38D55A9885ECBFA0A696ADF5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14887018912.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14887018912.webp', 'https://www.flickr.com/photos/zaragozaantigua/14887018912/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23928, 'Calle Santa Inâ”œÂ®s 1886', 'Vista de la calle de Santa Inâ”œÂ®s de Zaragoza desde la iglesia del Portillo. A la derecha, calle del Portillo (hoy Conde de Aranda), flanqueada por la Casa de la Galera, reconvertida en colegio infantil en 1883. Abajo a la izquierda, huertas del convento de Santa Inâ”œÂ®s. Al fondo, las torres de la ciudad: el Pilar, San Pablo, Santa Isabel, la Seo, la Torre Nueva...', 1886, 1886, 1886, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65593500, -0.89130800, '0101000020E6100000AC38D55A9885ECBFA0A696ADF5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21002883458.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21002883458.webp', 'https://www.flickr.com/photos/zaragozaantigua/21002883458/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23940, 'Calle General Franco 1971', 'Vista de la calle del General Franco, esquina con la de Santa Inâ”œÂ®s, en julio de 1971. A la derecha, los restos de la antigua Casa de la Galera, despuâ”œÂ®s colegio. Tras la valla con carteles comerciales, el colegio del Carmen y San Josâ”œÂ® de las Hijas de la Caridad de San Vicente de Paâ”œâ•‘l, en funcionamiento en ese lugar desde 1947, ocupando parte del terreno del convento de Santa Inâ”œÂ®s. En el centro, unidad tranviaria nâ”œâ•‘mero 80 de la lâ”œÂ¡nea 5, "Venecia-Delicias", proveniente del barrio de las Delicias. Al fondo, edificios desaparecidos de la esquina de la avenida de Madrid con el paseo de Marâ”œÂ¡a Agustâ”œÂ¡n. A la izquierda, vista parcial de la agencia urbana nâ”œâ•‘mero 1 de la Caja de Ahorros de Zaragoza y de la torre derecha de la iglesia del Portillo. Fuente visual: www.facebook.com/photo.php?fbid=1433912296624611&set=...', 1971, 1971, 1971, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65580400, -0.89130000, '0101000020E6100000F697DD938785ECBF024BAE62F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30125233381.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30125233381.webp', 'https://www.flickr.com/photos/zaragozaantigua/30125233381/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24416, 'Convento de Santa Inâ”œÂ®s 1930', 'Defectuosa pero interesante vista de 1930 del final de la calle de San Pablo, donde tambiâ”œÂ®n terminaba la de Santa Inâ”œÂ®s. Al fondo, portada del convento de Santa Inâ”œÂ®s, enclavado ahâ”œÂ¡ desde el siglo XIV, y ocupado por monjas dominicas contemplativas. A partir de 1835, se dedicaron a la enseâ”œâ–’anza. En 1942 se construyâ”œâ”‚ un edificio de nueva planta, en el chaflâ”œÃ­n entre Santa Inâ”œÂ®s y Boggiero. En 1949 se amplâ”œÂ¡a y traspasa a las dominicas de la Anunciata. Fuente visual: Colecciâ”œâ”‚n Particular.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65684600, -0.89083800, '0101000020E6100000EC1681B1BE81ECBF14419C8713D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33500671741.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33500671741.webp', 'https://www.flickr.com/photos/zaragozaantigua/33500671741/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25827, 'Calle de Boggiero 1951', 'Archivo Municipal de Zaragoza. Archivo Mora. Junio 1951. "Calle de Boggiero." Esta es una calle que nace en la calle Escuelas Pâ”œÂ¡as y termina en la de Santa Inâ”œÂ®s. Imagen del tramo entre la calle de Santa Inâ”œÂ®s hasta la de Mayoral. A la derecha, un pedazo de la antigua Casa de la Penitencia, habilitada en el siglo XVII en un edificio del siglo XV, derribada para construir la cosa que hoy hay.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65625600, -0.89075000, '0101000020E61000001B2FDD240681ECBFE2E6543200D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15071262611.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15071262611.webp', 'https://www.flickr.com/photos/zaragozaantigua/15071262611/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25849, 'Calle de Santa Inâ”œÂ®s 1951', 'Imagen capturada en la calle de Santa Inâ”œÂ®s y centrada en el tramo entre la calle de Boggiero y la de San Pablo. A la izquierda, el moderno colegio de Santa Inâ”œÂ®s, levantado en 1941 en una pequeâ”œâ–’a parte del antiguo convento de Santa Inâ”œÂ®s de las Madres Dominicas. A la derecha, original anchura de la calle definida por los antiguos inmuebles del nâ”¬â•‘ 164 de Boggiero, y del nâ”¬â•‘ 6, 8 y 10-12 de Santa Inâ”œÂ®s. Al fondo, antiguo nâ”¬â•‘ 162 de la calle de San Pablo, donde la calle de Santa Inâ”œÂ®s terminaba, desaparecido mâ”œÃ­s tarde con motivo de la prolongaciâ”œâ”‚n de esa calle hasta la de Santa Lucâ”œÂ¡a. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65646100, -0.89113700, '0101000020E61000007B2DE8BD3184ECBFBB0CFFE906D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41306896562.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41306896562.webp', 'https://www.flickr.com/photos/zaragozaantigua/41306896562/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25850, 'Calle del General Franco c.1955', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 81 de la calle del General Franco, y centrada en el moderno colegio de Nuestra Seâ”œâ–’ora del Carmen y San Josâ”œÂ®, esquinero con la calle de Santa Inâ”œÂ®s en primer tâ”œÂ®rmino y a la derecha. Casualmente y a su lado, transita una composiciâ”œâ”‚n tranviaria M+R (posiblemente motor de la serie 60, y remolque de la 80) en servicio en la lâ”œÂ¡nea 5 "Venecia-Delicias", encaminada hacia la moderna plaza de Huesca, antigua de Rocasolano. Fuente visual: Ediciones DARVI, en www.delcampe.net/', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65582500, -0.89117800, '0101000020E610000020459DB98784ECBF1973D712F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46246198735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46246198735.webp', 'https://www.flickr.com/photos/zaragozaantigua/46246198735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20872, 'Dominguito y los barqueros 1250', 'Recuperaciâ”œâ”‚n del cadâ”œÃ­ver de Santo Dominguito de Val. Museo de Huesca, siglo XVI. El niâ”œâ–’o de siete aâ”œâ–’os Dominguito de Val, infantico (monaguillo cantante) de La Seo, fue raptado por el judâ”œÂ¡o Albayuceto, que lo entregâ”œâ”‚ a sus correligionarios para que lo crucificaran (en el palacio de Sora o Salabert). Luego ocultaron su cuerpo en la ribera del Ebro tras cortarle los pies y la cabeza. Unas luces divinas mostraron el lugar a unos barqueros, que recuperaron el cuerpo. Como reza la pintura, "No es la primera ocasiâ”œâ”‚n que para hallar un infante se muestra el cielo radiante". Los caballeros de la barca son las autoridades que acudieron a dar fe. Esta leyenda fue creada en 1643, a imitaciâ”œâ”‚n de otras similares. A la izquierda, desembocadura del Huerva en el Ebro. Al fondo, puente de Tablas, puente de Piedra y Arrabal. Fuente: www.facebook.com/photo.php?fbid=10203933800178773&set...', 1250, 1250, 1250, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65285400, -0.86416000, '0101000020E6100000105D50DF32A7EBBF098849B890D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15208940932.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15208940932.webp', 'https://www.flickr.com/photos/zaragozaantigua/15208940932/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20877, 'Dominguito de Val 1250', 'Santo Dominguito de Val. Grabado de Mateo Gonzâ”œÃ­lez, 1793. Museo de Zaragoza. Niâ”œâ–’o legendario zaragozano del que se relataba su muerte violenta, situâ”œÃ­ndola en 1250, cuyo culto fue suprimido por el Concilio Vaticano II (1965). En el fondo de la imagen principal vemos una representaciâ”œâ”‚n del paso del râ”œÂ¡o Ebro por Zaragoza. En el â”œÃ­ngulo inferior derecho, el cadâ”œÃ­ver mutilado luminoso en la desembocadura del râ”œÂ¡o Huerva. A la izquierda, el Puente de Tablas y un embarcadero de dudosa verosimilitud.', 1250, 1250, 1250, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65285400, -0.86416000, '0101000020E6100000105D50DF32A7EBBF098849B890D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19054241565.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19054241565.webp', 'https://www.flickr.com/photos/zaragozaantigua/19054241565/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22310, 'Parque Bruil c.1969', 'Imagen del "Parque Torre de Bruil" de Zaragoza, inaugurado en 1965. Fuente: Foto para postal de Comercial Josan. Cesiâ”œâ”‚n de la familia de Josâ”œÂ® Marâ”œÂ¡a Sanz Gonzâ”œÃ­lez a Rafael Castillejo. Dataciâ”œâ”‚n y procesado:', 1969, 1969, 1969, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.64977900, -0.86902400, '0101000020E6100000240D6E6B0BCFEBBF555051F52BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15679984796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15679984796.webp', 'https://www.flickr.com/photos/zaragozaantigua/15679984796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22376, 'Vista aâ”œÂ®rea Ebro 1964', 'Vista aâ”œÂ®rea del râ”œÂ¡o Ebro a su paso por Zaragoza, desde el este. En primer tâ”œÂ®rmino, la desembocadura del râ”œÂ¡o Huerva, en la margen derecha. Fuente: Colecciâ”œâ”‚n Rafael Margalâ”œÂ®.', 1964, 1964, 1964, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65381700, -0.86519600, '0101000020E610000017299485AFAFEBBFCF488446B0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22129071029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22129071029.webp', 'https://www.flickr.com/photos/zaragozaantigua/22129071029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22446, 'Aloy Sala 1960', 'Imagen aâ”œÂ®rea capturada desde las alturas del este de la ciudad, centrada en el reciente Grupo Aloy Sala, construido en terrenos del arrabal de las Tenerâ”œÂ¡as lindantes con el talud del râ”œÂ¡o Huerva, que de izquierda a derecha, y en primer tâ”œÂ®rmino, desemboca en el Ebro; los campos de cultivos inmediatos a las traseras del militar Depâ”œâ”‚sito de Sementales y los terrenos de la antigua Torre de Bruil (izquierda); y la fâ”œÃ­brica de armamento Instalaza, en el indefinido espacio hasta el cauce del râ”œÂ¡o Ebro (derecha). Este Grupo preveâ”œÂ¡a la construcciâ”œâ”‚n de 1579 viviendas, locales comerciales y servicios varios, incluyendo escuelas, ocio e iglesia catâ”œâ”‚lica, como gâ”œÂ®nesis de un nuevo barrio completo destinado a la clase media, y en râ”œÂ®gimen de alquiler, a realizar en varias fases, de las que sâ”œâ”‚lo se completaron las dos primeras. En beneficio de todos, gratis et amore, hemos volteado horizontalmente la imagen original. Fuente visual: Arxiu Nacional de Catalunya', 1960, 1960, 1960, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65209000, -0.86674900, '0101000020E61000000CE71A6668BCEBBF3A0664AF77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31051119443.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31051119443.webp', 'https://www.flickr.com/photos/zaragozaantigua/31051119443/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23686, 'Aerâ”œâ”‚dromo Sanjurjo 1938', 'Imagen capturada en el aerâ”œâ”‚dromo Sanjurjo de Zaragoza con un contundente primer plano de bombas de 50 kg. apiladas y listas para cargarlas en los bombarderos operativos. Tras ellas y en la pista, un Junkers Ju-W 34 Hi, aparato de enlace, entrenamiento y servicio meteorolâ”œâ”‚gico, y varios Dornier Do-17 E.1, modernos bombarderos ligeros con capacidad de cargar 15 de estas bombas que los alemanes de la Legiâ”œâ”‚n Câ”œâ”‚ndor denominaban "Fliegender Bleistift" (lâ”œÃ­piz volador) por su alargado fuselaje, y que los nacionalistas espaâ”œâ–’oles redenominaron mâ”œÃ­s castizamente "Bacalao". Al fondo, lâ”œÂ¡nea de â”œÃ­rboles que seâ”œâ–’ala el curso del Canal Imperial de Aragâ”œâ”‚n.', 1938, 1938, 1938, 'Anos 30', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50301123318.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50301123318.webp', 'https://www.flickr.com/photos/zaragozaantigua/50301123318/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23057, 'Cuartel de Sementales 1994', 'Imagen capturada en el solar dejado tras el derribo de las instalaciones del cuartel 5â”¬â•‘ Depâ”œâ”‚sito de Sementales sito en la calle del Asalto, entre el parque de Bruil y el Grupo de Viviendas Aloy Sala. Esta dependencia militar no fue incluida en la Operaciâ”œâ”‚n Cuarteles a pesar de las gestiones del Ayuntamiento al principio de los aâ”œâ–’os 80 por las reclamaciones realizadas por el ramo de la Guerra, tanto econâ”œâ”‚micas como que allâ”œÂ¡ se levantaran viviendas militares. En paralelo, el vecindario del barrio de las Tenerâ”œÂ¡as promoviâ”œâ”‚ gestiones para solicitar el traslado de este cuartel por sus afecciones insalubres, nocivas y molestas. Finalmente, en 1994 se llegâ”œâ”‚ a un acuerdo y el cuartel fue desmantelado y trasladado a unas nuevas instalaciones en Garrapinillos. El solar resultante serâ”œÂ¡a objeto de un Plan Especial del â”œÃ¼rea de Intervenciâ”œâ”‚n U-7-2 aprobado en 1996 del que resultarâ”œÂ¡a la urbanizaciâ”œâ”‚n actual de este espacio. En la escena, vista del solar dejado tras el derribo del cuartel, con el parque de Bruil al fondo, sobre el que emergen los bloques de la calle de Alvira Lasierra. A la derecha, viviendas de la calle del Asalto esquineras con la calle de Cantâ”œÂ¡n y Gamboa y vecinas del convento de las madres agustinas de Santa Mâ”œâ”‚nica. Mâ”œÃ­s a la derecha, se destaca la torre del antiguo convento de San Agustâ”œÂ¡n.', 1994, 1994, 1994, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65102200, -0.86845600, '0101000020E6100000AF7AC03C64CAEBBFFE7C5BB054D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50449979087.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50449979087.webp', 'https://www.flickr.com/photos/zaragozaantigua/50449979087/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23201, 'Calle Vicente Lâ”œâ”‚pez Abadâ”œÂ¡a 2010', 'Foto: Oliver Duch. Solar entre las calles de Vicente Lâ”œâ”‚pez Abadâ”œÂ¡a (al fondo) y Pascual Albero Burillo, junto al parque Bruil. Allâ”œÂ¡ se construyâ”œâ”‚ en 2010 la Escuela Infantil Municipal Parque Bruil, inaugurada en octubre de 2012 con domicilio en la calle Vicente Lâ”œâ”‚pez Abadâ”œÂ¡a 4. En su subsuelo estâ”œÃ­ previsto un aparcamiento subterrâ”œÃ­neo. Fuente: Heraldo de Aragâ”œâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65156300, -0.86685900, '0101000020E6100000D2C8E7154FBDEBBF4F24986A66D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32518208074.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32518208074.webp', 'https://www.flickr.com/photos/zaragozaantigua/32518208074/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24706, 'Prolongaciâ”œâ”‚n Echegaray 1989', 'Vista aâ”œÂ®rea de las obras de 1989 en el entorno de la desembocadura del râ”œÂ¡o Huerva, en lo que serâ”œÃ­ la prolongaciâ”œâ”‚n del paseo de Echegaray y Caballero. En primer tâ”œÂ®rmino, construcciâ”œâ”‚n del puente de La Uniâ”œâ”‚n. En el centro, puente sobre el Huerva. Al fondo a la derecha, puentes del Pilar, de Piedra y de Santiago. Fuente: www.eszaragoza.eu/2017/06/lo-que-sucedia-en-zaragoza-dura...', 1989, 1989, 1989, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65240600, -0.86526100, '0101000020E6100000DD2230D637B0EBBF6ADB300A82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36403250961.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36403250961.webp', 'https://www.flickr.com/photos/zaragozaantigua/36403250961/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24736, 'El Huerva llega al Ebro 1977', 'Imagen de la desembocadura del Huerva en el Ebro. Pocos cambios en este entorno desde que el Huerva abandonara, hace ya bastante tiempo, su antiguo cauce, por la actual calle del Asalto, y se desviara hacia la derecha, hacia tierras mâ”œÃ­s bajas, dejando el meandro del actual Parque Bruil como un lugar muy favorable para la agricultura. En la margen izquierda, panorama de las diferentes urbanizaciones, en este caso con grandes bloques habitacionales que iban surgiendo desde mediados de los aâ”œâ–’os 70. En primer tâ”œÂ®rmino, sobresaliendo detrâ”œÃ­s de naves y almacenes, la urbanizaciâ”œâ”‚n Vadorrey. A la izquierda, mâ”œÃ­s al fondo, la urbanizaciâ”œâ”‚n denominada "El Colector", actual Manuel Viola. El alto bloque que sobresale por encima de todos, es el edificio "La Estrella", de 14 alturas, junto a la Avenida de Cataluâ”œâ–’a. Fuente visual: "La evoluciâ”œâ”‚n urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1977, 1977, 1977, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65295400, -0.86484000, '0101000020E610000078B988EFC4ACEBBF6DE525FF93D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15139541264.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15139541264.webp', 'https://www.flickr.com/photos/zaragozaantigua/15139541264/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24961, 'Al norte del Parque Bruil 1974', 'AYUNTAMIENTO DE ZARAGOZA/Sancho Ramo, Gerardo/Noviembre 1974. La Torre de Bruil-Parque Bruil, el Depâ”œâ”‚sito de Sementales del Ejâ”œÂ®rcito de Tierra, el Grupo de Viviendas "Aloy Sala" (Arrabal de las Tenerâ”œÂ¡as), y el râ”œÂ¡o Huerva ya casi desembocando en el Ebro, delimitaban una interesante y poco visitada zona de antiguos campos de cultivo, a escasos minutos del centro de la ciudad. Dos principales caminos de servicio de fincas hacâ”œÂ¡an las funciones de irregular cardo y decumano para un llano perâ”œÂ¡metro donde cereales y herbâ”œÃ­ceas se sucedâ”œÂ¡an segâ”œâ•‘n el aâ”œâ–’o. Un riego derivado de acequia, y un desagâ”œâ•e de viejos lavaderos, vertâ”œÂ¡an aguas a la trinchera del Huerva (a la izquierda). El desarrollo urbano de la ciudad habâ”œÂ¡a sido orientado hacia otras latitudes, y el entorno no se consideraba de la suficiente calidad como para esperar una revalorizaciâ”œâ”‚n suficiente y râ”œÃ­pida del precio del suelo agrâ”œÂ¡cola. Pese a tener de vecino al novâ”œÂ¡simo y espectacular Parque Bruil, la inmediatez del cuartel del Ejâ”œÂ®rcito (caballerâ”œÂ¡a), las viviendas baratas de los 50, y que las Tenerâ”œÂ¡as no era precisamente el Soho zaragozano, mantuvo en barbecho espectante esta zona durante alguna dâ”œÂ®cada mâ”œÃ­s. Ahora esto es otra cosa, distinta. En la imagen, vista de los campos de cultivo desde la actual calle Alto Aragâ”œâ”‚n. De izquierda a derecha, el râ”œÂ¡o Huerva, el reciente edificio Hâ”œÃ­bitat Don 2000 (1973), y tras el muro de delimitaciâ”œâ”‚n, los â”œÃ­rboles y fronda del Parque Bruil, y las aromâ”œÃ­ticas instalaciones del cuartel de caballerâ”œÂ¡a. Justo detrâ”œÃ­s, las ruinas del antiguo convento de S. Agustâ”œÂ¡n y su caracterâ”œÂ¡stica y desmochada torre, y la confluencia viaria de Alonso V con la calle Asalto.', 1974, 1974, 1974, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65139800, -0.86796800, '0101000020E6100000552FBFD364C6EBBF0457790261D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14849195251.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14849195251.webp', 'https://www.flickr.com/photos/zaragozaantigua/14849195251/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24963, 'Parque Bruil 1965', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/julio 1965. Tras mâ”œÃ­s de diez aâ”œâ–’os de gestiones, inauguraciâ”œâ”‚n del municipal Parque Bruil, entre el râ”œÂ¡o Huerva (este), la calle Asalto (oeste), el cuartel de Sementales y unos campos de cultivos (norte), y un vial que poco despuâ”œÂ®s se denominarâ”œÃ­ Mariano Alvira Lasierra.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.64977900, -0.86902400, '0101000020E6100000240D6E6B0BCFEBBF555051F52BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14850897742.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14850897742.webp', 'https://www.flickr.com/photos/zaragozaantigua/14850897742/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24974, 'Parque Bruil 1970', 'Piscinas del parque Bruil de Zaragoza. Postal, ed. Zerkowitz, serie 82, nâ”¬â•‘ 1.074, 1970. Fuente: www.todocoleccion.net', 1970, 1970, 1970, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.64977900, -0.86902400, '0101000020E6100000240D6E6B0BCFEBBF555051F52BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19585124351.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19585124351.webp', 'https://www.flickr.com/photos/zaragozaantigua/19585124351/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25421, 'Râ”œÂ¡o Ebro y murallas s.XVII', 'Trascoro de la Seo de Zaragoza. Siglo XVII. Relieve de la vista del râ”œÂ¡o Ebro y las murallas de Zaragoza con la puerta del â”œÃ¼ngel junto al puente de Piedra, y el puente de Tablas en primer tâ”œÂ®rmino. Escena de la leyenda del hallazgo del los restos de Santo Dominguito de Val decapitado. Fuente: Catâ”œÃ­logo El municipio en Aragâ”œâ”‚n, DPZ, 2004.', NULL, NULL, NULL, NULL, 'CASCO HISTâ”œÃ´RICO', 41.65285400, -0.86416000, '0101000020E6100000105D50DF32A7EBBF098849B890D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18672417202.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18672417202.webp', 'https://www.flickr.com/photos/zaragozaantigua/18672417202/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25536, 'Colector del Huerva 1934', 'El emisario del alcantarillado al râ”œÂ¡o Ebro en la margen izquierda de la desembocadura del Huerva fue construido en 1907 y ampliado en 1934, momento que recoge la foto. Entre los trabajadores, algunas bestias de carga. Hasta la urbanizaciâ”œâ”‚n reciente de la zona en el siglo XXI, el colector vertâ”œÂ¡a las aguas residuales al descubierto, dejando un olor caracterâ”œÂ¡stico. Fuente: Plan general de ensanche de Zaragoza, 1934.', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65312700, -0.86547500, '0101000020E6100000E02D90A0F8B1EBBF3A9160AA99D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18701889484.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18701889484.webp', 'https://www.flickr.com/photos/zaragozaantigua/18701889484/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23059, 'Vuelta ciclista a Espaâ”œâ–’a 1990', 'El 13 de mayo de 1990 se celebrâ”œâ”‚ la etapa 19 de la Vuelta ciclista a Espaâ”œâ–’a, con un recorrido de 30 km contrarreloj dentro de la ciudad de Zaragoza. El ganador de la prueba fue Peio Ruiz Cabestany, y el de la Vuelta, Marco GIovannetti. La imagen estâ”œÃ­ extraâ”œÂ¡da del vâ”œÂ¡deo de la retransmisiâ”œâ”‚n en TVE, y muestra al ciclista Pedro Delgado atravesando el puente de la Uniâ”œâ”‚n o de Las Fuentes sobre el Ebro, con el Pilar al fondo.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65246900, -0.86273700, '0101000020E6100000A79201A08A9BEBBFB153AC1A84D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50494089228.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50494089228.webp', 'https://www.flickr.com/photos/zaragozaantigua/50494089228/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21222, 'Râ”œÂ¡o Ebro c.1905', 'Photoglob Zâ”œâ•rich. Ca.1905. "Râ”œÂ¡o Ebro y Nuestra Seâ”œâ–’ora del Pilar". Imagen del Ebro, con el fluvial paso en barca, por aâ”œÂ®reo camino de sirga, del "Tâ”œÂ¡o Toni". Al fondo, el puente de las piedras, con sus pretiles y sus leones. Detrâ”œÃ­s, el de hierros. Fuente: www.el-trastero.eu/caddie/images/zaragoza-0010.webp', 1905, 1905, 1905, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65911000, -0.88090100, '0101000020E61000003370404B5730ECBFB83B6BB75DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15934073422.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15934073422.webp', 'https://www.flickr.com/photos/zaragozaantigua/15934073422/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21442, 'Râ”œÂ¡o Ebro c.1910', 'Imagen capturada junto a la ribera del râ”œÂ¡o Ebro inmediata a la arboleda de Macanaz, en la margen izquierda, y centrada en una vista que incluye al Puente de Piedra y el Puente de Hierro mâ”œÃ­s al fondo, y el templo del Pilar con las dos torres recayentes a la homâ”œâ”‚nima plaza. En primer tâ”œÂ®rmino, embarcadero del paso de barcas que dâ”œÂ®cadas mâ”œÃ­s tarde seâ”œâ–’alarâ”œÂ¡a la ubicaciâ”œâ”‚n de una pasarela peatonal permanente. Sobre el Puente de Piedra transita un coche posiblemente de la tranviaria lâ”œÂ¡nea del Arrabal. A la derecha, entre el Pilar y la ribera de la margen derecha, el recoleto espacio junto a la Puerta del Fin y la Escuela Normal de Maestras utilizado como ferial de ganado.', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65886900, -0.88098700, '0101000020E6100000D66F26A60B31ECBF93ACC3D155D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49334482061.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49334482061.webp', 'https://www.flickr.com/photos/zaragozaantigua/49334482061/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21502, 'Almadieros 1923', 'Miguel Faci Abad. 1923. "Zaragoza. Baâ”œâ–’os del Ebro y navatas." En la imagen, tomada desde la margen izquierda del râ”œÂ¡o Ebro, aspecto de la arboleda de Macanaz cuando aâ”œâ•‘n era utilizada para desembarcar los maderos que los almadieros del Valle del Roncal traâ”œÂ¡an a la ciudad. Los maderos, una vez sacados del agua, se dejaban "en cuarentena", para que se secaran completamente antes de su uso, o distribuciâ”œâ”‚n. Mientras los almadieros descansan al sol de la tarde, unos chavales en pelota picada se remojan para refrescarse, mientras otros, vestidos, se van a remojar sin pretenderlo. El uso del Ebro como fluvial ruta de transporte de madera fue posible hasta la puesta en funcionamiento de la presa de Yesa (1959-1960). Fuente visual: "Miguel y Gabriel Faci. Fotâ”œâ”‚grafos fundadores de la Real Sociedad Fotogrâ”œÃ­fica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaciâ”œâ”‚n Provincial de Zaragoza, 1999.', 1923, 1923, 1923, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65911000, -0.88090100, '0101000020E61000003370404B5730ECBFB83B6BB75DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15516887172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15516887172.webp', 'https://www.flickr.com/photos/zaragozaantigua/15516887172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21685, 'El paso del Ebro 1939', 'Albert Louis Deschamps. Cruzando el Ebro a mano, a la altura de San Juan de los Panetes y la Zuda, una maniobra de la Barca del Tâ”œÂ¡o Toni, al precio de cinco câ”œÂ®ntimos de peseta la persona. El Torreâ”œâ”‚n de la Zuda se encontraba entre diversas viviendas que se le habâ”œÂ¡an ido adosando a lo largo del tiempo. En 1931 comenzarâ”œÃ­ una intervenciâ”œâ”‚n en la zona, con la ampliaciâ”œâ”‚n de la avenida de Nuestra Seâ”œâ–’ora del Pilar, las murallas romanas, el torreâ”œâ”‚n de la Zuda y la iglesia de San Juan de los Panetes. Luego vendrâ”œÃ­ la idea de la Vâ”œÂ¡a Imperial, y luego la de Câ”œÂ®sar Augusto... En la imagen aâ”œâ•‘n no estaba construida la Pasarela Peatonal sobre el Ebro, que se iniciarâ”œÃ­ en 1940, y se inaugurarâ”œÃ­ en 1941.', 1939, 1939, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65835600, -0.88138400, '0101000020E61000001AF7E6374C34ECBF0C90680245D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14903094946.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14903094946.webp', 'https://www.flickr.com/photos/zaragozaantigua/14903094946/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21734, 'El Ebro y el Pilar aâ”œâ–’os 30', 'Foto: Miguel Marâ”œÂ¡n Chivite. Panorama del râ”œÂ¡o Ebro con el Pilar al fondo. A la izquierda, puente de piedra y niâ”œâ–’o bebiendo. La embarcaciâ”œâ”‚n que aparece es un modelo motorizado que efectâ”œâ•‘a el recorrido tradicional de la barca del Tâ”œÂ¡o Toni, que seguirâ”œÃ­ prestando sus servicios mediante sirga a mano hasta la construcciâ”œâ”‚n de la pasarela peatonal en los aâ”œâ–’os 40. Fuente: Archivo Heraldo de Aragâ”œâ”‚n.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65835600, -0.88148800, '0101000020E610000058207A522635ECBF0C90680245D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21351091648.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21351091648.webp', 'https://www.flickr.com/photos/zaragozaantigua/21351091648/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21773, 'Râ”œÂ¡o Ebro 1932', 'Râ”œÂ¡o Ebro. Al fondo, el puente del Ferrocarril. A la derecha, la arboleda de Macanaz, la Caseta de Baâ”œâ–’os, y la Ã”Ã‡Â£Sociedad Naturista HeliosÃ”Ã‡Ã˜. Una barca cruza el râ”œÂ¡o. Fuente visual: Foto Conrado Barlâ”œÂ®s, donada por Daniel Barlâ”œÂ®s y digitalizada por Josâ”œÂ® Luis Cintora para www.rafaelcastillejo.com', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65854900, -0.88066500, '0101000020E61000003C6BB75D682EECBF21E868554BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22855738617.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22855738617.webp', 'https://www.flickr.com/photos/zaragozaantigua/22855738617/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21829, 'Embarcadero 1933', 'Embarcadero en el râ”œÂ¡o Ebro. Al fondo, el Pilar. Fuente: Heraldo de Aragâ”œâ”‚n.', 1933, 1933, 1933, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65897000, -0.88242700, '0101000020E6100000C16F438CD73CECBFC685032159D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32935400752.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32935400752.webp', 'https://www.flickr.com/photos/zaragozaantigua/32935400752/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21842, 'Pasarela de Macanaz 1933', 'Dibujo representando la pasarela peatonal sobre el râ”œÂ¡o Ebro proyectada por el ingeniero Luis de Fuentes Lâ”œâ”‚pez como forma de conectar la calle de Antonio Pâ”œÂ®rez con la arboleda de Macanaz. El antropolâ”œâ”‚gico y â”œâ•‘nico paso de sirga del tâ”œÂ¡o Toni ya habâ”œÂ¡a dado paso a la introducciâ”œâ”‚n por â”œÃ¼ngel Bagâ”œâ•â”œÂ®s de las modernas barcas a gasolina que cubrâ”œÂ¡an el trâ”œÃ­nsito de personas entre las dos orillas mediante varios embarcaderos. Tras los diversos procesos de embellecimiento de ambas riberas del Ebro, ahora parecâ”œÂ¡a tocarle el turno a la construcciâ”œâ”‚n de un paso peatonal estable de orilla a orilla, si bien la idea finalmente serâ”œÂ¡a materializada al principio de la siguiente dâ”œÂ®cada, tan cercana, y tan diferente. En el dibujo, la proyectada pasarela representada entre la orilla derecha (a la izquierda) con el final de la calle de Antonio Pâ”œÂ®rez, y la orilla izquierda (a la derecha) con la arboleda de Macanaz y su acceso casi cinco metros mâ”œÃ­s bajo a salvar mediante escaleras. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65843900, -0.88113600, '0101000020E61000001381EA1F4432ECBF9AB4A9BA47D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35569416784.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35569416784.webp', 'https://www.flickr.com/photos/zaragozaantigua/35569416784/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21844, 'Calle de Demetrio Galâ”œÃ­n 1934', 'Imagen capturada en la despejada calle de Demetrio Galâ”œÃ­n, paralela a la arboleda de Macanaz, y centrada en la fâ”œÃ­brica de lavaje y apartado de lanas de Jaime Corcoy, que iniciâ”œâ”‚ su actividad en 1917 como Manufactura de Lanas de Morâ”œâ”‚n y Anâ”œâ”‚s, con diseâ”œâ–’o de Miguel â”œÃ¼ngel Navarro, en el entonces camino de Ranillas. De esta instalaciâ”œâ”‚n perdura la chimenea, en un entorno descontextualizado, bastante diferente. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.66064300, -0.88270300, '0101000020E61000004698A25C1A3FECBF69AA27F38FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35653992904.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35653992904.webp', 'https://www.flickr.com/photos/zaragozaantigua/35653992904/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22037, 'Râ”œÂ¡o Ebro c.1942', 'Acuarela del prolâ”œÂ¡fico dibujante, poeta y periodista Ambrosio Ruste Alonso (1871-1955) titulada "El Pilar" porque este templo centra desde el fondo de la escena una fluvial vista capturada desde un embarcadero recreativo en la arboleda de Macanaz. Apenas esbozada, la pasarela del Ebro aparece levemente tendida sobre el râ”œÂ¡o. Fue proyectada en 1933 por el ingeniero Luis de Fuentes Lâ”œâ”‚pez como forma de conectar la calle de Antonio Pâ”œÂ®rez con la arboleda de Macanaz, si bien su construcciâ”œâ”‚n se demorâ”œâ”‚ en el tiempo para ser finalmente bendecida e inaugurada el 25 de febrero de 1941, terminando asâ”œÂ¡ con la tradicional barca de sirga que desde el siglo XIX conectaba las dos riberas y que desde los aâ”œâ–’os 30 fue sustituida por "gasolineras" o barcazas a motor. Como siempre, una mejora en esta ciudad que conlleva un derribo o una desapariciâ”œâ”‚n de un elemento previo fue ardorosamente aplaudida en la prensa de la â”œÂ®poca, donde se sentenciâ”œâ”‚ que la referida barca era "vieja", "antiestâ”œÂ®tica" y "lenta", mientras que la nueva pasarela era "mâ”œÃ­s lâ”œâ”‚gica, câ”œâ”‚moda y eficaz". Asâ”œÂ¡ las cosas y de forma no menos lâ”œâ”‚gica, esta situaciâ”œâ”‚n se repetirâ”œÂ¡a casi un cuarto de siglo despuâ”œÂ®s, cuando esta pasarela fue desmontada para dar paso a un nuevo puente mâ”œÃ­s câ”œâ”‚modo y eficaz.', 1942, 1942, 1942, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65914200, -0.88259600, '0101000020E6100000C59272F7393EECBFC4B5DAC35ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54754018338.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54754018338.webp', 'https://www.flickr.com/photos/zaragozaantigua/54754018338/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22082, 'Pasarela sobre el Ebro aâ”œâ–’os 50', 'Magnâ”œÂ¡fica imagen del acceso desde la Arboleda de Macanaz a la pasarela sobre el râ”œÂ¡o Ebro construida en 1941, que desapareciâ”œâ”‚ para dar paso al puente de Santiago en 1967. Al fondo, la iglesia de San Juan de los Panetes. Fuente: www.facebook.com/photo.php?fbid=643306315778704&set=p...', 1950, 1950, 1959, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65902300, -0.88117100, '0101000020E61000002FE065868D32ECBFE9279CDD5AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15783586076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15783586076.webp', 'https://www.flickr.com/photos/zaragozaantigua/15783586076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22095, 'Pasarela 1955', '"Saliendo de la escuela", foto de Josâ”œÂ® Antonio Duce, 1955. Niâ”œâ–’os sobre la pasarela peatonal del Ebro que serâ”œÃ­ sustituida por el puente de Santiago. Al fondo, San Juan de los Panetes. Fuente: rafaelcastillejo.com', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20090004454.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20090004454.webp', 'https://www.flickr.com/photos/zaragozaantigua/20090004454/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22230, 'Helios c.1959', 'Imagen capturada desde el campin de Helios y orientada hacia el este, con vista parcial de la original piscina y la pista de baloncesto. Hacia el fondo, la arboleda de Macanaz, flanqueada por viviendas del Arrabal a la izquierda, y el templo del Pilar a la derecha.', 1959, 1959, 1959, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.66000800, -0.88296100, '0101000020E61000003197546D3741ECBF978C63247BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49911991977.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49911991977.webp', 'https://www.flickr.com/photos/zaragozaantigua/49911991977/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22289, 'Puente de Santiago 1965', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 23/01/1965. "Crecida del râ”œÂ¡o Ebro." 1965 fue otro aâ”œâ–’o de crecida destacable del râ”œÂ¡o Ebro. A su paso por la ciudad, la altura del agua fluyendo alcanzâ”œâ”‚ los cinco metros de altura. En la imagen, aspecto del puente de Santiago en construcciâ”œâ”‚n, mientras el cauce se hinchaba y desbordaba allâ”œÂ¡ donde las riberas lo permitâ”œÂ¡an, como en la zona de Helios.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65856500, -0.88158800, '0101000020E61000003A799109F835ECBF27A5A0DB4BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15208136758.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15208136758.webp', 'https://www.flickr.com/photos/zaragozaantigua/15208136758/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22313, 'Pasarela Ebro 1962', 'Josâ”œÂ® Antonio Duce. 1962. Imagen de la Pasarela Peatonal del Ebro. Captura de imagen desde la Margen Izquierda. En la ribera derecha, marcado contraluz para la fachada de edificios al paseo del Ebro. Entre las sombras, el dieciochesco antiguo Almacâ”œÂ®n de la Sal, junto a algunas otras edificaciones que siglo de las Luces, que aâ”œâ–’os despuâ”œÂ®s terminarâ”œÂ¡an cayendo derrumbados por piquetas y mecâ”œÃ­nicos ingenios. Fuente visual: www.gozazaragoza.com/contenido.php?id=9799', 1962, 1962, 1962, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65902300, -0.88117100, '0101000020E61000002FE065868D32ECBFE9279CDD5AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15747149020.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15747149020.webp', 'https://www.flickr.com/photos/zaragozaantigua/15747149020/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
