INSERT INTO public.photos VALUES (22364, 'Esquâ”œÂ¡ acuâ”œÃ­tico c.1969', 'Postal, finales de los aâ”œâ–’os 60. Vista del puente de Santiago sobre el râ”œÂ¡o Ebro en Zaragoza, con baturros en primer plano y una lancha practicando esquâ”œÂ¡ acuâ”œÃ­tico, deporte que no ha llegado a cuajar entre los tradicionales aragoneses. Fuente: www.facebook.com/photo.php?fbid=10201037600339410&set...', 1969, 1969, 1969, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65908400, -0.88194800, '0101000020E610000034B91803EB38ECBF8FA850DD5CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21268207276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21268207276.webp', 'https://www.flickr.com/photos/zaragozaantigua/21268207276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22431, 'Vista aâ”œÂ®rea 1966', 'Canicular vista aâ”œÂ®rea centrada en la construcciâ”œâ”‚n del nuevo puente sobre el râ”œÂ¡o Ebro y la apertura en la margen izquierda de la avenida de los Pirineos como inicio de la moderna carretera hacia Huesca. En la margen derecha, aun con los derribos de viviendas de la antigua calle de Antonio Pâ”œÂ®rez (moderna Vâ”œÂ¡a Imperial y luego avenida de Câ”œÂ®sar Augusto), el trâ”œÃ­nsito rodado se habrâ”œÂ¡a de topar, indefectiblemente, con el Mercado Central (en primer tâ”œÂ®rmino), construido en los albores del siglo cuando ninguna mente con visiâ”œâ”‚n de futuro pudo siquiera soâ”œâ–’ar que las necesidades de movilidad de un gran parque automâ”œâ”‚vil habrâ”œÂ¡an de requerir practicar cirugâ”œÂ¡a urbanâ”œÂ¡stica radical en el casco antiguo de la ciudad. No pasarâ”œÂ¡an muchos aâ”œâ–’os hasta que se fomentara la bochornosa campaâ”œâ–’a que exigâ”œÂ¡a derribar el Mercado Central para dar paso a la modernidad identificada con la hegemonâ”œÂ¡a del vehâ”œÂ¡culo privado, y la adecuaciâ”œâ”‚n viaria a sus exponenciales necesidades de espacio. Fuente: TAF Helicâ”œâ–“pters SA, en Arxiu Nacional de Catalunya.', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65858700, -0.88163100, '0101000020E61000000C7904375236ECBF0E492D944CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29290884717.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29290884717.webp', 'https://www.flickr.com/photos/zaragozaantigua/29290884717/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22434, 'Puente de Santiago 1966', 'Imagen capturada durante la construcciâ”œâ”‚n del "Nuevo puente sobre el râ”œÂ¡o Ebro" por el M.O.P., con interesante vista en la margen izquierda del barrio de la Hortilla (antes de perder la "h") y aun del de Ranillas, el ribereâ”œâ–’o camping de Helios, el antiguo edificio de los "Baâ”œâ–’os del Ebro" y, sobresaliendo entre la foresta, la chimenea de la antigua "Manufacturas de lanas de Morâ”œâ”‚n y Anâ”œâ”‚s", en el Camino de Ranillas. Al fondo, a la izquierda, el puente del ferrocarril. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30235519295.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30235519295.webp', 'https://www.flickr.com/photos/zaragozaantigua/30235519295/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22451, 'Puente de Santiago 1966', 'Imagen, capturada desde la margen izquierda, durante la construcciâ”œâ”‚n del nuevo puente sobre el râ”œÂ¡o Ebro que sustituyâ”œâ”‚ a la pasarela peatonal. A la izquierda, vista parcial de la obra de la piscina cubierta del Club Nataciâ”œâ”‚n Helios, ubicada donde estuviera el antiguo edificio de los Baâ”œâ–’os del Ebro. Una interesante crecida del râ”œÂ¡o pone a prueba las obras, aunque no tiene la descomunal categorâ”œÂ¡a de las de 1643, o 1871, entre otras cosas, por las obras de regulaciâ”œâ”‚n en cabecera de cuenca. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31407744436.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31407744436.webp', 'https://www.flickr.com/photos/zaragozaantigua/31407744436/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22488, 'Puente de Santiago 1966', 'Veraniega vista panorâ”œÃ­mica capturada en altura y centrada en la construcciâ”œâ”‚n del nuevo puente sobre el râ”œÂ¡o Ebro que, denominado de Santiago, supuso el desmontaje de la previa pasarela peatonal de pago, la apertura para el trâ”œÃ­fico rodado en la margen izquierda de la gran avenida de los Pirineos como inicio de la moderna carretera hacia Huesca, y en la margen derecha la consolidaciâ”œâ”‚n de la avenida de Câ”œÂ®sar Augusto como vâ”œÂ¡a de alta capacidad que habrâ”œÂ¡a de conducir el trâ”œÃ­fico, tras despejar el camino por una parte de la antigua ciudad, hasta la misma puerta del Carmen. En primer tâ”œÂ®rmino, la arbolada zona oriental de la gran plaza del Pilar determinada por el referencial monumento "A los hâ”œÂ®roes y mâ”œÃ­rtires de Zaragoza caâ”œÂ¡dos en nuestra Gloriosa Cruzada de Liberaciâ”œâ”‚n 1936-1939", la iglesia de San Juan de los Panetes y el torreâ”œâ”‚n de la Zuda. En la margen izquierda, la arboleda de Macanaz, el Club Nataciâ”œâ”‚n Helios en proceso de ampliaciâ”œâ”‚n de instalaciones, la antigua factoria "Manufacturas de lanas de Morâ”œâ”‚n y Anâ”œâ”‚s", el barrio de la Ortilla y el tendido del enlace ferroviario hacia Alsasua. Fuente: TAF Helicâ”œâ–“pters SA, en Arxiu Nacional de Catalunya.', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65852500, -0.88135200, '0101000020E61000004374081C0934ECBF984C158C4AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44125666581.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44125666581.webp', 'https://www.flickr.com/photos/zaragozaantigua/44125666581/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22569, 'Vista del Ebro c.1977', 'Postal. Vista aâ”œÂ®rea del râ”œÂ¡o Ebro cruzado por el puente de Santiago, desde la margen izquierda. La masa frondosa dividida por el Segundo Cinturâ”œâ”‚n es la Arboleda de Macanaz. A la derecha, el Club Nataciâ”œâ”‚n Helios, con su piscina cubierta construida en 1976. Al fondo, la vieja ciudad, con el Pilar como referencia vertical. Fuente visual: www.delcampe.net/', 1977, 1977, 1977, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65910000, -0.88142000, '0101000020E61000004D4A41B79734ECBF956588635DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15295952888.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15295952888.webp', 'https://www.flickr.com/photos/zaragozaantigua/15295952888/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22918, 'Baturros y Pilar aâ”œâ–’os 80', 'Pareja de baturros con el Pilar al fondo. Fuente: Foto para postal de Comercial Josan. Cesiâ”œâ”‚n de la familia de Josâ”œÂ® Marâ”œÂ¡a Sanz Gonzâ”œÃ­lez a Rafael Castillejo. Dataciâ”œâ”‚n y procesado:', 1980, 1980, 1989, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65910700, -0.87989500, '0101000020E6100000D53E1D8F1928ECBF47C8409E5DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27422065605.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27422065605.webp', 'https://www.flickr.com/photos/zaragozaantigua/27422065605/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22956, 'Av. de los Pirineos 1981', 'Imagen capturada durante la salida desde Zaragoza de la antorcha que anunciaba la celebraciâ”œâ”‚n de la Universiada de Invierno en el Pirineo Aragonâ”œÂ®s, en instalaciones de Formigal, Candanchâ”œâ•‘, Astâ”œâ•‘n, Panticosa, y Jaca, donde se celebrarâ”œÂ¡an entre otros actos las ceremonias de apertura, el dâ”œÂ¡a 24 de febrero, y la de clausura, el 4 de marzo. El fallido Golpe de Estado del 23 de febrero estuvo a punto de hacer que se suspendiera este evento deportivo, que finalmente tuvo lugar las fechas previstas con mâ”œÃ­s que notable presencia de Policâ”œÂ¡a, Guardia Civil, y Ejâ”œÂ®rcito. Este "Circo Blanco" fue el pistoletazo de salida de la carrera en pos del sueâ”œâ–’o, o pesadilla, de organizar una Olimpiada de Invierno en la Jacetania, que se prolongarâ”œÃ­ en el tiempo. Al fondo de la imagen, arboleda de Macanaz y el templo metropolitano del Pilar.', 1981, 1981, 1981, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.66020700, -0.88126600, '0101000020E61000009F7422C15433ECBF8ECBB8A981D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48641710017.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48641710017.webp', 'https://www.flickr.com/photos/zaragozaantigua/48641710017/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
