INSERT INTO public.photos VALUES (23826, 'El Pilar c.1864', 'Vista del Pilar desde la Margen Izquierda. Fuente visual: original de Ferrier et Soulier editada por J. Lâ”œÂ®vy & Câ”œÂ¡a, publicada en el libro de viajes "Spain and the spaniards", Edmondo De Amicis, ediciâ”œâ”‚n 1895. ("Espaâ”œâ–’a", viaje durante el reinado de Amadeo I de Saboya).', 1864, 1864, 1864, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65864200, -0.88221200, '0101000020E6100000A87004A9143BECBFD2E28C614ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20725320782.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20725320782.webp', 'https://www.flickr.com/photos/zaragozaantigua/20725320782/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24355, 'Barca y pasarela 1940', 'Construcciâ”œâ”‚n de la pasarela sobre el Ebro a la altura de San Juan de los Panetes, que estarâ”œÃ­ en servicio hasta la inauguraciâ”œâ”‚n del puente de Santiago, en 1967. Mientras van acabâ”œÃ­ndola, la câ”œÂ®lebre barca del Tâ”œÂ¡o Toni continâ”œâ•‘a llevando de orilla a orilla a la gente, con su sirga. En 1935 el MOPU habâ”œÂ¡a otorgado una concesiâ”œâ”‚n para la construcciâ”œâ”‚n de una pasarela que comunica ambas orillas del Ebro. Se construyâ”œâ”‚ en 1940, y se abriâ”œâ”‚ al servicio pâ”œâ•‘blico en 1941. El proyecto fue del ingeniero Luis Fuentes Lâ”œâ”‚pez. La construcciâ”œâ”‚n y montaje de la parte metâ”œÃ­lica de la pasarela se hizo por "Maquinista y Fundiciones del Ebro, S.A." Dirigiâ”œâ”‚ la obra de fâ”œÃ­brica complementaria Enrique Bressel. Funcionaba la pasarela dâ”œÂ¡a y noche.', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65832400, -0.88150600, '0101000020E6100000F14927124C35ECBF0116F9F543D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14934310221.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14934310221.webp', 'https://www.flickr.com/photos/zaragozaantigua/14934310221/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24675, 'Puente Santiago c.1979', 'Un hombre pasea una mula por el puente de Santiago de Zaragoza. Al fondo, la Cruz de los Caâ”œÂ¡dos, San Juan de los Panetes, el torreâ”œâ”‚n de la Zuda y el Mercado Central. Fuente: www.facebook.com/photo.php?fbid=1578563142386483&set=...', 1979, 1979, 1979, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65835600, -0.88148800, '0101000020E610000058207A522635ECBF0C90680245D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20723475792.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20723475792.webp', 'https://www.flickr.com/photos/zaragozaantigua/20723475792/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24681, 'Râ”œÂ¡o Ebro 1872', '"Râ”œÂ¡o Ebro y San Juan de los Panetes", â”œâ”‚leo sobre tabla, Francisco Pradilla, 1872. Vista del râ”œÂ¡o Ebro desde la arboleda de Macanaz, con la silueta de San Juan de los Panetes al fondo. Fuente: Zaragoza vista por los artistas, 1908-2008.', 1872, 1872, 1872, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65853000, -0.88008800, '0101000020E6100000FA43334FAE29ECBFAAB706B64AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32234419582.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32234419582.webp', 'https://www.flickr.com/photos/zaragozaantigua/32234419582/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24738, 'Puente de Santiago 1967', '"Gente en el reciâ”œÂ®n inaugurado Puente de Santiago." Aun la gente indâ”œÂ¡gena, tres semanas despuâ”œÂ®s de su oficial inauguraciâ”œâ”‚n, y hasta la normalizaciâ”œâ”‚n del trâ”œÃ­fico rodado a motor de explosiâ”œâ”‚n (ese era el principal horizonte funcional del puente), se quedaba en medio un ratico "a ver si el puente aguanta". Otros, mâ”œÃ­s prudentes, observaban la riesgosa probanza desde la ribera. En la margen izquierda, imagen del barrio de la Hortilla, antes de perder la "h", del camping de Helios y, sobresaliendo de los â”œÃ­rboles, de la chimenea de la antigua Manufacturas de lanas de Morâ”œâ”‚n y Anâ”œâ”‚s, en el Camino de Ranillas. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65835600, -0.88148800, '0101000020E610000058207A522635ECBF0C90680245D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15181013490.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15181013490.webp', 'https://www.flickr.com/photos/zaragozaantigua/15181013490/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24739, 'Baâ”œâ–’os pâ”œâ•‘blicos 1930', 'Foto colecciâ”œâ”‚n Luis Rasal, 1930. Edificio de los baâ”œâ–’os pâ”œâ•‘blicos de Zaragoza a orillas del Ebro (durante la riada de 1930). Situado en la actual ubicaciâ”œâ”‚n del Club Nataciâ”œâ”‚n Helios, en la margen izquierda. Al fondo, el Pilar. Fuente: www.facebook.com/photo.php?fbid=820302567992370&set=o...', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65915600, -0.88227400, '0101000020E61000002A8E03AF963BECBF297B4B395FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15259142238.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15259142238.webp', 'https://www.flickr.com/photos/zaragozaantigua/15259142238/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24782, 'Camino de Ranillas 1977', 'Imagen del pluricentenario camino de Ranillas, tras el cruce de la reciente avenida de los Pirineos abierta para trâ”œÃ­fico rodado. A la izquierda, prolongaciâ”œâ”‚n de la densa arboleda de Macanaz, y muros perimetrales de las instalaciones del C.N. Helios. A la derecha, el barrio de la Ortilla. Al fondo, la huerta y soto de Ranillas. El camino de Ranillas aparece muy despejado tras el derribo de las antiguas "Manufacturas de lanas de Morâ”œâ”‚n y Anâ”œâ”‚s", de las que sâ”œâ”‚lo se dejâ”œâ”‚ en pie su estilita chimenea, ya fuera de plano, hacia la derecha, como la recientemente clausurada y desmantelada lâ”œÂ¡nea del ferrocarril de los Enlaces. El crecimiento urbanâ”œÂ¡stico de la Margen Izquierda, desde la construcciâ”œâ”‚n del puente de Santiago y la apertura de la avenida de los Pirineos, en progresiâ”œâ”‚n geomâ”œÂ®trica y en unos pocos aâ”œâ–’os transformâ”œâ”‚, de forma radical, toda esta parte de la periferia rururbana de la ciudad, hasta dejarla irreconocible. Una supuesta "actuaciâ”œâ”‚n urgente" urbanâ”œÂ¡stica supuso la desapariciâ”œâ”‚n de los barrios de la Ortilla, y de Ranillas. Alguna dâ”œÂ®cada mâ”œÃ­s tarde, un gran evento expositivo se terminâ”œâ”‚ de llevar por delante la tradicional huerta. Fuente visual: amable aportaciâ”œâ”‚n personal de Pablo Valdâ”œÂ®s.', 1977, 1977, 1977, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.66025800, -0.88142600, '0101000020E6100000D6027B4CA434ECBF10768A5583D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27263779605.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27263779605.webp', 'https://www.flickr.com/photos/zaragozaantigua/27263779605/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25417, 'Pasarela Ebro 1945', 'Imagen de la Pasarela Peatonal del Ebro. Se construyâ”œâ”‚ en 1941, y comenzâ”œâ”‚ a dar servicio en febrero de 1942, como forma de comunicar las dos riberas, entre el puente de las piedras, y el puente del ferrocarril.', 1945, 1945, 1945, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65902300, -0.88117100, '0101000020E61000002FE065868D32ECBFE9279CDD5AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15748629947.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15748629947.webp', 'https://www.flickr.com/photos/zaragozaantigua/15748629947/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25431, 'Pasarela de Macanaz aâ”œâ–’os 40', 'Foto: Miguel Marâ”œÂ¡n Chivite. Vista de la pasarela sobre el Ebro tomada desde la arboleda de Macanaz. Ademâ”œÃ­s del Torreâ”œâ”‚n de la Zuda, podemos ver los edificios del paseo Echegaray y Caballero. Fuente: Archivo Heraldo de Aragâ”œâ”‚n.', 1940, 1940, 1949, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21549406816.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21549406816.webp', 'https://www.flickr.com/photos/zaragozaantigua/21549406816/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25432, 'Pasarela Ebro c.1957', 'Imagen capturada en altura, desde el inmediato torreâ”œâ”‚n de la Zuda, de la moderna pasarela peatonal para cruce en seco del râ”œÂ¡o Ebro, entre la densa arboleda de Macanaz, al fondo, y la confluencia del paseo de Echegaray y Caballero y la Vâ”œÂ¡a Imperial, antigua calle de Antonio Pâ”œÂ®rez, en primer plano, donde la taquilla de peaje. A la izquierda, humea la chimenea fabril de "Manufacturas de lanas de Morâ”œâ”‚n y Anâ”œâ”‚s". Fuente visual: Teodoro Naranjo Domâ”œÂ¡nguez, para ABC.', 1957, 1957, 1957, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24392641973.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24392641973.webp', 'https://www.flickr.com/photos/zaragozaantigua/24392641973/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25443, 'Pasarela del Ebro 1945', 'Imagen con el sonriente posado de varios oficiales del ejâ”œÂ®rcito de tierra (posiblemente, tenientes), en la pasarela peatonal recientemente tendida sobre el Ebro. Al fondo, el Pilar, y la novâ”œÂ¡sima y enorme Hospederâ”œÂ¡a del Pilar, cuyas dependencias se abren a tres fachadas, y con tres patios interiores. A su izquierda, mâ”œÃ­s tarde, se construirâ”œÂ¡a el edificio de las viviendas del Cabildo, y la nueva Casa de Infantes. A la derecha, fuera de plano, la iglesia de San Juan de los Panetes, y el antiguo embarcadero que, con la entrada en servicio de la pasarela, quedâ”œâ”‚ obsoleto. Fuente visual: www.todocoleccion.net/', 1945, 1945, 1945, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30901004865.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30901004865.webp', 'https://www.flickr.com/photos/zaragozaantigua/30901004865/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25447, 'Râ”œÂ¡o Ebro 1921', 'Dibujo del arquitecto Antonio Setiâ”œÂ®n, realizado en Hernani en 1921. Ofrece un proyecto de navegabilidad del râ”œÂ¡o Ebro, con un puente colgante. A la izquierda, câ”œâ•‘pulas y torre del Pilar. En la margen izquierda, un gran parque en los terrenos del futuro Club de Nataciâ”œâ”‚n Helios. Fuente visual: Revista Relieves, nâ”œâ•‘m. 2, 1933.', 1921, 1921, 1921, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65843000, -0.88077700, '0101000020E61000002F35423F532FECBF475A2A6F47D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32425819744.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32425819744.webp', 'https://www.flickr.com/photos/zaragozaantigua/32425819744/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25457, 'Pasarela de Macanaz 1949', 'Dibujo incluido en un artâ”œÂ¡culo referido a "La arquitectura de Zaragoza en estos â”œâ•‘ltimos aâ”œâ–’os", y justificado por la presencia de la pasarela de Macanaz, inaugurada en 1941. Bajo ella se representa la tradicional prâ”œÃ­ctica del transporte de maderas por el râ”œÂ¡o Ebro, si bien en esta lâ”œÃ­mina la conducciâ”œâ”‚n recae en embarcaciones a motor. Esta actividad fue realizada, entre otras cosas, hasta que la construcciâ”œâ”‚n del embalse de Yesa cerrâ”œâ”‚ el paso a los almadieros del valle del Roncal, que hasta aquâ”œÂ¡ descendâ”œÂ¡an sus troncos. Tras la pasarela y en la margen derecha, el templo del Pilar y la tambiâ”œÂ®n reciente y homâ”œâ”‚nima Hospederâ”œÂ¡a. Al fondo, el puente de Piedra. A la izquierda y en primer tâ”œÂ®rmino, un par de jubilados sentados en la arboleda de Macanaz contemplan la escena.', 1949, 1949, 1949, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65852500, -0.88135200, '0101000020E61000004374081C0934ECBF984C158C4AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50010448192.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50010448192.webp', 'https://www.flickr.com/photos/zaragozaantigua/50010448192/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25527, 'Puente de Santiago 1968', 'AHPZ. Foto Coyne. 1968. Imagen del Puente de Santiago, inaugurado en marzo de 1967. A la izquierda, Echegaray y Caballero conduce al Paso a Nivel de la Almozara, la puerta de la Quâ”œÂ¡mica. A la derecha, la Margen Izquierda con Helios, y las parcelas de la Ortilla. El meandro de Ranillas, una colecciâ”œâ”‚n de huertas.', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65856500, -0.88158800, '0101000020E61000003A799109F835ECBF27A5A0DB4BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14803772520.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14803772520.webp', 'https://www.flickr.com/photos/zaragozaantigua/14803772520/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25528, 'Pontoneros 1982', 'Pontoneros del regimiento de Monzalbarba venidos del moderno cuartel de Sangenis, junto a un pontâ”œâ”‚n con funciones de muelle sobre el râ”œÂ¡o Ebro durante una demostraciâ”œâ”‚n con notable expectaciâ”œâ”‚n de pâ”œâ•‘blico. La imagen ha sido capturada dando la espalda al Club Nataciâ”œâ”‚n Helios. A la izquierda, el puente de Santiago. Al fondo, torres de la iglesia de Santa Isabel, el colegio Valentâ”œÂ¡n Zabala, y varias construcciones en el entorno de la calle de Escobar, de Abâ”œÂ®n Aire y de los Predicadores.', 1982, 1982, 1982, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65903300, -0.88172500, '0101000020E61000006519E2581737ECBF0DFE7E315BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14922153074.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14922153074.webp', 'https://www.flickr.com/photos/zaragozaantigua/14922153074/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25534, 'Pasarela sobre Ebro 1958', 'Câ”œÂ®sar Gracia Jarque. 1958. "Râ”œÂ¡o Ebro. La Pasarela". Imagen de la Pasarela desde la altura de la Hospederâ”œÂ¡a del Pilar.', 1958, 1958, 1958, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65902300, -0.88117100, '0101000020E61000002FE065868D32ECBFE9279CDD5AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15936514862.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15936514862.webp', 'https://www.flickr.com/photos/zaragozaantigua/15936514862/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25537, 'Râ”œÂ¡o Ebro 1931', 'Grupo de baâ”œâ–’istas en el râ”œÂ¡o Ebro a su paso por Zaragoza, en 1931. Al fondo, el Pilar. Fuente: Revista Crâ”œâ”‚nica. Madrid, 1931', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65908400, -0.88194800, '0101000020E610000034B91803EB38ECBF8FA850DD5CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18765210669.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18765210669.webp', 'https://www.flickr.com/photos/zaragozaantigua/18765210669/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25543, 'Pasarela 1958', 'Pasarela peatonal tendida sobre el râ”œÂ¡o Ebro en 1941, tambiâ”œÂ®n conocida como de Macanaz, y que supuso el final de los embarcaderos de la zona que hasta entonces se dedicaban al transporte de personas entre una y otra orilla, generalmente para acceder a la arboleda de Macanaz. Se mantuvo la navegaciâ”œâ”‚n recreativa. Esta paralela fue desmantelada en 1967 con motivo de la construcciâ”œâ”‚n del moderno puente de Santiago. En el Pilar, la obra de la nueva torre de San Francisco de Borja progresa mâ”œÃ­s râ”œÃ­pido que la de Santa Leonor. Al fondo, el puente de Piedra y el de Hierro. Fuente visual: foto Josâ”œÂ® Antonio Duce, en rafaelcastillejo.com', 1958, 1958, 1958, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20525679189.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20525679189.webp', 'https://www.flickr.com/photos/zaragozaantigua/20525679189/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25570, 'Râ”œÂ¡o Ebro c.1931', 'Imagen capturada desde la arboleda de Macanaz y centrada en la barca del "Tâ”œÂ¡o Toni" que con nutrida parroquia cruza el râ”œÂ¡o de forma no mecanizada, a punto de llegar al embarcadero donde descenderâ”œÃ­ el pasaje venido de la margen derecha. La aâ”œÂ®rea sirga que posibilita la singladura aparece tendida y jalonando el recorrido. Otras embarcaciones recreativas, de menor tamaâ”œâ–’o, hacia el fondo del cauce fluvial. Encuadra la escena la tradicional estampa del templo del Pilar con dos torres (la de Santiago, en primer tâ”œÂ®rmino, y la de Nuestra seâ”œâ–’ora del Pilar, junto a la câ”œâ•‘pula mayor)', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65871900, -0.88053700, '0101000020E6100000DD5F3DEE5B2DECBF7D2079E750D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48881459702.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48881459702.webp', 'https://www.flickr.com/photos/zaragozaantigua/48881459702/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25576, 'Embarcadero del Ebro 1932', 'Imagen capturada en el embarcadero que en la margen izquierda y desde 1929 daba servicio al nuevo transbordo del râ”œÂ¡o Ebro mediante la lancha-gasolinera "Nuestra seâ”œâ–’ora del Pilar", aguas arriba del antiguo paso que mediante tradicional sirga realizaba la barca del Tâ”œÂ¡o Toni, que en la fotografâ”œÂ¡a se ve al fondo. Este nuevo servicio, asumido por Francisco Sâ”œÃ­nchez en râ”œÂ®gimen de concesiâ”œâ”‚n, era muy apreciado por los vecinos del barrio de Macanaz y por los usuarios del Centro Deportivo "Helios". Se trata de una imagen tomada durante el viaje de bodas del autor de la misma, que en ella retrata a su esposa Emilia Marimon Rovira con el tradicional fondo edilicio de un brumoso templo del Pilar y los puentes de Piedra y de Hierro.', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65911800, -0.88200600, '0101000020E61000005B069CA56439ECBF3B1A87FA5DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52993273588.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52993273588.webp', 'https://www.flickr.com/photos/zaragozaantigua/52993273588/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25975, 'Riada de 1961', 'Vista general de la margen izquierda durante la gran riada del Ebro de 1961. En primer plano se distinguen el edificio de los baâ”œâ–’os de las playas del Ebro y la torre de Helios. Fuente: Foto Marâ”œÂ¡n Chivite. AMZ.', 1961, 1961, 1961, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65933400, -0.88266000, '0101000020E610000074982F2FC03EECBF0892770E65D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15134684919.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15134684919.webp', 'https://www.flickr.com/photos/zaragozaantigua/15134684919/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26064, 'Vista aâ”œÂ®rea c.1968', 'Imagen capturada desde notable altura sobre el barrio de la Ortilla, con una interesante vista aâ”œÂ®rea del tramo urbano del râ”œÂ¡o Ebro comprendido entre el Puente de Santiago, en primer tâ”œÂ®rmino, y el puente de Hierro, alcanzando incluso hasta el nuevo Puente del Ferrocarril, al fondo. A la izquierda, la feraz arboleda de Macanaz sigue delimitada en buena parte por el enlace ferroviario. A la derecha y al fondo, en el barrio de Las Fuentes comienzan a surgir tambiâ”œÂ®n inmuebles que rompen la tradicional barrera de las 4-5 alturas, como el que se destaca en la plaza del Monasterio de San Victoriâ”œÃ­n. En esta perifâ”œÂ®rica ubicaciâ”œâ”‚n este fenâ”œâ”‚meno llama la atenciâ”œâ”‚n, aunque nada comparado con los ejemplos que comenzaban a proliferar de forma salvaje en la ciudad consolidada.', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65856500, -0.88030000, '0101000020E6100000CF66D5E76A2BECBF27A5A0DB4BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49223352466.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49223352466.webp', 'https://www.flickr.com/photos/zaragozaantigua/49223352466/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20947, 'San Juan de los Panetes 1855', 'Dibujada desde el "paseo de Macanaz", esta vista de la orilla derecha reproduce el campanario y la cabecera de la iglesia de San Juan de los Panetes, el torreâ”œâ”‚n de la Zuda con piso aâ”œâ–’adido y con un edificio de casi el mismo tamaâ”œâ–’o adosado a su izquierda, junto al que destaca al fondo la Torre Nueva. En la muralla al Ebro, la puerta de San Ildefonso o de la Triperâ”œÂ¡a. Fuente visual de la imagen: Valentâ”œÂ¡n Carderera, en "Viaje artâ”œÂ¡stico por Aragâ”œâ”‚n de Valentâ”œÂ¡n Carderera", Josâ”œÂ® Marâ”œÂ¡a Lanzarote Guiral, e Itziar Arana Cobos, IFC - Fundaciâ”œâ”‚n Lâ”œÃ­zaro Galdiano, 2013), recopilada, editada y comentada de forma exclusiva por el Gran Archivo Zaragoza Antigua (GAZA).', 1855, 1855, 1855, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65790400, -0.88140300, '0101000020E6100000CB1473107434ECBF2CF4C13236D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15082762216.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15082762216.webp', 'https://www.flickr.com/photos/zaragozaantigua/15082762216/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21058, 'Torreâ”œâ”‚n de la Zuda c.1877', 'Archivo RUIZ VERNACCI, Jean Laurent y Câ”œÂ¡a. 1860-1886. "Torre de la Calle de Antonio Pâ”œÂ®rez", o Torreâ”œâ”‚n de la Zuda (ss. I-XVI).', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65749100, -0.88157200, '0101000020E6100000CE37A27BD635ECBF093543AA28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14866141862.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14866141862.webp', 'https://www.flickr.com/photos/zaragozaantigua/14866141862/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21076, 'Calle Antonio Pâ”œÂ®rez c.1877', 'Los descartes desechados por Laurent y Câ”œÂ¡a para editar, al principio de la dâ”œÂ®cada de 1870, la producida imagen final de la "Torre de la calle de Antonio Pâ”œÂ®rez", los reutilizamos para unos interesantes rescates visuales, incluyendo los mâ”œÃ­rgenes marginados. A la izquierda, la nave de la nueva fâ”œÃ­brica barroca de la iglesia de San Juan de los Panetes, con sus contrafuertes de apoyo a la nave central. En primer plano, los edificios a ambos lados de la calle de Antonio Pâ”œÂ®rez, los nâ”œâ•‘meros pares adosados a la muralla romana y al torreâ”œâ”‚n de la Zuda (ya despejado del parasitario torreâ”œâ”‚n que tenâ”œÂ¡a adosado), y los impares de la manzana de Paseo del Ebro-Antonio Pâ”œÂ®rez-Culebra, desde donde se ha capturado la fotografâ”œÂ¡a. A la derecha, torreones y remates del antiguo complejo hospitalario de la orden de San Juan, que en el momento de la captura visual era convento de las MM. Adoratrices Esclavas del Santâ”œÂ¡simo Sacramento y de la Caridad. Y al fondo, la sorpresa final: emerge un pedacito del triple chapitel de la Torre Nueva. Fuente visual: Jean Laurent y Câ”œÂ¡a, Archivo Ruiz Vernacci (Fototeca del Patrimonio Histâ”œâ”‚rico, www.mcu.es/)', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65752400, -0.88159400, '0101000020E6100000C231CB9E0436ECBFE52A16BF29D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22095267584.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22095267584.webp', 'https://www.flickr.com/photos/zaragozaantigua/22095267584/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21186, 'La Zuda 1890', 'Imagen centrada en el antiguo torreâ”œâ”‚n de la Zuda, integrado desde 1857 como parte del convento de la congregaciâ”œâ”‚n de las Adoratrices Esclavas del Santâ”œÂ¡simo Sacramento y de la Caridad. Delante de â”œÂ®l, vista parcial de los edificios de viviendas a â”œÂ®l adosados desde la calle de Antonio Pâ”œÂ®rez, nâ”œâ•‘meros 16, y 18. Fuente visual: "Torreâ”œâ”‚n del Palacio de la Azuda", fototipia de Joarizti y Mariezcurrena, en Ã”Ã‡Â£Zaragoza Artâ”œÂ¡stica, Monumental e Histâ”œâ”‚ricaÃ”Ã‡Ã˜, Anselmo y Pedro Gascâ”œâ”‚n de Gotor (1890-91).', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65756000, -0.88160100, '0101000020E610000061DEE34C1336ECBF319413ED2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34457567312.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34457567312.webp', 'https://www.flickr.com/photos/zaragozaantigua/34457567312/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22548, 'Colegio Santo Domingo de Silos c.1975', 'El colegio Obra Diocesana de Santo Domingo de Silos fue inaugurado en 1959. El enorme complejo, hoy ampliado con zonas deportivas junto al Tercer Cinturâ”œâ”‚n, estâ”œÃ­ situado en el barrio de Las Fuentes, en la calle de la Amistad 9 (derecha de la foto aâ”œÂ®rea). En primer plano, la calle Fray Luis Urbano; en el lateral izquierdo, Rodrigo Rebolledo. Los edificios de la derecha, el Grupo Josâ”œÂ® Antonio Girâ”œâ”‚n. Fuente visual: AMZ.', 1975, 1975, 1975, 'Anos 70', 'LAS FUENTES', 41.64646000, -0.85990600, '0101000020E61000002B4B74965984EBBF09168733BFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15022288080.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15022288080.webp', 'https://www.flickr.com/photos/zaragozaantigua/15022288080/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21269, 'Ribera del Ebro 1900', 'Imagen de la habitual feria del ganado en la ribera del Ebro, desde la calle del Fin, y hasta San Juan de los Panetes (al fondo), que con motivo de las Fiestas del Pilar, convertâ”œÂ¡a Zaragoza en un gran mercado, o feria ganadera, con participaciâ”œâ”‚n de bestias y personas de casi toda la ribera del Ebro, resultando un importante nivel de transacciones econâ”œâ”‚micas. Como suele ser norma en la vegetaciâ”œâ”‚n de la ribera, â”œÂ®sta va y viene segâ”œâ•‘n tiempos, y momentos. En este caso, la feria se pudo hacer bajo la sombra del extraâ”œâ–’o sol de octubre. Fuente visual: Diario "ABC".', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65749900, -0.87979600, '0101000020E61000000ADAE4F04927ECBF8C135FED28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21637391743.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21637391743.webp', 'https://www.flickr.com/photos/zaragozaantigua/21637391743/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21564, 'Pilar 1929', '"Una vista de las torres del Pilar de Zaragoza", porque dos ya es plural, desde la foresta de la arboleda de Macanaz. A la derecha, el abigarrado conjunto de edificaciones entre la calle de los Agustinos, del Fin, el paseo del Ebro, y San Juan de los Panetes. Fuente visual: Ricardo Schmelz, revista "La Esfera" (Madrid).', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65759400, -0.88028000, '0101000020E610000008556AF6402BECBFDE054A0A2CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22586884107.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22586884107.webp', 'https://www.flickr.com/photos/zaragozaantigua/22586884107/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21682, 'La Zuda 1930', 'Fotografâ”œÂ¡a original de la imagen del Torreâ”œâ”‚n de la Zuda y San Juan de los Panetes, que, coloreada, apareciâ”œâ”‚ en la portada de la revista "Aragâ”œâ”‚n" en mayo de ese aâ”œâ–’o. Fuente visual: Archivo Juan Mora, AMZ.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65749100, -0.88157200, '0101000020E6100000CE37A27BD635ECBF093543AA28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877891000.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877891000.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877891000/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21704, 'Riada de 1930', 'Gran riada en el Ebro, vista por un grupo de personas desde el paseo de la Ribera. El barrio de Ranillas, a la izquierda, inundado. Las instalaciones de la Sociedad Naturista Helios, y Macanaz, a la derecha, tambiâ”œÂ®n. Fuente: foto Gil Marraco, en "El Ebro desbordado: una historia de las crecidas del râ”œÂ¡o en Zaragoza". Ayuntamiento de Zaragoza, 2011.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65809700, -0.88189000, '0101000020E61000000D6C95607138ECBF404CC2853CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15752575315.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15752575315.webp', 'https://www.flickr.com/photos/zaragozaantigua/15752575315/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21789, 'San Juan de los Panetes 1934', 'Imagen capturada durante el largo, complicado y polâ”œÂ®mico proceso de transformaciâ”œâ”‚n del antiguo, laberâ”œÂ¡ntico y enorme conjunto de la "iglesia de San Juan de los Panetes de la Religiâ”œâ”‚n de San Juan de Jerusalâ”œÂ®n, y la Casa y Palacio de la Castellanâ”œÂ¡a de Amposta". En esos momentos se estaba procediendo a derribar algunas dependencias del antiguo convento, cuyas â”œâ•‘ltimas inquilinas habâ”œÂ¡an sido miembros de la Congregaciâ”œâ”‚n de Adoratrices Esclavas del Santâ”œÂ¡simo Sacramento y de la Caridad. El acceso a la iglesia se realizaba, bien por el pequeâ”œâ–’o callejâ”œâ”‚n que desde la derecha comunicaba con la calle de los Agustinos, la plaza de Huesca, y la calle de la Zuda; o bien por otro estrecho callejâ”œâ”‚n que comunicaba con la plaza de San Antâ”œâ”‚n. Fuente visual: Miguel Marâ”œÂ¡n Chivite, Archivo Pâ”œâ•‘blico Municipal.', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23964636033.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23964636033.webp', 'https://www.flickr.com/photos/zaragozaantigua/23964636033/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21817, 'Embarcadero del Ebro aâ”œâ–’os 30', 'Foto: Miguel Marâ”œÂ¡n Chivite. Vista del embarcadero con una embarcaciâ”œâ”‚n a motor que cubrâ”œÂ¡a el recorrido de orilla a orilla del râ”œÂ¡o Ebro. Estaba situado a la altura de la calle de Antonio Pâ”œÂ®rez, en el desagâ”œâ•e del Mercado Central. Arriba se puede ver la sirga de las barcas de tracciâ”œâ”‚n humana. Fuente: Heraldo de Aragâ”œâ”‚n.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65801300, -0.88124900, '0101000020E61000001C3F541A3133ECBFE2AB1DC539D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31221034973.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31221034973.webp', 'https://www.flickr.com/photos/zaragozaantigua/31221034973/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21901, 'San Juan de los Panetes c.1932', 'Imagen centrada en la barroca fachada y torre de la iglesia de San Juan de los Panetes durante el proceso de derribo del antiguo convento hospitalario de la castellanâ”œÂ¡a de Amposta donde estaba inserta. A la derecha y en la umbrâ”œÂ¡a, callejâ”œâ”‚n de acceso desde la plaza de Huesca y traseras del inmueble del nâ”¬â•‘ 11 de la calle de la Zuda. En primer tâ”œÂ®rmino la chavalerâ”œÂ¡a juega en el talud producido durante la excavaciâ”œâ”‚n arqueolâ”œâ”‚gica realizada entre la iglesia y el tramo de murallas romanas de la Zuda.', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65745900, -0.88155600, '0101000020E610000062F6B2EDB435ECBFFEBAD39D27D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51421564681.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51421564681.webp', 'https://www.flickr.com/photos/zaragozaantigua/51421564681/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23689, 'Aerâ”œâ”‚dromo Sanjurjo 1937', 'Imagen capturada en el aerâ”œâ”‚dromo Sanjurjo tras el ataque que la Fuerza Aâ”œÂ®rea Republicana llevâ”œâ”‚ a cabo el dâ”œÂ¡a 15 de octubre de 1937. Este "raid" estuvo protagonizado de buena madrugada por dos escuadrillas de cazas Polikarpov I-15 ("Chatos") con 21 aparatos, provenientes de Bujaraloz y Sariâ”œâ–’ena, y 5 escuadrillas de Polikarpov I-16 ("Moscas") con 64 aparatos provenientes de Caspe, Hâ”œÂ¡jar, Escatrâ”œâ”‚n y Puig Moreno. Tras cuatro minutos de breve ataque, quedaron destruidos doce aparatos entre Ju-52 y He-46 alemanes, y Fiat CR-32 italianos, ademâ”œÃ­s de afectar en distinto grado a varias decenas de otros. En la imagen, tres Fiat CR-32 "Chirri" destruidos sobre la pista del aerâ”œâ”‚dromo Sanjurjo de Zaragoza en Garrapinillos.', 1937, 1937, 1937, 'Anos 30', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52037632159.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52037632159.webp', 'https://www.flickr.com/photos/zaragozaantigua/52037632159/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21908, 'P.â”¬â•‘ del Ebro c.1934', 'Imagen capturada en el paseo del Ebro junto al embarcadero ubicado a la altura de la calle de Antonio Pâ”œÂ®rez cuando una "canoa automâ”œâ”‚vil" maniobra posiblemente para dirigirse a la otra orilla del râ”œÂ¡o, zona de la arboleda de Macanaz prâ”œâ”‚xima a la municipal Caseta de los Baâ”œâ–’os. Este servicio funcionaba en el tramo fluvial comprendido entre el puente de Piedra y el puente del ferrocarril del Norte y estaba gestionado por un grupo de barqueros entre los que se encontraba Carlos Mar Sau, hijo del famoso "Tâ”œÂ¡o Toni", barquero que desde mediados del siglo XIX y hasta pocos aâ”œâ–’os antes de esta foto hizo historia en el imaginario popular de la ciudad. Esta moderna "canoa automâ”œâ”‚vil" a motor, capaz de transportar hasta cien pasajeros por viaje, supuso en 1930 un gran cambio respecto a la barca que hasta entonces se desplazaba manualmente por el tradicional camino de sirga. Por ello el fotâ”œâ”‚grafo titulâ”œâ”‚ esta imagen, de forma algo mâ”œÃ­s româ”œÃ­ntica, "Ferry with engine on Ebro. Formerly used current and wind" (Ferry con motor en el Ebro. Antes usaba la corriente y el viento). En primer tâ”œÂ®rmino, algunos espectadores contemplan desde la orilla las evoluciones de esta moderna barca motora.', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65804400, -0.88170600, '0101000020E6100000B5FB5580EF36ECBF1DAA29C93AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51745928448.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51745928448.webp', 'https://www.flickr.com/photos/zaragozaantigua/51745928448/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21917, 'La Zuda c.1932', 'Inâ”œÂ®dita imagen capturada junto a la portada de la iglesia de San Juan de los Panetes tras el derribo de buena parte del complejo ocupado por la congregaciâ”œâ”‚n de las Adoratrices hasta 1909. La fotografâ”œÂ¡a se centra en el torreâ”œâ”‚n de la Zuda con el aspecto de su cara este que, en la parte inferior y junto a la puerta que aparece "colgada" en altura tras el derribo, se intuye el vano que alberga la placa instalada en 1885 que recordaba la reparaciâ”œâ”‚n del torreâ”œâ”‚n acometida "a expensas de la Casa de Marâ”œÂ¡a Santâ”œÂ¡sima de las Desamparadas" (referencia a las Adoratrices aquâ”œÂ¡ establecidas en 1857). Tras la restauraciâ”œâ”‚n integral del torreâ”œâ”‚n en los aâ”œâ–’os 40 esta placa fue recolocada un poco mâ”œÃ­s hacia la esquina de la derecha, tal y como es visible desde entonces.', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65755500, -0.88170600, '0101000020E6100000B5FB5580EF36ECBF202922C32AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53241623602.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53241623602.webp', 'https://www.flickr.com/photos/zaragozaantigua/53241623602/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21934, 'La Zuda 1943', 'Archivo Municipal de Zaragoza. Archivo Mora "Torreâ”œâ”‚n de la Zuda."', 1943, 1943, 1943, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65749100, -0.88157200, '0101000020E6100000CE37A27BD635ECBF093543AA28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15066894912.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15066894912.webp', 'https://www.flickr.com/photos/zaragozaantigua/15066894912/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21943, 'Vista de Zaragoza 1940', 'Ayuntamiento de Zaragoza. Alberto Duce Baquero. 1940. Vista de Zaragoza Fuente: zaragozacool.blogspot.com.es/2010_05_01_archive.html', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65801200, -0.88167400, '0101000020E6100000DD787764AC36ECBF1230BABC39D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15699718410.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15699718410.webp', 'https://www.flickr.com/photos/zaragozaantigua/15699718410/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21964, 'Plaza del Pilar 1949', 'Imagen de la ampliada y nueva plaza del Pilar en la zona de la antigua plaza de Huesca, despejada para ampliar la antigua plaza del Pilar, desde donde se realiza la captura, junto a uno de los â”œÃ­rboles que le daban sombra. A la izquierda, el nuevo edificio para la Tienda Econâ”œâ”‚mica y el Convento de las Hijas de la Caridad de Santa Ana, en cuya portada se incrustarâ”œÃ­n los barrocos restos del ingreso al derribado Palacio de Sora. Enfrente, el "Monumento a los hâ”œÂ®roes y mâ”œÃ­rtires de Zaragoza. Caâ”œÂ¡dos en la Cruzada de Liberaciâ”œâ”‚n 1936-1939", en obras desde 1946, aâ”œâ•‘n sin la cruz que lo coronarâ”œÃ­. Detrâ”œÃ­s, la iglesia de San Juan de los Panetes, y la fachada del nuevo convento de las Hermanas Misioneras Eucarâ”œÂ¡sticas de Nazareth, finalizando las obras de construcciâ”œâ”‚n. A la derecha, la Hospederâ”œÂ¡a del Pilar, construida para la Sociedad Angâ”œÂ®lica del Sagrado Corazâ”œâ”‚n de Jesâ”œâ•‘s. Un muestrario significativo de los valores de la Nueva Espaâ”œâ–’a victoriosa del comunismo. Fuente Visual: Fotos Ysa, Archivo Pâ”œâ•‘blico Municipal.', 1949, 1949, 1949, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65722900, -0.88085200, '0101000020E6100000D8B79388F02FECBFCC7D721420D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21596013953.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21596013953.webp', 'https://www.flickr.com/photos/zaragozaantigua/21596013953/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22035, 'San Juan de los Panetes 1941', 'Inâ”œÂ®dita imagen capturada desde el solar que ocupara el antiguo hospital de San Juan de la Orden del Temple, centrada en la barroca iglesia de San Juan de los Panetes originalmente de la Religiâ”œâ”‚n de San Juan de la Castellanâ”œÂ¡a de Amposta, tras el derribo de buena parte de los edificios que albergaron el convento de las Adoratrices aquâ”œÂ¡ establecido desde 1857 y hasta 1909. Destaca el aspecto "colgado" de la iglesia tras el rebaje del solar originario para igualarlo al de la nueva gran plaza del Pilar proyectada para por la derecha llegar hasta la calle de Don Jaime I. Algo mâ”œÃ­s tarde aquâ”œÂ¡ se instalarâ”œÂ¡a una escalinata de piedra para poder acceder a la iglesia desde la altura del nuevo entorno. La precariedad del estado del templo queda evidenciada por el arbolito que despunta a la derecha del remate de su fachada, mientras que la torrecilla de la derecha apenas quedaba soportada por el muro al que estaba adosada, de forma que tuvo que ser apuntalada por detrâ”œÃ­s. A la derecha, restos de la antigua muralla de piedra "aparecida" inopinadamente durante el derribo de las antiguas viviendas de ese lado de la calle de Antonio Pâ”œÂ®rez, y al fondo, leve vista de uno de los postes metâ”œÃ­licos que soportaban la pasarela peatonal tendida sobre el râ”œÂ¡o Ebro y funcional desde el dâ”œÂ¡a 8 de febrero de 1941.', 1941, 1941, 1941, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65734600, -0.88138400, '0101000020E61000001AF7E6374C34ECBF0514EAE923D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53238458580.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53238458580.webp', 'https://www.flickr.com/photos/zaragozaantigua/53238458580/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22226, 'Plaza del Pilar c.1951', 'Imagen capturada desde cierta altura en la calle Imperial con vistas a la moderna plaza del Pilar. En primer tâ”œÂ®rmino y a la izquierda, la barroca iglesia de San Juan de los Panetes. Centran la escena las traseras del Monumento a los Hâ”œÂ®roes y Mâ”œÃ­rtires de Nuestra Gloriosa Cruzada, flanqueado por la Hospederâ”œÂ¡a del Pilar y la Tienda Econâ”œâ”‚mica en el Convento de las Hijas de la Caridad de Santa Ana, donde destaca la reubicada puerta principal de acceso a la derribada casa de los marqueses de Torrecilla. Al fondo y tras la cruz, andamios de obra durante la construcciâ”œâ”‚n de la Casa del Cabildo, el Museo Catedralicio y el nuevo Colegio de los Infantes. La ampliada plaza del Pilar todavâ”œÂ¡a conserva el arbolado espacio que significaba la plaza del Pilar de toda la vida.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65721000, -0.88084800, '0101000020E61000007DE71725E82FECBF554D10751FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49189141817.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49189141817.webp', 'https://www.flickr.com/photos/zaragozaantigua/49189141817/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23744, 'Marlofa 1962', 'John "Ganso" Kovatch, militar del ejâ”œÂ®rcito de los EE.UU de Norteamâ”œÂ®rica destinado en la Base Aâ”œÂ®rea de Zaragoza, haciendo turismo rural un dâ”œÂ¡a de permiso junto al râ”œâ”‚tulo de Marlofa (La Joyosa), localidad apenas distante 500 metros de Zaragoza (Villarrapa). El râ”œâ”‚tulo, rotulado convenientemente.', 1962, 1962, 1962, 'Anos 60', NULL, 41.73924000, -1.06816200, '0101000020E61000007C478D093117F1BF91F2936A9FDE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15211408905.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15211408905.webp', 'https://www.flickr.com/photos/zaragozaantigua/15211408905/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22239, 'Calle Imperial c.1951', 'Imagen capturada sobre las murallas de piedra romanas de la calle Imperial durante los trabajos de restauraciâ”œâ”‚n y recreaciâ”œâ”‚n de la misma. Un poco mâ”œÃ­s adelante, traseras de las viviendas recayentes a la plaza de san Antonio Abad, luego derribadas. A la derecha, viviendas de la antigua calle de Antonio Pâ”œÂ®rez, mâ”œÃ­s tarde tambiâ”œÂ®n derribadas. Al fondo, el Mercado Central de Lanuza, luego propuesto para ser derribado, aunque felizmente no fue asâ”œÂ¡. Esta intervenciâ”œâ”‚n reconstructora aparece delimitada por un "muro de contenciâ”œâ”‚n" dentro del cual se obraba tambiâ”œÂ®n en la restauraciâ”œâ”‚n del Torreâ”œâ”‚n de la Zuda.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65723400, -0.88196300, '0101000020E61000008A0629780A39ECBFDEE8633E20D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50949972821.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50949972821.webp', 'https://www.flickr.com/photos/zaragozaantigua/50949972821/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22248, 'Plaza del Pilar 1954', 'Imagen capturada en la plaza del Pilar durante la ceremonia de "consagraciâ”œâ”‚n de Espaâ”œâ–’a al inmaculado corazâ”œâ”‚n de Marâ”œÂ¡a" realizada como culminaciâ”œâ”‚n del Congreso Mariano celebrado en el marco de las fiestas del Pilar de ese aâ”œâ–’o. Un altar fue habilitado a tal efecto en el "monumento a los Hâ”œÂ®roes de Zaragoza de la Gloriosa Cruzada", y una vez terminada la misa el "Jefe del Estado y Generalâ”œÂ¡simo" Francisco Franco Bahamonde, de rodillas, dio lectura ante la imagen procesional en plata de la virgen del Pilar del texto por el que se consagraba a Espaâ”œâ–’a "de manera solemne, oficial e irrevocable" a la referida advocaciâ”œâ”‚n. Al fondo, la Hospederâ”œÂ¡a del Pilar, junto a la que aparece una tribuna cubierta ocupada por los arzobispos y obispos de toda Espaâ”œâ–’a.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65724200, -0.88094400, '0101000020E61000000470B378B130ECBF60C77F8120D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52272184910.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52272184910.webp', 'https://www.flickr.com/photos/zaragozaantigua/52272184910/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22271, 'La riada de 1961', 'Ayuntamiento de Zaragoza/Marâ”œÂ¡n Chivite. Enero 1961. Se esperaba una crecida normalica, pero fue de aâ”œâ•‘pa: el Ebro se hizo mar y se subiâ”œâ”‚ hasta casi los 6,5 metros. Esta riada era solo comparable a aquella de enero de 1871, que dicen las crâ”œâ”‚nicas que fue la madre de todas las crecidas. Los barrios mâ”œÃ­s afectados fueron Ranillas, la Ortilla, Jesâ”œâ•‘s, Arrabal. La magnitud no solo se debiâ”œâ”‚ a la cantidad de agua que llevâ”œâ”‚ el râ”œÂ¡o (en Zaragoza se midieron mâ”œÃ­s de 4 millones de litros por segundo), sino tambiâ”œÂ®n a su permanencia: hasta el 7 de enero no se apreciâ”œâ”‚ un decrecimiento notable. Asâ”œÂ¡ es el Ebro, ni mâ”œÃ­s ni menos que un râ”œÂ¡o mediterrâ”œÃ­neo, con un caudal de agua tan variable que la siguiente riada nos parecerâ”œÃ­ noticia. En la imagen, la crecida que convirtiâ”œâ”‚ a la Pasarela en un olâ”œÂ¡mpico trampolâ”œÂ¡n.', 1961, 1961, 1961, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65794000, -0.88119100, '0101000020E6100000F5F1D077B732ECBF795DBF6037D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14920612362.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14920612362.webp', 'https://www.flickr.com/photos/zaragozaantigua/14920612362/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22273, 'Margen Izquierda desde El Pilar 1968', 'Ayuntamiento de Zaragoza. Gerardo Sancho Ramo. 18/05/1968. "Vistas de Zaragoza desde la torre del Pilar." Panorâ”œÃ­mica pergeâ”œâ–’ada para la ocasiâ”œâ”‚n, en una composiciâ”œâ”‚n inâ”œÂ®dita, democrâ”œÃ­tica, cientâ”œÂ¡fica y popular, generada en los laboratorios del', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65794000, -0.88119100, '0101000020E6100000F5F1D077B732ECBF795DBF6037D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14940178856.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14940178856.webp', 'https://www.flickr.com/photos/zaragozaantigua/14940178856/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22274, 'Glorieta Pâ”œÂ¡o XII 1960', '1960. Heraldo de Aragâ”œâ”‚n. La Glorieta de Pâ”œÂ¡o XII estaba situada entre el torreâ”œâ”‚n de la Zuda y San Juan de los Panetes, en una zona con pozo ornamental (hoy en el parque Grande, junto al jardâ”œÂ¡n botâ”œÃ­nico) y jardines. Vemos la pasarela previa al puente de Santiago, al fondo. Hoy la zona estâ”œÃ­ arqueologizada, mostrando restos de la muralla romana.', 1960, 1960, 1960, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65759500, -0.88144400, '0101000020E61000006F2C280CCA34ECBFAE81AD122CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14948092592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14948092592.webp', 'https://www.flickr.com/photos/zaragozaantigua/14948092592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22329, 'Pl. del Pilar 1965', 'Como venâ”œÂ¡a siendo tradicional-de toda la vida desde 1939, el 20-N era el dâ”œÂ¡a de Josâ”œÂ® Antonio y de los "caâ”œÂ¡dos". Por ello, desde la Jefatura Provincial del Movimiento se organizâ”œâ”‚ un programa de actos a tono, con un carâ”œÃ­cter marcadamente nacional-catâ”œâ”‚lico que implicaba a las organizaciones del ramo: FET y JONS, Vieja Guardia, Frente de Juventudes, Secciâ”œâ”‚n Femenina, SEU, SEM, Asociaciâ”œâ”‚n de ex Cautivos, Asociaciâ”œâ”‚n de ex Combatientes. Perfectamente uniformados con su identitaria camisa azul, acudirâ”œÂ¡an a todos los frentes ordenados: concentraciones ante el monumento a los "caâ”œÂ¡dos"; rezo del rosario; toque de silencio, oraciâ”œâ”‚n y colocaciâ”œâ”‚n de corona de flores; canto del "Cara al sol"; misa, y solemne funeral. En la imagen, nocturna concentraciâ”œâ”‚n marcial del Frente de Juventudes ante el monumento a los "caâ”œÂ¡dos" de la plaza del Pilar. Fue el 19 de noviembre, como antesala a lo programado para el dâ”œÂ¡a siguiente, desde el punto de la maâ”œâ–’ana. Mientras tanto, y en su Escuela Hogar sita en el paseo de Mâ”¬Â¬ Agustâ”œÂ¡n, la Secciâ”œâ”‚n Femenina estaba haciendo cosas de chicas: rezar el rosario, y leyendo el testamento de Primo de Rivera. Fuente visual: Archivo Municipal. Gerardo Sancho. 1965.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65722900, -0.88085200, '0101000020E6100000D8B79388F02FECBFCC7D721420D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18523692289.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18523692289.webp', 'https://www.flickr.com/photos/zaragozaantigua/18523692289/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22440, 'San Juan de los Panetes 1965', 'Imagen del entorno de la iglesia de San Juan de los Panetes, capturada desde la altura de la antigua muralla de piedra de la ciudad, con el objetivo enfocando hacia el sureste, con el Altar de la Patria del Râ”œÂ®gimen, y la gran plaza del Pilar, hasta la Seo, al fondo. Fuente: www.todocoleccion.net/', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30962775146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30962775146.webp', 'https://www.flickr.com/photos/zaragozaantigua/30962775146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22697, 'Glorieta de Pâ”œÂ¡o XII c.1972', 'Seis baturros con copla alusiva a la indumentaria de ellos, junto al Torreâ”œâ”‚n de la Zuda (izquierda). Al fondo, glorieta de Pâ”œÂ¡o XII y arranque del Puente de Santiago. Tras la copla, espectadores. Fuente: Foto para postal de Comercial Josan. Cesiâ”œâ”‚n de la familia de Josâ”œÂ® Marâ”œÂ¡a Sanz Gonzâ”œÃ­lez a Rafael Castillejo. Dataciâ”œâ”‚n y procesado:', 1972, 1972, 1972, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65755400, -0.88149200, '0101000020E6100000B3F0F5B52E35ECBF4FADBEBA2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27347800801.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27347800801.webp', 'https://www.flickr.com/photos/zaragozaantigua/27347800801/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22707, 'La Zuda 1971', 'Calle Imperial, antigua de Antonio Pâ”œÂ®rez y actual tramo de la avenida de Câ”œÂ®sar Augusto, con el renovado Torreâ”œâ”‚n de la Zuda y el tramo reconstruido de la antigua muralla de piedra, tras la que se encuentra la iglesia de San Juan de los Panetes, cuya torre despunta mâ”œÂ¡nimamente a la derecha. Al fondo, el paseo de Echegaray y Caballero y la arboleda de Macanaz, ya al otro lado del râ”œÂ¡o Ebro y con acceso mediante el reciente puente de Santiago.', 1971, 1971, 1971, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65730800, -0.88196200, '0101000020E610000073124A5F0839ECBF18B325AB22D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27824111111.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27824111111.webp', 'https://www.flickr.com/photos/zaragozaantigua/27824111111/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22901, 'Plaza Câ”œÂ®sar Augusto 1989', 'Instantâ”œÃ­nea de excavaciones arqueolâ”œâ”‚gicas en la plaza de Câ”œÂ®sar Augusto de Zaragoza, con el Torreâ”œâ”‚n de la Zuda y la iglesia de San Juan de los Panetes al fondo, el 2 de marzo de 1989. Fueron hallados mosaicos romanos, como el llamado "de las Musas", sobre el que vemos a los operarios. Ese mismo aâ”œâ–’o tambiâ”œÂ®n se hallaron y soterraron las cimentaciones de la puerta de Toledo, cerca de aquâ”œÂ¡. En 1944 y en esta misma plaza apareciâ”œâ”‚ tambiâ”œÂ®n una villa romana, llamada Casa de Orfeo por el importante mosaico que albergaba (www.flickr.com/photos/zaragozaantigua/19113797851). Fuente: "Memoria de las calles de Zaragoza", Juliâ”œÃ­n Ruiz Marâ”œÂ¡n, Librerâ”œÂ¡a General, 1997.', 1989, 1989, 1989, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65725700, -0.88162100, '0101000020E610000028F04E3E3D36ECBF960854FF20D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21350613044.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21350613044.webp', 'https://www.flickr.com/photos/zaragozaantigua/21350613044/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23098, 'Av. de Câ”œÂ®sar Augusto 2000', 'Aâ”œÂ®rea visual centrada en el entorno de la Zuda y San Juan de los Panetes durante las excavaciones arqueolâ”œâ”‚gicas realizadas a finales del pasado siglo XX en la glorieta de Pâ”œÂ¡o XII para dejar al aire restos de la muralla romana e islâ”œÃ­mica. Fuente visual: AMZ.', 2000, 2000, 2000, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65756000, -0.88160100, '0101000020E610000061DEE34C1336ECBF319413ED2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23894210767.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23894210767.webp', 'https://www.flickr.com/photos/zaragozaantigua/23894210767/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23105, 'Torreâ”œâ”‚n de la Zuda 2000', 'Aspecto del acceso al Torreâ”œâ”‚n de la Zuda en 2000, durante su restauraciâ”œâ”‚n, que sacâ”œâ”‚ a la luz restos de las murallas romanas bajo la glorieta de Pâ”œÂ¡o XII. Al fondo, lienzo musealizado en los aâ”œâ–’os 50 en la calle Murallas Romanas. Fuente: Agencia EFE.', 2000, 2000, 2000, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65752400, -0.88159400, '0101000020E6100000C231CB9E0436ECBFE52A16BF29D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24349171610.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24349171610.webp', 'https://www.flickr.com/photos/zaragozaantigua/24349171610/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23813, 'Hospederâ”œÂ¡a del Pilar 1940', 'Fase avanzada de construcciâ”œâ”‚n de la Hospederâ”œÂ¡a del Pilar, junto a la Basâ”œÂ¡lica (al fondo a la derecha). Serâ”œÃ­ inaugurada en enero de 1941. En el horizonte, el puente de Piedra sobre el Ebro. Fuente visual: "Una mirada a travâ”œÂ®s de la arquitectura: Regino y Josâ”œÂ® Borobio Ojeda", Daniel Estabâ”œÂ®n Boldova, 2013.', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65743500, -0.88004100, '0101000020E6100000CD7344BE4B29ECBF751F80D426D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15726203761.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15726203761.webp', 'https://www.flickr.com/photos/zaragozaantigua/15726203761/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23830, 'Paseo del Ebro 1907', 'Perspectiva del paseo del Ebro, desde las traseras del convento de San Juan de los Panetes (tras la caseta de consumos). Aquâ”œÂ¡ estaba la Puerta del Fin, y el desemboque de la calle del mismo nombre, y era lugar de posadas (como la de la imagen, en el nâ”¬â•‘ 39, donde la acumulaciâ”œâ”‚n de carros, recientemente proyectada por Josâ”œÂ® de Yarza, y denominada "Posada de Huesca"), caballerizas, veterinarios, aperos metâ”œÃ­licos, y ferias de ganado. Fuente visual: Fototeca del Patrimonio Artâ”œÂ¡stico (www.mcu.es/)', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65759400, -0.88028000, '0101000020E610000008556AF6402BECBFDE054A0A2CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21949447688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21949447688.webp', 'https://www.flickr.com/photos/zaragozaantigua/21949447688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23832, 'Calle del Fin, 1939', 'Imagen, en su ubicaciâ”œâ”‚n original, del escudo de armas del barâ”œâ”‚n Don Hugo de Urriâ”œÂ®s y Veintemilla, un altorrelieve en piedra situado encima de la puerta de acceso a la iglesia del antiguo colegio de San Nicolâ”œÃ­s Tolentino, en la desaparecida calle del Fin. Tras la Desamortizaciâ”œâ”‚n del siglo XIX, el edificio fue utilizado como almacâ”œÂ®n y reconvertido a casa de vecinos, y con el proyecto de la nueva y gran plaza del Pilar, el conjunto del colegio, la iglesia, y el anexo palacio de los patronos Urriâ”œÂ®s, fueron derribados y explanados en 1939, y sobre ellos se construyeron la nueva Hospederâ”œÂ¡a para peregrinos, y la residencia del Cabildo de El Pilar, inaugurada en 1941. Segâ”œâ•‘n la prensa de la â”œÂ®poca, el Ayuntamiento decidiâ”œâ”‚ preservar este escudo. Fuente visual: Juan Mora Insa, AMZ.', 1939, 1939, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65722600, -0.87978600, '0101000020E610000026512FF83427ECBF5B0A48FB1FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21953131280.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21953131280.webp', 'https://www.flickr.com/photos/zaragozaantigua/21953131280/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23897, 'Pl. del Pilar 1954', 'Imagen capturada durante el homenaje del Ejâ”œÂ®rcito espaâ”œâ–’ol a la Santâ”œÂ¡sima Virgen celebrado en el marco del Congreso Mariano que tuvo lugar en la ciudad en octubre de ese aâ”œâ–’o. El altar de la marcial ceremonia se ubicâ”œâ”‚ en la altura del reciâ”œÂ®n terminado "Monumento a los hâ”œÂ®roes y mâ”œÃ­rtires de Zaragoza. Caâ”œÂ¡dos en la Cruzada de Liberaciâ”œâ”‚n 1936-1939", al oeste de la plaza del Pilar, tambiâ”œÂ®n denominada de las Catedrales desde que se culminâ”œâ”‚ "la iniciativa de derribar casas viejas y barrios enteros para conseguir esta inmensa explanada en la que pueden celebrarse concentraciones de esta importancia, teniendo como fondo las dos catedrales zaragozanas: el Pilar y La Seo" (ABC, 9 de octubre de 1954). La imagen se ha tomado, precisamente, desde el referido monumento, con el fondo doblemente catedralicio, ademâ”œÃ­s de los nuevos inmuebles del Gobierno Civil, y del Ayuntamiento (aâ”œâ•‘n en construcciâ”œâ”‚n). Fuente visual: fondo Julio Sâ”œÃ­nchez Millâ”œÃ­n, en Ministerio de Cultura y Deporte.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65720400, -0.88098600, '0101000020E6100000C07B478D0931ECBF7366BB421FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45297598391.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45297598391.webp', 'https://www.flickr.com/photos/zaragozaantigua/45297598391/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23958, 'Avenida Câ”œÂ®sar Augusto 1987', 'Cortejo mortuorio y sentada para protestar contra la reforma universitaria del PSOE, durante unas de las numerosas movilizaciones que, tras las luchas estudiantiles en Francia e Italia de finales de 1986, en confluencia con las enseâ”œâ–’anzas medias, y con el respaldo del rector, Vicente Camarena, caracterizaron los primeros meses de 1987. La escena tiene lugar donde la avenida de Câ”œÂ®sar Augusto desemboca en el paseo de Echegaray. A la derecha, el colegio Valentâ”œÂ¡n Zabala. Fuente: Zaragozarebelde.org', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65761900, -0.88182300, '0101000020E61000001A8A3BDEE437ECBF361D01DC2CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14822243977.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14822243977.webp', 'https://www.flickr.com/photos/zaragozaantigua/14822243977/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23983, 'Plaza Câ”œÂ®sar Augusto 1987', 'Foto: â”œÃ¼ngel de Castro. Atentado de ETA contra un autobâ”œâ•‘s de la Academia General Militar el 30 de enero de 1987 en la plaza Câ”œÂ®sar Augusto de Zaragoza. A la derecha, el Torreâ”œâ”‚n de la Zuda y la iglesia de San Juan de los Panetes. Fuente: Heraldo de Aragâ”œâ”‚n.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65722000, -0.88135200, '0101000020E61000004374081C0934ECBF7923F3C81FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15411932322.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15411932322.webp', 'https://www.flickr.com/photos/zaragozaantigua/15411932322/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23747, 'Movera 1970', 'Grupo escolar y parroquial de la iglesia de Nuestra Seâ”œâ–’ora de Movera, reciâ”œÂ®n inaugurados, en la plaza de Espaâ”œâ–’a del homâ”œâ”‚nimo barrio rural. Fuente visual: www.barriodemovera.es/', 1970, 1970, 1970, 'Anos 70', NULL, 41.64952200, -0.82180900, '0101000020E6100000F0DE5163424CEABF2904728923D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15500088328.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15500088328.webp', 'https://www.flickr.com/photos/zaragozaantigua/15500088328/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24078, 'Puente de Santiago 1967', 'Imagen capturada durante la inauguraciâ”œâ”‚n oficial del Puente de Santiago (13 de marzo) y centrada en el carrionâ”œÂ®s arzobispo de Zaragoza, Excelentâ”œÂ¡simo y Reverendâ”œÂ¡simo Seâ”œâ–’or Pedro Cantero Cuadrado, cuando procedâ”œÂ¡a a rociar con agua bendita al nuevo nexo de uniâ”œâ”‚n entre ambas riberas del râ”œÂ¡o Ebro que sustituyâ”œâ”‚ a la peatonal pasarela en servicio desde los aâ”œâ–’os cuarenta. Mediante este sencillo acto el puente quedâ”œâ”‚ exortizado, purificado y pleno de gracia santificante. Tras el arzobispo complementan el cortejo inaugural diversas autoridades militares y civiles. Al fondo, legiâ”œâ”‚n de parroquianos que observan atentamente el ceremonial desde la elevada replaceta junto a la barroca iglesia de San Juan de los Panetes. Unos meses despuâ”œÂ®s, Pedro Cantero Cuadrado serâ”œÂ¡a designado procurador en las Cortes Espaâ”œâ–’olas por el Jefe del Estado, Francisco Franco Bahamonde. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65801400, -0.88160800, '0101000020E6100000008BFCFA2136ECBFB32781CD39D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38431721346.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38431721346.webp', 'https://www.flickr.com/photos/zaragozaantigua/38431721346/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24344, 'S. Juan de los Panetes 1930', '"Iglesia de San Juan. La Torre". La nueva fabrica de la antigua iglesia templaria de San Juan, en el primer cuarto del siglo XVIII, supuso la reorientaciâ”œâ”‚n de su planta, la construcciâ”œâ”‚n de su caracterâ”œÂ¡stica torrecilla, y de un arco de acceso a la parroquia, denominado de San Juan, desde la calle de los Agustinos. En la imagen, el arco presenta en su parte superior una hornacida votiva barroca. La diâ”œÃ­fana y soleada plaza de Huesca, previa al arco, era consecuencia del derribo de la antigua manzana de edificios entre las calles de Agustinos, Danzas, y San Juan de los Panetes.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65733800, -0.88108900, '0101000020E6100000E6B0FB8EE131ECBF8335CEA623D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14688645699.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14688645699.webp', 'https://www.flickr.com/photos/zaragozaantigua/14688645699/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24354, 'Labordeta 1986', 'Foto: Rogelio Allepuz, febrero de 1986. Josâ”œÂ® Antonio Labordeta posa ante la iglesia de San Juan de los Panetes de Zaragoza. Fuente: El Periâ”œâ”‚dico de Aragâ”œâ”‚n', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65730100, -0.88100600, '0101000020E6100000868DB27E3331ECBF65506D7022D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14914840931.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14914840931.webp', 'https://www.flickr.com/photos/zaragozaantigua/14914840931/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24360, 'San Juan de los Panetes 1933', 'Entorno de la iglesia de San Juan de los Panetes en diciembre de 1933, tras el incendio provocado en su interior durante unos disturbios. Las tropas del Ejâ”œÂ®rcito de la Repâ”œâ•‘blica, desplegadas, montan guardia para prevenciâ”œâ”‚n de nuevos atentados. Fuente visual: Heraldo de Aragâ”œâ”‚n', 1933, 1933, 1933, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65729700, -0.88130000, '0101000020E6100000A4DFBE0E9C33ECBF2461DF4E22D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15000690245.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15000690245.webp', 'https://www.flickr.com/photos/zaragozaantigua/15000690245/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24364, 'Pilar y Panetes c.1915', 'AHPZ. Juan Mora Insa. SF "Zaragoza. Vista del Pilar por la ribera." Ribera derecha, con las traseras de San Juan de los Panetes detrâ”œÃ­s del â”œÃ­rbol en primerâ”œÂ¡simo plano. Un par de carros aparcados, y un paisano buscando gamusinos.', 1915, 1915, 1915, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65792400, -0.88119100, '0101000020E6100000F5F1D077B732ECBF73A087DA36D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15174618346.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15174618346.webp', 'https://www.flickr.com/photos/zaragozaantigua/15174618346/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24366, 'Puerta de San Ildefonso c.1900', '"Puerta de San Ildefonso", Antonio Callaved, 2010. Puerta de San Ildefonso o de la Triperâ”œÂ¡a, construida en ladrillo y abierta al paseo de la Ribera, en la zona de San Juan de los Panetes (izquierda) y el Torreâ”œâ”‚n de la Zuda (a su derecha). Derribada en 1904. Fuente: pinturascallaved.wordpress.com/5-mi-pintura-en-la-filatelia/', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65774400, -0.88172000, '0101000020E6100000F35487DC0C37ECBFF39194F430D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15275841691.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15275841691.webp', 'https://www.flickr.com/photos/zaragozaantigua/15275841691/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24373, 'San Juan de los Panetes aâ”œâ–’os 30', 'Aspecto de la calle Agustinos, conducente al acceso a la iglesia parroquial de San Juan de los Panetes. Fuente visual: Ascensiâ”œâ”‚n Hernâ”œÃ­ndez Martâ”œÂ¡nez, "De restauraciones, demoliciones y otros debates sobre el patrimonio monumental zaragozano del siglo XX", IFC, 2008.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15686649272.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15686649272.webp', 'https://www.flickr.com/photos/zaragozaantigua/15686649272/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24377, 'San Juan de los Panetes 1930', 'A mediados del siglo XIX comenzâ”œâ”‚ un largo, complejo y discutido proceso de transformaciâ”œâ”‚n del antiguo y enorme conjunto de la "iglesia de San Juan de los Panetes de la Religiâ”œâ”‚n de San Juan de Jerusalâ”œÂ®n, y la Casa y Palacio de la Castellanâ”œÂ¡a de Amposta". La imagen captura la portada y torre de la iglesia resultantes de la nueva fâ”œÃ­brica de 1720. En esos momentos se estaba procediendo a derribar algunas de las dependencias del antiguo convento, utilizado en â”œâ•‘ltima instancia por la Congregaciâ”œâ”‚n de Adoratrices Esclavas del Santâ”œÂ¡simo Sacramento y de la Caridad. El acceso a la iglesia estâ”œÃ­ al mismo nivel que la calle, y se accede por el pequeâ”œâ–’o callejâ”œâ”‚n de la imagen, desde la calle de los Agustinos, y tambiâ”œÂ®n desde la plaza de San Antâ”œâ”‚n, fuera de plano, y a la derecha. Tras dâ”œÂ®cadas de actuaciones, al final la iglesia quedâ”œâ”‚ exenta y elevada respecto del terreno que la rodea, el Torreâ”œâ”‚n de la Sudda fue reinventado, y volvieron a ver la luz tres torreones y un buen pedazo de la antigua muralla romana, tanto la original, como la aâ”œâ–’adida en el siglo III de la era.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19442963681.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19442963681.webp', 'https://www.flickr.com/photos/zaragozaantigua/19442963681/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24386, 'San Juan de los Panetes 1972', 'Torreâ”œâ”‚n de la Zuda e iglesia de San Juan de los Panetes. Al fondo, el antiguo colegio Valentâ”œÂ¡n Zabala. Fuente visual: Foto Leonardo Pâ”œÂ®rez Obis, donada por â”œÃ¼ngel Hernâ”œÃ­ndez Mostajo para www.rafaelcastillejo.com', 1972, 1972, 1972, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23146350105.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23146350105.webp', 'https://www.flickr.com/photos/zaragozaantigua/23146350105/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24390, 'San Juan de los Panetes aâ”œâ–’os 30', 'Portada y torre de la iglesia de San Juan de los Panetes, desde las ruinas de las casas adosadas a las murallas romanas. Fuente: www.skyscrapercity.com/', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24759743661.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24759743661.webp', 'https://www.flickr.com/photos/zaragozaantigua/24759743661/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24411, 'San Juan de los Panetes aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste representando la portada de la iglesia de San Juan de los Panetes. Fuente: Lâ”œÃ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65746300, -0.88131100, '0101000020E61000009E5C5320B333ECBF3FAA61BF27D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32317797271.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32317797271.webp', 'https://www.flickr.com/photos/zaragozaantigua/32317797271/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24412, 'Plaza de Huesca aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste, que muestra la torre de San Juan de los Panetes desde la plaza de Huesca, y el arco de San Juan. Fuente: Lâ”œÃ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65734300, -0.88091400, '0101000020E61000005AD5928E7230ECBF94A0BFD023D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32399025396.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32399025396.webp', 'https://www.flickr.com/photos/zaragozaantigua/32399025396/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24661, 'Torreâ”œâ”‚n de la Zuda 1972', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. Noviembre 1972. El Torreâ”œâ”‚n de la Zuda se levantâ”œâ”‚ sobre la torre del homenaje del alcâ”œÃ­zar palacio de La Sudda, La Zuda o Azuda, construido a su vez sobre uno de los torreones de la muralla romana. La Sudda fue la residencia fortificada de los gobernadores musulmanes de la taifa de Sarakusta, hasta que trasladaron su residencia oficial al palacio de la Aljaferâ”œÂ¡a. Tras la conquista cristina, fue residencia de los monarcas aragoneses hasta el siglo XIII, en que tambiâ”œÂ®n se orientaron hacia la Aljaferâ”œÂ¡a. El torreâ”œâ”‚n fue reedificado en la segunda mitad del siglo XVI. La imagen actual del torreâ”œâ”‚n responde a la restauraciâ”œâ”‚n llevada a cabo por Francisco Iâ”œâ–’iguez entre 1946 y 1952, quien dio prioridad a las formas renacentistas sobre las anteriores, en coherencia con la lâ”œÂ¡nea historicista-regionalista de la arquitectura del Râ”œÂ®gimen franquista en esos momentos. En la imagen de conjunto, el Torreâ”œâ”‚n, las murallas romanas, y el pozo que en la penâ”œâ•‘ltima intervenciâ”œâ”‚n fue llevado al Parque Grande.', 1972, 1972, 1972, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65739300, -0.88151400, '0101000020E6100000A7EA1ED95C35ECBF46CF2D7425D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14710521427.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14710521427.webp', 'https://www.flickr.com/photos/zaragozaantigua/14710521427/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24662, 'Puerta de San Ildefonso 1904', 'Colecciâ”œâ”‚n Rafael Esteban. Foto: Agustâ”œÂ¡n Esteban, 1904. Vista cercana de la puerta de San Ildefonso o de la Triperâ”œÂ¡a, tomada desde la calle de este nombre, a la orilla del Ebro. Hacia dentro, la calle Antonio Pâ”œÂ®rez hacia el Mercado, con el torreâ”œâ”‚n de la Zuda arriba a la izquierda. La puerta serâ”œÂ¡a derribada ese mismo aâ”œâ–’o. En la puerta, un azulejo advierte que "EN ESTA CIUDAD NO SE TOLERA LA MENDICIDAD NI LA BLASFEMIA". Dicho queda.', 1904, 1904, 1904, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65779400, -0.88163500, '0101000020E61000006649809A5A36ECBFA5C0029832D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14919914990.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14919914990.webp', 'https://www.flickr.com/photos/zaragozaantigua/14919914990/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24664, 'Embarcadero del Ebro c.1925', 'Imagen de las escaleras de acceso al servicio de barca que en este tramo del râ”œÂ¡o permitâ”œÂ¡a su paso. Al fondo, San Juan de los Panetes, el torreâ”œâ”‚n de la Zuda, la calle de Antonio Pâ”œÂ®rez conducente al Mercado Central, y el colegio Valentâ”œÂ¡n Zabala. Fuente visual: Archivo Coyne, en "El Ebro y sus riberas", Ayuntamiento de Zaragoza.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65800400, -0.88137300, '0101000020E6100000207A52263534ECBF8F519E7939D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15121638044.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15121638044.webp', 'https://www.flickr.com/photos/zaragozaantigua/15121638044/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24665, 'San Juan de los Panetes 1927', '"Rodio" (Luis Pablo Sanz Lafita) dibuja con trazos modernos y atinados una visual de San Juan de los Panetes desde la inmediata ribera del Ebro, y la acompaâ”œâ–’a de un â”œÃ­rbol retorcido, una anciana crepuscular, un viejo "Ford", y un carro a la funerala. Hay nubes, sombras y claros para una composiciâ”œâ”‚n propia de un dâ”œÂ¡a de difuntos, tanto para los que ya lo son, como para los que lo seremos. Fuente visual: "Aragâ”œâ”‚n : revista grâ”œÃ­fica de cultura aragonesa" (Aâ”œâ–’o III, Nâ”¬â•‘ 20, mayo 1927).', 1927, 1927, 1927, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65771500, -0.88075300, '0101000020E61000000D535BEA202FECBF598B4F0130D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15480634399.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15480634399.webp', 'https://www.flickr.com/photos/zaragozaantigua/15480634399/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24666, 'La Zuda 1987', 'Luis Mâ”œÂ¡nguez. 1987. Desde el Torreâ”œâ”‚n de la Zuda, un vistazo al Suroeste, siguiendo la Avenida de Câ”œÂ®sar Augusto, por encima de los cubos ultrasemicirculares de la Murallas Romanas del s.III, la antigua plaza de Lanuza, el Mercado Central, hasta llegar a la câ”œâ•‘pula de Santiago el Mayor, al fondo. A su derecha, la iglesia de los Escolapios. Hegemonâ”œÂ¡a espacial del trâ”œÃ­fico rodado, en movimiento, y aparcado. Solares en barbecho.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65752400, -0.88159400, '0101000020E6100000C231CB9E0436ECBFE52A16BF29D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15667970199.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15667970199.webp', 'https://www.flickr.com/photos/zaragozaantigua/15667970199/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24667, 'Plaza de Huesca 1925', 'Miguel Faci Abad. 1920-1925. "Zaragoza. Antigua plaza Huesca ante la iglesia de San Juan de los Panetes". La plaza de Huesca era una placica al lado de la plaza del Pilar, entre las calles de la Zuda (izquierda), de la Regla (donde los adoquines), de Agustinos (enfrente a â”œÂ®sta), y del Fin (derecha). Esta â”œâ•‘ltima comunicaba, por medio de un antiguo trenque, con el paseo de la ribera. Al fondo, otra puerta daba entrada al recinto donde se levantaba San Juan de los Panetes. La clase social que aquâ”œÂ¡ vivâ”œÂ¡a era sustancialmente diferente a la de la vecina plaza del Pilar, como reflejan los tipos y situaciones que la imagen captura, impensables apenas 100 metros hacia la derecha, en el "salâ”œâ”‚n de la ciudad". Es uno de esos dâ”œÂ¡as en que la sombra apetece mâ”œÃ­s que la solana, y un cabrero ordeâ”œâ–’a a una chiva del rebaâ”œâ–’o, mientras unos chavales callejean a su gusto. Estos â”œÃ­rboles no eran tampoco como los de la plaza del Pilar. Fuente visual: "Miguel y Gabriel Faci. Fotâ”œâ”‚grafos fundadores de la Real Sociedad Fotogrâ”œÃ­fica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaciâ”œâ”‚n Provincial de Zaragoza, 1999.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65722900, -0.88085200, '0101000020E6100000D8B79388F02FECBFCC7D721420D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15789998832.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15789998832.webp', 'https://www.flickr.com/photos/zaragozaantigua/15789998832/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24669, 'Murallas romanas 1987', 'Luis Mâ”œÂ¡nguez. 1987. Desde un â”œâ”‚culo de la octogonal, barroca, inclinada y enladrillada torre de San Juan de los Panetes, una insâ”œâ”‚lita mirada sobre el entorno. Inmediato, el incontingente aparcamiento. A la izquierda, el salvado Mercado Central. Enfrente, los recios lienzos de la muralla de piedra, y el vacâ”œÂ¡o dejado en su pedestal por el casi semoviente Câ”œÂ®sar Augusto primaportado y mussolâ”œÂ¡niano. Al fondo, la rotunda fachada de la original "Poblaciâ”œâ”‚n" (San Pablo), y su inmemorial acceso por la calle de Predicadores. Plagado de publicidad comercial, un enorme solar esquinado a la avenida y a la calle Ben Aire, en modo espera.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65723400, -0.88186700, '0101000020E6100000027E8D244138ECBFDEE8633E20D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15834431621.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15834431621.webp', 'https://www.flickr.com/photos/zaragozaantigua/15834431621/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24670, 'San Juan de los Panetes 1927', 'Imagen a cierta altura de la octogonal y barroca torre de San Juan de los Panetes, emergente en el entorno de callejas y recovecos que caracterizaba esta zonba, junto a la plaza de Huesca, desde la que se accedâ”œÂ¡a por la calle de Agustinos (izquierda), tras cruzar un pequeâ”œâ–’o arco de medio punto. Esta torre se apoyaba en construcciones que se le habâ”œÂ¡an ido anexando en el transcurso de los siglos. La imagen estâ”œÃ­ tomada, precisamente, desde la altura de una de estas viviendas, la nâ”¬â•‘ 35 recayente al paseo del Ebro. A la derecha destaca por su altura el tejado a doble vertiente de la nave central de la iglesia, y algunos de sus contrafuertes de refuerzo. Enfrente, viviendas del nâ”¬â•‘ 11 de la calle de La Zuda y dependencias del, hasta hace poco, antiguo convento de las Adoratrices. El Torreâ”œâ”‚n de la Zuda queda un poco hacia la derecha, y, como las murallas romanas, rodeado de un compost de edificaciones. Cuando unos aâ”œâ–’os despuâ”œÂ®s, se inicien obras para abrir calles y despejar la zona, la torre presentarâ”œÃ­ graves problemas de estabilidad por la merma de sus tradicionales apoyos. El Ayuntamiento del momento estaba decidido a su derribo para construir un mercado en el lugar, pero mientras tanto, se proclamâ”œâ”‚ la Segunda Repâ”œâ•‘blica, y el nuevo Gobierno declarâ”œâ”‚ el templo como Monumento Nacional. Fuente visual: Instituto Amatller de Arte Hispâ”œÃ­nico (Arxiu Mas). Fuente textual: Ascensiâ”œâ”‚n Hernâ”œÃ­ndez Martâ”œÂ¡nez, "De restauraciones, demoliciones y otros debates sobre el patrimonio monumental zaragozano del siglo XX", IFC, 2008.', 1927, 1927, 1927, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15893540992.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15893540992.webp', 'https://www.flickr.com/photos/zaragozaantigua/15893540992/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24105, 'Jardâ”œÂ¡n de Invierno 1960', 'Imagen capturada en el "auditorium" (sic) del Jardâ”œÂ¡n de Invierno en el parque de Primo de Rivera durante la solemne celebraciâ”œâ”‚n del aniversario 55 de la "coronaciâ”œâ”‚n canâ”œâ”‚nica de la Virgen del Pilar" que, a iniciativa del Ayuntamiento, consistiâ”œâ”‚ en una misa con rito pontifical oficiada por el arzobispo Casimiro Morcillo. Al fondo, escenario donde se instalâ”œâ”‚ el altar con la imagen procesional en plata de la Virgen, y una gran cruz de cinco metros de altura iluminada por reflectores que presidâ”œÂ¡a la ceremonia. A la derecha, banderas de Acciâ”œâ”‚n Catâ”œâ”‚lica, y a la izquierda, representaciâ”œâ”‚n de seminaristas. Sobre el firme, espacio para el pâ”œâ•‘blico asistente, al frente del cual se colocaron bancos para las autoridades (entre ellas la Corporaciâ”œâ”‚n municipal encabezada por el alcalde Luis Gâ”œâ”‚mez Laguna; la Corporaciâ”œâ”‚n provincial con el presidente Antonio Zubiri Vidal; el gobernador civil y jefe provincial del "Movimiento" Josâ”œÂ® Manuel Pardo de Santayana; y autoridades militares encabezadas por el capitâ”œÃ­n general Manuel Baturone Colombo), ademâ”œÃ­s de mil sillas de pago. Este evento comenzâ”œâ”‚ a las 20:00h. y terminâ”œâ”‚ a las 22:00h. del dâ”œÂ¡a 20 de mayo de ese aâ”œâ–’o.', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.63175500, -0.89290700, '0101000020E6100000B7D26BB3B192ECBFD00A0C59DDD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51653859433.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51653859433.webp', 'https://www.flickr.com/photos/zaragozaantigua/51653859433/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24671, 'Paseo del Ebro c.1900', 'Tener el Pilar a las espaldas, tras el Callejâ”œâ”‚n del Retiro Alto, tampoco es mala cosa a la hora de capturar instantâ”œÃ­neas en Zaragoza, en este caso, desde altura, y mirando hacia el Puente del Ferrocarril (al fondo). A la derecha, Macanaz-Ranillas, con un brazal de la acequia de Juslibol desaguando al Ebro. En el despejado Paseo, una unidad de la Lâ”œÂ¡nea de Circunvalaciâ”œâ”‚n, a propulsiâ”œâ”‚n de sangre, dirigiâ”œÂ®ndose hacia la mitad de su periplo a lo Sâ”œÂ¡sifo. Un jinete solitario completa el trâ”œÃ­fico rodado en velocidad. A la izquierda, junto a la Puerta del Fin, un destacado concesionario de â”œÂ®quidos, mulos, y carros, con alto y animado volumen comercial. Al otro lado de la calle del Fin, el entramado de calles que configura las traseras de la plaza de Huesca: Agustinos, de la Regla, de la Zuda, de las Flores... un espacio urbano complejo e irrepetible, con elementos desaparecidos, como el Colegio de los Agustinos Descalzos de San Nicolâ”œÃ­s de Tolentino, la iglesia de San Antâ”œâ”‚n, el Hospital de San Juan de los Panetes... ademâ”œÃ­s de todas las casas donde los prostituidores desfogâ”œÃ­banse a sus anchas, a cambio de unos dineros, en otro tipo de comercio de la carne. Superviven la reorientada, modificada y barroca torre e iglesia de San Juan de los Panetes, y el torreâ”œâ”‚n de la Zuda, que sobresale tras la iglesia, por encima de vestigios de muralla romana. Fuente visual: AHPZ, Archivo Coyne, ca. 1900', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65749900, -0.87979600, '0101000020E61000000ADAE4F04927ECBF8C135FED28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16451696592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16451696592.webp', 'https://www.flickr.com/photos/zaragozaantigua/16451696592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24672, 'Plaza del Mercado 1975', 'Desde el Torreâ”œâ”‚n de la Zuda, vista de la plaza de Lanuza. Estamos en la linde entre la parroquia del Pilar, a la izquierda, y la de San Pablo, a la derecha. Al fondo, la câ”œâ•‘pula de Santiago el Mayor y siluetas de los monstruos edilicios que van surgiendo como edificios singulares y actuaciones aisladas. En primer tâ”œÂ®rmino, las murallas romanas, seguidas del Mercado Central, y de la manzana entre las calles de Cerdâ”œÃ­n y de las Escuelas Pâ”œÂ¡as.', 1975, 1975, 1975, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65752400, -0.88159400, '0101000020E6100000C231CB9E0436ECBFE52A16BF29D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19025863396.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19025863396.webp', 'https://www.flickr.com/photos/zaragozaantigua/19025863396/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24673, 'Puerta del Fin 1922', 'Dibujo de Dâ”œÂ¡az Domâ”œÂ¡nguez del rincâ”œâ”‚n del paseo del Ebro de Zaragoza a la altura de la calle del Fin (tras la garita del fielato). Esta calle era uno de los accesos a la ciudad, cerrado con su puerta, que daba nombre a toda la explanada, utilizada como feria del ganado. El edificio donde se encuentra el negocio del veterinario Remacha habâ”œÂ¡a sido Colegio de los Agustinos, vulgo Agustinicos. Al fondo, la torreta de la câ”œâ•‘pula de San Juan de los Panetes. Fuente: La Cadiera 114, 1957.', 1922, 1922, 1922, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65749900, -0.87979600, '0101000020E61000000ADAE4F04927ECBF8C135FED28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20057942382.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20057942382.webp', 'https://www.flickr.com/photos/zaragozaantigua/20057942382/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24674, 'San Juan de los Panetes 1988', 'Foto Eduardo Zamarripa, 1988. Vista aâ”œÂ®rea del torreâ”œâ”‚n de la Zuda y la iglesia de San Juan de los Panetes de Zaragoza en 1988. Fuente: Aragâ”œâ”‚n desde el aire, Ministerio de Defensa, 1988.', 1988, 1988, 1988, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20325163741.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20325163741.webp', 'https://www.flickr.com/photos/zaragozaantigua/20325163741/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24677, 'Paseo del Ebro 1926', 'Imagen del paseo del Ebro en la zona cercana a las traseras del convento de San Juan de los Panetes, entre las calles de Antonio Pâ”œÂ®rez, y la del Fin, con notable proliferaciâ”œâ”‚n de caballerâ”œÂ¡as y carros. Despunta la linterna y el â”œÃ­bside principal de la barroca iglesia de San Juan. Al fondo, el chaflâ”œÃ­n del colegio Valentâ”œÂ¡n Zabala. Fuente visual: Miguel Marâ”œÂ¡n Chivite, AMZ', 1926, 1926, 1926, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65759400, -0.88028000, '0101000020E610000008556AF6402BECBFDE054A0A2CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24505950831.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24505950831.webp', 'https://www.flickr.com/photos/zaragozaantigua/24505950831/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24679, 'Cruz de los caâ”œÂ¡dos 1971', 'Foto: Iâ”œâ–’aki Urbez. Vista de la Cruz de los caâ”œÂ¡dos y el entorno de San Juan de los Panetes, desde la torre de San Francisco de Borja del Pilar. Fuente: www.facebook.com/groups/fotosantiguasdezaragoza/permalink...', 1971, 1971, 1971, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65726000, -0.88086300, '0101000020E6100000D234289A0730ECBF077C7E1821D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29653584062.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29653584062.webp', 'https://www.flickr.com/photos/zaragozaantigua/29653584062/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24680, 'San Juan de los Panetes c.1925', 'Imagen capturada desde la margen izquierda del râ”œÂ¡o Ebro, en la arboleda de Macanaz, frente a la iglesia de San Juan de los Panetes y la embocadura a la calle de Antonio Pâ”œÂ®rez. A la derecha, asoma levemente el torreâ”œâ”‚n de la Zuda. Destacan las escaleras de acceso a las barcas que daban servicio de paso en este tramo del râ”œÂ¡o. El gran agujero abovedado en el pretil recuerda el antiguo desagâ”œâ•e que aquâ”œÂ¡ vertâ”œÂ¡a desde la antigua plaza del Mercado. Fuente: fotografâ”œÂ¡a de Claudi Carbonell Flo, en www.museunacional.cat/', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65801400, -0.88160800, '0101000020E6100000008BFCFA2136ECBFB32781CD39D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30134489963.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30134489963.webp', 'https://www.flickr.com/photos/zaragozaantigua/30134489963/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24683, 'La Zuda 1882', 'Grabado con diseâ”œâ–’o de Bernardo Rico, basado en una fotografâ”œÂ¡a de Jean Laurent capturada en la calle de Antonio Pâ”œÂ®rez, y titulado "Zaragoza.-El torreâ”œâ”‚n de la Azuda donde se firmâ”œâ”‚ la rendiciâ”œâ”‚n de la ciudad â”œÃ­ Don Alfonso I â”¬Â½El Batalladorâ”¬â•— (1118)". Fuente visual: La Ilustraciâ”œâ”‚n espaâ”œâ–’ola y americana (1882)', 1882, 1882, 1882, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65756000, -0.88160100, '0101000020E610000061DEE34C1336ECBF319413ED2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34638029461.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34638029461.webp', 'https://www.flickr.com/photos/zaragozaantigua/34638029461/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24685, 'Torreâ”œâ”‚n de la Zuda 1890', '"Torreâ”œâ”‚n del Palacio Real de la Azuda donde, al tomar Zaragoza, se aposentâ”œâ”‚ Alfonso el Batallador". Ilustraciâ”œâ”‚n de Ambrosio del Ruste, 1948, basada en una fotografâ”œÂ¡a de 1890. Fuente: "Conquista de Zaragoza por Don Alfonso I el Batallador", La Cadiera, 1948.', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65756000, -0.88163100, '0101000020E61000000C7904375236ECBF319413ED2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41407425642.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41407425642.webp', 'https://www.flickr.com/photos/zaragozaantigua/41407425642/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24686, 'Murallas romanas ca. 2005', 'Vista desde el torreâ”œâ”‚n de la Zuda de los restos de las murallas romanas, con la calle homâ”œâ”‚nima a la izquierda y la avenida de Câ”œÂ®sar Augusto a la derecha. Se estâ”œÃ­ procediendo a su restauraciâ”œâ”‚n, que incluye la retirada del pedestal con dos columnas que sostuvo la estatua de Câ”œÂ®sar Augusto. Entre 2012 y 2013, esta zona se verâ”œÃ­ modificada por el paso del tranvâ”œÂ¡a y la retirada de los arcos "Alegorâ”œÂ¡a de la Puerta de la Paz", entre las murallas y el Mercado Central. Al fondo, la câ”œâ•‘pula de la iglesia de Santiago el Mayor. Fuente: Archivo Antonio Tausiet.', 2005, 2005, 2005, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65718500, -0.88192100, '0101000020E6100000CEFA9463B238ECBFFC3559A31ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41597324550.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41597324550.webp', 'https://www.flickr.com/photos/zaragozaantigua/41597324550/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24687, 'Plaza de Huesca 1914', 'Foto: Serrano Sancho. "Hundimiento de una casa en Zaragoza. Estado en que quedâ”œâ”‚ la casa de la plaza de Huesca que se derrumbâ”œâ”‚ el miâ”œÂ®rcoles â”œâ•‘ltimo", 28 de enero de 1914. Al fondo, la câ”œâ•‘pula de la torre de San Juan de los Panetes. Fuente: Diario ABC, 31-1-1914.', 1914, 1914, 1914, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65734300, -0.88091400, '0101000020E61000005AD5928E7230ECBF94A0BFD023D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43256261372.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43256261372.webp', 'https://www.flickr.com/photos/zaragozaantigua/43256261372/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24688, 'Avenida de Câ”œÂ®sar Augusto 1999', 'La avenida de Câ”œÂ®sar Augusto, en su tramo adyacente a las Murallas Romanas, entre el paseo de Echegaray y Caballero y el Mercado Central. A la izquierda, el Torreâ”œâ”‚n de la Zuda, y tras el lienzo de muralla, la iglesia de San Juan de los Panetes. Este entorno, olivos incluidos, serâ”œÃ­ trocado en otro distinto con el paso de la nueva lâ”œÂ¡nea de tranvâ”œÂ¡a en 2013.', 1999, 1999, 1999, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65718500, -0.88192100, '0101000020E6100000CEFA9463B238ECBFFC3559A31ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50210619061.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50210619061.webp', 'https://www.flickr.com/photos/zaragozaantigua/50210619061/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24689, 'San Juan de los Panetes 1990', 'En el proyecto de rehabilitaciâ”œâ”‚n y embellecimiento de la plaza del Pilar, cuyas obras comenzaron tras las Fiestas del Pilar de 1990, estaba incluido el desmantelamiento del "Monumento a los hâ”œÂ®roes y mâ”œÃ­rtires de Zaragoza caâ”œÂ¡dos en la Cruzada de Liberaciâ”œâ”‚n 1936-1939", que serâ”œÂ¡a trasladado al cementerio catâ”œâ”‚lico de Torrero y sustituido por una fuente alusiva a la "Hispanidad". En la imagen, montaje de los andamios previo al desmontaje de este monumental cenotafio terminado en 1954, quince aâ”œâ–’os despuâ”œÂ®s del oficial final de la guerra, como muestra de que el râ”œÂ®gimen franquista no pasaba pâ”œÃ­gina ni a sus orâ”œÂ¡genes ni a sus sâ”œÂ¡mbolos fundacionales, ni a la memoria de sus muertos. Este trâ”œÃ­nsito edilicio apenas suscitâ”œâ”‚ polâ”œÂ®mica o resiliencia social.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65725800, -0.88091200, '0101000020E61000002DEDD45C6E30ECBF6684B70721D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50374895517.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50374895517.webp', 'https://www.flickr.com/photos/zaragozaantigua/50374895517/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23749, 'Torre de Santa Engracia 1972', 'Torre de Santa Engracia era una finca del barrio rural de Movera que fue adquirida en 1970 por el Ayuntamiento, mediante permuta con la papelera La Montaâ”œâ–’anesa. El edificio responde a la tipologâ”œÂ¡a de las agrâ”œÂ¡colas torres de la periferia de Zaragoza, y estâ”œÃ­ datada en el siglo XVII, cuando era propiedad del monasterio de Santa Engracia. En el siglo XIX fue desamortizada y muy modificada. Desde 2015 acoge a la Escuela Agrâ”œÂ¡cola Municipal Km 0.', 1972, 1972, 1972, 'Anos 70', NULL, 41.64234700, -0.80543500, '0101000020E610000067B8019F1FC6E9BF84D72E6D38D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15795238915.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15795238915.webp', 'https://www.flickr.com/photos/zaragozaantigua/15795238915/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24692, 'Torreâ”œâ”‚n de la Zuda c.1885', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 25 de la calle de Antonio Pâ”œÂ®rez y centrada en el Torreâ”œâ”‚n de la Zuda reciâ”œÂ®n restaurado y al que se ha incorporado una nueva cubierta a cuatro aguas proyectada por el arquitecto municipal Ricardo Magdalena. Este torreâ”œâ”‚n despunta de las instalaciones del antiguo palacio de la Castellanâ”œÂ¡a de Amposta de san Juan de Jerusalâ”œÂ®n, desde unos pocos aâ”œâ–’os antes convertido en convento de las Madres Adoratrices, y con varias casas adosadas recayentes al lado de los pares de la calle de Antonio Pâ”œÂ®rez. Tras el torreâ”œâ”‚n y a la izquierda aparece la iglesia de san Juan de los Panetes, y a la derecha la antigua torre inacabada de Santiago del templo del Pilar. Mâ”œÃ­s al fondo, la barroca torre de la Seo.', 1885, 1885, 1885, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65755500, -0.88170600, '0101000020E6100000B5FB5580EF36ECBF202922C32AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52286836398.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52286836398.webp', 'https://www.flickr.com/photos/zaragozaantigua/52286836398/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24865, 'P.â”¬â•‘ del Ebro 1929', 'Imagen centrada en el antiguo paseo del Ebro, en la zona comprendida entre la calle del Fin y la iglesia de San Juan de los Panetes, al fondo, con el firme pendiente de embellecimiento, y notable trâ”œÃ­fico de vehâ”œÂ¡culos tirados por caballerâ”œÂ¡a. Este tramo de la antigua lâ”œÂ¡nea tranviaria de Circunvalaciâ”œâ”‚n estaba suprimido desde 1925, cuando entrâ”œâ”‚ en servicio la lâ”œÂ¡nea del Ayuntamiento. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65750100, -0.87988100, '0101000020E610000097E5EB32FC27ECBF2D0B26FE28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35307218056.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35307218056.webp', 'https://www.flickr.com/photos/zaragozaantigua/35307218056/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25131, 'Calle del Fin aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste. Portada de la iglesia del antiguo Convento y colegio de San Nicolâ”œÃ­s de Tolentino de los Agustinos, situado en la calle del Fin, uno de los postigos abiertos en la antigua muralla romana, que anteriormente fue conocido como "Postigo de Montaner", y luego "de la madera", por el trâ”œÃ­fago de este material desde la ribera del Ebro hacia el interior de la ciudad. Este colegio fue abierto en 1605, y tenâ”œÂ¡a una pequeâ”œâ–’a iglesia que conectaba con el inmediato palacio de los Ayerbe, sus grandes financiadores. El colegio dio nombre ("Agustinos") a la calle que desde la plaza del Pilar conducâ”œÂ¡a a San Juan de los Panetes. Como todas las demâ”œÃ­s construcciones de la zona, fueran palacios, colegios, o sencillas viviendas, fue arrasado cuando la plaza del Pilar fue retro-evolucionada del barroco, al nacional-catolicismo. En la imagen, la sencilla portada de la iglesia del colegio-convento. Destaca el escudo nobiliario en altorrelieve del barâ”œâ”‚n don Hugo de Urriâ”œÂ®s y su mujer, doâ”œâ–’a Beatriz de Cardona y Requesens, patrocinadores del colegio. Por la izquierda se accedâ”œÂ¡a a la "puerta del Fin" que daba acceso al paseo de la ribera. Por la derecha, a la calle Agustinos. Fuente visual: Lâ”œÃ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65722600, -0.87978600, '0101000020E610000026512FF83427ECBF5B0A48FB1FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18546963160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18546963160.webp', 'https://www.flickr.com/photos/zaragozaantigua/18546963160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25153, 'Torreâ”œâ”‚n de la Zuda aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste representando el torreâ”œâ”‚n de la Zuda, con la iglesia de San Juan de los Panetes a la derecha. Fuente: Lâ”œÃ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65756000, -0.88160100, '0101000020E610000061DEE34C1336ECBF319413ED2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31627244013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31627244013.webp', 'https://www.flickr.com/photos/zaragozaantigua/31627244013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25406, 'Pasarela sobre el Ebro c.1945', 'Aguas arriba del puente de Piedra, estuvo en servicio esta pasarela peatonal sobre el Ebro, con taquillas en ambos mâ”œÃ­rgenes, desde el 25 de febrero de 1941 hasta la inauguraciâ”œâ”‚n del puente de Santiago en 1967. Conocida como pasarela de Macanaz.', 1945, 1945, 1945, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65787500, -0.88078600, '0101000020E6100000FBC9181F662FECBF91ED7C3F35D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14899757335.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14899757335.webp', 'https://www.flickr.com/photos/zaragozaantigua/14899757335/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25419, 'Echegaray y Caballero 1956', 'Foto Josâ”œÂ® Antonio Duce, 1956. Dâ”œÂ¡a de niebla en el Paseo de Echegaray y Caballero de Zaragoza, junto al Ebro, a la altura de la pasarela de Macanaz (al fondo). Fuente: www.rafaelcastillejo.com/zaraduce.htm', 1956, 1956, 1956, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65771500, -0.88075300, '0101000020E61000000D535BEA202FECBF598B4F0130D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15842183336.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15842183336.webp', 'https://www.flickr.com/photos/zaragozaantigua/15842183336/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25453, 'Pasarela de Macanaz 1950', 'Imagen estival centrada en la pasarela peatonal tendida sobre el râ”œÂ¡o Ebro en 1941, tambiâ”œÂ®n conocida como de Macanaz, flanqueada por los escalonados descensos hacia los embarcaderos, y con una vista del antiguo colector de la Triperâ”œÂ¡a. La escena se ha capturado desde uno de los embarcaderos recreativos de la Margen Izquierda. El fondo edilicio viene determinado por el templo del Pilar con sus dos torres, como desde principios de siglo, la gran Hospederâ”œÂ¡a del Pilar de la Sociedad Angâ”œÂ®lica del Sagrado Corazâ”œâ”‚n de Jesâ”œâ•‘s, el nuevo convento de las Hermanas Misioneras Eucarâ”œÂ¡sticas de Nazareth, adosado a la iglesia de San Juan de los Panetes, y el Grupo Escolar de Valentâ”œÂ¡n Zabala, sobre el que emerge el Torreâ”œâ”‚n de la Zuda. Fuente visual: AMZ', 1950, 1950, 1950, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65801400, -0.88160800, '0101000020E6100000008BFCFA2136ECBFB32781CD39D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39994558783.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39994558783.webp', 'https://www.flickr.com/photos/zaragozaantigua/39994558783/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25554, 'Puente de Santiago 2012', 'Obras para la segunda fase de la lâ”œÂ¡nea 1 del tranvâ”œÂ¡a, a su paso por el puente de Santiago. Al fondo, la margen izquierda del Ebro. Fuente: www.skyscrapercity.com/', 2012, 2012, 2012, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65821000, -0.88163300, '0101000020E61000003961C2685636ECBF38F3AB3940D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24825966856.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24825966856.webp', 'https://www.flickr.com/photos/zaragozaantigua/24825966856/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20894, 'Puerto fluvial siglo I', 'Maqueta del edificio de acceso del puerto fluvial de Caesaraugusta, siglo I. Al derribar las casas de la plaza de San Bruno en 1989 para construir las actuales viviendas de protecciâ”œâ”‚n oficial, se descubrieron los vestigios de una edificaciâ”œâ”‚n al nordeste del foro. Consta de una serie de vanos pertenecientes a una fachada de arquerâ”œÂ¡as orientada hacia el râ”œÂ¡o Ebro, por las que se alcanzaba un vestâ”œÂ¡bulo y desde â”œÂ®ste una escalinata que comunicaba los muelles del puerto fluvial con la plaza del foro. Hoy es un museo visitable, en la plaza de San Bruno 8. Fuente: www.zaragoza.es/ciudad/museos/es/puerto', 50, NULL, 99, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65518900, -0.87460400, '0101000020E6100000D36C1E87C1FCEBBF77D9AF3BDDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19783359583.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19783359583.webp', 'https://www.flickr.com/photos/zaragozaantigua/19783359583/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20895, 'Puerto fluvial 1989', 'Estructura del puerto fluvial romano del siglo I en el entorno de la plaza de San Bruno de Zaragoza. Al fondo, la calle Arcedianos. Fuente: dp-foto.blogspot.com', 1989, 1989, 1989, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65518900, -0.87460400, '0101000020E6100000D36C1E87C1FCEBBF77D9AF3BDDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20082409184.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20082409184.webp', 'https://www.flickr.com/photos/zaragozaantigua/20082409184/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20903, 'Puerto fluvial siglo I', 'Recreaciâ”œâ”‚n infogrâ”œÃ­fica del puerto fluvial de Caesaraugusta y su entorno junto al râ”œÂ¡o Ebro. A la derecha, el puente romano. Tras el gran edificio del puerto, el foro con su templo.', 50, NULL, 99, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65592200, -0.87462000, '0101000020E61000003EAE0D15E3FCEBBF0B5D8940F5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54170714151.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54170714151.webp', 'https://www.flickr.com/photos/zaragozaantigua/54170714151/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20925, 'Casa Diputados Reino 1539', 'Dibujo de Valentâ”œÂ¡n Carderera y Solano, del "patinejo" de la antigua Casa hospedaje de los Diputados del Reino de Aragâ”œâ”‚n, en la calle del General del Reino, un palacio del siglo XVI demolido parcialmente en 1863-64, cuando el patio fue desmontado, y completamente en la dâ”œÂ®cada de los aâ”œâ–’os 40 del siglo XX, cuando el entorno de la Seo, como la calle de Palafox, fue "reordenado". Este palacio habâ”œÂ¡a sido adquirido como residencia de los Diputados del Reino que no vivâ”œÂ¡an en Zaragoza, mientras su estancia en la ciudad. El dibujo estâ”œÃ­ tomado al natural, y datado en torno a 1860, poco antes del desmontaje del patio, aunque el autor parece situarlo en "1539", fecha de la talla del patio por Renâ”œÂ® Trayanus, introduciendo para ambientar dos ficcionados personajes de esa â”œÂ®poca. Cuatro columnas, cuatro pilastras, y algunos fragmentos del arquitrabe, en alabastro ensuciado, perduran en el Museo de Zaragoza, recompuestos desordenadamente. Fuente visual: ceres.mcu.es/', 1539, 1539, 1539, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65440600, -0.87472000, '0101000020E6100000210725CCB4FDEBBF31276893C3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22357296016.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22357296016.webp', 'https://www.flickr.com/photos/zaragozaantigua/22357296016/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
