INSERT INTO public.photos VALUES (22073, 'San Pablo 1953', 'Imagen de la puerta principal y la torre de la parroquia de San Pablo. La pâ”œÂ®trea fachada y los jarrones incrustados que luce son una impostaciâ”œâ”‚n del siglo XVIII, cuando se recubriâ”œâ”‚ con piedra el ladrillo de la fâ”œÃ­brica original. Fuente visual: "Aragâ”œâ”‚n : revista grâ”œÃ­fica de cultura aragonesa" (Aâ”œâ–’o XXVIII, Nâ”¬â•‘ 227, abril-junio 1953).', 1953, 1953, 1953, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65588600, -0.88609200, '0101000020E610000053E9279CDD5AECBFBFF38B12F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15507137488.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15507137488.webp', 'https://www.flickr.com/photos/zaragozaantigua/15507137488/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
