INSERT INTO public.photos VALUES (22452, 'Calle General Franco 1967', 'Foto: Emilio Aure Durbâ”œÃ­n. Vista de la calle del General Franco, con la zona del Portillo al fondo. A la derecha, en el nâ”œâ•‘mero 32, cartel del Cine Monumental, inaugurado en 1933 como "Monumental Cinema" y clausurado en 1972. Fuente visual: www.facebook.com/photo.php?fbid=1802072866697326&set=...', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65493800, -0.88719100, '0101000020E6100000F3C64961DE63ECBF2E742502D5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31419929176.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31419929176.webp', 'https://www.flickr.com/photos/zaragozaantigua/31419929176/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
