INSERT INTO public.photos VALUES (22492, 'Calle del General Franco 1968', 'Imagen capturada en el adoquinado tramo inicial de la calle del General Franco, entre el colegio de los Escolapios y el inmueble del nâ”¬â•‘ 28, a la izquierda. Centra la escena la composiciâ”œâ”‚n tranviaria M59+R87 de la lâ”œÂ¡nea 5 "Venecia-Delicias" encaminada hacia la terminal de la plaza de Huesca. Tras ella, la desaparecida fachada edilicia de la manzana entre la calle de Miguel de Ara y la de Ramâ”œâ”‚n y Cajal. A la derecha extrema sobresale el torreâ”œâ”‚n occidental del palacio de la Audiencia, y algunos de los anuncios comerciales que culminaban el arranque de la desaparecida manzana entre la calle de Cerdâ”œÃ­n y la de las Escuelas Pâ”œÂ¡as. Fuente visual: foto Charles F. Firminger en "30937 Transport Photograph Database".', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65473500, -0.88642500, '0101000020E6100000E86A2BF6975DECBFF645425BCED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46933109132.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46933109132.webp', 'https://www.flickr.com/photos/zaragozaantigua/46933109132/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22568, 'Rastro del Mercado 1975', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Junio 1975. "Rastro del Mercado." Zaragoza 100%: estâ”œÃ­ pegando un sol enorme, pero no por ello hay que buscar la sombra: con ponerse un periâ”œâ”‚dico en la cabeza, vale. Imagen del rastro, secciâ”œâ”‚n sables, braseros, candelabros y quincalla varia, en el entorno de la puerta principal de acceso al Mercado Central, inmediata a la calle Cerdâ”œÃ­n, calle a la que le quedaba apenas una legislatura de vida.', 1975, 1975, 1975, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65559900, -0.88345500, '0101000020E6100000139B8F6B4345ECBF292504ABEAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15246198251.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15246198251.webp', 'https://www.flickr.com/photos/zaragozaantigua/15246198251/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22646, 'Calle Cerdâ”œÃ­n 1977', 'Foto: Colecciâ”œâ”‚n Antonio Gâ”œÃ­mez. Calle Cerdâ”œÃ­n de Zaragoza, vista desde el Mercado Central, en 1977. Fuente: rafaelcastillejo.com', 1977, 1977, 1977, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65562300, -0.88343900, '0101000020E6100000A759A0DD2145ECBFB1C05774EBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20683891666.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20683891666.webp', 'https://www.flickr.com/photos/zaragozaantigua/20683891666/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22655, 'San Pablo 1977', 'La iglesia parroquial de San Pablo ha sido objeto, a lo largo de su extensa historia desde que fuera alminar del arrabal musulmâ”œÃ­n al oeste de la ciudad, de numerosas modificaciones en su fâ”œÃ­brica, aspecto, y espacio interior. A finales del siglo XVIII su fachada y portada de acceso principal, en la calle de San Pablo, fueron profusamente reformadas con elementos tardo-neoclâ”œÃ­sicos. Asâ”œÂ¡, el muro fue revestido de piedra, y decorado con pilastras lisas, una cornisa superior y hornacinas con jarrones. Posteriores restauraciones han eliminado toda esta traza, excepto en la puerta de ingreso. En la imagen, captura del exterior del muro de la iglesia de San Pablo, con el arrasamiento de los aâ”œâ–’adidos de finales del XVIII, en la bâ”œâ•‘squeda del previo muro mudâ”œÂ®jar. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1977, 1977, 1977, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65588600, -0.88609200, '0101000020E610000053E9279CDD5AECBFBFF38B12F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21655866670.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21655866670.webp', 'https://www.flickr.com/photos/zaragozaantigua/21655866670/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
